def _build_project_roadmap_items(
    *,
    project_planning_summary_compact: Mapping[str, Any],
    planning_source_status: str,
) -> list[dict[str, Any]]:
    continuation_budget_status = _normalize_text(
        project_planning_summary_compact.get("continuation_budget_status"),
        default="unknown",
    )
    continuation_budget_branch_status = _normalize_text(
        project_planning_summary_compact.get("continuation_budget_branch_status"),
        default="unknown",
    )
    continuation_failure_bucket = _normalize_text(
        project_planning_summary_compact.get("continuation_failure_bucket"),
        default="unknown",
    )
    continuation_failure_bucket_denied = bool(
        project_planning_summary_compact.get("continuation_failure_bucket_denied", False)
    )
    continuation_next_step_selection_status = _normalize_text(
        project_planning_summary_compact.get("continuation_next_step_selection_status"),
        default="unknown",
    )
    continuation_next_step_target = _normalize_text(
        project_planning_summary_compact.get("continuation_next_step_target"),
        default="none",
    )
    supported_repair_execution_status = _normalize_text(
        project_planning_summary_compact.get("supported_repair_execution_status"),
        default="unknown",
    )
    final_human_review_required = bool(
        project_planning_summary_compact.get("final_human_review_required", False)
    )
    final_human_review_reason = _normalize_text(
        project_planning_summary_compact.get("final_human_review_reason"),
        default="final_review_not_required",
    )

    roadmap_items: list[dict[str, Any]] = [
        {
            "roadmap_item_id": "roadmap_continuation_budget",
            "topic_theme": "continuation_budget",
            "bounded_scope_class": "runner_only",
            "planning_source_status": planning_source_status,
            "blocked": continuation_budget_status != "available",
            "blocked_reason": (
                "budget_not_available"
                if continuation_budget_status != "available"
                else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
        {
            "roadmap_item_id": "roadmap_branch_ceiling",
            "topic_theme": "branch_ceiling",
            "bounded_scope_class": "runner_only",
            "planning_source_status": planning_source_status,
            "blocked": continuation_budget_branch_status != "available",
            "blocked_reason": (
                "branch_ceiling_not_available"
                if continuation_budget_branch_status != "available"
                else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
        {
            "roadmap_item_id": "roadmap_failure_bucket_gate",
            "topic_theme": "failure_bucket_gate",
            "bounded_scope_class": "runner_only",
            "planning_source_status": planning_source_status,
            "blocked": continuation_failure_bucket_denied,
            "blocked_reason": (
                f"failure_bucket_denied:{continuation_failure_bucket}"
                if continuation_failure_bucket_denied
                else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
        {
            "roadmap_item_id": "roadmap_next_step_selection",
            "topic_theme": "next_step_selection",
            "bounded_scope_class": "runner_and_tests",
            "planning_source_status": planning_source_status,
            "blocked": continuation_next_step_selection_status != "selected",
            "blocked_reason": (
                "next_step_not_selected"
                if continuation_next_step_selection_status != "selected"
                else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
        {
            "roadmap_item_id": "roadmap_supported_repair_posture",
            "topic_theme": "supported_repair_posture",
            "bounded_scope_class": "runner_and_tests",
            "planning_source_status": planning_source_status,
            "blocked": supported_repair_execution_status in {
                "executed_verification_failed",
                "not_executed_precheck_blocked",
                "not_executed_qualification_failed",
                "not_executed_launch_failed",
            },
            "blocked_reason": (
                f"supported_repair_status:{supported_repair_execution_status}"
                if supported_repair_execution_status
                not in {"", "not_selected", "executed_verification_passed"}
                else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
        {
            "roadmap_item_id": "roadmap_human_review_gate",
            "topic_theme": "human_review_gate",
            "bounded_scope_class": "runner_and_tests",
            "planning_source_status": planning_source_status,
            "blocked": final_human_review_required,
            "blocked_reason": (
                final_human_review_reason if final_human_review_required else "none"
            ),
            "prerequisite_item_ids": [],
            "insufficient_reason": "",
        },
    ]

    raw_blocked_by_id = {
        _normalize_text(item.get("roadmap_item_id"), default=""): bool(item.get("blocked", False))
        for item in roadmap_items
    }
    for item in roadmap_items:
        item_id = _normalize_text(item.get("roadmap_item_id"), default="")
        prerequisites = list(_PROJECT_ROADMAP_PREREQUISITES.get(item_id, ()))
        item["prerequisite_item_ids"] = prerequisites
        item["blocked"] = bool(
            item.get("blocked", False)
            or any(raw_blocked_by_id.get(prereq_id, False) for prereq_id in prerequisites)
        )
        if item["blocked"] and _normalize_text(item.get("blocked_reason"), default="none") == "none":
            item["blocked_reason"] = "blocked_by_prerequisite"

    ordered_items = sorted(
        roadmap_items,
        key=lambda item: (
            1 if bool(item.get("blocked", False)) else 0,
            _PROJECT_ROADMAP_SCOPE_CLASS_ORDER.get(
                _normalize_text(item.get("bounded_scope_class"), default="unknown"),
                _PROJECT_ROADMAP_SCOPE_CLASS_ORDER["unknown"],
            ),
            _PROJECT_ROADMAP_ITEM_ORDER.get(
                _normalize_text(item.get("roadmap_item_id"), default=""),
                len(_PROJECT_ROADMAP_ITEM_ORDER),
            ),
        ),
    )
    for index, item in enumerate(ordered_items, start=1):
        item["order"] = index
        item["priority"] = index
        item["priority_class"] = "blocked" if bool(item.get("blocked", False)) else "active"
    return ordered_items


def _build_project_pr_slices(
    roadmap_items: list[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    if not roadmap_items:
        return []

    item_id_to_slice_id: dict[str, str] = {}
    slices: list[dict[str, Any]] = []
    for index, item in enumerate(roadmap_items, start=1):
        topic_theme = _normalize_text(item.get("topic_theme"), default="unknown")
        item_id = _normalize_text(item.get("roadmap_item_id"), default="")
        slice_id = f"slice_{index:02d}_{topic_theme}"
        item_id_to_slice_id[item_id] = slice_id
        slices.append(
            {
                "slice_id": slice_id,
                "order": index,
                "priority": _as_non_negative_int(item.get("priority"), default=index),
                "topic_theme": topic_theme,
                "roadmap_item_id": item_id,
                "bounded_scope_class": _normalize_text(
                    item.get("bounded_scope_class"),
                    default="unknown",
                ),
                "planning_source_status": _normalize_text(
                    item.get("planning_source_status"),
                    default="planning_summary_available",
                ),
                "blocked": bool(item.get("blocked", False)),
                "blocked_reason": _normalize_text(
                    item.get("blocked_reason"),
                    default="none",
                ),
                "one_pr_size_decision": "single_theme_single_pr",
                "insufficient_reason": _normalize_text(
                    item.get("insufficient_reason"),
                    default="",
                ),
                "prerequisite_slice_ids": [],
            }
        )
    for item, slice_entry in zip(roadmap_items, slices):
        prerequisite_ids = [
            item_id_to_slice_id[prereq_id]
            for prereq_id in item.get("prerequisite_item_ids", [])
            if prereq_id in item_id_to_slice_id
        ]
        slice_entry["prerequisite_slice_ids"] = prerequisite_ids
    return slices


def _normalize_implementation_prompt_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _IMPLEMENTATION_PROMPT_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _IMPLEMENTATION_PROMPT_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["prompt_planning_insufficient_truth"]


def _build_implementation_prompt_payload(
    *,
    objective_id: str,
    project_planning_summary_status: str,
    project_pr_slicing_status: str,
    project_pr_one_pr_size_decision: str,
    project_pr_slices: list[Mapping[str, Any]],
) -> dict[str, Any]:
    prompt_status = "insufficient_truth"
    prompt_available = False
    prompt_reason = "prompt_planning_insufficient_truth"

    selected_slice: Mapping[str, Any] = {}
    if project_planning_summary_status != "available":
        prompt_reason = "prompt_planning_insufficient_truth"
    elif project_pr_slicing_status != "available":
        prompt_reason = "prompt_slice_state_insufficient_truth"
    elif project_pr_one_pr_size_decision != "single_theme_single_pr":
        prompt_reason = "prompt_size_posture_unbounded"
    elif not project_pr_slices:
        prompt_reason = "prompt_slice_missing"
    else:
        prompt_status = "available"
        prompt_available = True
        prompt_reason = "prompt_compiled"
        selected_slice = min(
            project_pr_slices,
            key=lambda item: (
                _as_non_negative_int(item.get("order"), default=0),
                _normalize_text(item.get("slice_id"), default=""),
            ),
        )

    prompt_reason_codes = _normalize_implementation_prompt_reason_codes([prompt_reason])
    slice_id = _normalize_text(selected_slice.get("slice_id"), default="")
    roadmap_item_id = _normalize_text(selected_slice.get("roadmap_item_id"), default="")
    topic_theme = _normalize_text(selected_slice.get("topic_theme"), default="unknown")
    bounded_scope_class = _normalize_text(
        selected_slice.get("bounded_scope_class"),
        default="unknown",
    )
    objective_or_theme = (
        f"{objective_id}:{topic_theme}" if objective_id and topic_theme != "unknown" else topic_theme
    )
    in_scope = list(
        _IMPLEMENTATION_PROMPT_IN_SCOPE_BY_THEME.get(
            topic_theme,
            ("deterministic bounded slice implementation only",),
        )
    )
    return {
        "prompt_status": (
            prompt_status
            if prompt_status in _IMPLEMENTATION_PROMPT_STATUSES
            else "insufficient_truth"
        ),
        "prompt_available": bool(prompt_available),
        "prompt_reason": prompt_reason_codes[0],
        "prompt_reason_codes": prompt_reason_codes,
        "slice_id": slice_id,
        "roadmap_item_id": roadmap_item_id,
        "objective_or_theme": objective_or_theme,
        "bounded_scope_class": bounded_scope_class,
        "in_scope": in_scope if prompt_available else [],
        "out_of_scope": (
            list(_IMPLEMENTATION_PROMPT_DEFAULT_OUT_OF_SCOPE) if prompt_available else []
        ),
        "preferred_files": (
            list(_IMPLEMENTATION_PROMPT_DEFAULT_PREFERRED_FILES) if prompt_available else []
        ),
        "preserved_constraints_ref": (
            list(_IMPLEMENTATION_PROMPT_PRESERVED_CONSTRAINTS_REFS) if prompt_available else []
        ),
        "suggested_validation_targets": (
            ["uv run python -m unittest tests.test_planned_execution_runner -v"]
            if prompt_available
            else []
        ),
        "return_format": (
            [
                "1. exact files changed",
                "2. tests not run by instruction",
                "3. suggested validation targets",
                "4. out-of-scope changes explicitly avoided",
                "5. prior increments / accumulated execution history / current architecture constraints explicitly preserved",
                "6. prompt-generation rule explicitly preserved",
            ]
            if prompt_available
            else []
        ),
    }


def _normalize_project_pr_queue_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_PR_QUEUE_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_PR_QUEUE_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["queue_state_insufficient_truth"]


def _build_project_pr_queue_state(
    *,
    project_pr_slicing_status: str,
    project_pr_slices: list[Mapping[str, Any]],
    implementation_prompt_payload: Mapping[str, Any],
    prior_processed_slice_ids: list[str],
) -> dict[str, Any]:
    queue_status = "insufficient_truth"
    queue_reason = "queue_state_insufficient_truth"
    queue_items: list[dict[str, Any]] = []
    selected_item: dict[str, Any] = {}
    handoff_prepared = False
    handoff_payload: dict[str, Any] = {}
    processed_before = _serialize_required_signals(prior_processed_slice_ids)
    processed_set = set(processed_before)

    if project_pr_slicing_status == "available":
        ordered_slices = sorted(
            project_pr_slices,
            key=lambda item: (
                _as_non_negative_int(item.get("order"), default=0),
                _normalize_text(item.get("slice_id"), default=""),
            ),
        )
        for item in ordered_slices:
            slice_id = _normalize_text(item.get("slice_id"), default="")
            blocked = bool(item.get("blocked", False))
            processed = bool(slice_id and slice_id in processed_set)
            runnable = bool(slice_id and not blocked and not processed)
            blocked_reason = _normalize_text(item.get("blocked_reason"), default="")
            if processed and not blocked_reason:
                blocked_reason = "already_prepared"
            queue_items.append(
                {
                    "slice_id": slice_id,
                    "roadmap_item_id": _normalize_text(item.get("roadmap_item_id"), default=""),
                    "order": _as_non_negative_int(item.get("order"), default=0),
                    "blocked": blocked,
                    "processed": processed,
                    "runnable": runnable,
                    "blocked_reason": blocked_reason,
                }
            )

        if not queue_items:
            queue_status = "empty"
            queue_reason = "queue_empty"
        else:
            runnable_items = [item for item in queue_items if bool(item.get("runnable", False))]
            if not runnable_items:
                if any(bool(item.get("processed", False)) for item in queue_items):
                    queue_status = "empty"
                    queue_reason = "queue_empty"
                else:
                    queue_status = "blocked"
                    queue_reason = "queue_item_blocked"
                    selected_item = dict(queue_items[0])
            else:
                selected_item = dict(runnable_items[0])
                prompt_available = bool(implementation_prompt_payload.get("prompt_available", False))
                prompt_slice_id = _normalize_text(
                    implementation_prompt_payload.get("slice_id"),
                    default="",
                )
                selected_slice_id = _normalize_text(selected_item.get("slice_id"), default="")
                if prompt_available and prompt_slice_id == selected_slice_id:
                    queue_status = "prepared"
                    queue_reason = "queue_item_prepared"
                    handoff_prepared = True
                    handoff_payload = {
                        "slice_id": selected_slice_id,
                        "roadmap_item_id": _normalize_text(
                            selected_item.get("roadmap_item_id"),
                            default="",
                        ),
                        "order": _as_non_negative_int(
                            selected_item.get("order"),
                            default=0,
                        ),
                        "implementation_prompt_payload": dict(implementation_prompt_payload),
                    }
                else:
                    queue_status = "blocked"
                    queue_reason = "prompt_unavailable_for_selected_slice"

    queue_reason_codes = _normalize_project_pr_queue_reason_codes([queue_reason])
    selected_slice_id = _normalize_text(selected_item.get("slice_id"), default="")
    processed_after = processed_before
    if handoff_prepared and selected_slice_id:
        processed_after = _serialize_required_signals([*processed_before, selected_slice_id])
    runnable_count = sum(1 for item in queue_items if bool(item.get("runnable", False)))
    blocked_count = sum(
        1
        for item in queue_items
        if bool(item.get("blocked", False)) or bool(item.get("processed", False))
    )
    return {
        "queue_status": (
            queue_status if queue_status in _PROJECT_PR_QUEUE_STATUSES else "insufficient_truth"
        ),
        "queue_reason": queue_reason_codes[0],
        "queue_reason_codes": queue_reason_codes,
        "queue_item_count": len(queue_items),
        "queue_runnable_count": runnable_count,
        "queue_blocked_count": blocked_count,
        "queue_selected_slice_id": selected_slice_id,
        "queue_selected_roadmap_item_id": _normalize_text(
            selected_item.get("roadmap_item_id"),
            default="",
        ),
        "queue_selected_blocked": bool(selected_item.get("blocked", False)),
        "queue_handoff_prepared": bool(handoff_prepared),
        "queue_handoff_payload": handoff_payload,
        "queue_items": queue_items,
        "queue_processed_slice_ids_before": processed_before,
        "queue_processed_slice_ids_after": processed_after,
    }


def _normalize_review_assimilation_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _REVIEW_ASSIMILATION_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _REVIEW_ASSIMILATION_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["assimilation_result_insufficient_truth"]


def _build_review_assimilation_state(
    *,
    queue_status: str,
    queue_reason: str,
    queue_handoff_prepared: bool,
    queue_handoff_payload: Mapping[str, Any] | None,
    restart_result_status: str,
    continuation_next_step_target: str,
    continuation_next_step_reason: str,
    continuation_next_step_truth_insufficiency_explicit: bool,
    final_human_review_required: bool,
    final_human_review_reason: str,
) -> dict[str, Any]:
    normalized_queue_status = _normalize_text(queue_status, default="insufficient_truth")
    normalized_queue_reason = _normalize_text(queue_reason, default="")
    normalized_result_status = _normalize_text(restart_result_status, default="not_attempted")
    normalized_next_step_target = _normalize_text(continuation_next_step_target, default="none")
    normalized_next_step_reason = _normalize_text(continuation_next_step_reason, default="")
    normalized_final_review_reason = _normalize_text(final_human_review_reason, default="")
    handoff_payload_map = (
        dict(queue_handoff_payload)
        if isinstance(queue_handoff_payload, Mapping)
        else {}
    )
    handoff_slice_id = _normalize_text(handoff_payload_map.get("slice_id"), default="")
    handoff_roadmap_item_id = _normalize_text(
        handoff_payload_map.get("roadmap_item_id"),
        default="",
    )

    assimilation_status = "insufficient_truth"
    assimilation_action = "none"
    assimilation_reason = "assimilation_result_insufficient_truth"
    reviewable = False

    if normalized_queue_status == "insufficient_truth":
        assimilation_status = "insufficient_truth"
        assimilation_reason = "assimilation_queue_state_insufficient_truth"
    elif normalized_queue_status == "empty":
        assimilation_status = "no_action"
        assimilation_reason = "assimilation_queue_empty"
    elif normalized_queue_status == "blocked":
        assimilation_status = "no_action"
        assimilation_reason = (
            "assimilation_prompt_unavailable"
            if normalized_queue_reason == "prompt_unavailable_for_selected_slice"
            else "assimilation_queue_blocked"
        )
    elif normalized_queue_status != "prepared":
        assimilation_status = "insufficient_truth"
        assimilation_reason = "assimilation_queue_state_insufficient_truth"
    elif not queue_handoff_prepared:
        assimilation_status = "no_action"
        assimilation_reason = "assimilation_queue_blocked"
    else:
        reviewable = True
        if normalized_result_status in {"", "unknown", "not_attempted", "not_started", "running"}:
            assimilation_status = "insufficient_truth"
            assimilation_reason = "assimilation_result_insufficient_truth"
        elif final_human_review_required:
            assimilation_status = "assimilated"
            assimilation_action = "escalate"
            assimilation_reason = "assimilation_escalate_manual_followup"
        elif normalized_result_status == "completed":
            assimilation_status = "assimilated"
            assimilation_action = "accept"
            assimilation_reason = "assimilation_accept_succeeded"
        elif normalized_result_status in {"failed", "timed_out"}:
            assimilation_status = "assimilated"
            if normalized_next_step_target == "replan" or normalized_next_step_reason == "next_step_selected_replan":
                assimilation_action = "replan"
                assimilation_reason = "assimilation_replan_design_invalid"
            elif (
                normalized_next_step_target == "truth_gather"
                or continuation_next_step_truth_insufficiency_explicit
            ):
                assimilation_action = "split"
                assimilation_reason = "assimilation_split_scope_signal"
            elif normalized_next_step_target in {"retry", "supported_repair"}:
                assimilation_action = "retry"
                assimilation_reason = "assimilation_retry_retryable_failure"
            elif (
                normalized_final_review_reason
                and normalized_final_review_reason != "final_review_not_required"
            ):
                assimilation_action = "escalate"
                assimilation_reason = "assimilation_escalate_manual_followup"
            else:
                assimilation_action = "escalate"
                assimilation_reason = "assimilation_escalate_unclassified"
        else:
            assimilation_status = "insufficient_truth"
            assimilation_reason = "assimilation_result_insufficient_truth"

    assimilation_reason_codes = _normalize_review_assimilation_reason_codes([assimilation_reason])
    if assimilation_status not in _REVIEW_ASSIMILATION_STATUSES:
        assimilation_status = "insufficient_truth"
    if assimilation_action not in _REVIEW_ASSIMILATION_ACTIONS:
        assimilation_action = "none"
    return {
        "review_assimilation_status": assimilation_status,
        "review_assimilation_action": assimilation_action,
        "review_assimilation_reason": assimilation_reason_codes[0],
        "review_assimilation_reason_codes": assimilation_reason_codes,
        "review_assimilation_available": bool(
            assimilation_status == "assimilated" and assimilation_action != "none"
        ),
        "review_assimilation_reviewable": bool(reviewable),
        "review_assimilation_queue_status": normalized_queue_status,
        "review_assimilation_queue_reason": normalized_queue_reason,
        "review_assimilation_result_status": normalized_result_status,
        "review_assimilation_handoff_slice_id": handoff_slice_id,
        "review_assimilation_handoff_roadmap_item_id": handoff_roadmap_item_id,
    }


def _normalize_self_healing_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _SELF_HEALING_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _SELF_HEALING_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["self_healing_insufficient_assimilation_truth"]


def _build_bounded_self_healing_state(
    *,
    review_assimilation_status: str,
    review_assimilation_action: str,
    review_assimilation_available: bool,
    review_assimilation_reviewable: bool,
    review_assimilation_queue_status: str,
    continuation_next_step_truth_insufficiency_explicit: bool,
    supported_repair_execution_status: str,
    continuation_repair_playbook_selected: bool,
    continuation_repair_playbook_class: str,
    continuation_repair_playbook_candidate_action: str,
    final_human_review_required: bool,
    final_human_review_reason: str,
    continuation_budget_status: str,
    continuation_branch_budget_status: str,
    continuation_no_progress_stop_required: bool,
    continuation_failure_bucket_denied: bool,
    safety_duplicate_pending: bool,
    safety_cooldown_active: bool,
    safety_loop_suspected: bool,
    safety_delivery_blocked: bool,
    safety_delivery_deferred: bool,
    prior_self_healing_transition_count: int,
    self_healing_chain_limit: int,
    prior_continuation_retry_count: int,
    prior_continuation_replan_count: int,
    prior_continuation_truth_gather_count: int,
    continuation_retry_limit: int,
    continuation_replan_limit: int,
    continuation_truth_gather_limit: int,
) -> dict[str, Any]:
    assimilation_status = _normalize_text(
        review_assimilation_status,
        default="insufficient_truth",
    )
    assimilation_action = _normalize_text(
        review_assimilation_action,
        default="none",
    )
    queue_status = _normalize_text(
        review_assimilation_queue_status,
        default="insufficient_truth",
    )
    continuation_budget_status = _normalize_text(
        continuation_budget_status,
        default="insufficient_truth",
    )
    continuation_branch_budget_status = _normalize_text(
        continuation_branch_budget_status,
        default="not_applicable",
    )
    final_human_review_reason = _normalize_text(
        final_human_review_reason,
        default="",
    )

    transition_target = "none"
    transition_selected = False
    transition_executed = False
    transition_allowed = False
    self_healing_status = "insufficient_truth"
    self_healing_reason = "self_healing_insufficient_assimilation_truth"

    chain_limit = max(0, _as_non_negative_int(self_healing_chain_limit, default=0))
    transition_count_before = _as_non_negative_int(
        prior_self_healing_transition_count,
        default=0,
    )
    chain_budget_remaining_before = max(0, chain_limit - transition_count_before)

    assimilation_unavailable = bool(
        assimilation_status in {"insufficient_truth", ""}
        or not review_assimilation_reviewable
        or queue_status in {"insufficient_truth", "blocked", "empty"}
    )
    if assimilation_unavailable and assimilation_status == "insufficient_truth":
        self_healing_status = "insufficient_truth"
        self_healing_reason = "self_healing_insufficient_assimilation_truth"
    elif assimilation_status == "no_action" or assimilation_action == "none":
        self_healing_status = "not_applicable"
        self_healing_reason = (
            "self_healing_not_applicable_assimilation_accept"
            if assimilation_action == "accept"
            else "self_healing_not_applicable_assimilation_no_action"
        )
    elif not review_assimilation_available:
        self_healing_status = "not_applicable"
        self_healing_reason = "self_healing_not_applicable_assimilation_no_action"
    elif queue_status != "prepared":
        self_healing_status = "blocked"
        self_healing_reason = "self_healing_blocked_queue_non_runnable"
    else:
        if assimilation_action == "retry":
            transition_target = "retry"
        elif assimilation_action == "replan":
            transition_target = "replan"
        elif assimilation_action == "split":
            transition_target = "truth_gather"
        elif assimilation_action == "escalate":
            alternative_supported_repair_allowed = bool(
                supported_repair_execution_status == "executed_verification_failed"
                and continuation_repair_playbook_selected
                and continuation_repair_playbook_class in _SUPPORTED_REPAIR_EXECUTABLE_PLAYBOOK_CLASSES
                and continuation_repair_playbook_candidate_action
                in _SUPPORTED_REPAIR_EXECUTABLE_CANDIDATE_ACTIONS
            )
            if alternative_supported_repair_allowed:
                transition_target = "alternative_supported_repair"
            else:
                self_healing_status = "blocked"
                self_healing_reason = "self_healing_blocked_alternative_repair_not_allowed"
        elif assimilation_action == "accept":
            self_healing_status = "not_applicable"
            self_healing_reason = "self_healing_not_applicable_assimilation_accept"
        else:
            self_healing_status = "blocked"
            self_healing_reason = "self_healing_blocked_unsupported_action"

        if transition_target != "none":
            transition_selected = True
            selected_reason_map = {
                "retry": "self_healing_selected_retry",
                "replan": "self_healing_selected_replan",
                "truth_gather": "self_healing_selected_truth_gather",
                "alternative_supported_repair": (
                    "self_healing_selected_alternative_supported_repair"
                ),
            }
            executed_reason_map = {
                "retry": "self_healing_executed_retry",
                "replan": "self_healing_executed_replan",
                "truth_gather": "self_healing_executed_truth_gather",
                "alternative_supported_repair": (
                    "self_healing_executed_alternative_supported_repair"
                ),
            }
            self_healing_status = "selected"
            self_healing_reason = selected_reason_map.get(
                transition_target,
                "self_healing_blocked_unsupported_action",
            )

            safety_gate_blocked = bool(
                continuation_budget_status != "available"
                or continuation_no_progress_stop_required
                or continuation_failure_bucket_denied
                or safety_duplicate_pending
                or safety_cooldown_active
                or safety_loop_suspected
                or safety_delivery_blocked
                or safety_delivery_deferred
            )
            branch_budget_exhausted = False
            if transition_target == "retry":
                branch_budget_exhausted = bool(
                    prior_continuation_retry_count >= continuation_retry_limit
                )
            elif transition_target == "replan":
                branch_budget_exhausted = bool(
                    prior_continuation_replan_count >= continuation_replan_limit
                )
            elif transition_target == "truth_gather":
                branch_budget_exhausted = bool(
                    prior_continuation_truth_gather_count
                    >= continuation_truth_gather_limit
                )
            if continuation_branch_budget_status == "exhausted":
                branch_budget_exhausted = True

            allow_despite_final_review = bool(
                transition_target == "alternative_supported_repair"
                and final_human_review_reason
                == "final_review_supported_repair_verification_failed"
            )
            final_human_blocked = bool(
                final_human_review_required and not allow_despite_final_review
            )

            if chain_budget_remaining_before <= 0:
                self_healing_status = "blocked"
                self_healing_reason = "self_healing_blocked_budget_exhausted"
            elif safety_gate_blocked:
                self_healing_status = "blocked"
                self_healing_reason = "self_healing_blocked_safety_gate"
            elif branch_budget_exhausted:
                self_healing_status = "blocked"
                self_healing_reason = "self_healing_blocked_branch_budget_exhausted"
            elif final_human_blocked:
                self_healing_status = "blocked"
                self_healing_reason = "self_healing_blocked_final_human_review"
            else:
                transition_allowed = True
                transition_executed = True
                self_healing_status = "executed"
                self_healing_reason = executed_reason_map.get(
                    transition_target,
                    "self_healing_blocked_unsupported_action",
                )

    transition_count_after = transition_count_before + (1 if transition_executed else 0)
    chain_budget_remaining_after = max(0, chain_limit - transition_count_after)
    self_healing_reason_codes = _normalize_self_healing_reason_codes([self_healing_reason])
    human_fallback_preserved = bool(
        self_healing_status in {"blocked", "insufficient_truth", "not_applicable"}
    )
    if self_healing_status not in _SELF_HEALING_STATUSES:
        self_healing_status = "insufficient_truth"
    if transition_target not in _SELF_HEALING_TRANSITION_TARGETS:
        transition_target = "none"
    return {
        "self_healing_status": self_healing_status,
        "self_healing_transition_selected": bool(transition_selected),
        "self_healing_transition_target": transition_target,
        "self_healing_transition_allowed": bool(transition_allowed),
        "self_healing_transition_executed": bool(transition_executed),
        "self_healing_reason": self_healing_reason_codes[0],
        "self_healing_reason_codes": self_healing_reason_codes,
        "self_healing_chain_limit": chain_limit,
        "self_healing_transition_count_before": transition_count_before,
        "self_healing_transition_count_after": transition_count_after,
        "self_healing_chain_budget_remaining_before": chain_budget_remaining_before,
        "self_healing_chain_budget_remaining_after": chain_budget_remaining_after,
        "self_healing_human_fallback_preserved": bool(human_fallback_preserved),
        "self_healing_source_assimilation_status": assimilation_status,
        "self_healing_source_assimilation_action": assimilation_action,
        "self_healing_truth_insufficiency_signal": bool(
            continuation_next_step_truth_insufficiency_explicit
        ),
    }


def _normalize_long_running_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _LONG_RUNNING_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _LONG_RUNNING_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["long_running_insufficient_truth_queue_state"]


def _build_long_running_stability_state(
    *,
    objective_id: str,
    queue_status: str,
    queue_selected_slice_id: str,
    queue_handoff_prepared: bool,
    queue_processed_count: int,
    review_assimilation_status: str,
    review_assimilation_action: str,
    review_assimilation_available: bool,
    self_healing_status: str,
    self_healing_transition_target: str,
    self_healing_transition_executed: bool,
    self_healing_human_fallback_preserved: bool,
    self_healing_chain_budget_remaining_after: int,
    self_healing_transition_count_after: int,
    final_human_review_required: bool,
    automatic_restart_executed: bool,
    automatic_continuation_run_count: int,
    prior_long_running_replay_key: str,
    prior_long_running_progress_signature: str,
    prior_long_running_stale_cycle_count: int,
    prior_long_running_stuck_cycle_count: int,
    prior_long_running_watchdog_heartbeat_at: str,
    now: Callable[[], datetime],
) -> dict[str, Any]:
    now_dt = now()
    now_at = now_dt.isoformat(timespec="seconds")
    normalized_objective_id = _normalize_text(objective_id, default="")
    normalized_queue_status = _normalize_text(queue_status, default="insufficient_truth")
    normalized_selected_slice_id = _normalize_text(queue_selected_slice_id, default="")
    normalized_assimilation_status = _normalize_text(
        review_assimilation_status,
        default="insufficient_truth",
    )
    normalized_assimilation_action = _normalize_text(
        review_assimilation_action,
        default="none",
    )
    normalized_self_healing_status = _normalize_text(
        self_healing_status,
        default="insufficient_truth",
    )
    normalized_self_healing_target = _normalize_text(
        self_healing_transition_target,
        default="none",
    )
    queue_processed_count_value = _as_non_negative_int(queue_processed_count, default=0)
    run_count_value = _as_non_negative_int(automatic_continuation_run_count, default=0)
    self_healing_transition_count_value = _as_non_negative_int(
        self_healing_transition_count_after,
        default=0,
    )
    chain_budget_remaining = _as_non_negative_int(
        self_healing_chain_budget_remaining_after,
        default=0,
    )
    current_replay_key = "|".join(
        [
            normalized_objective_id,
            normalized_selected_slice_id,
            normalized_assimilation_status,
            normalized_assimilation_action,
            normalized_self_healing_status,
            normalized_self_healing_target,
        ]
    ).strip("|")
    progress_signature = "|".join(
        [
            str(run_count_value),
            str(queue_processed_count_value),
            str(self_healing_transition_count_value),
            "restart_executed" if automatic_restart_executed else "restart_not_executed",
            "self_healing_executed" if self_healing_transition_executed else "self_healing_not_executed",
        ]
    )
    prior_replay_key = _normalize_text(prior_long_running_replay_key, default="")
    prior_progress_signature = _normalize_text(
        prior_long_running_progress_signature,
        default="",
    )
    replay_key_unchanged = bool(
        current_replay_key and prior_replay_key and current_replay_key == prior_replay_key
    )
    progress_unchanged = bool(
        replay_key_unchanged
        and progress_signature
        and prior_progress_signature
        and progress_signature == prior_progress_signature
    )
    stale_cycle_count = (
        _as_non_negative_int(prior_long_running_stale_cycle_count, default=0) + 1
        if progress_unchanged
        else 0
    )
    stuck_cycle_count = (
        _as_non_negative_int(prior_long_running_stuck_cycle_count, default=0) + 1
        if progress_unchanged
        else 0
    )
    stale_after_seconds = _LONG_RUNNING_STALE_AFTER_SECONDS_DEFAULT
    prior_heartbeat_dt = _parse_iso_timestamp(prior_long_running_watchdog_heartbeat_at)
    stale_age_seconds = 0
    if prior_heartbeat_dt is not None:
        comparable_now = now_dt
        if prior_heartbeat_dt.tzinfo is None and comparable_now.tzinfo is not None:
            prior_heartbeat_dt = prior_heartbeat_dt.replace(tzinfo=comparable_now.tzinfo)
        elif prior_heartbeat_dt.tzinfo is not None and comparable_now.tzinfo is None:
            comparable_now = comparable_now.replace(tzinfo=prior_heartbeat_dt.tzinfo)
        stale_age_seconds = max(
            0,
            int((comparable_now - prior_heartbeat_dt).total_seconds()),
        )
    stale_detected = bool(
        progress_unchanged
        and stale_age_seconds >= stale_after_seconds
    )
    stuck_detected = bool(
        progress_unchanged
        and stuck_cycle_count >= _LONG_RUNNING_STUCK_CYCLE_THRESHOLD_DEFAULT
    )

    status = "insufficient_truth"
    reason = "long_running_insufficient_truth_queue_state"
    pause_required = True
    resume_allowed = False
    escalation_required = False
    safe_stop_required = True
    watchdog_active = False

    if normalized_queue_status == "insufficient_truth":
        status = "insufficient_truth"
        reason = "long_running_insufficient_truth_queue_state"
    elif final_human_review_required:
        status = "escalated"
        reason = "long_running_escalated_final_human_review_required"
        escalation_required = True
    elif normalized_queue_status == "empty":
        status = "safe_stop"
        reason = "long_running_safe_stop_queue_empty"
    elif normalized_queue_status == "blocked":
        status = "safe_stop"
        reason = "long_running_safe_stop_queue_blocked"
    elif bool(self_healing_human_fallback_preserved):
        status = "safe_stop"
        reason = "long_running_safe_stop_human_fallback"
    elif chain_budget_remaining <= 0:
        status = "safe_stop"
        reason = "long_running_safe_stop_chain_budget_exhausted"
    elif stuck_detected:
        status = "escalated"
        reason = "long_running_escalated_stuck_detection"
        escalation_required = True
    elif stale_detected:
        status = "paused"
        reason = "long_running_paused_stale_watchdog"
        resume_allowed = bool(current_replay_key)
    elif (
        normalized_queue_status == "prepared"
        and queue_handoff_prepared
        and review_assimilation_available
    ):
        status = "monitoring"
        reason = "long_running_monitoring_active"
        pause_required = False
        safe_stop_required = False
        watchdog_active = True
    elif (
        normalized_queue_status == "prepared"
        and queue_handoff_prepared
        and current_replay_key
    ):
        status = "resume_ready"
        reason = "long_running_resume_ready_replay_safe"
        resume_allowed = True
        safe_stop_required = False
    else:
        status = "safe_stop"
        reason = "long_running_safe_stop_human_fallback"

    reason_codes = _normalize_long_running_reason_codes([reason])
    if status not in _LONG_RUNNING_STABILITY_STATUSES:
        status = "insufficient_truth"
    if status in {"monitoring"}:
        pause_required = False
    replay_safe = bool(current_replay_key and progress_signature)
    resume_token = (
        f"{current_replay_key}|{self_healing_transition_count_value}|{queue_processed_count_value}"
        if replay_safe
        else ""
    )
    return {
        "long_running_stability_status": status,
        "long_running_watchdog_active": bool(watchdog_active),
        "long_running_stale_detected": bool(stale_detected),
        "long_running_stuck_detected": bool(stuck_detected),
        "long_running_pause_required": bool(pause_required),
        "long_running_resume_allowed": bool(resume_allowed),
        "long_running_escalation_required": bool(escalation_required),
        "long_running_safe_stop_required": bool(safe_stop_required),
        "long_running_replay_safe": bool(replay_safe),
        "long_running_replay_key": current_replay_key,
        "long_running_progress_signature": progress_signature,
        "long_running_resume_token": resume_token,
        "long_running_watchdog_heartbeat_at": now_at,
        "long_running_watchdog_stale_after_seconds": stale_after_seconds,
        "long_running_watchdog_stale_age_seconds": stale_age_seconds,
        "long_running_stale_cycle_count": stale_cycle_count,
        "long_running_stuck_cycle_count": stuck_cycle_count,
        "long_running_reason": reason_codes[0],
        "long_running_reason_codes": reason_codes,
        "long_running_source_queue_status": normalized_queue_status,
        "long_running_source_review_assimilation_status": normalized_assimilation_status,
        "long_running_source_review_assimilation_action": normalized_assimilation_action,
        "long_running_source_self_healing_status": normalized_self_healing_status,
        "long_running_source_self_healing_target": normalized_self_healing_target,
    }


def _normalize_objective_compiler_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _OBJECTIVE_COMPILER_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _OBJECTIVE_COMPILER_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["objective_truth_insufficient"]


def _normalize_project_autonomy_budget_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_AUTONOMY_BUDGET_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_AUTONOMY_BUDGET_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["autonomy_budget_insufficient_truth"]


def _build_objective_done_compiler_state(
    *,
    objective_id: str,
    project_planning_summary_status: str,
    project_pr_slicing_status: str,
    project_pr_slice_count: int,
    project_pr_queue_status: str,
    project_pr_queue_reason: str,
    project_pr_queue_processed_slice_ids_after: list[str],
    review_assimilation_reason: str,
    self_healing_human_fallback_preserved: bool,
    long_running_stability_status: str,
    final_human_review_required: bool,
) -> dict[str, Any]:
    normalized_objective_id = _normalize_text(objective_id, default="")
    planning_status = _normalize_text(
        project_planning_summary_status,
        default="insufficient_truth",
    )
    slicing_status = _normalize_text(
        project_pr_slicing_status,
        default="insufficient_truth",
    )
    queue_status = _normalize_text(project_pr_queue_status, default="insufficient_truth")
    queue_reason = _normalize_text(project_pr_queue_reason, default="")
    assimilation_reason = _normalize_text(review_assimilation_reason, default="")
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    processed_slice_ids = _normalize_string_list(project_pr_queue_processed_slice_ids_after)
    processed_count = len(processed_slice_ids)
    slice_count = _as_non_negative_int(project_pr_slice_count, default=0)

    compiler_status = "insufficient_truth"
    compiler_reason = "objective_truth_insufficient"
    current_objective_available = False
    if not normalized_objective_id:
        compiler_status = "insufficient_truth"
        compiler_reason = "objective_identity_missing"
    elif planning_status != "available" and slicing_status != "available":
        compiler_status = "insufficient_truth"
        compiler_reason = "objective_truth_insufficient"
    else:
        compiler_status = "available"
        compiler_reason = "objective_compiled"
        current_objective_available = True

    scope_drift_status = "insufficient_truth"
    scope_drift_reason = "scope_drift_insufficient_truth"
    scope_drift_detected = False
    if slicing_status == "available":
        scope_drift_detected = bool(
            queue_reason == "prompt_unavailable_for_selected_slice"
            or assimilation_reason == "assimilation_split_scope_signal"
        )
        if scope_drift_detected:
            scope_drift_status = "detected"
            scope_drift_reason = (
                "scope_drift_detected_queue_prompt_mismatch"
                if queue_reason == "prompt_unavailable_for_selected_slice"
                else "scope_drift_detected_split_signal"
            )
        else:
            scope_drift_status = "clear"
            scope_drift_reason = "scope_drift_clear"

    done_status = "insufficient_truth"
    done_reason = "done_criteria_insufficient_truth"
    done_met = False
    done_remaining_count = 0
    if compiler_status == "available" and slicing_status == "available":
        done_remaining_count = max(0, slice_count - processed_count)
        done_met = bool(
            slice_count > 0
            and done_remaining_count == 0
            and queue_status == "empty"
        )
        done_status = "met" if done_met else "not_met"
        done_reason = "done_criteria_met" if done_met else "done_criteria_incomplete"

    stop_status = "insufficient_truth"
    stop_reason = "stop_criteria_insufficient_truth"
    stop_met = True
    if compiler_status == "available":
        stop_met = bool(
            final_human_review_required
            or long_running_status in {"safe_stop", "paused", "escalated"}
            or bool(self_healing_human_fallback_preserved)
        )
        stop_status = "stop" if stop_met else "continue"
        if not stop_met:
            stop_reason = "stop_criteria_continue"
        elif done_met:
            stop_reason = "stop_criteria_done_met"
        elif final_human_review_required:
            stop_reason = "stop_criteria_human_review_required"
        elif long_running_status in {"paused", "escalated"}:
            stop_reason = "stop_criteria_stability_pause_or_escalation"
        else:
            stop_reason = "stop_criteria_human_fallback_preserved"

    completion_posture = "objective_insufficient_truth"
    completion_reason = "completion_objective_insufficient_truth"
    if compiler_status != "available":
        completion_posture = "objective_insufficient_truth"
        completion_reason = "completion_objective_insufficient_truth"
    elif done_met and not scope_drift_detected:
        completion_posture = "objective_completed"
        completion_reason = "completion_objective_completed"
    elif stop_met and (
        final_human_review_required
        or queue_status == "blocked"
        or long_running_status in {"paused", "escalated"}
        or bool(self_healing_human_fallback_preserved)
    ):
        completion_posture = "objective_blocked"
        completion_reason = "completion_objective_blocked"
    else:
        completion_posture = "objective_active"
        completion_reason = "completion_objective_active"

    reason_codes = _normalize_objective_compiler_reason_codes(
        [
            compiler_reason,
            done_reason,
            scope_drift_reason,
            stop_reason,
            completion_reason,
        ]
    )
    if compiler_status not in _OBJECTIVE_COMPILER_STATUSES:
        compiler_status = "insufficient_truth"
    if done_status not in _OBJECTIVE_DONE_CRITERIA_STATUSES:
        done_status = "insufficient_truth"
    if stop_status not in _OBJECTIVE_STOP_CRITERIA_STATUSES:
        stop_status = "insufficient_truth"
    if completion_posture not in _OBJECTIVE_COMPLETION_POSTURES:
        completion_posture = "objective_insufficient_truth"
    if scope_drift_status not in _OBJECTIVE_SCOPE_DRIFT_STATUSES:
        scope_drift_status = "insufficient_truth"
    return {
        "objective_compiler_status": compiler_status,
        "objective_compiler_reason": reason_codes[0],
        "objective_compiler_reason_codes": reason_codes,
        "current_objective_id": normalized_objective_id,
        "current_objective_available": bool(current_objective_available),
        "objective_done_criteria_status": done_status,
        "objective_done_criteria_met": bool(done_met),
        "objective_done_remaining_slice_count": done_remaining_count,
        "objective_stop_criteria_status": stop_status,
        "objective_stop_criteria_met": bool(stop_met),
        "objective_completion_posture": completion_posture,
        "objective_scope_drift_status": scope_drift_status,
        "objective_scope_drift_detected": bool(scope_drift_detected),
        "objective_scope_drift_reason": scope_drift_reason,
        "objective_source_slice_count": slice_count,
        "objective_source_processed_count": processed_count,
        "objective_source_queue_status": queue_status,
    }


def _build_project_autonomy_budget_state(
    *,
    project_planning_summary_status: str,
    objective_compiler_status: str,
    objective_completion_posture: str,
    final_human_review_required: bool,
    high_risk_posture: bool,
    continuation_budget_truth_sufficient: bool,
    continuation_budget_status: str,
    continuation_budget_run_exhausted: bool,
    continuation_budget_objective_exhausted: bool,
    continuation_budget_run_limit: int,
    continuation_budget_objective_limit: int,
    continuation_budget_run_remaining: int,
    continuation_budget_objective_remaining: int,
    continuation_budget_branch_type: str,
    continuation_budget_branch_status: str,
    continuation_budget_branch_exhausted: bool,
    continuation_budget_branch_limit: int,
    continuation_budget_branch_remaining: int,
) -> dict[str, Any]:
    planning_status = _normalize_text(
        project_planning_summary_status,
        default="insufficient_truth",
    )
    objective_status = _normalize_text(
        objective_compiler_status,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    budget_status = _normalize_text(
        continuation_budget_status,
        default="insufficient_truth",
    )
    branch_type = _normalize_text(continuation_budget_branch_type, default="unknown")
    branch_status = _normalize_text(
        continuation_budget_branch_status,
        default="insufficient_truth",
    )

    compiler_status = "insufficient_truth"
    priority_posture = "insufficient_truth"
    run_budget_posture = "insufficient_truth"
    objective_budget_posture = "insufficient_truth"
    pr_retry_budget_posture = "insufficient_truth"
    high_risk_defer_posture = "insufficient_truth"
    priority_deferred = False
    high_risk_defer_active = False
    pr_retry_budget_applicable = False
    pr_retry_budget_exhausted = False
    run_budget_exhausted = False
    objective_budget_exhausted = False

    reason_codes: list[str] = []
    truth_sufficient = bool(
        planning_status == "available"
        and objective_status == "available"
        and continuation_budget_truth_sufficient
        and budget_status in _CONTINUATION_BUDGET_STATUSES
    )
    if not truth_sufficient:
        reason_codes.extend(
            [
                "autonomy_budget_insufficient_truth",
                "project_priority_insufficient_truth",
                "run_budget_insufficient_truth",
                "objective_budget_insufficient_truth",
                "pr_retry_budget_insufficient_truth",
                "high_risk_defer_insufficient_truth",
            ]
        )
    else:
        compiler_status = "available"
        run_budget_exhausted = bool(continuation_budget_run_exhausted)
        objective_budget_exhausted = bool(continuation_budget_objective_exhausted)
        run_budget_posture = "exhausted" if run_budget_exhausted else "available"
        objective_budget_posture = (
            "exhausted" if objective_budget_exhausted else "available"
        )
        if branch_type == "retry":
            pr_retry_budget_applicable = True
            pr_retry_budget_exhausted = bool(continuation_budget_branch_exhausted)
            if branch_status in {"available", "exhausted"}:
                pr_retry_budget_posture = branch_status
            else:
                pr_retry_budget_posture = "insufficient_truth"
        else:
            pr_retry_budget_posture = "not_applicable"

        high_risk_defer_active = bool(
            high_risk_posture or final_human_review_required
        )
        high_risk_defer_posture = "defer" if high_risk_defer_active else "clear"
        priority_deferred = bool(
            high_risk_defer_active or completion_posture == "objective_blocked"
        )
        any_budget_exhausted = bool(
            run_budget_exhausted
            or objective_budget_exhausted
            or pr_retry_budget_exhausted
        )
        if completion_posture == "objective_completed":
            priority_posture = "completed"
        elif priority_deferred:
            priority_posture = "deferred"
        elif any_budget_exhausted:
            priority_posture = "lower_priority"
        else:
            priority_posture = "active"

        reason_codes.append("autonomy_budget_compiled")
        if priority_posture == "completed":
            reason_codes.append("project_priority_completed")
        elif priority_posture == "deferred":
            reason_codes.append(
                "project_priority_deferred_high_risk"
                if high_risk_defer_active
                else "project_priority_deferred_blocked"
            )
        elif priority_posture == "lower_priority":
            reason_codes.append("project_priority_lowered_budget_exhausted")
        else:
            reason_codes.append("project_priority_active")
        reason_codes.append(
            "run_budget_exhausted" if run_budget_exhausted else "run_budget_available"
        )
        reason_codes.append(
            "objective_budget_exhausted"
            if objective_budget_exhausted
            else "objective_budget_available"
        )
        if pr_retry_budget_posture == "available":
            reason_codes.append("pr_retry_budget_available")
        elif pr_retry_budget_posture == "exhausted":
            reason_codes.append("pr_retry_budget_exhausted")
        elif pr_retry_budget_posture == "not_applicable":
            reason_codes.append("pr_retry_budget_not_applicable")
        else:
            reason_codes.append("pr_retry_budget_insufficient_truth")
        reason_codes.append(
            "high_risk_defer_active"
            if high_risk_defer_active
            else "high_risk_defer_clear"
        )

    reason_codes = _normalize_project_autonomy_budget_reason_codes(reason_codes)
    if compiler_status not in _PROJECT_AUTONOMY_BUDGET_STATUSES:
        compiler_status = "insufficient_truth"
    if priority_posture not in _PROJECT_PRIORITY_POSTURES:
        priority_posture = "insufficient_truth"
    if run_budget_posture not in _PROJECT_BUDGET_POSTURES:
        run_budget_posture = "insufficient_truth"
    if objective_budget_posture not in _PROJECT_BUDGET_POSTURES:
        objective_budget_posture = "insufficient_truth"
    if pr_retry_budget_posture not in _PROJECT_PR_RETRY_BUDGET_POSTURES:
        pr_retry_budget_posture = "insufficient_truth"
    if high_risk_defer_posture not in _PROJECT_HIGH_RISK_DEFER_POSTURES:
        high_risk_defer_posture = "insufficient_truth"

    return {
        "project_autonomy_budget_status": compiler_status,
        "project_autonomy_budget_reason": reason_codes[0],
        "project_autonomy_budget_reason_codes": reason_codes,
        "project_priority_posture": priority_posture,
        "project_priority_deferred": bool(priority_deferred),
        "project_high_risk_defer_posture": high_risk_defer_posture,
        "project_high_risk_defer_active": bool(high_risk_defer_active),
        "project_run_budget_posture": run_budget_posture,
        "project_run_budget_limit": _as_non_negative_int(
            continuation_budget_run_limit,
            default=0,
        ),
        "project_run_budget_remaining": _as_non_negative_int(
            continuation_budget_run_remaining,
            default=0,
        ),
        "project_run_budget_exhausted": bool(run_budget_exhausted),
        "project_objective_budget_posture": objective_budget_posture,
        "project_objective_budget_limit": _as_non_negative_int(
            continuation_budget_objective_limit,
            default=0,
        ),
        "project_objective_budget_remaining": _as_non_negative_int(
            continuation_budget_objective_remaining,
            default=0,
        ),
        "project_objective_budget_exhausted": bool(objective_budget_exhausted),
        "project_pr_retry_budget_posture": pr_retry_budget_posture,
        "project_pr_retry_budget_applicable": bool(pr_retry_budget_applicable),
        "project_pr_retry_budget_limit": _as_non_negative_int(
            continuation_budget_branch_limit if branch_type == "retry" else 0,
            default=0,
        ),
        "project_pr_retry_budget_remaining": _as_non_negative_int(
            continuation_budget_branch_remaining if branch_type == "retry" else 0,
            default=0,
        ),
        "project_pr_retry_budget_exhausted": bool(pr_retry_budget_exhausted),
    }


def _normalize_project_quality_gate_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_QUALITY_GATE_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_QUALITY_GATE_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["quality_gate_insufficient_truth"]


def _build_project_quality_gate_state(
    *,
    project_planning_summary_status: str,
    project_pr_slicing_status: str,
    implementation_prompt_status: str,
    implementation_prompt_payload: Mapping[str, Any],
    project_pr_queue_status: str,
    review_assimilation_status: str,
    review_assimilation_action: str,
    self_healing_status: str,
    long_running_stability_status: str,
    objective_compiler_status: str,
    objective_completion_posture: str,
    objective_scope_drift_detected: bool,
    project_autonomy_budget_status: str,
    project_priority_posture: str,
    project_run_budget_posture: str,
    project_objective_budget_posture: str,
    project_pr_retry_budget_posture: str,
    project_high_risk_defer_posture: str,
    continuation_failure_bucket_denied: bool,
    continuation_no_progress_stop_required: bool,
    continuation_next_step_selection_status: str,
    continuation_next_step_target: str,
    supported_repair_execution_status: str,
    final_human_review_required: bool,
) -> dict[str, Any]:
    planning_status = _normalize_text(
        project_planning_summary_status,
        default="insufficient_truth",
    )
    slicing_status = _normalize_text(
        project_pr_slicing_status,
        default="insufficient_truth",
    )
    prompt_status = _normalize_text(
        implementation_prompt_status,
        default="insufficient_truth",
    )
    queue_status = _normalize_text(
        project_pr_queue_status,
        default="insufficient_truth",
    )
    assimilation_status = _normalize_text(
        review_assimilation_status,
        default="insufficient_truth",
    )
    assimilation_action = _normalize_text(review_assimilation_action, default="none")
    normalized_self_healing_status = _normalize_text(
        self_healing_status,
        default="insufficient_truth",
    )
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    objective_status = _normalize_text(
        objective_compiler_status,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    autonomy_budget_status = _normalize_text(
        project_autonomy_budget_status,
        default="insufficient_truth",
    )
    priority_posture = _normalize_text(
        project_priority_posture,
        default="insufficient_truth",
    )
    run_budget_posture = _normalize_text(
        project_run_budget_posture,
        default="insufficient_truth",
    )
    objective_budget_posture = _normalize_text(
        project_objective_budget_posture,
        default="insufficient_truth",
    )
    pr_retry_budget_posture = _normalize_text(
        project_pr_retry_budget_posture,
        default="insufficient_truth",
    )
    high_risk_defer_posture = _normalize_text(
        project_high_risk_defer_posture,
        default="insufficient_truth",
    )
    next_step_selection_status = _normalize_text(
        continuation_next_step_selection_status,
        default="insufficient_truth",
    )
    next_step_target = _normalize_text(continuation_next_step_target, default="none")
    repair_status = _normalize_text(
        supported_repair_execution_status,
        default="not_selected",
    )

    prompt_payload = (
        dict(implementation_prompt_payload)
        if isinstance(implementation_prompt_payload, Mapping)
        else {}
    )
    preferred_files = [
        _normalize_text(path, default="")
        for path in prompt_payload.get("preferred_files", [])
        if isinstance(path, str)
    ]
    has_runner_files = any(
        path.startswith("automation/orchestration/") for path in preferred_files
    )
    has_test_files = any(path.startswith("tests/") for path in preferred_files)
    changed_area_class = "unknown"
    if has_runner_files and has_test_files:
        changed_area_class = "runner_and_tests"
    elif has_runner_files:
        changed_area_class = "runner_only"
    else:
        prompt_scope_class = _normalize_text(
            prompt_payload.get("bounded_scope_class"),
            default="unknown",
        )
        if prompt_scope_class in {"runner_and_tests", "runner_only"}:
            changed_area_class = prompt_scope_class
    if changed_area_class not in _PROJECT_QUALITY_GATE_CHANGED_AREA_CLASSES:
        changed_area_class = "unknown"

    truth_sufficient = bool(
        planning_status == "available"
        and slicing_status == "available"
        and prompt_status == "available"
        and queue_status in _PROJECT_PR_QUEUE_STATUSES
        and queue_status != "insufficient_truth"
        and objective_status == "available"
        and autonomy_budget_status == "available"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_quality_gate_reason_codes(
            [
                "quality_gate_insufficient_truth",
                "quality_gate_posture_insufficient_truth",
                "quality_gate_changed_area_insufficient_truth",
                "quality_gate_risk_insufficient_truth",
            ]
        )
        return {
            "project_quality_gate_status": "insufficient_truth",
            "project_quality_gate_reason": reason_codes[0],
            "project_quality_gate_reason_codes": reason_codes,
            "project_quality_gate_posture": "insufficient_truth",
            "project_quality_gate_merge_ready": False,
            "project_quality_gate_review_ready": False,
            "project_quality_gate_retry_needed": False,
            "project_quality_gate_recommended": [],
            "project_quality_gate_recommended_count": 0,
            "project_quality_gate_changed_area_class": "unknown",
            "project_quality_gate_risk_level": "insufficient_truth",
            "project_quality_gate_high_risk": False,
            "project_quality_gate_unavailable": True,
        }

    high_risk = bool(
        high_risk_defer_posture == "defer"
        or final_human_review_required
        or continuation_failure_bucket_denied
        or continuation_no_progress_stop_required
        or completion_posture == "objective_blocked"
        or long_running_status in {"paused", "escalated", "safe_stop"}
        or repair_status
        in {
            "executed_verification_failed",
            "not_executed_precheck_blocked",
            "not_executed_qualification_failed",
            "not_executed_launch_failed",
        }
    )
    retry_signal = bool(
        assimilation_action in {"retry", "replan", "split"}
        or (
            next_step_selection_status == "selected"
            and next_step_target in {"retry", "replan", "truth_gather", "supported_repair"}
        )
        or normalized_self_healing_status in {"selected", "executed"}
        or run_budget_posture == "exhausted"
        or objective_budget_posture == "exhausted"
        or pr_retry_budget_posture == "exhausted"
    )
    merge_ready = bool(
        completion_posture == "objective_completed"
        and assimilation_status == "assimilated"
        and assimilation_action == "accept"
        and queue_status == "empty"
        and not high_risk
        and not retry_signal
        and priority_posture not in {"deferred", "insufficient_truth"}
    )
    retry_needed = bool(not merge_ready and retry_signal)
    review_ready = bool(not merge_ready and not retry_needed)

    posture = "review_ready"
    if merge_ready:
        posture = "merge_ready"
    elif retry_needed:
        posture = "retry_needed"
    if posture not in _PROJECT_QUALITY_GATE_POSTURES:
        posture = "insufficient_truth"

    recommended = {"unit", "lint", "typecheck"}
    targeted_regression_required = bool(
        high_risk
        or retry_needed
        or changed_area_class == "runner_and_tests"
        or bool(objective_scope_drift_detected)
    )
    if targeted_regression_required:
        recommended.add("targeted_regression")
    ordered_gates = [
        gate
        for gate in ["unit", "targeted_regression", "lint", "typecheck"]
        if gate in recommended and gate in _PROJECT_QUALITY_GATE_NAMES
    ]

    risk_level = "low"
    if high_risk:
        risk_level = "high"
    elif retry_needed or bool(objective_scope_drift_detected):
        risk_level = "moderate"
    if risk_level not in _PROJECT_QUALITY_GATE_RISK_LEVELS:
        risk_level = "insufficient_truth"

    reason_codes = ["quality_gate_compiled"]
    if posture == "merge_ready":
        reason_codes.append("quality_gate_posture_merge_ready")
    elif posture == "retry_needed":
        reason_codes.append("quality_gate_posture_retry_needed")
    else:
        reason_codes.append("quality_gate_posture_review_ready")
    if changed_area_class == "runner_and_tests":
        reason_codes.append("quality_gate_changed_area_runner_and_tests")
    elif changed_area_class == "runner_only":
        reason_codes.append("quality_gate_changed_area_runner_only")
    else:
        reason_codes.append("quality_gate_changed_area_unknown")
    if risk_level == "high":
        reason_codes.append("quality_gate_risk_high")
    elif risk_level == "moderate":
        reason_codes.append("quality_gate_risk_moderate")
    else:
        reason_codes.append("quality_gate_risk_low")
    reason_codes.append(
        "quality_gate_targeted_regression_enabled"
        if targeted_regression_required
        else "quality_gate_targeted_regression_not_required"
    )
    reason_codes = _normalize_project_quality_gate_reason_codes(reason_codes)
    return {
        "project_quality_gate_status": "available",
        "project_quality_gate_reason": reason_codes[0],
        "project_quality_gate_reason_codes": reason_codes,
        "project_quality_gate_posture": posture,
        "project_quality_gate_merge_ready": bool(merge_ready),
        "project_quality_gate_review_ready": bool(review_ready),
        "project_quality_gate_retry_needed": bool(retry_needed),
        "project_quality_gate_recommended": ordered_gates,
        "project_quality_gate_recommended_count": len(ordered_gates),
        "project_quality_gate_changed_area_class": changed_area_class,
        "project_quality_gate_risk_level": risk_level,
        "project_quality_gate_high_risk": bool(high_risk),
        "project_quality_gate_unavailable": False,
    }


def _normalize_project_merge_branch_lifecycle_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_MERGE_BRANCH_LIFECYCLE_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_MERGE_BRANCH_LIFECYCLE_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["merge_branch_lifecycle_insufficient_truth"]


def _build_project_merge_branch_lifecycle_state(
    *,
    project_quality_gate_status: str,
    project_quality_gate_posture: str,
    project_quality_gate_merge_ready: bool,
    project_quality_gate_retry_needed: bool,
    project_quality_gate_high_risk: bool,
    objective_compiler_status: str,
    objective_completion_posture: str,
    project_autonomy_budget_status: str,
    project_priority_posture: str,
    project_high_risk_defer_posture: str,
    project_pr_queue_status: str,
    project_pr_queue_processed_count: int,
    review_assimilation_status: str,
    review_assimilation_action: str,
    self_healing_status: str,
    long_running_stability_status: str,
    final_human_review_required: bool,
    final_human_review_gate_status: str,
    continuation_failure_bucket_denied: bool,
    continuation_no_progress_stop_required: bool,
    supported_repair_execution_status: str,
) -> dict[str, Any]:
    quality_gate_status = _normalize_text(
        project_quality_gate_status,
        default="insufficient_truth",
    )
    quality_gate_posture = _normalize_text(
        project_quality_gate_posture,
        default="insufficient_truth",
    )
    objective_status = _normalize_text(
        objective_compiler_status,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    autonomy_budget_status = _normalize_text(
        project_autonomy_budget_status,
        default="insufficient_truth",
    )
    priority_posture = _normalize_text(
        project_priority_posture,
        default="insufficient_truth",
    )
    high_risk_defer_posture = _normalize_text(
        project_high_risk_defer_posture,
        default="insufficient_truth",
    )
    queue_status = _normalize_text(
        project_pr_queue_status,
        default="insufficient_truth",
    )
    review_status = _normalize_text(
        review_assimilation_status,
        default="insufficient_truth",
    )
    review_action = _normalize_text(review_assimilation_action, default="none")
    normalized_self_healing_status = _normalize_text(
        self_healing_status,
        default="insufficient_truth",
    )
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    final_review_gate_status = _normalize_text(
        final_human_review_gate_status,
        default="not_required",
    )
    repair_status = _normalize_text(
        supported_repair_execution_status,
        default="not_selected",
    )
    processed_count = _as_non_negative_int(
        project_pr_queue_processed_count,
        default=0,
    )

    truth_sufficient = bool(
        quality_gate_status == "available"
        and quality_gate_posture in _PROJECT_QUALITY_GATE_POSTURES
        and quality_gate_posture != "insufficient_truth"
        and objective_status == "available"
        and completion_posture in _OBJECTIVE_COMPLETION_POSTURES
        and completion_posture != "objective_insufficient_truth"
        and autonomy_budget_status == "available"
        and queue_status in _PROJECT_PR_QUEUE_STATUSES
        and queue_status != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_merge_branch_lifecycle_reason_codes(
            [
                "merge_branch_lifecycle_insufficient_truth",
                "merge_branch_posture_insufficient_truth",
                "merge_branch_cleanup_candidate_insufficient_truth",
                "merge_branch_quarantine_candidate_insufficient_truth",
                "merge_branch_local_main_sync_insufficient_truth",
            ]
        )
        return {
            "project_merge_branch_lifecycle_status": "insufficient_truth",
            "project_merge_branch_lifecycle_reason": reason_codes[0],
            "project_merge_branch_lifecycle_reason_codes": reason_codes,
            "project_merge_ready_posture": "insufficient_truth",
            "project_merge_ready": False,
            "project_branch_cleanup_candidate_posture": "insufficient_truth",
            "project_branch_cleanup_candidate": False,
            "project_branch_quarantine_candidate_posture": "insufficient_truth",
            "project_branch_quarantine_candidate": False,
            "project_local_main_sync_posture": "insufficient_truth",
            "project_local_main_sync_required": False,
            "project_merge_branch_lifecycle_unavailable": True,
        }

    quarantine_candidate = bool(
        final_human_review_required
        or final_review_gate_status == "required"
        or high_risk_defer_posture == "defer"
        or bool(project_quality_gate_high_risk)
        or continuation_failure_bucket_denied
        or continuation_no_progress_stop_required
        or completion_posture == "objective_blocked"
        or priority_posture == "deferred"
        or long_running_status in {"paused", "escalated", "safe_stop"}
        or repair_status
        in {
            "executed_verification_failed",
            "not_executed_precheck_blocked",
            "not_executed_qualification_failed",
            "not_executed_launch_failed",
        }
    )
    merge_ready = bool(
        not quarantine_candidate
        and quality_gate_posture == "merge_ready"
        and bool(project_quality_gate_merge_ready)
        and not bool(project_quality_gate_retry_needed)
        and completion_posture == "objective_completed"
        and review_status == "assimilated"
        and review_action == "accept"
        and queue_status == "empty"
        and normalized_self_healing_status in {"not_applicable", "not_selected", "executed"}
    )
    cleanup_candidate = bool(
        not quarantine_candidate
        and (
            merge_ready
            or (
                completion_posture == "objective_completed"
                and review_status == "assimilated"
                and review_action == "accept"
                and queue_status in {"empty", "blocked"}
            )
        )
    )
    local_main_sync_required = bool(
        queue_status in {"empty", "blocked"}
        and (
            merge_ready
            or cleanup_candidate
            or quarantine_candidate
            or priority_posture in {"deferred", "lower_priority"}
            or processed_count > 0
        )
    )

    merge_ready_posture = "merge_ready" if merge_ready else "not_merge_ready"
    cleanup_posture = "candidate" if cleanup_candidate else "not_candidate"
    quarantine_posture = "candidate" if quarantine_candidate else "not_candidate"
    sync_posture = "sync_required" if local_main_sync_required else "sync_not_required"

    reason_codes = ["merge_branch_lifecycle_compiled"]
    reason_codes.append(
        "merge_branch_posture_merge_ready"
        if merge_ready
        else "merge_branch_posture_not_merge_ready"
    )
    reason_codes.append(
        "merge_branch_cleanup_candidate_yes"
        if cleanup_candidate
        else "merge_branch_cleanup_candidate_no"
    )
    reason_codes.append(
        "merge_branch_quarantine_candidate_yes"
        if quarantine_candidate
        else "merge_branch_quarantine_candidate_no"
    )
    reason_codes.append(
        "merge_branch_local_main_sync_required"
        if local_main_sync_required
        else "merge_branch_local_main_sync_not_required"
    )
    reason_codes = _normalize_project_merge_branch_lifecycle_reason_codes(reason_codes)

    return {
        "project_merge_branch_lifecycle_status": "available",
        "project_merge_branch_lifecycle_reason": reason_codes[0],
        "project_merge_branch_lifecycle_reason_codes": reason_codes,
        "project_merge_ready_posture": merge_ready_posture,
        "project_merge_ready": bool(merge_ready),
        "project_branch_cleanup_candidate_posture": cleanup_posture,
        "project_branch_cleanup_candidate": bool(cleanup_candidate),
        "project_branch_quarantine_candidate_posture": quarantine_posture,
        "project_branch_quarantine_candidate": bool(quarantine_candidate),
        "project_local_main_sync_posture": sync_posture,
        "project_local_main_sync_required": bool(local_main_sync_required),
        "project_merge_branch_lifecycle_unavailable": False,
    }


def _normalize_project_failure_memory_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_FAILURE_MEMORY_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_FAILURE_MEMORY_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["failure_memory_insufficient_truth"]


def _build_project_failure_memory_state(
    *,
    project_merge_branch_lifecycle_status: str,
    project_branch_quarantine_candidate: bool,
    failure_bucketing_status: str,
    failure_bucketing_validity: str,
    failure_bucketing_primary_bucket: str,
    continuation_next_step_selection_status: str,
    continuation_next_step_target: str,
    continuation_no_progress_stop_required: bool,
    continuation_failure_bucket_denied: bool,
    review_assimilation_status: str,
    review_assimilation_action: str,
    self_healing_status: str,
    supported_repair_execution_status: str,
    execution_status: str,
    execution_reason: str,
    restart_result_status: str,
    final_human_review_required: bool,
    prior_retry_failure_count: int,
    prior_repair_failure_count: int,
    prior_review_issue_count: int,
    prior_failure_bucket_recurrence_count: int,
    prior_failure_bucket_value: str,
) -> dict[str, Any]:
    lifecycle_status = _normalize_text(
        project_merge_branch_lifecycle_status,
        default="insufficient_truth",
    )
    bucket_status = _normalize_text(
        failure_bucketing_status,
        default="insufficient_truth",
    )
    bucket_validity = _normalize_text(
        failure_bucketing_validity,
        default="insufficient_truth",
    )
    bucket_value = _normalize_text(
        failure_bucketing_primary_bucket,
        default="unknown",
    )
    next_step_status = _normalize_text(
        continuation_next_step_selection_status,
        default="insufficient_truth",
    )
    next_step_target = _normalize_text(
        continuation_next_step_target,
        default="none",
    )
    assimilation_status = _normalize_text(
        review_assimilation_status,
        default="insufficient_truth",
    )
    assimilation_action = _normalize_text(
        review_assimilation_action,
        default="none",
    )
    normalized_self_healing_status = _normalize_text(
        self_healing_status,
        default="insufficient_truth",
    )
    repair_status = _normalize_text(
        supported_repair_execution_status,
        default="not_selected",
    )
    normalized_execution_status = _normalize_text(
        execution_status,
        default="not_executed",
    )
    normalized_execution_reason = _normalize_text(
        execution_reason,
        default="restart_not_executed",
    )
    normalized_restart_result_status = _normalize_text(
        restart_result_status,
        default="not_attempted",
    )
    prior_bucket = _normalize_text(prior_failure_bucket_value, default="unknown")

    truth_sufficient = bool(
        lifecycle_status == "available"
        and bucket_status not in {"", "unknown", "insufficient_truth"}
        and bucket_validity in {"valid", "partial"}
        and next_step_status in {"selected", "not_selected"}
        and assimilation_status != "insufficient_truth"
        and normalized_self_healing_status != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_failure_memory_reason_codes(
            [
                "failure_memory_insufficient_truth",
            ]
        )
        return {
            "project_failure_memory_status": "insufficient_truth",
            "project_failure_memory_reason": reason_codes[0],
            "project_failure_memory_reason_codes": reason_codes,
            "project_failure_memory_ineffective_retry": False,
            "project_failure_memory_failed_repair": False,
            "project_failure_memory_repeated_review_issue": False,
            "project_failure_memory_recurring_failure_bucket": False,
            "project_failure_memory_retry_failure_count": _as_non_negative_int(
                prior_retry_failure_count,
                default=0,
            ),
            "project_failure_memory_repair_failure_count": _as_non_negative_int(
                prior_repair_failure_count,
                default=0,
            ),
            "project_failure_memory_review_issue_count": _as_non_negative_int(
                prior_review_issue_count,
                default=0,
            ),
            "project_failure_memory_failure_bucket_recurrence_count": _as_non_negative_int(
                prior_failure_bucket_recurrence_count,
                default=0,
            ),
            "project_failure_memory_last_failure_bucket": bucket_value,
            "project_failure_memory_suppression_posture": "insufficient_truth",
            "project_failure_memory_suppression_active": False,
            "project_failure_memory_unavailable": True,
        }

    retry_failure_now = bool(
        next_step_target == "retry"
        and (
            continuation_no_progress_stop_required
            or normalized_execution_status != "executed"
            or normalized_restart_result_status not in {"completed", "not_attempted"}
            or normalized_execution_reason
            in {
                "continuation_budget_exhausted",
                "continuation_no_progress_stop",
                "failure_bucket_continuation_denied",
                "continuation_next_step_not_selected",
            }
        )
    )
    failed_repair_now = bool(
        repair_status
        in {
            "executed_verification_failed",
            "not_executed_precheck_blocked",
            "not_executed_qualification_failed",
            "not_executed_launch_failed",
        }
    )
    repeated_review_issue_now = bool(
        assimilation_status == "assimilated"
        and assimilation_action in {"retry", "replan", "split", "escalate"}
    )
    recurring_failure_bucket_now = bool(
        bucket_value not in {"", "unknown", "insufficient_truth"}
        and prior_bucket not in {"", "unknown", "insufficient_truth"}
        and bucket_value == prior_bucket
        and (
            _as_non_negative_int(prior_failure_bucket_recurrence_count, default=0) > 0
            or retry_failure_now
            or failed_repair_now
            or repeated_review_issue_now
            or bool(continuation_failure_bucket_denied)
        )
    )

    retry_failure_count = _as_non_negative_int(prior_retry_failure_count, default=0) + (
        1 if retry_failure_now else 0
    )
    repair_failure_count = _as_non_negative_int(prior_repair_failure_count, default=0) + (
        1 if failed_repair_now else 0
    )
    review_issue_count = _as_non_negative_int(prior_review_issue_count, default=0) + (
        1 if repeated_review_issue_now else 0
    )
    failure_bucket_recurrence_count = _as_non_negative_int(
        prior_failure_bucket_recurrence_count,
        default=0,
    ) + (1 if recurring_failure_bucket_now else 0)

    suppression_posture = "none"
    suppression_active = False
    if final_human_review_required and bool(project_branch_quarantine_candidate):
        if failure_bucket_recurrence_count >= 2:
            suppression_posture = "suppress_failure_bucket"
            suppression_active = True
        elif review_issue_count >= 2:
            suppression_posture = "suppress_review_issue"
            suppression_active = True
        elif repair_failure_count >= 2:
            suppression_posture = "suppress_repair"
            suppression_active = True
        elif retry_failure_count >= 2:
            suppression_posture = "suppress_retry"
            suppression_active = True
    elif failure_bucket_recurrence_count >= 3:
        suppression_posture = "suppress_failure_bucket"
        suppression_active = True
    elif review_issue_count >= 3:
        suppression_posture = "suppress_review_issue"
        suppression_active = True
    elif repair_failure_count >= 3:
        suppression_posture = "suppress_repair"
        suppression_active = True
    elif retry_failure_count >= 3:
        suppression_posture = "suppress_retry"
        suppression_active = True
    if suppression_posture not in _PROJECT_FAILURE_MEMORY_SUPPRESSION_POSTURES:
        suppression_posture = "insufficient_truth"
        suppression_active = False

    reason_codes = ["failure_memory_compiled"]
    reason_codes.append(
        "failure_memory_ineffective_retry_detected"
        if retry_failure_now
        else "failure_memory_no_ineffective_retry"
    )
    reason_codes.append(
        "failure_memory_failed_repair_detected"
        if failed_repair_now
        else "failure_memory_no_failed_repair"
    )
    reason_codes.append(
        "failure_memory_repeated_review_issue_detected"
        if repeated_review_issue_now
        else "failure_memory_no_repeated_review_issue"
    )
    reason_codes.append(
        "failure_memory_recurring_failure_bucket_detected"
        if recurring_failure_bucket_now
        else "failure_memory_no_recurring_failure_bucket"
    )
    if suppression_posture == "suppress_failure_bucket":
        reason_codes.append("failure_memory_suppression_failure_bucket")
    elif suppression_posture == "suppress_review_issue":
        reason_codes.append("failure_memory_suppression_review_issue")
    elif suppression_posture == "suppress_repair":
        reason_codes.append("failure_memory_suppression_repair")
    elif suppression_posture == "suppress_retry":
        reason_codes.append("failure_memory_suppression_retry")
    else:
        reason_codes.append("failure_memory_suppression_none")
    reason_codes = _normalize_project_failure_memory_reason_codes(reason_codes)

    return {
        "project_failure_memory_status": "available",
        "project_failure_memory_reason": reason_codes[0],
        "project_failure_memory_reason_codes": reason_codes,
        "project_failure_memory_ineffective_retry": bool(retry_failure_now),
        "project_failure_memory_failed_repair": bool(failed_repair_now),
        "project_failure_memory_repeated_review_issue": bool(repeated_review_issue_now),
        "project_failure_memory_recurring_failure_bucket": bool(
            recurring_failure_bucket_now
        ),
        "project_failure_memory_retry_failure_count": retry_failure_count,
        "project_failure_memory_repair_failure_count": repair_failure_count,
        "project_failure_memory_review_issue_count": review_issue_count,
        "project_failure_memory_failure_bucket_recurrence_count": (
            failure_bucket_recurrence_count
        ),
        "project_failure_memory_last_failure_bucket": bucket_value,
        "project_failure_memory_suppression_posture": suppression_posture,
        "project_failure_memory_suppression_active": bool(suppression_active),
        "project_failure_memory_unavailable": False,
    }


def _normalize_project_external_boundary_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_EXTERNAL_BOUNDARY_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_EXTERNAL_BOUNDARY_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["external_boundary_insufficient_truth"]


def _build_project_external_boundary_state(
    *,
    project_failure_memory_status: str,
    project_failure_memory_suppression_posture: str,
    project_failure_memory_suppression_active: bool,
    project_merge_branch_lifecycle_status: str,
    project_merge_ready_posture: str,
    project_branch_quarantine_candidate_posture: str,
    project_local_main_sync_posture: str,
    project_quality_gate_status: str,
    project_quality_gate_posture: str,
    project_quality_gate_risk_level: str,
    project_pr_queue_status: str,
    project_autonomy_budget_status: str,
    project_priority_posture: str,
    long_running_stability_status: str,
    supported_repair_execution_status: str,
    execution_reason: str,
    final_human_review_required: bool,
    final_human_review_gate_status: str,
    manual_only_posture_active: bool,
    fleet_manual_review_required: bool,
    approval_reason_class: str,
) -> dict[str, Any]:
    failure_memory_status = _normalize_text(
        project_failure_memory_status,
        default="insufficient_truth",
    )
    suppression_posture = _normalize_text(
        project_failure_memory_suppression_posture,
        default="insufficient_truth",
    )
    lifecycle_status = _normalize_text(
        project_merge_branch_lifecycle_status,
        default="insufficient_truth",
    )
    merge_ready_posture = _normalize_text(
        project_merge_ready_posture,
        default="insufficient_truth",
    )
    quarantine_posture = _normalize_text(
        project_branch_quarantine_candidate_posture,
        default="insufficient_truth",
    )
    local_main_sync_posture = _normalize_text(
        project_local_main_sync_posture,
        default="insufficient_truth",
    )
    quality_gate_status = _normalize_text(
        project_quality_gate_status,
        default="insufficient_truth",
    )
    quality_gate_posture = _normalize_text(
        project_quality_gate_posture,
        default="insufficient_truth",
    )
    quality_gate_risk_level = _normalize_text(
        project_quality_gate_risk_level,
        default="insufficient_truth",
    )
    queue_status = _normalize_text(
        project_pr_queue_status,
        default="insufficient_truth",
    )
    autonomy_budget_status = _normalize_text(
        project_autonomy_budget_status,
        default="insufficient_truth",
    )
    priority_posture = _normalize_text(
        project_priority_posture,
        default="insufficient_truth",
    )
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    repair_status = _normalize_text(
        supported_repair_execution_status,
        default="not_selected",
    )
    normalized_execution_reason = _normalize_text(
        execution_reason,
        default="restart_not_executed",
    )
    final_review_gate_status = _normalize_text(
        final_human_review_gate_status,
        default="not_required",
    )
    normalized_approval_reason_class = _normalize_text(
        approval_reason_class,
        default="unknown",
    )

    truth_sufficient = bool(
        failure_memory_status == "available"
        and lifecycle_status == "available"
        and quality_gate_status == "available"
        and queue_status in _PROJECT_PR_QUEUE_STATUSES
        and queue_status != "insufficient_truth"
        and autonomy_budget_status == "available"
        and priority_posture in _PROJECT_PRIORITY_POSTURES
        and priority_posture != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_external_boundary_reason_codes(
            ["external_boundary_insufficient_truth"]
        )
        return {
            "project_external_boundary_status": "insufficient_truth",
            "project_external_boundary_reason": reason_codes[0],
            "project_external_boundary_reason_codes": reason_codes,
            "project_external_dependency_posture": "insufficient_truth",
            "project_external_dependency_available": False,
            "project_external_dependency_blocked": False,
            "project_external_manual_only_posture": "insufficient_truth",
            "project_external_manual_only_required": False,
            "project_external_network_boundary_posture": "insufficient_truth",
            "project_external_ci_boundary_posture": "insufficient_truth",
            "project_external_secrets_boundary_posture": "insufficient_truth",
            "project_external_github_boundary_posture": "insufficient_truth",
            "project_external_api_boundary_posture": "insufficient_truth",
            "project_external_boundary_unavailable": True,
        }

    manual_only_required = bool(
        manual_only_posture_active
        or final_human_review_required
        or final_review_gate_status == "required"
        or fleet_manual_review_required
        or normalized_approval_reason_class == "manual_only"
    )

    dependency_blocked = bool(
        not manual_only_required
        and (
            bool(project_failure_memory_suppression_active)
            or suppression_posture in {"suppress_retry", "suppress_repair", "suppress_review_issue", "suppress_failure_bucket"}
            or quarantine_posture == "candidate"
            or quality_gate_posture in {"retry_needed", "insufficient_truth"}
            or merge_ready_posture != "merge_ready"
            or queue_status == "blocked"
            or priority_posture == "deferred"
            or local_main_sync_posture == "sync_required"
            or long_running_status in {"paused", "escalated"}
            or normalized_execution_reason in {"restart_launch_failed"}
            or repair_status in {"not_executed_launch_failed"}
        )
    )
    dependency_available = bool(not manual_only_required and not dependency_blocked)
    dependency_posture = "dependency_available"
    if manual_only_required:
        dependency_posture = "manual_only"
    elif dependency_blocked:
        dependency_posture = "dependency_blocked"
    if dependency_posture not in _PROJECT_EXTERNAL_DEPENDENCY_POSTURES:
        dependency_posture = "insufficient_truth"

    if manual_only_required:
        network_posture = "manual_only"
        ci_posture = "manual_only"
        secrets_posture = "manual_only"
        github_posture = "manual_only"
        api_posture = "manual_only"
    else:
        network_posture = (
            "blocked"
            if (
                suppression_posture == "suppress_failure_bucket"
                or long_running_status in {"paused", "escalated"}
                or normalized_execution_reason == "restart_launch_failed"
            )
            else "clear"
        )
        ci_posture = (
            "blocked"
            if quality_gate_posture in {"retry_needed", "insufficient_truth"}
            or quality_gate_risk_level == "high"
            else "clear"
        )
        secrets_posture = (
            "blocked"
            if suppression_posture in {"suppress_repair", "suppress_failure_bucket"}
            or repair_status in {"not_executed_precheck_blocked", "not_executed_launch_failed"}
            else "clear"
        )
        github_posture = (
            "blocked"
            if merge_ready_posture != "merge_ready"
            or quarantine_posture == "candidate"
            or local_main_sync_posture == "sync_required"
            else "clear"
        )
        api_posture = (
            "blocked"
            if suppression_posture in {"suppress_repair", "suppress_failure_bucket"}
            or repair_status
            in {
                "executed_verification_failed",
                "not_executed_qualification_failed",
                "not_executed_launch_failed",
            }
            else "clear"
        )

    for boundary_posture in (
        network_posture,
        ci_posture,
        secrets_posture,
        github_posture,
        api_posture,
    ):
        if boundary_posture not in _PROJECT_EXTERNAL_BOUNDARY_POSTURES:
            reason_codes = _normalize_project_external_boundary_reason_codes(
                ["external_boundary_insufficient_truth"]
            )
            return {
                "project_external_boundary_status": "insufficient_truth",
                "project_external_boundary_reason": reason_codes[0],
                "project_external_boundary_reason_codes": reason_codes,
                "project_external_dependency_posture": "insufficient_truth",
                "project_external_dependency_available": False,
                "project_external_dependency_blocked": False,
                "project_external_manual_only_posture": "insufficient_truth",
                "project_external_manual_only_required": False,
                "project_external_network_boundary_posture": "insufficient_truth",
                "project_external_ci_boundary_posture": "insufficient_truth",
                "project_external_secrets_boundary_posture": "insufficient_truth",
                "project_external_github_boundary_posture": "insufficient_truth",
                "project_external_api_boundary_posture": "insufficient_truth",
                "project_external_boundary_unavailable": True,
            }

    reason_codes = ["external_boundary_compiled"]
    if dependency_posture == "manual_only":
        reason_codes.append("external_dependency_manual_only")
        reason_codes.append("external_boundary_manual_only")
    elif dependency_posture == "dependency_blocked":
        reason_codes.append("external_dependency_blocked")
    else:
        reason_codes.append("external_dependency_available")
    reason_codes.append(
        "external_network_boundary_blocked"
        if network_posture == "blocked"
        else "external_network_boundary_clear"
    )
    reason_codes.append(
        "external_ci_boundary_blocked"
        if ci_posture == "blocked"
        else "external_ci_boundary_clear"
    )
    reason_codes.append(
        "external_secrets_boundary_blocked"
        if secrets_posture == "blocked"
        else "external_secrets_boundary_clear"
    )
    reason_codes.append(
        "external_github_boundary_blocked"
        if github_posture == "blocked"
        else "external_github_boundary_clear"
    )
    reason_codes.append(
        "external_api_boundary_blocked"
        if api_posture == "blocked"
        else "external_api_boundary_clear"
    )
    reason_codes = _normalize_project_external_boundary_reason_codes(reason_codes)

    return {
        "project_external_boundary_status": "available",
        "project_external_boundary_reason": reason_codes[0],
        "project_external_boundary_reason_codes": reason_codes,
        "project_external_dependency_posture": dependency_posture,
        "project_external_dependency_available": bool(dependency_available),
        "project_external_dependency_blocked": bool(dependency_blocked),
        "project_external_manual_only_posture": (
            "manual_only" if manual_only_required else "clear"
        ),
        "project_external_manual_only_required": bool(manual_only_required),
        "project_external_network_boundary_posture": network_posture,
        "project_external_ci_boundary_posture": ci_posture,
        "project_external_secrets_boundary_posture": secrets_posture,
        "project_external_github_boundary_posture": github_posture,
        "project_external_api_boundary_posture": api_posture,
        "project_external_boundary_unavailable": False,
    }


def _normalize_project_human_escalation_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_HUMAN_ESCALATION_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_HUMAN_ESCALATION_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["escalation_insufficient_truth"]


def _build_project_human_escalation_state(
    *,
    final_human_review_gate_status: str,
    final_human_review_required: bool,
    final_human_review_reason: str,
    objective_compiler_status: str,
    objective_completion_posture: str,
    objective_scope_drift_status: str,
    project_autonomy_budget_status: str,
    project_priority_posture: str,
    project_high_risk_defer_posture: str,
    project_run_budget_posture: str,
    project_objective_budget_posture: str,
    project_pr_retry_budget_posture: str,
    project_quality_gate_status: str,
    project_quality_gate_risk_level: str,
    project_quality_gate_high_risk: bool,
    project_merge_branch_lifecycle_status: str,
    project_branch_quarantine_candidate_posture: str,
    project_failure_memory_status: str,
    project_failure_memory_suppression_posture: str,
    project_failure_memory_suppression_active: bool,
    project_failure_memory_retry_failure_count: int,
    project_failure_memory_repair_failure_count: int,
    project_failure_memory_review_issue_count: int,
    project_failure_memory_failure_bucket_recurrence_count: int,
    project_external_boundary_status: str,
    project_external_dependency_posture: str,
    project_external_manual_only_posture: str,
    project_external_manual_only_required: bool,
    long_running_stability_status: str,
    supported_repair_execution_status: str,
    manual_only_posture_active: bool,
    fleet_manual_review_required: bool,
) -> dict[str, Any]:
    final_gate_status = _normalize_text(
        final_human_review_gate_status,
        default="not_required",
    )
    final_reason = _normalize_text(
        final_human_review_reason,
        default="final_review_not_required",
    )
    objective_status = _normalize_text(
        objective_compiler_status,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    scope_drift_status = _normalize_text(
        objective_scope_drift_status,
        default="insufficient_truth",
    )
    autonomy_budget_status = _normalize_text(
        project_autonomy_budget_status,
        default="insufficient_truth",
    )
    priority_posture = _normalize_text(
        project_priority_posture,
        default="insufficient_truth",
    )
    high_risk_defer_posture = _normalize_text(
        project_high_risk_defer_posture,
        default="insufficient_truth",
    )
    run_budget_posture = _normalize_text(
        project_run_budget_posture,
        default="insufficient_truth",
    )
    objective_budget_posture = _normalize_text(
        project_objective_budget_posture,
        default="insufficient_truth",
    )
    pr_retry_budget_posture = _normalize_text(
        project_pr_retry_budget_posture,
        default="insufficient_truth",
    )
    quality_gate_status = _normalize_text(
        project_quality_gate_status,
        default="insufficient_truth",
    )
    quality_gate_risk_level = _normalize_text(
        project_quality_gate_risk_level,
        default="insufficient_truth",
    )
    lifecycle_status = _normalize_text(
        project_merge_branch_lifecycle_status,
        default="insufficient_truth",
    )
    quarantine_posture = _normalize_text(
        project_branch_quarantine_candidate_posture,
        default="insufficient_truth",
    )
    failure_memory_status = _normalize_text(
        project_failure_memory_status,
        default="insufficient_truth",
    )
    suppression_posture = _normalize_text(
        project_failure_memory_suppression_posture,
        default="insufficient_truth",
    )
    external_boundary_status = _normalize_text(
        project_external_boundary_status,
        default="insufficient_truth",
    )
    external_dependency_posture = _normalize_text(
        project_external_dependency_posture,
        default="insufficient_truth",
    )
    external_manual_only_posture = _normalize_text(
        project_external_manual_only_posture,
        default="insufficient_truth",
    )
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    repair_status = _normalize_text(
        supported_repair_execution_status,
        default="not_selected",
    )

    truth_sufficient = bool(
        final_gate_status in _FINAL_HUMAN_REVIEW_GATE_STATUSES
        and objective_status == "available"
        and completion_posture in _OBJECTIVE_COMPLETION_POSTURES
        and completion_posture != "objective_insufficient_truth"
        and scope_drift_status in _OBJECTIVE_SCOPE_DRIFT_STATUSES
        and scope_drift_status != "insufficient_truth"
        and autonomy_budget_status == "available"
        and priority_posture in _PROJECT_PRIORITY_POSTURES
        and priority_posture != "insufficient_truth"
        and high_risk_defer_posture in _PROJECT_HIGH_RISK_DEFER_POSTURES
        and high_risk_defer_posture != "insufficient_truth"
        and run_budget_posture in _PROJECT_BUDGET_POSTURES
        and run_budget_posture != "insufficient_truth"
        and objective_budget_posture in _PROJECT_BUDGET_POSTURES
        and objective_budget_posture != "insufficient_truth"
        and pr_retry_budget_posture in _PROJECT_PR_RETRY_BUDGET_POSTURES
        and pr_retry_budget_posture != "insufficient_truth"
        and quality_gate_status == "available"
        and quality_gate_risk_level in _PROJECT_QUALITY_GATE_RISK_LEVELS
        and quality_gate_risk_level != "insufficient_truth"
        and lifecycle_status == "available"
        and quarantine_posture in _PROJECT_BRANCH_CANDIDATE_POSTURES
        and quarantine_posture != "insufficient_truth"
        and failure_memory_status == "available"
        and suppression_posture in _PROJECT_FAILURE_MEMORY_SUPPRESSION_POSTURES
        and suppression_posture != "insufficient_truth"
        and external_boundary_status == "available"
        and external_dependency_posture in _PROJECT_EXTERNAL_DEPENDENCY_POSTURES
        and external_dependency_posture != "insufficient_truth"
        and external_manual_only_posture in _PROJECT_EXTERNAL_BOUNDARY_POSTURES
        and external_manual_only_posture != "insufficient_truth"
        and long_running_status in _LONG_RUNNING_STABILITY_STATUSES
        and long_running_status != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_human_escalation_reason_codes(
            ["escalation_insufficient_truth"]
        )
        return {
            "project_human_escalation_status": "insufficient_truth",
            "project_human_escalation_reason": reason_codes[0],
            "project_human_escalation_reason_codes": reason_codes,
            "project_human_escalation_posture": "insufficient_truth",
            "project_human_escalation_required": False,
            "project_architecture_risk_posture": "insufficient_truth",
            "project_scope_risk_posture": "insufficient_truth",
            "project_external_risk_posture": "insufficient_truth",
            "project_budget_risk_posture": "insufficient_truth",
            "project_repeated_failure_risk_posture": "insufficient_truth",
            "project_manual_only_risk_posture": "insufficient_truth",
            "project_human_escalation_unavailable": True,
        }

    architecture_risk_elevated = bool(
        completion_posture == "objective_blocked"
        or bool(project_quality_gate_high_risk)
        or quarantine_posture == "candidate"
        or long_running_status in {"paused", "escalated", "safe_stop"}
        or repair_status == "executed_verification_failed"
        or final_reason
        in {
            "final_review_high_risk_posture",
            "final_review_supported_repair_verification_failed",
        }
    )
    scope_risk_elevated = bool(
        scope_drift_status == "detected"
        or final_reason == "final_review_next_step_unresolved"
    )
    external_risk_elevated = bool(
        external_dependency_posture in {"dependency_blocked", "manual_only"}
        or external_manual_only_posture == "manual_only"
        or bool(project_external_manual_only_required)
    )
    budget_risk_elevated = bool(
        high_risk_defer_posture == "defer"
        or priority_posture == "deferred"
        or run_budget_posture == "exhausted"
        or objective_budget_posture == "exhausted"
        or pr_retry_budget_posture == "exhausted"
    )
    repeated_failure_risk_elevated = bool(
        bool(project_failure_memory_suppression_active)
        or suppression_posture != "none"
        or _as_non_negative_int(project_failure_memory_retry_failure_count, default=0) > 1
        or _as_non_negative_int(project_failure_memory_repair_failure_count, default=0)
        > 0
        or _as_non_negative_int(project_failure_memory_review_issue_count, default=0) > 1
        or _as_non_negative_int(
            project_failure_memory_failure_bucket_recurrence_count,
            default=0,
        )
        > 0
    )
    manual_only_risk_elevated = bool(
        bool(manual_only_posture_active)
        or bool(fleet_manual_review_required)
        or bool(project_external_manual_only_required)
        or external_manual_only_posture == "manual_only"
        or final_reason
        in {
            "final_review_manual_only_posture",
            "final_review_explicit_manual_review_required",
        }
    )

    escalation_required = bool(
        final_human_review_required
        or architecture_risk_elevated
        or scope_risk_elevated
        or external_risk_elevated
        or budget_risk_elevated
        or repeated_failure_risk_elevated
        or manual_only_risk_elevated
    )
    posture = "escalation_required" if escalation_required else "not_required"
    if posture not in _PROJECT_HUMAN_ESCALATION_POSTURES:
        posture = "insufficient_truth"

    reason_codes = ["escalation_compiled"]
    reason_codes.append(
        "escalation_required" if escalation_required else "escalation_not_required"
    )
    reason_codes.append(
        "escalation_architecture_risk_elevated"
        if architecture_risk_elevated
        else "escalation_architecture_risk_clear"
    )
    reason_codes.append(
        "escalation_scope_risk_elevated"
        if scope_risk_elevated
        else "escalation_scope_risk_clear"
    )
    reason_codes.append(
        "escalation_external_risk_elevated"
        if external_risk_elevated
        else "escalation_external_risk_clear"
    )
    reason_codes.append(
        "escalation_budget_risk_elevated"
        if budget_risk_elevated
        else "escalation_budget_risk_clear"
    )
    reason_codes.append(
        "escalation_repeated_failure_risk_elevated"
        if repeated_failure_risk_elevated
        else "escalation_repeated_failure_risk_clear"
    )
    reason_codes.append(
        "escalation_manual_only_risk_elevated"
        if manual_only_risk_elevated
        else "escalation_manual_only_risk_clear"
    )
    reason_codes = _normalize_project_human_escalation_reason_codes(reason_codes)

    return {
        "project_human_escalation_status": "available",
        "project_human_escalation_reason": reason_codes[0],
        "project_human_escalation_reason_codes": reason_codes,
        "project_human_escalation_posture": posture,
        "project_human_escalation_required": bool(escalation_required),
        "project_architecture_risk_posture": (
            "elevated" if architecture_risk_elevated else "clear"
        ),
        "project_scope_risk_posture": "elevated" if scope_risk_elevated else "clear",
        "project_external_risk_posture": (
            "elevated" if external_risk_elevated else "clear"
        ),
        "project_budget_risk_posture": "elevated" if budget_risk_elevated else "clear",
        "project_repeated_failure_risk_posture": (
            "elevated" if repeated_failure_risk_elevated else "clear"
        ),
        "project_manual_only_risk_posture": (
            "elevated" if manual_only_risk_elevated else "clear"
        ),
        "project_human_escalation_unavailable": False,
    }


def _normalize_project_approval_notification_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_APPROVAL_NOTIFICATION_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_APPROVAL_NOTIFICATION_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["approval_notification_insufficient_truth"]


def _build_project_approval_notification_state(
    *,
    approval_required: bool,
    approval_email_status: str,
    approval_email_validity: str,
    approval_priority: str,
    approval_reason_class: str,
    proposed_next_direction: str,
    delivery_mode: str,
    delivery_outcome: str,
    approval_response_status: str,
    approval_response_validity: str,
    response_received: bool,
    response_decision_class: str,
    project_human_escalation_status: str,
    project_human_escalation_posture: str,
    project_human_escalation_required: bool,
    project_human_escalation_reason: str,
    project_architecture_risk_posture: str,
    project_scope_risk_posture: str,
    project_external_risk_posture: str,
    project_budget_risk_posture: str,
    project_repeated_failure_risk_posture: str,
    project_manual_only_risk_posture: str,
    project_external_manual_only_posture: str,
) -> dict[str, Any]:
    normalized_email_status = _normalize_text(
        approval_email_status,
        default="insufficient_truth",
    )
    normalized_email_validity = _normalize_text(
        approval_email_validity,
        default="insufficient_truth",
    )
    normalized_priority = _normalize_text(approval_priority, default="unknown")
    normalized_reason_class = _normalize_text(approval_reason_class, default="unknown")
    normalized_direction = _normalize_text(proposed_next_direction, default="unknown")
    normalized_delivery_mode = _normalize_text(delivery_mode, default="unknown")
    normalized_delivery_outcome = _normalize_text(delivery_outcome, default="unknown")
    normalized_response_status = _normalize_text(
        approval_response_status,
        default="insufficient_truth",
    )
    normalized_response_validity = _normalize_text(
        approval_response_validity,
        default="insufficient_truth",
    )
    normalized_response_decision_class = _normalize_text(
        response_decision_class,
        default="unknown",
    )
    escalation_status = _normalize_text(
        project_human_escalation_status,
        default="insufficient_truth",
    )
    escalation_posture = _normalize_text(
        project_human_escalation_posture,
        default="insufficient_truth",
    )
    escalation_reason = _normalize_text(
        project_human_escalation_reason,
        default="escalation_insufficient_truth",
    )
    architecture_risk_posture = _normalize_text(
        project_architecture_risk_posture,
        default="insufficient_truth",
    )
    scope_risk_posture = _normalize_text(
        project_scope_risk_posture,
        default="insufficient_truth",
    )
    external_risk_posture = _normalize_text(
        project_external_risk_posture,
        default="insufficient_truth",
    )
    budget_risk_posture = _normalize_text(
        project_budget_risk_posture,
        default="insufficient_truth",
    )
    repeated_failure_risk_posture = _normalize_text(
        project_repeated_failure_risk_posture,
        default="insufficient_truth",
    )
    manual_only_risk_posture = _normalize_text(
        project_manual_only_risk_posture,
        default="insufficient_truth",
    )
    external_manual_only_posture = _normalize_text(
        project_external_manual_only_posture,
        default="insufficient_truth",
    )

    truth_sufficient = bool(
        normalized_email_validity == "valid"
        and normalized_response_validity == "valid"
        and normalized_email_status not in {"", "insufficient_truth"}
        and escalation_status == "available"
        and escalation_posture in _PROJECT_HUMAN_ESCALATION_POSTURES
        and escalation_posture != "insufficient_truth"
        and architecture_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and architecture_risk_posture != "insufficient_truth"
        and scope_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and scope_risk_posture != "insufficient_truth"
        and external_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and external_risk_posture != "insufficient_truth"
        and budget_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and budget_risk_posture != "insufficient_truth"
        and repeated_failure_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and repeated_failure_risk_posture != "insufficient_truth"
        and manual_only_risk_posture in _PROJECT_HUMAN_ESCALATION_RISK_POSTURES
        and manual_only_risk_posture != "insufficient_truth"
        and external_manual_only_posture in _PROJECT_EXTERNAL_BOUNDARY_POSTURES
        and external_manual_only_posture != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_approval_notification_reason_codes(
            ["approval_notification_insufficient_truth"]
        )
        return {
            "project_approval_notification_status": "insufficient_truth",
            "project_approval_notification_reason": reason_codes[0],
            "project_approval_notification_reason_codes": reason_codes,
            "project_approval_notification_ready_posture": "insufficient_truth",
            "project_approval_notification_ready": False,
            "project_approval_reply_required_posture": "insufficient_truth",
            "project_approval_reply_required": False,
            "project_approval_channel_posture": "insufficient_truth",
            "project_approval_mobile_summary_posture": "insufficient_truth",
            "project_approval_mobile_summary_compact": "",
            "project_approval_mobile_summary_tokens": [],
            "project_approval_notification_unavailable": True,
        }

    escalation_required = bool(
        project_human_escalation_required
        or escalation_posture == "escalation_required"
    )
    notification_required = bool(approval_required and escalation_required)

    channel_posture = "insufficient_truth"
    if not notification_required:
        channel_posture = "not_required"
    elif (
        manual_only_risk_posture == "elevated"
        or external_manual_only_posture == "manual_only"
        or escalation_reason in {
            "escalation_manual_only_risk_elevated",
            "escalation_external_risk_elevated",
        }
    ):
        channel_posture = "manual_only"
    elif normalized_delivery_mode == "gmail_send" or normalized_delivery_outcome == "sent":
        channel_posture = "email_send"
    elif (
        normalized_delivery_mode == "gmail_draft"
        or normalized_delivery_outcome == "draft_created"
    ):
        channel_posture = "email_draft"
    elif (
        normalized_delivery_mode == "review_queue_only"
        or normalized_delivery_outcome == "queued_for_review"
    ):
        channel_posture = "review_queue"
    elif normalized_email_status in {"required", "delivered_for_review"}:
        channel_posture = "review_queue"

    if channel_posture not in _PROJECT_APPROVAL_CHANNEL_POSTURES:
        channel_posture = "insufficient_truth"

    notification_ready_posture = "insufficient_truth"
    notification_ready = False
    if not notification_required:
        notification_ready_posture = "not_required"
    elif channel_posture in {"email_send", "email_draft", "review_queue", "manual_only"}:
        if normalized_email_status in {"required", "delivered_for_review"}:
            notification_ready_posture = "ready"
            notification_ready = True
        else:
            notification_ready_posture = "not_ready"

    if notification_ready_posture not in _PROJECT_APPROVAL_NOTIFICATION_READY_POSTURES:
        notification_ready_posture = "insufficient_truth"

    terminal_response = normalized_response_status in {
        "response_accepted",
        "response_rejected",
        "response_held",
        "response_unsupported",
    } or normalized_response_decision_class in {"approved", "rejected", "held", "unsupported"}
    reply_required = bool(
        notification_required
        and not terminal_response
        and normalized_response_status in {"awaiting_response", "response_received"}
    )
    reply_required_posture = (
        "reply_required"
        if reply_required
        else (
            "reply_not_required"
            if notification_required or not notification_required
            else "insufficient_truth"
        )
    )
    if reply_required_posture not in _PROJECT_APPROVAL_REPLY_REQUIRED_POSTURES:
        reply_required_posture = "insufficient_truth"

    mobile_summary_posture = "insufficient_truth"
    summary_tokens: list[str] = []
    summary_compact = ""
    if not notification_required:
        mobile_summary_posture = "not_required"
    elif notification_ready_posture in {"ready", "not_ready"}:
        mobile_summary_posture = "available"
        elevated_risks = [
            risk_name
            for risk_name, risk_posture in (
                ("arch", architecture_risk_posture),
                ("scope", scope_risk_posture),
                ("ext", external_risk_posture),
                ("budget", budget_risk_posture),
                ("repeat", repeated_failure_risk_posture),
                ("manual", manual_only_risk_posture),
            )
            if risk_posture == "elevated"
        ]
        risk_token = "+".join(elevated_risks) if elevated_risks else "none"
        summary_tokens = _serialize_required_signals(
            [
                "escalate",
                f"prio:{normalized_priority}",
                f"dir:{normalized_direction}",
                f"ch:{channel_posture}",
                f"reply:{'yes' if reply_required else 'no'}",
                f"risk:{risk_token}",
            ]
        )
        summary_compact = " | ".join(summary_tokens[:6])

    if mobile_summary_posture not in _PROJECT_APPROVAL_MOBILE_SUMMARY_POSTURES:
        mobile_summary_posture = "insufficient_truth"

    reason_codes = ["approval_notification_compiled"]
    reason_codes.append(
        "approval_escalation_required"
        if escalation_required
        else "approval_escalation_not_required"
    )
    if notification_ready_posture == "ready":
        reason_codes.append("approval_notification_ready")
    elif notification_ready_posture == "not_ready":
        reason_codes.append("approval_notification_not_ready")
    else:
        reason_codes.append("approval_notification_not_required")
    reason_codes.append(
        "approval_reply_required"
        if reply_required
        else "approval_reply_not_required"
    )
    if channel_posture == "email_send":
        reason_codes.append("approval_channel_email_send")
    elif channel_posture == "email_draft":
        reason_codes.append("approval_channel_email_draft")
    elif channel_posture == "review_queue":
        reason_codes.append("approval_channel_review_queue")
    elif channel_posture == "manual_only":
        reason_codes.append("approval_channel_manual_only")
    elif channel_posture == "not_required":
        reason_codes.append("approval_channel_not_required")
    else:
        reason_codes.append("approval_channel_insufficient_truth")
    if mobile_summary_posture == "available":
        reason_codes.append("approval_mobile_summary_available")
    elif mobile_summary_posture == "not_required":
        reason_codes.append("approval_mobile_summary_not_required")
    else:
        reason_codes.append("approval_mobile_summary_insufficient_truth")
    reason_codes.append(
        "approval_response_awaiting"
        if not terminal_response and not response_received
        else "approval_response_terminal"
    )
    reason_codes = _normalize_project_approval_notification_reason_codes(reason_codes)

    return {
        "project_approval_notification_status": "available",
        "project_approval_notification_reason": reason_codes[0],
        "project_approval_notification_reason_codes": reason_codes,
        "project_approval_notification_ready_posture": notification_ready_posture,
        "project_approval_notification_ready": bool(notification_ready),
        "project_approval_reply_required_posture": reply_required_posture,
        "project_approval_reply_required": bool(reply_required),
        "project_approval_channel_posture": channel_posture,
        "project_approval_mobile_summary_posture": mobile_summary_posture,
        "project_approval_mobile_summary_compact": summary_compact,
        "project_approval_mobile_summary_tokens": summary_tokens,
        "project_approval_notification_unavailable": False,
    }


def _normalize_project_multi_objective_reason_codes(
    reason_codes: list[str],
) -> list[str]:
    normalized = _serialize_required_signals(
        [
            reason
            for reason in reason_codes
            if reason in _PROJECT_MULTI_OBJECTIVE_REASON_CODES
        ]
    )
    ordered = [
        reason
        for reason in _PROJECT_MULTI_OBJECTIVE_REASON_ORDER
        if reason in normalized
    ]
    return ordered if ordered else ["multi_objective_insufficient_truth"]


def _build_project_multi_objective_state(
    *,
    objective_id: str,
    objective_compiler_status: str,
    objective_completion_posture: str,
    project_priority_posture: str,
    project_high_risk_defer_posture: str,
    project_run_budget_posture: str,
    project_objective_budget_posture: str,
    project_pr_retry_budget_posture: str,
    project_merge_branch_lifecycle_status: str,
    project_merge_ready_posture: str,
    project_branch_quarantine_candidate_posture: str,
    project_human_escalation_status: str,
    project_human_escalation_required: bool,
    project_approval_notification_status: str,
    project_approval_notification_ready_posture: str,
    project_approval_reply_required_posture: str,
    project_pr_queue_status: str,
    project_pr_queue_selected_slice_id: str,
    project_pr_queue_processed_slice_ids_after: list[str],
    project_pr_queue_item_count: int,
    project_pr_queue_runnable_count: int,
    project_pr_queue_blocked_count: int,
    project_pr_queue_handoff_prepared: bool,
) -> dict[str, Any]:
    normalized_objective_id = _normalize_text(objective_id, default="")
    objective_status = _normalize_text(
        objective_compiler_status,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    priority_posture = _normalize_text(
        project_priority_posture,
        default="insufficient_truth",
    )
    high_risk_defer_posture = _normalize_text(
        project_high_risk_defer_posture,
        default="insufficient_truth",
    )
    run_budget_posture = _normalize_text(
        project_run_budget_posture,
        default="insufficient_truth",
    )
    objective_budget_posture = _normalize_text(
        project_objective_budget_posture,
        default="insufficient_truth",
    )
    pr_retry_budget_posture = _normalize_text(
        project_pr_retry_budget_posture,
        default="insufficient_truth",
    )
    lifecycle_status = _normalize_text(
        project_merge_branch_lifecycle_status,
        default="insufficient_truth",
    )
    merge_ready_posture = _normalize_text(
        project_merge_ready_posture,
        default="insufficient_truth",
    )
    quarantine_posture = _normalize_text(
        project_branch_quarantine_candidate_posture,
        default="insufficient_truth",
    )
    escalation_status = _normalize_text(
        project_human_escalation_status,
        default="insufficient_truth",
    )
    notification_status = _normalize_text(
        project_approval_notification_status,
        default="insufficient_truth",
    )
    notification_ready_posture = _normalize_text(
        project_approval_notification_ready_posture,
        default="insufficient_truth",
    )
    reply_required_posture = _normalize_text(
        project_approval_reply_required_posture,
        default="insufficient_truth",
    )
    queue_status = _normalize_text(project_pr_queue_status, default="insufficient_truth")
    selected_slice_id = _normalize_text(project_pr_queue_selected_slice_id, default="")
    processed_slice_ids = _normalize_string_list(project_pr_queue_processed_slice_ids_after)
    queue_item_count = _as_non_negative_int(project_pr_queue_item_count, default=0)
    queue_runnable_count = _as_non_negative_int(project_pr_queue_runnable_count, default=0)
    queue_blocked_count = _as_non_negative_int(project_pr_queue_blocked_count, default=0)

    truth_sufficient = bool(
        normalized_objective_id
        and objective_status == "available"
        and completion_posture in _OBJECTIVE_COMPLETION_POSTURES
        and completion_posture != "objective_insufficient_truth"
        and priority_posture in _PROJECT_PRIORITY_POSTURES
        and priority_posture != "insufficient_truth"
        and high_risk_defer_posture in _PROJECT_HIGH_RISK_DEFER_POSTURES
        and high_risk_defer_posture != "insufficient_truth"
        and run_budget_posture in _PROJECT_BUDGET_POSTURES
        and run_budget_posture != "insufficient_truth"
        and objective_budget_posture in _PROJECT_BUDGET_POSTURES
        and objective_budget_posture != "insufficient_truth"
        and pr_retry_budget_posture in _PROJECT_PR_RETRY_BUDGET_POSTURES
        and pr_retry_budget_posture != "insufficient_truth"
        and lifecycle_status == "available"
        and merge_ready_posture in _PROJECT_MERGE_READY_POSTURES
        and merge_ready_posture != "insufficient_truth"
        and quarantine_posture in _PROJECT_BRANCH_CANDIDATE_POSTURES
        and quarantine_posture != "insufficient_truth"
        and escalation_status == "available"
        and notification_status == "available"
        and notification_ready_posture in _PROJECT_APPROVAL_NOTIFICATION_READY_POSTURES
        and notification_ready_posture != "insufficient_truth"
        and reply_required_posture in _PROJECT_APPROVAL_REPLY_REQUIRED_POSTURES
        and reply_required_posture != "insufficient_truth"
        and queue_status in _PROJECT_PR_QUEUE_STATUSES
        and queue_status != "insufficient_truth"
    )
    if not truth_sufficient:
        reason_codes = _normalize_project_multi_objective_reason_codes(
            ["multi_objective_insufficient_truth"]
        )
        return {
            "project_multi_objective_status": "insufficient_truth",
            "project_multi_objective_reason": reason_codes[0],
            "project_multi_objective_reason_codes": reason_codes,
            "project_active_objective_selection_posture": "insufficient_truth",
            "project_active_objective_id": "",
            "project_blocked_objective_deferral_posture": "insufficient_truth",
            "project_blocked_objective_deferred": False,
            "project_resumable_queue_ordering_posture": "insufficient_truth",
            "project_resumable_queue_ordering_key": "",
            "project_resumable_queue_next_slice_id": "",
            "project_resumable_queue_has_pending": False,
            "project_multi_objective_unavailable": True,
        }

    blocked_objective_deferred = bool(
        completion_posture == "objective_blocked"
        or priority_posture == "deferred"
        or high_risk_defer_posture == "defer"
        or bool(project_human_escalation_required)
        or notification_ready_posture in {"ready", "not_ready"}
        or reply_required_posture == "reply_required"
        or quarantine_posture == "candidate"
    )

    active_selection_posture = (
        "deferred" if blocked_objective_deferred else "selected"
    )
    if active_selection_posture not in _PROJECT_ACTIVE_OBJECTIVE_SELECTION_POSTURES:
        active_selection_posture = "insufficient_truth"
    blocked_deferral_posture = (
        "deferred" if blocked_objective_deferred else "not_deferred"
    )
    if blocked_deferral_posture not in _PROJECT_BLOCKED_OBJECTIVE_DEFERRAL_POSTURES:
        blocked_deferral_posture = "insufficient_truth"

    queue_ordering_posture = "insufficient_truth"
    if blocked_objective_deferred:
        queue_ordering_posture = "deferred_non_runnable"
    elif queue_status == "prepared":
        queue_ordering_posture = "resume_selected_first"
    elif queue_status == "blocked":
        queue_ordering_posture = "resume_blocked"
    elif queue_status == "empty":
        if processed_slice_ids or bool(project_pr_queue_handoff_prepared):
            queue_ordering_posture = "resume_completed_waiting"
        else:
            queue_ordering_posture = "resume_empty"
    if queue_ordering_posture not in _PROJECT_RESUMABLE_QUEUE_ORDERING_POSTURES:
        queue_ordering_posture = "insufficient_truth"

    queue_has_pending = bool(
        not blocked_objective_deferred
        and (
            queue_status == "prepared"
            or queue_runnable_count > 0
            or (queue_item_count > 0 and queue_status == "blocked" and queue_blocked_count > 0)
        )
    )
    queue_ordering_key = (
        f"{normalized_objective_id}:{queue_status}:{selected_slice_id or '-'}:{len(processed_slice_ids)}"
    )

    reason_codes = ["multi_objective_compiled"]
    reason_codes.append(
        "multi_objective_deferred"
        if blocked_objective_deferred
        else "multi_objective_selected"
    )
    reason_codes.append(
        "multi_objective_blocked_objective_deferred"
        if blocked_objective_deferred
        else "multi_objective_blocked_objective_not_deferred"
    )
    if queue_ordering_posture == "resume_selected_first":
        reason_codes.append("multi_objective_queue_resume_selected_first")
    elif queue_ordering_posture == "resume_blocked":
        reason_codes.append("multi_objective_queue_resume_blocked")
    elif queue_ordering_posture == "resume_completed_waiting":
        reason_codes.append("multi_objective_queue_resume_completed_waiting")
    elif queue_ordering_posture == "resume_empty":
        reason_codes.append("multi_objective_queue_resume_empty")
    else:
        reason_codes.append("multi_objective_queue_deferred_non_runnable")
    if notification_ready_posture in {"ready", "not_ready"} or reply_required_posture == "reply_required":
        reason_codes.append("multi_objective_approval_notification_deferred")
    if bool(project_human_escalation_required):
        reason_codes.append("multi_objective_escalation_deferred")
    reason_codes = _normalize_project_multi_objective_reason_codes(reason_codes)

    return {
        "project_multi_objective_status": "available",
        "project_multi_objective_reason": reason_codes[0],
        "project_multi_objective_reason_codes": reason_codes,
        "project_active_objective_selection_posture": active_selection_posture,
        "project_active_objective_id": normalized_objective_id,
        "project_blocked_objective_deferral_posture": blocked_deferral_posture,
        "project_blocked_objective_deferred": bool(blocked_objective_deferred),
        "project_resumable_queue_ordering_posture": queue_ordering_posture,
        "project_resumable_queue_ordering_key": queue_ordering_key,
        "project_resumable_queue_next_slice_id": selected_slice_id,
        "project_resumable_queue_has_pending": bool(queue_has_pending),
        "project_multi_objective_unavailable": False,
    }


def _normalize_project_browser_reason_codes(reason_codes: list[str]) -> list[str]:
    normalized = _serialize_required_signals(
        [reason for reason in reason_codes if reason in _PROJECT_BROWSER_REASON_CODES]
    )
    ordered = [
        reason for reason in _PROJECT_BROWSER_REASON_ORDER if reason in normalized
    ]
    return ordered if ordered else ["browser_task_insufficient_truth"]


def _parse_project_browser_structured_response(
    raw_response: Any,
) -> tuple[str, dict[str, Any], str]:
    if raw_response is None:
        return "unavailable", {}, "browser_response_unavailable"

    payload: dict[str, Any] = {}
    if isinstance(raw_response, Mapping):
        payload = dict(raw_response)
    elif isinstance(raw_response, str):
        raw_text = raw_response.strip()
        if not raw_text:
            return "unavailable", {}, "browser_response_unavailable"
        try:
            parsed = json.loads(raw_text)
        except Exception:
            return "invalid_response", {}, "browser_response_invalid"
        if not isinstance(parsed, Mapping):
            return "invalid_response", {}, "browser_response_invalid"
        payload = dict(parsed)
    else:
        return "invalid_response", {}, "browser_response_invalid"

    if any(field not in payload for field in _PROJECT_BROWSER_JSON_REQUIRED_FIELDS):
        return "invalid_response", {}, "browser_response_invalid"

    task_type = _normalize_text(payload.get("task_type"), default="none")
    decision = _normalize_text(payload.get("decision"), default="")
    risk_level = _normalize_text(payload.get("risk_level"), default="")
    if task_type not in _PROJECT_BROWSER_TASK_TYPES or task_type == "none":
        return "invalid_response", {}, "browser_response_invalid"
    if decision not in _PROJECT_BROWSER_DECISIONS:
        return "invalid_response", {}, "browser_response_invalid"
    if risk_level not in _PROJECT_BROWSER_RISK_LEVELS:
        return "invalid_response", {}, "browser_response_invalid"

    success_score = _as_non_negative_int(payload.get("success_score"), default=0)
    confidence_score = _as_non_negative_int(payload.get("confidence_score"), default=0)
    if success_score > 100 or confidence_score > 100:
        return "invalid_response", {}, "browser_response_invalid"

    compact_payload = {
        "status": _normalize_text(payload.get("status"), default="ok"),
        "task_type": task_type,
        "objective_id": _normalize_text(payload.get("objective_id"), default=""),
        "step_id": _normalize_text(payload.get("step_id"), default=""),
        "success_score": success_score,
        "confidence_score": confidence_score,
        "decision": decision,
        "decision_reason": _normalize_text(payload.get("decision_reason"), default=""),
        "risk_level": risk_level,
        "summary": _normalize_text(payload.get("summary"), default=""),
        "token_list": _normalize_string_list(payload.get("token_list")),
    }
    return "valid", compact_payload, "browser_response_valid"


def _build_project_browser_ui_readiness_state(
    *,
    browser_task_status: str,
    browser_response_status: str,
    prior_browser_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    prior = dict(prior_browser_state or {})
    active = browser_task_status != "inactive"
    selector_contract = (
        dict(prior.get("project_browser_selector_contract"))
        if isinstance(prior.get("project_browser_selector_contract"), Mapping)
        else {}
    )

    selector_targets: list[dict[str, Any]] = []
    any_selector_defined = False
    all_targets_have_any_selector = True
    primary_selector_available = True
    secondary_selector_available = True
    fallback_selector_available = True
    for target in _PROJECT_BROWSER_SELECTOR_TARGETS:
        entry = (
            dict(selector_contract.get(target))
            if isinstance(selector_contract.get(target), Mapping)
            else {}
        )
        target_primary = bool(
            entry.get("primary_selector_available", False)
            or prior.get(
                f"project_browser_selector_{target}_primary_selector_available",
                False,
            )
        )
        target_secondary = bool(
            entry.get("secondary_selector_available", False)
            or prior.get(
                f"project_browser_selector_{target}_secondary_selector_available",
                False,
            )
        )
        target_fallback = bool(
            entry.get("fallback_selector_available", False)
            or prior.get(
                f"project_browser_selector_{target}_fallback_selector_available",
                False,
            )
        )
        target_any = bool(target_primary or target_secondary or target_fallback)
        any_selector_defined = bool(any_selector_defined or target_any)
        all_targets_have_any_selector = bool(all_targets_have_any_selector and target_any)
        primary_selector_available = bool(primary_selector_available and target_primary)
        secondary_selector_available = bool(secondary_selector_available and target_secondary)
        fallback_selector_available = bool(fallback_selector_available and target_fallback)
        selector_targets.append(
            {
                "selector_target": target,
                "primary_selector_available": bool(target_primary),
                "secondary_selector_available": bool(target_secondary),
                "fallback_selector_available": bool(target_fallback),
            }
        )

    session_facts_available = bool(
        prior.get("project_browser_ui_session_facts_available", False)
        or _normalize_text(
            prior.get("project_browser_ui_session_posture"),
            default="",
        )
        in {"ready", "available", "known"}
    )

    ui_readiness_status = "inactive"
    selector_contract_status = "inactive"
    if active:
        if not any_selector_defined:
            selector_contract_status = "unavailable"
        elif all_targets_have_any_selector:
            selector_contract_status = "ready"
        else:
            selector_contract_status = "insufficient_truth"
        if selector_contract_status == "ready" and session_facts_available:
            ui_readiness_status = "ready"
        elif selector_contract_status == "unavailable" and not session_facts_available:
            ui_readiness_status = "unavailable"
        else:
            ui_readiness_status = "insufficient_truth"
    if selector_contract_status not in _PROJECT_BROWSER_UI_READINESS_STATUSES:
        selector_contract_status = "insufficient_truth"
    if ui_readiness_status not in _PROJECT_BROWSER_UI_READINESS_STATUSES:
        ui_readiness_status = "insufficient_truth"

    failure_signal = _normalize_text(
        prior.get("project_browser_ui_failure_signal"),
        default="",
    )
    ui_failure_status = "no_failure"
    if not active:
        ui_failure_status = "no_failure"
    elif failure_signal in _PROJECT_BROWSER_UI_FAILURE_STATUSES:
        ui_failure_status = failure_signal
    elif browser_response_status == "unavailable":
        ui_failure_status = "response_unavailable"
    elif ui_readiness_status in {"unavailable", "insufficient_truth"}:
        ui_failure_status = "insufficient_truth"
    if ui_failure_status not in _PROJECT_BROWSER_UI_FAILURE_STATUSES:
        ui_failure_status = "insufficient_truth"

    recommended_recovery = ""
    if ui_failure_status == "retryable_ui_failure":
        recommended_recovery = "same_chat_retry"
    elif ui_failure_status == "loading_timeout":
        recommended_recovery = "page_reload"
    elif ui_failure_status == "login_interruption":
        recommended_recovery = "new_chat_handoff"
    elif ui_failure_status == "response_unavailable":
        recommended_recovery = "resend_same_prompt"
    elif ui_failure_status == "insufficient_truth":
        recommended_recovery = "escalate"
    if recommended_recovery and recommended_recovery not in _PROJECT_BROWSER_UI_RECOVERY_ACTIONS:
        recommended_recovery = ""

    return {
        "project_browser_selector_targets": [
            entry["selector_target"] for entry in selector_targets
        ],
        "project_browser_selector_contract_targets": selector_targets,
        "project_browser_selector_primary_selector_available": bool(
            primary_selector_available
        ),
        "project_browser_selector_secondary_selector_available": bool(
            secondary_selector_available
        ),
        "project_browser_selector_fallback_selector_available": bool(
            fallback_selector_available
        ),
        "project_browser_selector_contract_status": selector_contract_status,
        "project_browser_selector_definition_only": True,
        "project_browser_ui_readiness_status": ui_readiness_status,
        "project_browser_ui_metadata_complete": bool(
            ui_readiness_status == "ready"
        ),
        "project_browser_ui_runtime_dom_checked": False,
        "project_browser_ui_runtime_session_checked": False,
        "project_browser_ui_failure_status": ui_failure_status,
        "project_browser_ui_failure_retryable": bool(
            ui_failure_status == "retryable_ui_failure"
        ),
        "project_browser_ui_failure_login_interruption": bool(
            ui_failure_status == "login_interruption"
        ),
        "project_browser_ui_failure_loading_timeout": bool(
            ui_failure_status == "loading_timeout"
        ),
        "project_browser_ui_failure_response_unavailable": bool(
            ui_failure_status == "response_unavailable"
        ),
        "project_browser_ui_recovery_options": [
            "same_chat_retry",
            "resend_same_prompt",
            "page_reload",
            "new_chat_handoff",
            "escalate",
        ],
        "project_browser_ui_recovery_recommended": recommended_recovery,
        "project_browser_ui_recovery_metadata_only": True,
        "project_browser_ui_recovery_attempted": False,
    }


def _build_project_browser_prompt_payload_state(
    *,
    browser_task_status: str,
    browser_task_type: str,
    browser_task_envelope_status: str,
    browser_task_envelope: Mapping[str, Any] | None,
    browser_response_schema_ref: str,
    browser_selector_contract_status: str,
    browser_ui_readiness_status: str,
    browser_ui_failure_status: str,
    browser_selector_targets: list[str],
    project_planning_summary_status: str,
    objective_compiler_status: str,
    implementation_prompt_status: str,
    project_pr_queue_status: str,
    project_failure_memory_status: str,
    project_autonomy_budget_status: str,
    project_external_boundary_status: str,
    project_external_dependency_posture: str,
    project_human_escalation_status: str,
    project_human_escalation_required: bool,
    project_failure_memory_suppression_active: bool,
) -> dict[str, Any]:
    normalized_task_status = _normalize_text(browser_task_status, default="inactive")
    normalized_task_type = _normalize_text(browser_task_type, default="none")
    normalized_envelope_status = _normalize_text(
        browser_task_envelope_status,
        default="inactive",
    )
    envelope = (
        dict(browser_task_envelope)
        if isinstance(browser_task_envelope, Mapping)
        else {}
    )
    task_type = _normalize_text(
        envelope.get("task_type"),
        default=normalized_task_type,
    )
    objective_id = _normalize_text(envelope.get("objective_id"), default="")
    step_id = _normalize_text(envelope.get("step_id"), default="")
    schema_ref = _normalize_text(
        envelope.get("required_json_schema_ref"),
        default=_normalize_text(
            browser_response_schema_ref,
            default="",
        ),
    )
    active = normalized_task_status != "inactive" and task_type != "none"
    missing_required_fields = _serialize_required_signals(
        [
            "task_type_missing"
            if task_type in {"", "none"}
            else "",
            "objective_id_missing" if not objective_id else "",
            "step_id_missing" if not step_id else "",
            "required_json_schema_missing" if not schema_ref else "",
        ]
    )

    payload_status = "inactive"
    if not active:
        payload_status = "inactive"
    elif missing_required_fields or normalized_envelope_status != "ready":
        payload_status = "insufficient_truth"
    elif _normalize_text(browser_ui_failure_status, default="") in {
        "login_interruption",
        "loading_timeout",
    }:
        payload_status = "unavailable"
    elif normalized_task_status in {"available", "invalid_response"}:
        payload_status = "ready"
    elif normalized_task_status == "insufficient_truth":
        payload_status = "insufficient_truth"
    else:
        payload_status = "unavailable"
    if payload_status not in _PROJECT_BROWSER_PROMPT_PAYLOAD_STATUSES:
        payload_status = "insufficient_truth"

    section_availability: dict[str, bool] = {
        "project_brief_summary": bool(project_planning_summary_status == "available"),
        "active_objective_summary": bool(objective_compiler_status == "available"),
        "current_constraints_summary": bool(
            project_external_boundary_status == "available"
            and project_human_escalation_status == "available"
        ),
        "current_state_summary": bool(active),
        "latest_diff_summary": bool(
            implementation_prompt_status == "available"
            or project_pr_queue_status in {"prepared", "blocked", "empty"}
        ),
        "failure_memory_summary": bool(project_failure_memory_status == "available"),
        "budget_boundary_summary": bool(
            project_autonomy_budget_status == "available"
            and project_external_boundary_status == "available"
        ),
        "requested_task_type": bool(task_type and task_type != "none"),
        "required_json_schema": bool(schema_ref),
    }
    section_statuses: list[dict[str, Any]] = []
    for section_name in _PROJECT_BROWSER_PROMPT_SECTION_NAMES:
        available = bool(section_availability.get(section_name, False))
        section_statuses.append(
            {
                "section": section_name,
                "available": available,
                "status": "available" if available else "insufficient_truth",
            }
        )
    sections_available_count = sum(
        1 for section in section_statuses if bool(section.get("available", False))
    )

    context_level = "minimal"
    if payload_status == "insufficient_truth":
        context_level = "insufficient_truth"
    else:
        expanded_required = bool(
            task_type in {"planner", "repair", "scoring"}
            or project_human_escalation_required
            or project_failure_memory_suppression_active
            or project_external_dependency_posture in {"dependency_blocked", "manual_only"}
            or _normalize_text(browser_ui_readiness_status, default="")
            in {"insufficient_truth", "unavailable"}
            or _normalize_text(browser_selector_contract_status, default="")
            in {"insufficient_truth", "unavailable"}
        )
        context_level = "expanded" if expanded_required else "minimal"
    if context_level not in _PROJECT_BROWSER_PROMPT_CONTEXT_LEVELS:
        context_level = "insufficient_truth"

    token_posture = "compact"
    if payload_status == "insufficient_truth":
        token_posture = "blocked_insufficient_truth"
    elif context_level == "expanded":
        token_posture = "expanded_required"
    if token_posture not in _PROJECT_BROWSER_PROMPT_TOKEN_POSTURES:
        token_posture = "blocked_insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_browser_send",
        "no_dom_read",
        "no_session_check",
    ]

    return {
        "project_browser_prompt_payload_status": payload_status,
        "project_browser_prompt_payload_style": "summary_first",
        "project_browser_prompt_payload_sections": section_statuses,
        "project_browser_prompt_payload_section_count": len(section_statuses),
        "project_browser_prompt_payload_sections_available_count": sections_available_count,
        "project_browser_prompt_payload_missing_required_fields": missing_required_fields,
        "project_browser_prompt_context_level": context_level,
        "project_browser_prompt_payload_context_level": context_level,
        "project_browser_prompt_token_posture": token_posture,
        "project_browser_prompt_payload_token_posture": token_posture,
        "project_browser_prompt_context_task_type": task_type,
        "project_browser_prompt_context_objective_id": objective_id,
        "project_browser_prompt_context_step_id": step_id,
        "project_browser_prompt_context_selector_contract_status": _normalize_text(
            browser_selector_contract_status,
            default="insufficient_truth",
        ),
        "project_browser_prompt_context_selector_targets": _normalize_string_list(
            browser_selector_targets
        ),
        "project_browser_prompt_schema_required_json_ref": schema_ref,
        "project_browser_prompt_schema_required_json_available": bool(schema_ref),
        "project_browser_prompt_runtime_posture": runtime_posture,
        "project_browser_prompt_payload_runtime_posture": runtime_posture,
        "project_browser_prompt_runtime_metadata_only": True,
        "project_browser_prompt_runtime_no_browser_send": True,
        "project_browser_prompt_runtime_no_dom_read": True,
        "project_browser_prompt_runtime_no_session_check": True,
        "project_browser_prompt_runtime_dom_checked": False,
        "project_browser_prompt_runtime_session_checked": False,
        "project_browser_prompt_runtime_recovery_attempted": False,
    }


def _build_project_browser_response_assimilation_state(
    *,
    browser_task_status: str,
    browser_response_status: str,
    browser_response_compact: Mapping[str, Any] | None,
    browser_prompt_payload_status: str,
    browser_prompt_context_level: str,
    browser_prompt_token_posture: str,
    browser_prompt_schema_required_json_available: bool,
    browser_ui_failure_status: str,
    hard_gate_blocked: bool,
    continuation_threshold: int,
) -> dict[str, Any]:
    normalized_task_status = _normalize_text(browser_task_status, default="inactive")
    normalized_response_status = _normalize_text(
        browser_response_status,
        default="inactive",
    )
    normalized_prompt_status = _normalize_text(
        browser_prompt_payload_status,
        default="insufficient_truth",
    )
    response = (
        dict(browser_response_compact)
        if isinstance(browser_response_compact, Mapping)
        else {}
    )

    status = "inactive"
    decision = "unavailable"
    risk_level = "unavailable"
    score_posture = "unavailable"
    proof_posture = "unavailable"
    next_action_posture = "no_action"

    if normalized_task_status == "inactive" or normalized_prompt_status == "inactive":
        status = "inactive"
    elif normalized_prompt_status == "unavailable":
        status = "unavailable"
    elif (
        normalized_prompt_status == "insufficient_truth"
        or not browser_prompt_schema_required_json_available
        or _normalize_text(browser_prompt_context_level, default="insufficient_truth")
        == "insufficient_truth"
        or _normalize_text(browser_prompt_token_posture, default="blocked_insufficient_truth")
        == "blocked_insufficient_truth"
    ):
        status = "insufficient_truth"
    elif normalized_response_status == "invalid_response":
        status = "invalid_response"
    elif normalized_response_status == "unavailable":
        status = "unavailable"
        if _normalize_text(browser_ui_failure_status, default="") in {
            "retryable_ui_failure",
            "response_unavailable",
            "loading_timeout",
        }:
            next_action_posture = "candidate_retry"
    elif normalized_response_status != "valid":
        status = "insufficient_truth"
    else:
        parsed_decision = _normalize_text(response.get("decision"), default="")
        parsed_risk = _normalize_text(response.get("risk_level"), default="")
        parsed_task_type = _normalize_text(response.get("task_type"), default="")
        parsed_objective_id = _normalize_text(response.get("objective_id"), default="")
        parsed_step_id = _normalize_text(response.get("step_id"), default="")
        missing_required = any(
            (
                parsed_decision not in _PROJECT_BROWSER_DECISIONS,
                parsed_risk not in _PROJECT_BROWSER_RISK_LEVELS,
                not parsed_task_type,
                not parsed_objective_id,
                not parsed_step_id,
            )
        )
        if missing_required:
            status = "insufficient_truth"
        else:
            status = "assimilated"
            decision = (
                parsed_decision
                if parsed_decision in _PROJECT_BROWSER_ASSIMILATED_DECISIONS
                else "unavailable"
            )
            risk_level = (
                parsed_risk
                if parsed_risk in _PROJECT_BROWSER_ASSIMILATED_RISK_LEVELS
                else "unavailable"
            )
            raw_score = response.get("success_score")
            score_missing = bool(
                raw_score is None
                or isinstance(raw_score, bool)
                or (
                    isinstance(raw_score, str)
                    and not raw_score.strip().isdigit()
                )
            )
            if score_missing:
                score_posture = "insufficient_truth"
                proof_posture = "insufficient_truth"
            else:
                success_score = _as_non_negative_int(raw_score, default=0)
                if success_score >= max(0, continuation_threshold):
                    score_posture = "above_threshold"
                    proof_posture = (
                        "proof_loss" if hard_gate_blocked else "proof_available"
                    )
                else:
                    score_posture = "below_threshold"
                    proof_posture = "proof_missing"
            next_action_posture = {
                "continue": "candidate_continue",
                "retry": "candidate_retry",
                "replan": "candidate_replan",
                "split": "candidate_split",
                "repair": "candidate_repair",
                "restart": "candidate_restart",
                "escalate": "candidate_escalate",
                "stop": "candidate_stop",
            }.get(decision, "no_action")

    if status not in _PROJECT_BROWSER_RESPONSE_ASSIMILATION_STATUSES:
        status = "insufficient_truth"
    if decision not in _PROJECT_BROWSER_ASSIMILATED_DECISIONS:
        decision = "unavailable"
    if risk_level not in _PROJECT_BROWSER_ASSIMILATED_RISK_LEVELS:
        risk_level = "unavailable"
    if score_posture not in _PROJECT_BROWSER_SCORE_POSTURES:
        score_posture = "insufficient_truth"
    if proof_posture not in _PROJECT_BROWSER_PROOF_POSTURES:
        proof_posture = "insufficient_truth"
    if next_action_posture not in _PROJECT_BROWSER_NEXT_ACTION_POSTURES:
        next_action_posture = "no_action"

    runtime_posture = [
        "metadata_only",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_browser_action",
    ]
    return {
        "project_browser_response_assimilation_status": status,
        "project_browser_assimilated_decision": decision,
        "project_browser_assimilated_risk_level": risk_level,
        "project_browser_score_posture": score_posture,
        "project_browser_proof_posture": proof_posture,
        "project_browser_next_action_posture": next_action_posture,
        "project_browser_response_assimilation_hard_gate_blocked": bool(
            hard_gate_blocked
        ),
        "project_browser_response_assimilation_threshold": _as_non_negative_int(
            continuation_threshold,
            default=_PROJECT_BROWSER_CONTINUATION_THRESHOLD,
        ),
        "project_browser_assimilation_runtime_posture": runtime_posture,
        "project_browser_assimilation_runtime_metadata_only": True,
        "project_browser_assimilation_runtime_no_queue_mutation": True,
        "project_browser_assimilation_runtime_no_retry_execution": True,
        "project_browser_assimilation_runtime_no_repair_execution": True,
        "project_browser_assimilation_runtime_no_restart_execution": True,
        "project_browser_assimilation_runtime_no_browser_action": True,
    }


def _build_project_browser_ui_recovery_decision_state(
    *,
    browser_task_status: str,
    browser_response_status: str,
    browser_chat_rotation_due: bool,
    browser_handoff_summary_required: bool,
    browser_handoff_summary_available: bool,
    browser_ui_failure_status: str,
    browser_prompt_payload_status: str,
    browser_prompt_runtime_metadata_only: bool,
    browser_prompt_runtime_no_browser_send: bool,
    browser_prompt_runtime_no_dom_read: bool,
    browser_prompt_runtime_no_session_check: bool,
    browser_response_assimilation_status: str,
    browser_next_action_posture: str,
    browser_assimilation_runtime_no_queue_mutation: bool,
    browser_assimilation_runtime_no_retry_execution: bool,
    browser_assimilation_runtime_no_repair_execution: bool,
    browser_assimilation_runtime_no_restart_execution: bool,
    browser_assimilation_runtime_no_browser_action: bool,
    retry_limit: int,
    prior_retry_count: int,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    response_status = _normalize_text(browser_response_status, default="inactive")
    ui_failure_status = _normalize_text(
        browser_ui_failure_status,
        default="insufficient_truth",
    )
    prompt_payload_status = _normalize_text(
        browser_prompt_payload_status,
        default="insufficient_truth",
    )
    assimilation_status = _normalize_text(
        browser_response_assimilation_status,
        default="insufficient_truth",
    )
    next_action_posture = _normalize_text(
        browser_next_action_posture,
        default="no_action",
    )

    retry_limit_value = _as_non_negative_int(
        retry_limit,
        default=_PROJECT_BROWSER_RETRY_LIMIT,
    )
    retry_count = _as_non_negative_int(prior_retry_count, default=0)
    retry_count_posture = "not_applicable"
    if task_status != "inactive":
        if retry_limit_value <= 0:
            retry_count_posture = "insufficient_truth"
        elif retry_count >= retry_limit_value:
            retry_count_posture = "retry_limit_reached"
        else:
            retry_count_posture = "retry_available"
    if retry_count_posture not in _PROJECT_BROWSER_UI_RETRY_COUNT_POSTURES:
        retry_count_posture = "insufficient_truth"
    retry_remaining = max(0, retry_limit_value - retry_count)

    handoff_dependency_posture = "not_required"
    if browser_chat_rotation_due:
        if browser_handoff_summary_available:
            handoff_dependency_posture = "required_available"
        elif browser_handoff_summary_required:
            handoff_dependency_posture = "required_missing"
        else:
            handoff_dependency_posture = "insufficient_truth"
    if handoff_dependency_posture not in _PROJECT_BROWSER_UI_HANDOFF_DEPENDENCY_POSTURES:
        handoff_dependency_posture = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_same_chat_retry_execution",
        "no_resend_execution",
        "no_page_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery_execution",
        "no_browser_action",
    ]
    runtime_contract_ok = bool(
        browser_prompt_runtime_metadata_only
        and browser_prompt_runtime_no_browser_send
        and browser_prompt_runtime_no_dom_read
        and browser_prompt_runtime_no_session_check
        and browser_assimilation_runtime_no_queue_mutation
        and browser_assimilation_runtime_no_retry_execution
        and browser_assimilation_runtime_no_repair_execution
        and browser_assimilation_runtime_no_restart_execution
        and browser_assimilation_runtime_no_browser_action
    )

    status = "inactive"
    candidate = "none"
    reason = "no_failure"
    blocked = False
    retry_available = bool(retry_count_posture == "retry_available")
    retry_limit_reached = bool(retry_count_posture == "retry_limit_reached")

    if (
        task_status not in _PROJECT_BROWSER_TASK_STATUSES
        or response_status not in _PROJECT_BROWSER_RESPONSE_STATUSES
        or ui_failure_status not in _PROJECT_BROWSER_UI_FAILURE_STATUSES
        or prompt_payload_status not in _PROJECT_BROWSER_PROMPT_PAYLOAD_STATUSES
        or assimilation_status not in _PROJECT_BROWSER_RESPONSE_ASSIMILATION_STATUSES
        or next_action_posture not in _PROJECT_BROWSER_NEXT_ACTION_POSTURES
    ):
        status = "insufficient_truth"
        reason = "insufficient_truth"
    elif (
        task_status == "inactive"
        or prompt_payload_status == "inactive"
        or assimilation_status == "inactive"
    ):
        status = "inactive"
    elif not runtime_contract_ok:
        status = "insufficient_truth"
        reason = "insufficient_truth"
    elif (
        assimilation_status == "assimilated"
        and response_status in {"invalid_response", "unavailable", "inactive"}
    ):
        status = "insufficient_truth"
        reason = "insufficient_truth"
    elif prompt_payload_status == "unavailable":
        status = "unavailable"
        reason = "insufficient_truth"
    elif (
        prompt_payload_status == "insufficient_truth"
        or assimilation_status == "insufficient_truth"
        or handoff_dependency_posture == "insufficient_truth"
        or retry_count_posture == "insufficient_truth"
    ):
        status = "insufficient_truth"
        reason = "insufficient_truth"
    elif ui_failure_status == "login_interruption":
        status = "selected"
        candidate = "escalate"
        reason = "login_interruption"
    elif browser_chat_rotation_due:
        reason = "rotation_due"
        if handoff_dependency_posture == "required_available":
            status = "selected"
            candidate = "new_chat_handoff"
        elif handoff_dependency_posture == "required_missing":
            status = "blocked"
            blocked = True
        else:
            status = "insufficient_truth"
            reason = "insufficient_truth"
    elif ui_failure_status == "loading_timeout":
        status = "selected"
        candidate = "page_reload"
        reason = "loading_timeout"
    elif ui_failure_status == "retryable_ui_failure":
        reason = "retryable_ui_failure"
        if retry_available:
            status = "selected"
            candidate = "same_chat_retry"
        elif retry_limit_reached:
            status = "blocked"
            blocked = True
            candidate = "escalate"
            reason = "retry_limit_reached"
        else:
            status = "insufficient_truth"
            reason = "insufficient_truth"
    elif ui_failure_status == "response_unavailable":
        reason = "response_unavailable"
        if retry_available:
            status = "selected"
            candidate = "resend_same_prompt"
        elif retry_limit_reached:
            status = "blocked"
            blocked = True
            candidate = "escalate"
            reason = "retry_limit_reached"
        else:
            status = "unavailable"
    elif response_status == "invalid_response" or assimilation_status == "invalid_response":
        reason = "invalid_response"
        if retry_available:
            status = "selected"
            candidate = "resend_same_prompt"
        elif retry_limit_reached:
            status = "blocked"
            blocked = True
            candidate = "escalate"
            reason = "retry_limit_reached"
        else:
            status = "unavailable"
    elif response_status == "unavailable" or assimilation_status == "unavailable":
        reason = "response_unavailable"
        if retry_available:
            status = "selected"
            candidate = "resend_same_prompt"
        elif retry_limit_reached:
            status = "blocked"
            blocked = True
            candidate = "escalate"
            reason = "retry_limit_reached"
        else:
            status = "unavailable"
    elif next_action_posture == "candidate_retry":
        reason = "assimilation_candidate_retry"
        if retry_available:
            status = "selected"
            candidate = "same_chat_retry"
        elif retry_limit_reached:
            status = "blocked"
            blocked = True
            candidate = "escalate"
            reason = "retry_limit_reached"
        else:
            status = "unavailable"
    elif next_action_posture == "candidate_repair":
        status = "blocked"
        blocked = True
        candidate = "escalate"
        reason = "assimilation_candidate_repair"
    elif next_action_posture == "candidate_restart":
        status = "blocked"
        blocked = True
        candidate = "escalate"
        reason = "assimilation_candidate_restart"
    elif ui_failure_status == "no_failure":
        status = "selected"
        candidate = "none"
        reason = "no_failure"
    else:
        status = "unavailable"
        candidate = "none"
        reason = "insufficient_truth"

    if status not in _PROJECT_BROWSER_UI_RECOVERY_DECISION_STATUSES:
        status = "insufficient_truth"
    if candidate not in _PROJECT_BROWSER_UI_RECOVERY_CANDIDATES:
        candidate = "none"
    if reason not in _PROJECT_BROWSER_UI_RECOVERY_REASONS:
        reason = "insufficient_truth"

    return {
        "project_browser_ui_recovery_decision_status": status,
        "project_browser_recovery_candidate": candidate,
        "project_browser_recovery_reason": reason,
        "project_browser_retry_count_posture": retry_count_posture,
        "project_browser_retry_count_current": retry_count,
        "project_browser_retry_count_limit": retry_limit_value,
        "project_browser_retry_count_remaining": retry_remaining,
        "project_browser_handoff_dependency_posture": handoff_dependency_posture,
        "project_browser_ui_recovery_decision_blocked": bool(blocked),
        "project_browser_recovery_runtime_posture": runtime_posture,
        "project_browser_recovery_runtime_metadata_only": True,
        "project_browser_recovery_runtime_no_same_chat_retry_execution": True,
        "project_browser_recovery_runtime_no_resend_execution": True,
        "project_browser_recovery_runtime_no_page_reload_execution": True,
        "project_browser_recovery_runtime_no_new_chat_execution": True,
        "project_browser_recovery_runtime_no_login_recovery_execution": True,
        "project_browser_recovery_runtime_no_browser_action": True,
    }


def _build_project_browser_handoff_compile_state(
    *,
    browser_task_status: str,
    browser_chat_rotation_due: bool,
    browser_handoff_summary_required: bool,
    browser_handoff_summary_available: bool,
    browser_prompt_payload_status: str,
    browser_prompt_payload_sections: list[Mapping[str, Any]] | None,
    browser_response_assimilation_status: str,
    browser_next_action_posture: str,
    browser_recovery_decision_status: str,
    browser_recovery_candidate: str,
    browser_handoff_dependency_posture: str,
    project_planning_summary_status: str,
    objective_completion_posture: str,
    project_failure_memory_status: str,
    project_autonomy_budget_status: str,
    project_external_boundary_status: str,
    project_blocked_objective_deferral_posture: str,
    project_human_escalation_required: bool,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    prompt_payload_status = _normalize_text(
        browser_prompt_payload_status,
        default="insufficient_truth",
    )
    assimilation_status = _normalize_text(
        browser_response_assimilation_status,
        default="insufficient_truth",
    )
    next_action_posture = _normalize_text(
        browser_next_action_posture,
        default="no_action",
    )
    recovery_decision_status = _normalize_text(
        browser_recovery_decision_status,
        default="insufficient_truth",
    )
    recovery_candidate = _normalize_text(
        browser_recovery_candidate,
        default="none",
    )
    handoff_dependency_posture = _normalize_text(
        browser_handoff_dependency_posture,
        default="insufficient_truth",
    )
    completion_posture = _normalize_text(
        objective_completion_posture,
        default="objective_insufficient_truth",
    )
    planning_summary_status = _normalize_text(
        project_planning_summary_status,
        default="insufficient_truth",
    )
    failure_memory_status = _normalize_text(
        project_failure_memory_status,
        default="insufficient_truth",
    )
    autonomy_budget_status = _normalize_text(
        project_autonomy_budget_status,
        default="insufficient_truth",
    )
    external_boundary_status = _normalize_text(
        project_external_boundary_status,
        default="insufficient_truth",
    )
    blocked_objective_deferral_posture = _normalize_text(
        project_blocked_objective_deferral_posture,
        default="insufficient_truth",
    )

    prompt_sections = [
        dict(entry)
        for entry in (browser_prompt_payload_sections or [])
        if isinstance(entry, Mapping)
    ]
    prompt_section_available: dict[str, bool] = {}
    for entry in prompt_sections:
        section_name = _normalize_text(entry.get("section"), default="")
        if not section_name:
            continue
        prompt_section_available[section_name] = bool(entry.get("available", False))

    section_availability = {
        "project_summary": bool(
            prompt_section_available.get("project_brief_summary", False)
            and planning_summary_status == "available"
        ),
        "active_objective_summary": bool(
            prompt_section_available.get("active_objective_summary", False)
            and completion_posture == "objective_active"
        ),
        "completed_objective_summary": bool(completion_posture == "objective_completed"),
        "blocked_items": bool(
            blocked_objective_deferral_posture == "deferred"
            or bool(project_human_escalation_required)
            or completion_posture == "objective_blocked"
        ),
        "failure_memory_summary": bool(
            prompt_section_available.get("failure_memory_summary", False)
            and failure_memory_status == "available"
        ),
        "current_budgets_limits": bool(
            prompt_section_available.get("budget_boundary_summary", False)
            and autonomy_budget_status == "available"
        ),
        "current_repo_constraints": bool(
            prompt_section_available.get("current_constraints_summary", False)
            and external_boundary_status == "available"
        ),
        "next_intended_action": bool(
            next_action_posture in _PROJECT_BROWSER_NEXT_ACTION_POSTURES - {"no_action"}
            or prompt_section_available.get("requested_task_type", False)
        ),
    }
    sections_status: list[dict[str, Any]] = []
    for section_name in _PROJECT_BROWSER_HANDOFF_SECTION_NAMES:
        available = bool(section_availability.get(section_name, False))
        sections_status.append(
            {
                "section": section_name,
                "available": available,
                "status": "available" if available else "insufficient_truth",
            }
        )
    sections_available_count = sum(
        1 for section in sections_status if bool(section.get("available", False))
    )

    objective_summary_available = bool(
        section_availability.get("active_objective_summary", False)
        or section_availability.get("completed_objective_summary", False)
    )
    missing_required_sections = _serialize_required_signals(
        [
            "project_summary"
            if not section_availability.get("project_summary", False)
            else "",
            "objective_summary" if not objective_summary_available else "",
            "current_budgets_limits"
            if not section_availability.get("current_budgets_limits", False)
            else "",
            "current_repo_constraints"
            if not section_availability.get("current_repo_constraints", False)
            else "",
            "next_intended_action"
            if not section_availability.get("next_intended_action", False)
            else "",
        ]
    )

    compile_status = "inactive"
    handoff_trigger = "none"
    payload_posture = "unavailable"
    handoff_required = bool(
        browser_chat_rotation_due or recovery_candidate == "new_chat_handoff"
    )

    if (
        task_status not in _PROJECT_BROWSER_TASK_STATUSES
        or prompt_payload_status not in _PROJECT_BROWSER_PROMPT_PAYLOAD_STATUSES
        or assimilation_status not in _PROJECT_BROWSER_RESPONSE_ASSIMILATION_STATUSES
        or next_action_posture not in _PROJECT_BROWSER_NEXT_ACTION_POSTURES
        or recovery_decision_status not in _PROJECT_BROWSER_UI_RECOVERY_DECISION_STATUSES
        or recovery_candidate not in _PROJECT_BROWSER_UI_RECOVERY_CANDIDATES
        or handoff_dependency_posture not in _PROJECT_BROWSER_UI_HANDOFF_DEPENDENCY_POSTURES
    ):
        compile_status = "insufficient_truth"
        handoff_trigger = "insufficient_truth"
        payload_posture = "insufficient_truth"
    elif task_status == "inactive" or recovery_decision_status == "inactive":
        compile_status = "inactive"
        handoff_trigger = "none"
        payload_posture = "unavailable"
    elif not handoff_required:
        compile_status = "not_required"
        handoff_trigger = "none"
        payload_posture = "unavailable"
    else:
        if (
            handoff_dependency_posture == "required_missing"
            or (
                browser_handoff_summary_required
                and not browser_handoff_summary_available
                and recovery_candidate != "new_chat_handoff"
            )
        ):
            compile_status = "unavailable"
            handoff_trigger = "manual_required"
            payload_posture = "unavailable"
        elif (
            prompt_payload_status == "insufficient_truth"
            or assimilation_status == "insufficient_truth"
            or handoff_dependency_posture == "insufficient_truth"
        ):
            compile_status = "insufficient_truth"
            handoff_trigger = "insufficient_truth"
            payload_posture = "insufficient_truth"
        elif missing_required_sections:
            compile_status = "unavailable"
            handoff_trigger = (
                "new_chat_handoff_recovery"
                if recovery_candidate == "new_chat_handoff"
                else "rotation_due"
            )
            payload_posture = "missing_required_sections"
        else:
            compile_status = "ready"
            handoff_trigger = (
                "new_chat_handoff_recovery"
                if recovery_candidate == "new_chat_handoff"
                else "rotation_due"
            )
            payload_posture = "compact_ready"

    if compile_status not in _PROJECT_BROWSER_HANDOFF_COMPILE_STATUSES:
        compile_status = "insufficient_truth"
    if handoff_trigger not in _PROJECT_BROWSER_HANDOFF_TRIGGERS:
        handoff_trigger = "insufficient_truth"
    if payload_posture not in _PROJECT_BROWSER_HANDOFF_PAYLOAD_POSTURES:
        payload_posture = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_new_chat_execution",
        "no_browser_send",
        "no_dom_read",
        "no_session_check",
        "no_handoff_delivery",
    ]
    return {
        "project_browser_handoff_compile_status": compile_status,
        "project_browser_handoff_trigger": handoff_trigger,
        "project_browser_handoff_sections_status": sections_status,
        "project_browser_handoff_sections_available_count": sections_available_count,
        "project_browser_handoff_missing_required_sections": missing_required_sections,
        "project_browser_handoff_payload_posture": payload_posture,
        "project_browser_handoff_runtime_posture": runtime_posture,
        "project_browser_handoff_runtime_metadata_only": True,
        "project_browser_handoff_runtime_no_new_chat_execution": True,
        "project_browser_handoff_runtime_no_browser_send": True,
        "project_browser_handoff_runtime_no_dom_read": True,
        "project_browser_handoff_runtime_no_session_check": True,
        "project_browser_handoff_runtime_no_handoff_delivery": True,
    }


def _build_project_browser_execution_handoff_state(
    *,
    browser_task_status: str,
    browser_task_envelope_status: str,
    browser_response_status: str,
    browser_ui_readiness_status: str,
    browser_selector_contract_status: str,
    browser_prompt_payload_status: str,
    browser_response_assimilation_status: str,
    browser_recovery_decision_status: str,
    browser_recovery_candidate: str,
    browser_recovery_reason: str,
    browser_retry_count_posture: str,
    browser_handoff_dependency_posture: str,
    browser_handoff_compile_status: str,
    browser_handoff_payload_posture: str,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    envelope_status = _normalize_text(browser_task_envelope_status, default="inactive")
    response_status = _normalize_text(browser_response_status, default="inactive")
    ui_readiness_status = _normalize_text(
        browser_ui_readiness_status,
        default="insufficient_truth",
    )
    selector_contract_status = _normalize_text(
        browser_selector_contract_status,
        default="insufficient_truth",
    )
    prompt_payload_status = _normalize_text(
        browser_prompt_payload_status,
        default="insufficient_truth",
    )
    response_assimilation_status = _normalize_text(
        browser_response_assimilation_status,
        default="insufficient_truth",
    )
    recovery_decision_status = _normalize_text(
        browser_recovery_decision_status,
        default="insufficient_truth",
    )
    recovery_candidate = _normalize_text(
        browser_recovery_candidate,
        default="none",
    )
    recovery_reason = _normalize_text(
        browser_recovery_reason,
        default="insufficient_truth",
    )
    retry_count_posture = _normalize_text(
        browser_retry_count_posture,
        default="insufficient_truth",
    )
    handoff_dependency_posture = _normalize_text(
        browser_handoff_dependency_posture,
        default="insufficient_truth",
    )
    handoff_compile_status = _normalize_text(
        browser_handoff_compile_status,
        default="insufficient_truth",
    )
    handoff_payload_posture = _normalize_text(
        browser_handoff_payload_posture,
        default="insufficient_truth",
    )

    prerequisites: dict[str, str] = {
        "task_envelope": "insufficient_truth",
        "prompt_payload": "insufficient_truth",
        "ui_readiness": "insufficient_truth",
        "selector_contract": "insufficient_truth",
        "response_assimilation": "insufficient_truth",
        "recovery_decision": "insufficient_truth",
        "handoff_summary": "not_required",
    }
    if task_status == "inactive":
        prerequisites["task_envelope"] = "inactive"
        prerequisites["prompt_payload"] = "inactive"
        prerequisites["ui_readiness"] = "inactive"
        prerequisites["selector_contract"] = "inactive"
        prerequisites["response_assimilation"] = "inactive"
        prerequisites["recovery_decision"] = "inactive"
        prerequisites["handoff_summary"] = "inactive"
    else:
        prerequisites["task_envelope"] = (
            "ready" if envelope_status == "ready" else "insufficient_truth"
        )
        if prompt_payload_status == "ready":
            prerequisites["prompt_payload"] = "ready"
        elif prompt_payload_status == "unavailable":
            prerequisites["prompt_payload"] = "unavailable"
        else:
            prerequisites["prompt_payload"] = "insufficient_truth"

        if ui_readiness_status == "ready":
            prerequisites["ui_readiness"] = "ready"
        elif ui_readiness_status == "unavailable":
            prerequisites["ui_readiness"] = "unavailable"
        else:
            prerequisites["ui_readiness"] = "insufficient_truth"

        if selector_contract_status == "ready":
            prerequisites["selector_contract"] = "ready"
        elif selector_contract_status == "unavailable":
            prerequisites["selector_contract"] = "unavailable"
        else:
            prerequisites["selector_contract"] = "insufficient_truth"

        if response_assimilation_status == "assimilated":
            prerequisites["response_assimilation"] = "ready"
        elif response_assimilation_status in {"unavailable", "invalid_response"}:
            prerequisites["response_assimilation"] = "unavailable"
        elif response_assimilation_status == "inactive":
            prerequisites["response_assimilation"] = "inactive"
        else:
            prerequisites["response_assimilation"] = "insufficient_truth"

        if recovery_decision_status in {"selected", "ready"}:
            prerequisites["recovery_decision"] = "ready"
        elif recovery_decision_status in {"blocked", "unavailable"}:
            prerequisites["recovery_decision"] = "blocked"
        else:
            prerequisites["recovery_decision"] = "insufficient_truth"

    handoff_required = bool(
        recovery_candidate == "new_chat_handoff"
        or handoff_dependency_posture in {"required_available", "required_missing"}
    )
    if handoff_required and task_status != "inactive":
        if (
            handoff_compile_status == "ready"
            and handoff_payload_posture == "compact_ready"
        ):
            prerequisites["handoff_summary"] = "ready"
        elif handoff_compile_status in {"unavailable", "blocked"} or handoff_payload_posture in {
            "missing_required_sections",
            "unavailable",
        }:
            prerequisites["handoff_summary"] = "unavailable"
        else:
            prerequisites["handoff_summary"] = "insufficient_truth"

    normalized_prerequisites = {
        key: (
            value
            if value in _PROJECT_BROWSER_EXECUTION_PREREQUISITE_VALUES
            else "insufficient_truth"
        )
        for key, value in prerequisites.items()
    }

    handoff_status = "insufficient_truth"
    handoff_kind = "none"
    block_reason = "insufficient_truth"

    if (
        task_status not in _PROJECT_BROWSER_TASK_STATUSES
        or envelope_status not in _PROJECT_BROWSER_TASK_ENVELOPE_STATUSES
        or response_status not in _PROJECT_BROWSER_RESPONSE_STATUSES
        or ui_readiness_status not in _PROJECT_BROWSER_UI_READINESS_STATUSES
        or selector_contract_status not in _PROJECT_BROWSER_UI_READINESS_STATUSES
        or prompt_payload_status not in _PROJECT_BROWSER_PROMPT_PAYLOAD_STATUSES
        or response_assimilation_status not in _PROJECT_BROWSER_RESPONSE_ASSIMILATION_STATUSES
        or recovery_decision_status not in _PROJECT_BROWSER_UI_RECOVERY_DECISION_STATUSES
        or recovery_candidate not in _PROJECT_BROWSER_UI_RECOVERY_CANDIDATES
        or recovery_reason not in _PROJECT_BROWSER_UI_RECOVERY_REASONS
        or retry_count_posture not in _PROJECT_BROWSER_UI_RETRY_COUNT_POSTURES
        or handoff_dependency_posture not in _PROJECT_BROWSER_UI_HANDOFF_DEPENDENCY_POSTURES
        or handoff_compile_status not in _PROJECT_BROWSER_HANDOFF_COMPILE_STATUSES
        or handoff_payload_posture not in _PROJECT_BROWSER_HANDOFF_PAYLOAD_POSTURES
    ):
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif task_status == "inactive" or recovery_decision_status == "inactive":
        handoff_status = "inactive"
        handoff_kind = "none"
        block_reason = "browser_task_inactive"
    elif retry_count_posture == "retry_limit_reached":
        handoff_status = "blocked"
        handoff_kind = "escalate"
        block_reason = "retry_limit_reached"
    elif recovery_decision_status == "blocked":
        handoff_status = "blocked"
        handoff_kind = "escalate" if recovery_candidate == "escalate" else "none"
        block_reason = "recovery_blocked"
    elif normalized_prerequisites.get("task_envelope") != "ready":
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif normalized_prerequisites.get("prompt_payload") == "unavailable":
        handoff_status = "blocked"
        handoff_kind = "none"
        block_reason = "payload_unavailable"
    elif normalized_prerequisites.get("prompt_payload") != "ready":
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif normalized_prerequisites.get("selector_contract") == "unavailable":
        handoff_status = "blocked"
        handoff_kind = "none"
        block_reason = "selector_contract_missing"
    elif normalized_prerequisites.get("selector_contract") != "ready":
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif normalized_prerequisites.get("ui_readiness") == "unavailable":
        handoff_status = "blocked"
        handoff_kind = "none"
        block_reason = "ui_not_ready"
    elif normalized_prerequisites.get("ui_readiness") != "ready":
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif (
        handoff_required
        and normalized_prerequisites.get("handoff_summary") == "unavailable"
    ):
        handoff_status = "blocked"
        handoff_kind = "none"
        block_reason = "handoff_missing"
    elif (
        handoff_required
        and normalized_prerequisites.get("handoff_summary") != "ready"
    ):
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif recovery_reason == "login_interruption":
        handoff_status = "ready"
        handoff_kind = (
            "escalate" if recovery_candidate == "escalate" else "pause_for_login"
        )
        block_reason = "login_interruption"
    elif recovery_candidate in {
        "same_chat_retry",
        "resend_same_prompt",
        "page_reload",
        "new_chat_handoff",
        "escalate",
    }:
        handoff_status = "ready"
        handoff_kind = recovery_candidate
        block_reason = "none"
    elif response_assimilation_status in {"unavailable", "invalid_response"}:
        handoff_status = "blocked"
        handoff_kind = "none"
        block_reason = "response_unavailable"
    elif response_assimilation_status == "insufficient_truth":
        handoff_status = "insufficient_truth"
        handoff_kind = "none"
        block_reason = "insufficient_truth"
    elif response_status == "inactive":
        handoff_status = "ready"
        handoff_kind = "send_prompt"
        block_reason = "none"
    elif response_status == "unavailable":
        handoff_status = "ready"
        handoff_kind = "wait_for_response"
        block_reason = "none"
    elif response_assimilation_status in {"assimilated", "inactive"}:
        handoff_status = "ready"
        handoff_kind = "wait_for_response"
        block_reason = "none"
    else:
        handoff_status = "unavailable"
        handoff_kind = "none"
        block_reason = "response_unavailable"

    if handoff_status not in _PROJECT_BROWSER_EXECUTION_HANDOFF_STATUSES:
        handoff_status = "insufficient_truth"
    if handoff_kind not in _PROJECT_BROWSER_EXECUTION_HANDOFF_KINDS:
        handoff_kind = "none"
    if block_reason not in _PROJECT_BROWSER_EXECUTION_BLOCK_REASONS:
        block_reason = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_playwright_execution",
        "no_browser_open",
        "no_dom_interaction",
        "no_browser_send",
        "no_response_wait",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_external_operation",
    ]
    return {
        "project_browser_execution_handoff_status": handoff_status,
        "project_browser_execution_handoff_kind": handoff_kind,
        "project_browser_execution_prerequisite_posture": normalized_prerequisites,
        "project_browser_execution_prerequisite_task_envelope": normalized_prerequisites.get(
            "task_envelope",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_prompt_payload": normalized_prerequisites.get(
            "prompt_payload",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_ui_readiness": normalized_prerequisites.get(
            "ui_readiness",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_selector_contract": normalized_prerequisites.get(
            "selector_contract",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_response_assimilation": normalized_prerequisites.get(
            "response_assimilation",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_recovery_decision": normalized_prerequisites.get(
            "recovery_decision",
            "insufficient_truth",
        ),
        "project_browser_execution_prerequisite_handoff_summary": normalized_prerequisites.get(
            "handoff_summary",
            "insufficient_truth",
        ),
        "project_browser_execution_block_reason": block_reason,
        "project_browser_executor_contract_version": (
            _PROJECT_BROWSER_EXECUTOR_CONTRACT_VERSION
        ),
        "project_browser_execution_runtime_posture": runtime_posture,
        "project_browser_execution_runtime_metadata_only": True,
        "project_browser_execution_runtime_no_playwright_execution": True,
        "project_browser_execution_runtime_no_browser_open": True,
        "project_browser_execution_runtime_no_dom_interaction": True,
        "project_browser_execution_runtime_no_browser_send": True,
        "project_browser_execution_runtime_no_response_wait": True,
        "project_browser_execution_runtime_no_retry_execution": True,
        "project_browser_execution_runtime_no_reload_execution": True,
        "project_browser_execution_runtime_no_new_chat_execution": True,
        "project_browser_execution_runtime_no_login_recovery": True,
        "project_browser_execution_runtime_no_external_operation": True,
    }


def _build_project_browser_executor_interface_state(
    *,
    browser_execution_handoff_status: str,
    browser_execution_handoff_kind: str,
    browser_execution_block_reason: str,
    browser_execution_prerequisite_posture: Mapping[str, Any] | None,
    browser_execution_contract_version: str,
) -> dict[str, Any]:
    handoff_status = _normalize_text(
        browser_execution_handoff_status,
        default="insufficient_truth",
    )
    handoff_kind = _normalize_text(
        browser_execution_handoff_kind,
        default="none",
    )
    handoff_block_reason = _normalize_text(
        browser_execution_block_reason,
        default="insufficient_truth",
    )
    contract_version = _normalize_text(
        browser_execution_contract_version,
        default="",
    )
    prerequisite_posture = (
        dict(browser_execution_prerequisite_posture)
        if isinstance(browser_execution_prerequisite_posture, Mapping)
        else {}
    )
    prerequisite_values = [
        _normalize_text(value, default="insufficient_truth")
        for value in prerequisite_posture.values()
    ]

    prerequisite_insufficient = any(
        value == "insufficient_truth" for value in prerequisite_values
    )
    prerequisite_blocked = any(
        value in {"blocked", "unavailable"} for value in prerequisite_values
    )

    interface_status = "insufficient_truth"
    mode = "none"
    receipt_status = "not_created"
    receipt_kind = "none"
    block_reason = "insufficient_truth"

    if handoff_status not in _PROJECT_BROWSER_EXECUTION_HANDOFF_STATUSES:
        interface_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif handoff_status == "inactive":
        interface_status = "inactive"
        mode = "none"
        block_reason = "handoff_inactive"
        receipt_status = "not_created"
        receipt_kind = "none"
    elif handoff_status == "unavailable":
        interface_status = "unavailable"
        mode = "none"
        block_reason = "handoff_unavailable"
        receipt_status = "not_created"
        receipt_kind = "none"
    elif handoff_status == "blocked":
        interface_status = "blocked"
        mode = "none"
        block_reason = (
            "prerequisite_not_ready"
            if handoff_block_reason in {
                "payload_unavailable",
                "ui_not_ready",
                "selector_contract_missing",
                "response_unavailable",
                "handoff_missing",
            }
            else "handoff_blocked"
        )
        receipt_status = "blocked"
        receipt_kind = "none"
    elif handoff_status == "insufficient_truth":
        interface_status = "insufficient_truth"
        mode = "none"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
        receipt_kind = "none"
    elif contract_version != _PROJECT_BROWSER_EXECUTOR_CONTRACT_VERSION:
        interface_status = "blocked"
        mode = "none"
        block_reason = (
            "contract_version_unsupported"
            if contract_version
            else "insufficient_truth"
        )
        receipt_status = "blocked" if contract_version else "insufficient_truth"
        receipt_kind = "none"
    elif prerequisite_blocked:
        interface_status = "blocked"
        mode = "none"
        block_reason = "prerequisite_not_ready"
        receipt_status = "blocked"
        receipt_kind = "none"
    elif prerequisite_insufficient:
        interface_status = "insufficient_truth"
        mode = "none"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
        receipt_kind = "none"
    else:
        interface_status = "contract_ready"
        mode = (
            "dry_run_contract_only"
            if handoff_kind in {"send_prompt", "wait_for_response"}
            else "stub_only"
        )
        block_reason = "none"
        receipt_status = "receipt_ready"
        receipt_kind = (
            "dry_run_contract_receipt"
            if mode == "dry_run_contract_only"
            else "non_execution_stub_receipt"
        )

    if interface_status not in _PROJECT_BROWSER_EXECUTOR_INTERFACE_STATUSES:
        interface_status = "insufficient_truth"
    if mode not in _PROJECT_BROWSER_EXECUTOR_MODES:
        mode = "none"
    if receipt_status not in _PROJECT_BROWSER_EXECUTOR_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_EXECUTOR_RECEIPT_KINDS:
        receipt_kind = "none"
    if block_reason not in _PROJECT_BROWSER_EXECUTOR_BLOCK_REASONS:
        block_reason = "insufficient_truth"

    capability_posture = [
        "accepts_handoff_contract",
        "validates_contract_shape",
        "returns_non_execution_receipt",
        "does_not_open_browser",
        "does_not_call_playwright",
        "does_not_touch_dom",
        "does_not_send_prompt",
        "does_not_wait_response",
    ]
    capability_posture = [
        token
        for token in capability_posture
        if token in _PROJECT_BROWSER_EXECUTOR_CAPABILITY_POSTURES
    ]

    receipt_payload = {}
    if receipt_status == "receipt_ready":
        receipt_payload = {
            "receipt_kind": receipt_kind,
            "interface_status": interface_status,
            "executor_mode": mode,
            "source_handoff_status": handoff_status,
            "source_handoff_kind": handoff_kind,
            "non_execution": True,
        }

    return {
        "project_browser_executor_interface_status": interface_status,
        "project_browser_executor_mode": mode,
        "project_browser_executor_capability_posture": capability_posture,
        "project_browser_executor_capability_accepts_handoff_contract": True,
        "project_browser_executor_capability_validates_contract_shape": True,
        "project_browser_executor_capability_returns_non_execution_receipt": True,
        "project_browser_executor_capability_does_not_open_browser": True,
        "project_browser_executor_capability_does_not_call_playwright": True,
        "project_browser_executor_capability_does_not_touch_dom": True,
        "project_browser_executor_capability_does_not_send_prompt": True,
        "project_browser_executor_capability_does_not_wait_response": True,
        "project_browser_executor_receipt_status": receipt_status,
        "project_browser_executor_receipt_kind": receipt_kind,
        "project_browser_executor_receipt_payload": receipt_payload,
        "project_browser_executor_block_reason": block_reason,
        "project_browser_executor_interface_contract_version": (
            _PROJECT_BROWSER_EXECUTOR_INTERFACE_CONTRACT_VERSION
        ),
        "project_browser_executor_contract_source_version": contract_version,
        "project_browser_executor_contract_source_handoff_status": handoff_status,
        "project_browser_executor_contract_source_handoff_kind": handoff_kind,
    }


def _build_project_browser_command_queue_state(
    *,
    browser_executor_interface_status: str,
    browser_executor_mode: str,
    browser_executor_block_reason: str,
    browser_execution_handoff_status: str,
    browser_execution_handoff_kind: str,
    browser_execution_block_reason: str,
    browser_execution_prerequisite_posture: Mapping[str, Any] | None,
    browser_execution_prerequisite_task_envelope: str,
    browser_execution_prerequisite_prompt_payload: str,
    browser_execution_prerequisite_ui_readiness: str,
    browser_execution_prerequisite_selector_contract: str,
    browser_execution_prerequisite_recovery_decision: str,
    browser_execution_prerequisite_handoff_summary: str,
) -> dict[str, Any]:
    interface_status = _normalize_text(
        browser_executor_interface_status,
        default="insufficient_truth",
    )
    interface_mode = _normalize_text(browser_executor_mode, default="none")
    interface_block_reason = _normalize_text(
        browser_executor_block_reason,
        default="insufficient_truth",
    )
    handoff_status = _normalize_text(
        browser_execution_handoff_status,
        default="insufficient_truth",
    )
    handoff_kind = _normalize_text(
        browser_execution_handoff_kind,
        default="none",
    )
    handoff_block_reason = _normalize_text(
        browser_execution_block_reason,
        default="insufficient_truth",
    )
    raw_prerequisites = (
        dict(browser_execution_prerequisite_posture)
        if isinstance(browser_execution_prerequisite_posture, Mapping)
        else {}
    )

    preconditions = {
        "executor_interface": (
            "ready"
            if interface_status == "contract_ready"
            else (
                "inactive"
                if interface_status == "inactive"
                else (
                    "blocked"
                    if interface_status == "blocked"
                    else (
                        "unavailable"
                        if interface_status == "unavailable"
                        else "insufficient_truth"
                    )
                )
            )
        ),
        "source_contract": (
            "ready"
            if handoff_status == "ready"
            else (
                "inactive"
                if handoff_status == "inactive"
                else (
                    "blocked"
                    if handoff_status == "blocked"
                    else (
                        "unavailable"
                        if handoff_status == "unavailable"
                        else "insufficient_truth"
                    )
                )
            )
        ),
        "payload_contract": _normalize_text(
            browser_execution_prerequisite_prompt_payload
            or raw_prerequisites.get("prompt_payload"),
            default="insufficient_truth",
        ),
        "ui_contract": _normalize_text(
            browser_execution_prerequisite_ui_readiness
            or raw_prerequisites.get("ui_readiness"),
            default="insufficient_truth",
        ),
        "selector_contract": _normalize_text(
            browser_execution_prerequisite_selector_contract
            or raw_prerequisites.get("selector_contract"),
            default="insufficient_truth",
        ),
        "recovery_contract": _normalize_text(
            browser_execution_prerequisite_recovery_decision
            or raw_prerequisites.get("recovery_decision"),
            default="insufficient_truth",
        ),
        "handoff_contract": _normalize_text(
            browser_execution_prerequisite_handoff_summary
            or raw_prerequisites.get("handoff_summary"),
            default="insufficient_truth",
        ),
    }
    preconditions["payload_contract"] = (
        preconditions["payload_contract"]
        if preconditions["payload_contract"] in _PROJECT_BROWSER_COMMAND_PRECONDITION_VALUES
        else "insufficient_truth"
    )
    preconditions["ui_contract"] = (
        preconditions["ui_contract"]
        if preconditions["ui_contract"] in _PROJECT_BROWSER_COMMAND_PRECONDITION_VALUES
        else "insufficient_truth"
    )
    preconditions["selector_contract"] = (
        preconditions["selector_contract"]
        if preconditions["selector_contract"] in _PROJECT_BROWSER_COMMAND_PRECONDITION_VALUES
        else "insufficient_truth"
    )
    preconditions["recovery_contract"] = (
        preconditions["recovery_contract"]
        if preconditions["recovery_contract"] in _PROJECT_BROWSER_COMMAND_PRECONDITION_VALUES
        else "insufficient_truth"
    )
    preconditions["handoff_contract"] = (
        preconditions["handoff_contract"]
        if preconditions["handoff_contract"] in _PROJECT_BROWSER_COMMAND_PRECONDITION_VALUES
        else "insufficient_truth"
    )

    queue_status = "insufficient_truth"
    queue_mode = "none"
    command_type = "none"
    command_source = "none"
    block_reason = "insufficient_truth"

    if interface_status not in _PROJECT_BROWSER_EXECUTOR_INTERFACE_STATUSES:
        queue_status = "insufficient_truth"
        block_reason = "insufficient_truth"
    elif interface_status == "inactive":
        queue_status = "inactive"
        queue_mode = "none"
        command_type = "none"
        command_source = "none"
        block_reason = "executor_interface_inactive"
    elif interface_status == "blocked":
        queue_status = "blocked"
        queue_mode = "none"
        command_type = "none"
        command_source = "pr98_executor_interface"
        block_reason = "executor_interface_blocked"
    elif interface_status == "unavailable":
        queue_status = "unavailable"
        queue_mode = "none"
        command_type = "none"
        command_source = "pr98_executor_interface"
        block_reason = "executor_interface_unavailable"
    elif interface_status == "insufficient_truth":
        queue_status = "insufficient_truth"
        queue_mode = "none"
        command_type = "none"
        command_source = "insufficient_truth"
        block_reason = "insufficient_truth"
    elif handoff_status != "ready":
        queue_status = (
            "blocked"
            if handoff_status == "blocked"
            else (
                "unavailable" if handoff_status == "unavailable" else "insufficient_truth"
            )
        )
        queue_mode = "none"
        command_type = "none"
        command_source = "pr97_execution_handoff"
        if handoff_status == "blocked":
            block_reason = (
                "payload_unavailable"
                if handoff_block_reason == "payload_unavailable"
                else (
                    "selector_contract_missing"
                    if handoff_block_reason == "selector_contract_missing"
                    else (
                        "handoff_missing"
                        if handoff_block_reason == "handoff_missing"
                        else (
                            "login_interruption"
                            if handoff_block_reason == "login_interruption"
                            else (
                                "retry_limit_reached"
                                if handoff_block_reason == "retry_limit_reached"
                                else "precondition_missing"
                            )
                        )
                    )
                )
            )
        elif handoff_status == "unavailable":
            block_reason = "precondition_missing"
        else:
            block_reason = "insufficient_truth"
    elif handoff_kind not in _PROJECT_BROWSER_COMMAND_TYPES or handoff_kind == "none":
        queue_status = "blocked"
        queue_mode = "none"
        command_type = "none"
        command_source = "pr97_execution_handoff"
        block_reason = (
            "insufficient_truth"
            if handoff_kind == "none"
            else "unsupported_command_type"
        )
    elif (
        preconditions["payload_contract"] in {"unavailable", "blocked"}
        or preconditions["ui_contract"] in {"unavailable", "blocked"}
        or preconditions["selector_contract"] in {"unavailable", "blocked"}
        or preconditions["recovery_contract"] in {"unavailable", "blocked"}
        or preconditions["handoff_contract"] in {"unavailable", "blocked"}
        or preconditions["payload_contract"] == "insufficient_truth"
        or preconditions["ui_contract"] == "insufficient_truth"
        or preconditions["selector_contract"] == "insufficient_truth"
        or preconditions["recovery_contract"] == "insufficient_truth"
        or preconditions["handoff_contract"] == "insufficient_truth"
    ):
        queue_status = (
            "blocked"
            if (
                preconditions["payload_contract"] in {"unavailable", "blocked"}
                or preconditions["ui_contract"] in {"unavailable", "blocked"}
                or preconditions["selector_contract"] in {"unavailable", "blocked"}
                or preconditions["recovery_contract"] in {"unavailable", "blocked"}
                or preconditions["handoff_contract"] in {"unavailable", "blocked"}
            )
            else "insufficient_truth"
        )
        queue_mode = "none"
        command_type = "none"
        command_source = "pr97_execution_handoff"
        if preconditions["payload_contract"] in {"unavailable", "blocked"}:
            block_reason = "payload_unavailable"
        elif preconditions["selector_contract"] in {"unavailable", "blocked"}:
            block_reason = "selector_contract_missing"
        elif preconditions["handoff_contract"] in {"unavailable", "blocked"}:
            block_reason = "handoff_missing"
        elif preconditions["recovery_contract"] in {"unavailable", "blocked"}:
            block_reason = "precondition_missing"
        elif preconditions["ui_contract"] in {"unavailable", "blocked"}:
            block_reason = "precondition_missing"
        else:
            block_reason = "insufficient_truth"
    else:
        queue_status = "prepared"
        queue_mode = (
            "dry_run_contract_only"
            if interface_mode == "dry_run_contract_only"
            else "single_command"
        )
        command_type = handoff_kind
        command_source = (
            "handoff_contract"
            if handoff_kind == "new_chat_handoff"
            else (
                "recovery_candidate"
                if handoff_kind
                in {
                    "same_chat_retry",
                    "resend_same_prompt",
                    "page_reload",
                    "pause_for_login",
                    "escalate",
                }
                else "pr97_execution_handoff"
            )
        )
        block_reason = "none"

    if queue_status not in _PROJECT_BROWSER_COMMAND_QUEUE_STATUSES:
        queue_status = "insufficient_truth"
    if queue_mode not in _PROJECT_BROWSER_COMMAND_QUEUE_MODES:
        queue_mode = "none"
    if command_type not in _PROJECT_BROWSER_COMMAND_TYPES:
        command_type = "none"
    if command_source not in _PROJECT_BROWSER_COMMAND_SOURCES:
        command_source = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_COMMAND_BLOCK_REASONS:
        block_reason = "insufficient_truth"

    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    receipt_result = "insufficient_truth"
    if queue_status == "prepared":
        receipt_status = "dry_run_ready"
        receipt_kind = (
            "dry_run_command_receipt"
            if queue_mode == "dry_run_contract_only"
            else "non_execution_command_receipt"
        )
        receipt_result = "not_executed"
    elif queue_status in {"inactive", "empty"}:
        receipt_status = "not_created"
        receipt_kind = "none"
        receipt_result = "not_executed"
    elif queue_status == "blocked":
        receipt_status = "blocked"
        receipt_kind = "none"
        receipt_result = "blocked"
    elif queue_status == "unavailable":
        receipt_status = "unavailable"
        receipt_kind = "none"
        receipt_result = "unavailable"
    else:
        receipt_status = "insufficient_truth"
        receipt_kind = "none"
        receipt_result = "insufficient_truth"

    if receipt_status not in _PROJECT_BROWSER_COMMAND_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_COMMAND_RECEIPT_KINDS:
        receipt_kind = "none"
    if receipt_result not in _PROJECT_BROWSER_COMMAND_RECEIPT_RESULTS:
        receipt_result = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_playwright_execution",
        "no_browser_open",
        "no_dom_interaction",
        "no_browser_send",
        "no_response_wait",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_external_operation",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_COMMAND_RUNTIME_POSTURES
    ]

    return {
        "project_browser_command_queue_status": queue_status,
        "project_browser_command_queue_mode": queue_mode,
        "project_browser_command_type": command_type,
        "project_browser_command_source": command_source,
        "project_browser_command_precondition_posture": preconditions,
        "project_browser_command_precondition_executor_interface": preconditions.get(
            "executor_interface",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_source_contract": preconditions.get(
            "source_contract",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_payload_contract": preconditions.get(
            "payload_contract",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_ui_contract": preconditions.get(
            "ui_contract",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_selector_contract": preconditions.get(
            "selector_contract",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_recovery_contract": preconditions.get(
            "recovery_contract",
            "insufficient_truth",
        ),
        "project_browser_command_precondition_handoff_contract": preconditions.get(
            "handoff_contract",
            "insufficient_truth",
        ),
        "project_browser_command_block_reason": block_reason,
        "project_browser_command_receipt_status": receipt_status,
        "project_browser_command_receipt_kind": receipt_kind,
        "project_browser_command_receipt_result": receipt_result,
        "project_browser_command_receipt_runtime_posture": runtime_posture,
        "project_browser_command_runtime_metadata_only": True,
        "project_browser_command_runtime_no_playwright_execution": True,
        "project_browser_command_runtime_no_browser_open": True,
        "project_browser_command_runtime_no_dom_interaction": True,
        "project_browser_command_runtime_no_browser_send": True,
        "project_browser_command_runtime_no_response_wait": True,
        "project_browser_command_runtime_no_retry_execution": True,
        "project_browser_command_runtime_no_reload_execution": True,
        "project_browser_command_runtime_no_new_chat_execution": True,
        "project_browser_command_runtime_no_login_recovery": True,
        "project_browser_command_runtime_no_external_operation": True,
    }


def _probe_playwright_import_posture() -> str:
    try:
        return (
            "import_available"
            if importlib.util.find_spec("playwright") is not None
            else "import_unavailable"
        )
    except Exception:
        return "import_unavailable"


def _build_project_browser_launch_preflight_state(
    *,
    browser_command_queue_status: str,
    browser_command_type: str,
    browser_command_block_reason: str,
    browser_command_precondition_posture: Mapping[str, Any] | None,
    prior_browser_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    prior = dict(prior_browser_state or {})
    queue_status = _normalize_text(
        browser_command_queue_status,
        default="insufficient_truth",
    )
    command_type = _normalize_text(browser_command_type, default="none")
    command_block_reason = _normalize_text(
        browser_command_block_reason,
        default="insufficient_truth",
    )
    preconditions = (
        dict(browser_command_precondition_posture)
        if isinstance(browser_command_precondition_posture, Mapping)
        else {}
    )
    payload_contract = _normalize_text(
        preconditions.get("payload_contract"),
        default="insufficient_truth",
    )
    selector_contract = _normalize_text(
        preconditions.get("selector_contract"),
        default="insufficient_truth",
    )
    handoff_contract = _normalize_text(
        preconditions.get("handoff_contract"),
        default="insufficient_truth",
    )

    supported_command_types = _PROJECT_BROWSER_COMMAND_TYPES - {"none"}
    session_mode = _normalize_text(
        prior.get("project_browser_session_mode"),
        default="none",
    )
    if session_mode not in _PROJECT_BROWSER_SESSION_MODES:
        session_mode = "none"
    if session_mode == "none":
        if _normalize_text(prior.get("project_browser_session_user_data_dir"), default=""):
            session_mode = "explicit_user_data_dir"
        elif bool(prior.get("project_browser_session_persistent_context", False)):
            session_mode = "persistent_context"
        elif bool(prior.get("project_browser_session_existing_profile", False)) or (
            _normalize_text(prior.get("project_browser_ui_session_posture"), default="")
            in {"ready", "available", "known"}
        ):
            session_mode = "existing_profile"

    import_posture = _normalize_text(
        prior.get("project_browser_playwright_import_posture"),
        default="not_checked",
    )
    probe_enabled = bool(prior.get("project_browser_playwright_import_probe_enabled", False))
    if queue_status == "inactive":
        import_posture = "import_not_required"
    elif queue_status in {"blocked", "unavailable"}:
        if import_posture not in {"import_available", "import_unavailable"}:
            import_posture = "not_checked"
    elif queue_status == "insufficient_truth":
        import_posture = "insufficient_truth"
    elif queue_status == "prepared":
        if import_posture not in {"import_available", "import_unavailable"}:
            import_posture = _probe_playwright_import_posture() if probe_enabled else "not_checked"
    if import_posture not in _PROJECT_BROWSER_PLAYWRIGHT_IMPORT_POSTURES:
        import_posture = "insufficient_truth"

    session_status = "insufficient_truth"
    if queue_status == "inactive":
        session_status = "inactive"
        session_mode = "none"
    elif queue_status == "blocked":
        session_status = "blocked"
    elif queue_status == "unavailable":
        session_status = "unavailable"
    elif queue_status == "insufficient_truth":
        session_status = "insufficient_truth"
    elif session_mode in _PROJECT_BROWSER_SESSION_MODES - {"none", "insufficient_truth"}:
        session_status = "configured"
    elif session_mode == "insufficient_truth":
        session_status = "insufficient_truth"
    else:
        session_status = "unavailable"
    if session_status not in _PROJECT_BROWSER_SESSION_CONFIG_STATUSES:
        session_status = "insufficient_truth"
    if session_mode not in _PROJECT_BROWSER_SESSION_MODES:
        session_mode = "insufficient_truth"

    login_preflight_posture = "not_checked"
    runtime_block_reason = "insufficient_truth"
    launch_status = "insufficient_truth"
    launch_mode = "blocked"

    if queue_status == "inactive":
        launch_status = "inactive"
        launch_mode = "none"
        runtime_block_reason = "command_queue_inactive"
    elif queue_status == "blocked":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "command_queue_blocked"
        login_preflight_posture = (
            "blocked"
            if command_block_reason in {"login_interruption", "retry_limit_reached"}
            else "not_checked"
        )
    elif queue_status == "unavailable":
        launch_status = "unavailable"
        launch_mode = "metadata_only"
        runtime_block_reason = "command_queue_unavailable"
    elif queue_status == "insufficient_truth":
        launch_status = "insufficient_truth"
        launch_mode = "blocked"
        runtime_block_reason = "insufficient_truth"
        login_preflight_posture = "insufficient_truth"
    elif queue_status != "prepared":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "command_not_prepared"
    elif command_type not in supported_command_types:
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "unsupported_command_type"
    elif command_type == "pause_for_login":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "login_truth_missing"
        login_preflight_posture = "login_pause_required_if_detected_later"
    elif command_type == "escalate":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "launch_not_allowed"
    elif import_posture == "import_unavailable":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "playwright_import_unavailable"
    elif payload_contract in {"unavailable", "blocked", "insufficient_truth"}:
        launch_status = (
            "insufficient_truth"
            if payload_contract == "insufficient_truth"
            else "unavailable"
        )
        launch_mode = "metadata_only" if launch_status == "unavailable" else "blocked"
        runtime_block_reason = (
            "insufficient_truth"
            if payload_contract == "insufficient_truth"
            else "session_config_missing"
        )
    elif selector_contract in {"unavailable", "blocked", "insufficient_truth"}:
        launch_status = (
            "insufficient_truth"
            if selector_contract == "insufficient_truth"
            else "unavailable"
        )
        launch_mode = "metadata_only" if launch_status == "unavailable" else "blocked"
        runtime_block_reason = (
            "insufficient_truth"
            if selector_contract == "insufficient_truth"
            else "session_config_missing"
        )
    elif handoff_contract in {"unavailable", "blocked", "insufficient_truth"}:
        launch_status = (
            "insufficient_truth"
            if handoff_contract == "insufficient_truth"
            else "unavailable"
        )
        launch_mode = "metadata_only" if launch_status == "unavailable" else "blocked"
        runtime_block_reason = (
            "insufficient_truth"
            if handoff_contract == "insufficient_truth"
            else "session_config_missing"
        )
    elif session_status == "configured":
        launch_status = "ready"
        launch_mode = "launch_allowed_later"
        runtime_block_reason = "none"
        login_preflight_posture = "assumed_existing_session"
    elif session_status == "unavailable":
        launch_status = "unavailable"
        launch_mode = "metadata_only"
        runtime_block_reason = "session_config_missing"
    elif session_status == "blocked":
        launch_status = "blocked"
        launch_mode = "blocked"
        runtime_block_reason = "session_config_missing"
    else:
        launch_status = "insufficient_truth"
        launch_mode = "blocked"
        runtime_block_reason = "insufficient_truth"
        login_preflight_posture = "insufficient_truth"

    if launch_status not in _PROJECT_BROWSER_LAUNCH_PREFLIGHT_STATUSES:
        launch_status = "insufficient_truth"
    if launch_mode not in _PROJECT_BROWSER_LAUNCH_PREFLIGHT_MODES:
        launch_mode = "blocked"
    if login_preflight_posture not in _PROJECT_BROWSER_LOGIN_PREFLIGHT_POSTURES:
        login_preflight_posture = "insufficient_truth"
    if runtime_block_reason not in _PROJECT_BROWSER_RUNTIME_BLOCK_REASONS:
        runtime_block_reason = "insufficient_truth"

    boundary_status = "insufficient_truth"
    if queue_status == "inactive":
        boundary_status = "inactive"
    elif queue_status == "blocked":
        boundary_status = "blocked"
    elif queue_status == "unavailable":
        boundary_status = "unavailable"
    elif queue_status == "insufficient_truth":
        boundary_status = "insufficient_truth"
    elif launch_status == "ready" and import_posture in {"import_available", "not_checked"}:
        boundary_status = "available"
    elif import_posture == "import_unavailable":
        boundary_status = "unavailable"
    elif launch_status == "blocked":
        boundary_status = "blocked"
    elif launch_status == "unavailable":
        boundary_status = "unavailable"
    else:
        boundary_status = "insufficient_truth"
    if boundary_status not in _PROJECT_BROWSER_PLAYWRIGHT_BOUNDARY_STATUSES:
        boundary_status = "insufficient_truth"

    launch_receipt_status = "insufficient_truth"
    launch_receipt_kind = "none"
    if launch_status == "inactive":
        launch_receipt_status = "not_created"
    elif launch_status == "ready":
        launch_receipt_status = "preflight_ready"
        launch_receipt_kind = "launch_preflight_receipt"
    elif launch_status == "blocked":
        launch_receipt_status = "blocked"
        launch_receipt_kind = "non_execution_launch_receipt"
    elif launch_status == "unavailable":
        launch_receipt_status = "unavailable"
        launch_receipt_kind = "non_execution_launch_receipt"
    else:
        launch_receipt_status = "insufficient_truth"
        launch_receipt_kind = "none"
    if launch_receipt_status not in _PROJECT_BROWSER_LAUNCH_RECEIPT_STATUSES:
        launch_receipt_status = "insufficient_truth"
    if launch_receipt_kind not in _PROJECT_BROWSER_LAUNCH_RECEIPT_KINDS:
        launch_receipt_kind = "none"

    return {
        "project_browser_playwright_boundary_status": boundary_status,
        "project_browser_playwright_import_posture": import_posture,
        "project_browser_session_config_status": session_status,
        "project_browser_session_mode": session_mode,
        "project_browser_launch_preflight_status": launch_status,
        "project_browser_launch_preflight_mode": launch_mode,
        "project_browser_login_preflight_posture": login_preflight_posture,
        "project_browser_runtime_block_reason": runtime_block_reason,
        "project_browser_launch_receipt_status": launch_receipt_status,
        "project_browser_launch_receipt_kind": launch_receipt_kind,
    }


def _resolve_project_browser_chatgpt_url(
    prior_browser_state: Mapping[str, Any] | None,
) -> str:
    prior = dict(prior_browser_state or {})
    configured_url = _normalize_text(
        prior.get("project_browser_chatgpt_url"),
        default="",
    )
    allowed_prefixes = (
        "https://chatgpt.com",
        "https://chat.openai.com",
    )
    if any(configured_url.startswith(prefix) for prefix in allowed_prefixes):
        return configured_url
    return "https://chatgpt.com/"


def _is_project_browser_login_interruption_url(url: str) -> bool:
    normalized = _normalize_text(url, default="").lower()
    if not normalized:
        return False
    tokens = (
        "/auth",
        "/login",
        "/signin",
        "/sign-in",
        "/challenge",
        "/checkpoint",
    )
    return any(token in normalized for token in tokens)


def _normalize_selector_candidates(value: Any) -> list[str]:
    if isinstance(value, str):
        candidate = _normalize_text(value, default="")
        return [candidate] if candidate else []
    if isinstance(value, list):
        normalized: list[str] = []
        for entry in value:
            candidate = _normalize_text(entry, default="")
            if candidate:
                normalized.append(candidate)
        return normalized
    return []


def _collect_project_browser_selector_candidates_for_target(
    *,
    target: str,
    prior_browser_state: Mapping[str, Any] | None,
) -> list[str]:
    prior = dict(prior_browser_state or {})
    contract_map = (
        dict(prior.get("project_browser_selector_contract"))
        if isinstance(prior.get("project_browser_selector_contract"), Mapping)
        else {}
    )
    entry = (
        dict(contract_map.get(target))
        if isinstance(contract_map.get(target), Mapping)
        else {}
    )
    return (
        _normalize_selector_candidates(entry.get("primary_selector"))
        + _normalize_selector_candidates(entry.get("primary_selectors"))
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_primary_selector")
        )
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_primary_selectors")
        )
        + _normalize_selector_candidates(entry.get("secondary_selector"))
        + _normalize_selector_candidates(entry.get("secondary_selectors"))
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_secondary_selector")
        )
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_secondary_selectors")
        )
        + _normalize_selector_candidates(entry.get("fallback_selector"))
        + _normalize_selector_candidates(entry.get("fallback_selectors"))
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_fallback_selector")
        )
        + _normalize_selector_candidates(
            prior.get(f"project_browser_selector_{target}_fallback_selectors")
        )
    )


def _resolve_project_browser_prepared_prompt_text(
    *,
    browser_prompt_payload: Mapping[str, Any] | None,
    browser_queue_handoff_payload: Mapping[str, Any] | None,
    prior_browser_state: Mapping[str, Any] | None,
) -> tuple[str, str, str]:
    payload = (
        dict(browser_prompt_payload)
        if isinstance(browser_prompt_payload, Mapping)
        else {}
    )
    queue_payload = (
        dict(browser_queue_handoff_payload)
        if isinstance(browser_queue_handoff_payload, Mapping)
        else {}
    )
    prior = dict(prior_browser_state or {})
    implementation_prompt_payload = (
        dict(queue_payload.get("implementation_prompt_payload"))
        if isinstance(queue_payload.get("implementation_prompt_payload"), Mapping)
        else {}
    )
    explicit_present = False
    explicit_empty = False
    candidates: list[Any] = [
        prior.get("project_browser_prepared_prompt_text"),
        prior.get("project_browser_prompt_text"),
        prior.get("project_browser_prompt_payload_text"),
        prior.get("project_browser_command_prompt_text"),
        payload.get("project_browser_prepared_prompt_text"),
        payload.get("project_browser_prompt_text"),
        payload.get("project_browser_prompt_payload_text"),
        payload.get("project_browser_prompt_prepared_text"),
        queue_payload.get("project_browser_prepared_prompt_text"),
        queue_payload.get("project_browser_prompt_text"),
        queue_payload.get("project_browser_command_prompt_text"),
        queue_payload.get("prompt_text"),
        implementation_prompt_payload.get("project_browser_prepared_prompt_text"),
        implementation_prompt_payload.get("project_browser_prompt_text"),
        implementation_prompt_payload.get("prompt_text"),
        implementation_prompt_payload.get("prepared_prompt_text"),
    ]
    for value in candidates:
        if value is None:
            continue
        explicit_present = True
        if not isinstance(value, str):
            continue
        normalized = _normalize_text(value, default="")
        if normalized:
            return normalized, "available", "none"
        explicit_empty = True
    if explicit_empty:
        return "", "available", "prompt_text_empty"
    if explicit_present:
        return "", "insufficient_truth", "insufficient_truth"
    return "", "unavailable", "prompt_text_missing"


def _build_project_browser_selector_probe_state(
    *,
    browser_launch_status: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_launch_receipt_status: str,
    browser_launch_block_reason: str,
    browser_command_type: str,
    browser_selector_contract_status: str,
    prior_browser_state: Mapping[str, Any] | None,
    page: Any | None,
) -> dict[str, Any]:
    prior = dict(prior_browser_state or {})
    launch_status = _normalize_text(browser_launch_status, default="insufficient_truth")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    launch_receipt_status = _normalize_text(
        browser_launch_receipt_status,
        default="insufficient_truth",
    )
    launch_block_reason = _normalize_text(
        browser_launch_block_reason,
        default="insufficient_truth",
    )
    command_type = _normalize_text(browser_command_type, default="none")
    selector_contract_status = _normalize_text(
        browser_selector_contract_status,
        default="insufficient_truth",
    )

    target_statuses: dict[str, str] = {
        target: "not_checked" for target in _PROJECT_BROWSER_SELECTOR_REQUIRED_PROBE_TARGETS
    }
    runtime_posture_tokens = [
        "no_prompt_fill",
        "no_send_click",
        "no_response_wait",
        "no_response_read",
        "no_json_parse",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_executor_loop",
    ]

    resolver_status = "insufficient_truth"
    probe_status = "insufficient_truth"
    dom_readiness_status = "insufficient_truth"
    block_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    probe_attempted = False

    if launch_status == "inactive":
        resolver_status = "inactive"
        probe_status = "inactive"
        dom_readiness_status = "inactive"
        block_reason = "launch_inactive"
        receipt_status = "not_created"
        receipt_kind = "none"
    elif launch_status in {"blocked"}:
        resolver_status = "blocked"
        probe_status = "blocked"
        dom_readiness_status = "blocked"
        block_reason = (
            "playwright_unavailable"
            if launch_block_reason == "playwright_unavailable"
            else "page_not_opened"
        )
        receipt_status = "blocked"
        receipt_kind = "blocked_probe_receipt"
    elif launch_status in {"failed"}:
        resolver_status = "failed"
        probe_status = "failed"
        dom_readiness_status = "failed"
        block_reason = (
            "playwright_unavailable"
            if launch_block_reason == "playwright_unavailable"
            else "page_unavailable"
        )
        receipt_status = "failed"
        receipt_kind = "failed_probe_receipt"
    elif launch_status in {"not_attempted"}:
        resolver_status = "not_attempted"
        probe_status = "not_attempted"
        dom_readiness_status = "not_attempted"
        block_reason = "page_not_opened"
        receipt_status = "not_created"
        receipt_kind = "none"
    elif launch_status in {"insufficient_truth"}:
        resolver_status = "insufficient_truth"
        probe_status = "insufficient_truth"
        dom_readiness_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
        receipt_kind = "none"
    elif login_status == "detected" or page_status == "login_interruption":
        resolver_status = "blocked"
        probe_status = "blocked"
        dom_readiness_status = "login_interruption"
        block_reason = "login_interruption"
        receipt_status = "login_pause_required"
        receipt_kind = "login_interruption_receipt"
        target_statuses["login_interruption"] = "found"
    elif page_status != "opened" or launch_receipt_status != "launch_opened":
        resolver_status = "blocked"
        probe_status = "blocked"
        dom_readiness_status = "blocked"
        block_reason = (
            "playwright_unavailable"
            if launch_block_reason == "playwright_unavailable"
            else "page_not_opened"
        )
        receipt_status = "blocked"
        receipt_kind = "blocked_probe_receipt"
    elif selector_contract_status != "ready":
        resolver_status = (
            "insufficient_truth"
            if selector_contract_status == "insufficient_truth"
            else "blocked"
        )
        probe_status = (
            "insufficient_truth"
            if selector_contract_status == "insufficient_truth"
            else "blocked"
        )
        dom_readiness_status = (
            "insufficient_truth"
            if selector_contract_status == "insufficient_truth"
            else "blocked"
        )
        block_reason = (
            "insufficient_truth"
            if selector_contract_status == "insufficient_truth"
            else "selector_contract_missing"
        )
        receipt_status = (
            "insufficient_truth"
            if selector_contract_status == "insufficient_truth"
            else "blocked"
        )
        receipt_kind = "none" if receipt_status == "insufficient_truth" else "blocked_probe_receipt"
    elif command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
        resolver_status = "blocked"
        probe_status = "blocked"
        dom_readiness_status = "blocked"
        block_reason = "unsupported_command_type"
        receipt_status = "blocked"
        receipt_kind = "blocked_probe_receipt"
    elif page is None:
        resolver_status = "failed"
        probe_status = "failed"
        dom_readiness_status = "failed"
        block_reason = "page_unavailable"
        receipt_status = "failed"
        receipt_kind = "failed_probe_receipt"
    else:
        contract_map = (
            dict(prior.get("project_browser_selector_contract"))
            if isinstance(prior.get("project_browser_selector_contract"), Mapping)
            else {}
        )
        probe_timeout_ms = _as_non_negative_int(
            prior.get("project_browser_selector_probe_timeout_ms"),
            default=1500,
        )
        if probe_timeout_ms <= 0 or probe_timeout_ms > 5000:
            probe_timeout_ms = 1500
        probe_attempted = True
        runtime_posture_tokens.append("read_only_probe")
        try:
            try:
                page.set_default_timeout(probe_timeout_ms)
            except Exception:
                pass
            try:
                page.wait_for_load_state(
                    "domcontentloaded",
                    timeout=probe_timeout_ms,
                )
            except Exception:
                pass
            for target in _PROJECT_BROWSER_SELECTOR_REQUIRED_PROBE_TARGETS:
                entry = (
                    dict(contract_map.get(target))
                    if isinstance(contract_map.get(target), Mapping)
                    else {}
                )
                candidates = (
                    _normalize_selector_candidates(entry.get("primary_selector"))
                    + _normalize_selector_candidates(entry.get("primary_selectors"))
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_primary_selector")
                    )
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_primary_selectors")
                    )
                    + _normalize_selector_candidates(entry.get("secondary_selector"))
                    + _normalize_selector_candidates(entry.get("secondary_selectors"))
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_secondary_selector")
                    )
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_secondary_selectors")
                    )
                    + _normalize_selector_candidates(entry.get("fallback_selector"))
                    + _normalize_selector_candidates(entry.get("fallback_selectors"))
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_fallback_selector")
                    )
                    + _normalize_selector_candidates(
                        prior.get(f"project_browser_selector_{target}_fallback_selectors")
                    )
                )
                found = False
                if not candidates:
                    target_statuses[target] = "missing"
                    continue
                for selector in candidates:
                    try:
                        if page.locator(selector).count() > 0:
                            found = True
                            break
                    except Exception:
                        continue
                target_statuses[target] = "found" if found else "missing"

            required_found = bool(
                target_statuses.get("chat_input") == "found"
                and target_statuses.get("send_trigger") == "found"
            )
            all_found = all(
                target_statuses.get(target) == "found"
                for target in _PROJECT_BROWSER_SELECTOR_REQUIRED_PROBE_TARGETS
            )
            any_found = any(
                target_statuses.get(target) == "found"
                for target in _PROJECT_BROWSER_SELECTOR_REQUIRED_PROBE_TARGETS
            )
            login_found = target_statuses.get("login_interruption") == "found"
            if login_found:
                resolver_status = "blocked"
                probe_status = "blocked"
                dom_readiness_status = "login_interruption"
                block_reason = "login_interruption"
                receipt_status = "login_pause_required"
                receipt_kind = "login_interruption_receipt"
            elif all_found:
                resolver_status = "resolved"
                probe_status = "ready"
                dom_readiness_status = "ready"
                block_reason = "none"
                receipt_status = "ready"
                receipt_kind = "read_only_dom_probe_receipt"
            elif required_found:
                resolver_status = "partially_resolved"
                probe_status = "ready"
                dom_readiness_status = "ready"
                block_reason = "none"
                receipt_status = "ready"
                receipt_kind = "read_only_dom_probe_receipt"
            else:
                resolver_status = "partially_resolved" if any_found else "failed"
                probe_status = "not_ready"
                dom_readiness_status = "not_ready"
                block_reason = "selector_not_found"
                receipt_status = "not_ready"
                receipt_kind = "read_only_dom_probe_receipt"
        except Exception:
            resolver_status = "failed"
            probe_status = "failed"
            dom_readiness_status = "failed"
            block_reason = "probe_failed"
            receipt_status = "failed"
            receipt_kind = "failed_probe_receipt"

    if resolver_status not in _PROJECT_BROWSER_SELECTOR_RESOLVER_STATUSES:
        resolver_status = "insufficient_truth"
    if probe_status not in _PROJECT_BROWSER_SELECTOR_PROBE_STATUSES:
        probe_status = "insufficient_truth"
    if dom_readiness_status not in _PROJECT_BROWSER_DOM_READINESS_STATUSES:
        dom_readiness_status = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_DOM_PROBE_BLOCK_REASONS:
        block_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_SELECTOR_PROBE_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_SELECTOR_PROBE_RECEIPT_KINDS:
        receipt_kind = "none"
    for target in _PROJECT_BROWSER_SELECTOR_REQUIRED_PROBE_TARGETS:
        normalized_status = _normalize_text(target_statuses.get(target), default="insufficient_truth")
        if normalized_status not in _PROJECT_BROWSER_SELECTOR_TARGET_STATUSES:
            normalized_status = "insufficient_truth"
        target_statuses[target] = normalized_status

    runtime_posture = [
        token
        for token in runtime_posture_tokens
        if token in _PROJECT_BROWSER_SELECTOR_RUNTIME_POSTURES
    ]
    if not probe_attempted and "read_only_probe" in runtime_posture:
        runtime_posture = [token for token in runtime_posture if token != "read_only_probe"]

    return {
        "project_browser_selector_resolver_status": resolver_status,
        "project_browser_selector_probe_status": probe_status,
        "project_browser_selector_target_status": target_statuses,
        "project_browser_dom_readiness_status": dom_readiness_status,
        "project_browser_dom_probe_block_reason": block_reason,
        "project_browser_selector_runtime_posture": runtime_posture,
        "project_browser_selector_probe_receipt_status": receipt_status,
        "project_browser_selector_probe_receipt_kind": receipt_kind,
        "project_browser_selector_runtime_read_only_probe": bool(
            "read_only_probe" in runtime_posture
        ),
        "project_browser_selector_runtime_no_prompt_fill": True,
        "project_browser_selector_runtime_no_send_click": True,
        "project_browser_selector_runtime_no_response_wait": True,
        "project_browser_selector_runtime_no_response_read": True,
        "project_browser_selector_runtime_no_json_parse": True,
        "project_browser_selector_runtime_no_retry_execution": True,
        "project_browser_selector_runtime_no_reload_execution": True,
        "project_browser_selector_runtime_no_new_chat_execution": True,
        "project_browser_selector_runtime_no_login_recovery": True,
        "project_browser_selector_runtime_no_executor_loop": True,
    }


def _build_project_browser_prompt_fill_state(
    *,
    browser_task_status: str,
    browser_command_type: str,
    browser_prompt_payload_status: str,
    browser_launch_status: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_dom_readiness_status: str,
    browser_chat_input_target_status: str,
    prior_browser_state: Mapping[str, Any] | None,
    browser_prompt_payload: Mapping[str, Any] | None,
    browser_queue_handoff_payload: Mapping[str, Any] | None,
    page: Any | None,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    command_type = _normalize_text(browser_command_type, default="none")
    prompt_payload_status = _normalize_text(
        browser_prompt_payload_status,
        default="insufficient_truth",
    )
    launch_status = _normalize_text(browser_launch_status, default="insufficient_truth")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    dom_status = _normalize_text(browser_dom_readiness_status, default="insufficient_truth")
    chat_input_target_status = _normalize_text(
        browser_chat_input_target_status,
        default="insufficient_truth",
    )
    prompt_text, prompt_source_status, prompt_source_reason = (
        _resolve_project_browser_prepared_prompt_text(
            browser_prompt_payload=browser_prompt_payload,
            browser_queue_handoff_payload=browser_queue_handoff_payload,
            prior_browser_state=prior_browser_state,
        )
    )

    fill_status = "insufficient_truth"
    target_status = "insufficient_truth"
    block_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    fill_attempted = False
    runtime_tokens = [
        "no_send_click",
        "no_enter_submit",
        "no_response_wait",
        "no_response_read",
        "no_json_parse",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_executor_loop",
    ]

    if task_status == "inactive" or prompt_payload_status == "inactive":
        fill_status = "inactive"
        target_status = "missing"
        block_reason = "dom_not_ready"
        receipt_status = "not_created"
    elif launch_status == "inactive" or dom_status == "inactive":
        fill_status = "inactive"
        target_status = "missing"
        block_reason = "dom_not_ready"
        receipt_status = "not_created"
    elif launch_status == "failed" or page_status == "failed" or dom_status == "failed":
        fill_status = "failed"
        target_status = "blocked"
        block_reason = "fill_failed"
        receipt_status = "failed"
        receipt_kind = "failed_fill_receipt"
    elif (
        launch_status in {"blocked", "not_attempted"}
        or page_status in {"blocked", "not_attempted", "unavailable"}
        or dom_status in {"blocked", "not_attempted", "not_ready"}
    ):
        fill_status = "blocked" if dom_status != "not_attempted" else "not_attempted"
        target_status = "blocked"
        block_reason = "dom_not_ready"
        receipt_status = "blocked" if fill_status == "blocked" else "not_created"
        receipt_kind = "blocked_fill_receipt" if fill_status == "blocked" else "none"
    elif (
        launch_status == "insufficient_truth"
        or page_status == "insufficient_truth"
        or dom_status == "insufficient_truth"
        or prompt_payload_status == "insufficient_truth"
    ):
        fill_status = "insufficient_truth"
        target_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif login_status == "detected" or page_status == "login_interruption":
        fill_status = "blocked"
        target_status = "blocked"
        block_reason = "login_interruption"
        receipt_status = "blocked"
        receipt_kind = "blocked_fill_receipt"
    elif command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
        fill_status = "blocked"
        target_status = "blocked"
        block_reason = "unsupported_command_type"
        receipt_status = "blocked"
        receipt_kind = "blocked_fill_receipt"
    elif dom_status != "ready":
        fill_status = "blocked"
        target_status = "blocked"
        block_reason = "dom_not_ready"
        receipt_status = "blocked"
        receipt_kind = "blocked_fill_receipt"
    elif chat_input_target_status != "found":
        fill_status = "blocked"
        target_status = (
            "insufficient_truth"
            if chat_input_target_status == "insufficient_truth"
            else "missing"
        )
        block_reason = (
            "insufficient_truth"
            if chat_input_target_status == "insufficient_truth"
            else "chat_input_missing"
        )
        receipt_status = "blocked" if block_reason != "insufficient_truth" else "insufficient_truth"
        receipt_kind = "blocked_fill_receipt" if receipt_status == "blocked" else "none"
    elif prompt_source_status == "unavailable":
        fill_status = "blocked"
        target_status = "available"
        block_reason = "prompt_text_missing"
        receipt_status = "blocked"
        receipt_kind = "blocked_fill_receipt"
    elif prompt_source_reason == "prompt_text_empty":
        fill_status = "blocked"
        target_status = "available"
        block_reason = "prompt_text_empty"
        receipt_status = "blocked"
        receipt_kind = "blocked_fill_receipt"
    elif prompt_source_status == "insufficient_truth":
        fill_status = "insufficient_truth"
        target_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif page is None:
        fill_status = "failed"
        target_status = "available"
        block_reason = "fill_failed"
        receipt_status = "failed"
        receipt_kind = "failed_fill_receipt"
    else:
        fill_attempted = True
        runtime_tokens.append("fill_attempted")
        fill_timeout_ms = _as_non_negative_int(
            dict(prior_browser_state or {}).get("project_browser_prompt_fill_timeout_ms"),
            default=2000,
        )
        if fill_timeout_ms <= 0 or fill_timeout_ms > 10000:
            fill_timeout_ms = 2000
        selector_candidates = _collect_project_browser_selector_candidates_for_target(
            target="chat_input",
            prior_browser_state=prior_browser_state,
        )
        if not selector_candidates:
            fill_status = "blocked"
            target_status = "missing"
            block_reason = "chat_input_missing"
            receipt_status = "blocked"
            receipt_kind = "blocked_fill_receipt"
        else:
            filled = False
            try:
                try:
                    page.set_default_timeout(fill_timeout_ms)
                except Exception:
                    pass
                for selector in selector_candidates:
                    try:
                        locator = page.locator(selector).first
                        if locator.count() <= 0:
                            continue
                        locator.fill(prompt_text, timeout=fill_timeout_ms)
                        filled = True
                        break
                    except Exception:
                        continue
            except Exception:
                filled = False
            if filled:
                fill_status = "filled"
                target_status = "available"
                block_reason = "none"
                receipt_status = "filled"
                receipt_kind = "prompt_fill_receipt"
            else:
                fill_status = "failed"
                target_status = "available"
                block_reason = "fill_failed"
                receipt_status = "failed"
                receipt_kind = "failed_fill_receipt"

    if fill_status not in _PROJECT_BROWSER_PROMPT_FILL_STATUSES:
        fill_status = "insufficient_truth"
    if prompt_source_status not in _PROJECT_BROWSER_PROMPT_FILL_SOURCE_STATUSES:
        prompt_source_status = "insufficient_truth"
    if target_status not in _PROJECT_BROWSER_PROMPT_FILL_TARGET_STATUSES:
        target_status = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_PROMPT_FILL_BLOCK_REASONS:
        block_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_PROMPT_FILL_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_PROMPT_FILL_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        token
        for token in runtime_tokens
        if token in _PROJECT_BROWSER_PROMPT_FILL_RUNTIME_POSTURES
    ]
    if not fill_attempted and "fill_attempted" in runtime_posture:
        runtime_posture = [token for token in runtime_posture if token != "fill_attempted"]

    return {
        "project_browser_prompt_fill_status": fill_status,
        "project_browser_prompt_fill_source_status": prompt_source_status,
        "project_browser_prompt_fill_target_status": target_status,
        "project_browser_prompt_fill_block_reason": block_reason,
        "project_browser_prompt_fill_runtime_posture": runtime_posture,
        "project_browser_prompt_fill_receipt_status": receipt_status,
        "project_browser_prompt_fill_receipt_kind": receipt_kind,
        "project_browser_prompt_fill_runtime_fill_attempted": bool(
            "fill_attempted" in runtime_posture
        ),
        "project_browser_prompt_fill_runtime_no_send_click": True,
        "project_browser_prompt_fill_runtime_no_enter_submit": True,
        "project_browser_prompt_fill_runtime_no_response_wait": True,
        "project_browser_prompt_fill_runtime_no_response_read": True,
        "project_browser_prompt_fill_runtime_no_json_parse": True,
        "project_browser_prompt_fill_runtime_no_retry_execution": True,
        "project_browser_prompt_fill_runtime_no_reload_execution": True,
        "project_browser_prompt_fill_runtime_no_new_chat_execution": True,
        "project_browser_prompt_fill_runtime_no_login_recovery": True,
        "project_browser_prompt_fill_runtime_no_executor_loop": True,
    }


def _build_project_browser_prompt_send_state(
    *,
    browser_command_type: str,
    browser_launch_status: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_dom_readiness_status: str,
    browser_prompt_fill_status: str,
    browser_send_trigger_target_status: str,
    prior_browser_state: Mapping[str, Any] | None,
    page: Any | None,
) -> dict[str, Any]:
    command_type = _normalize_text(browser_command_type, default="none")
    launch_status = _normalize_text(browser_launch_status, default="insufficient_truth")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    dom_status = _normalize_text(browser_dom_readiness_status, default="insufficient_truth")
    fill_status = _normalize_text(browser_prompt_fill_status, default="insufficient_truth")
    send_target_status = _normalize_text(
        browser_send_trigger_target_status,
        default="insufficient_truth",
    )

    send_status = "insufficient_truth"
    target_status = "insufficient_truth"
    block_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    send_attempted = False
    runtime_tokens = [
        "no_response_wait",
        "no_response_read",
        "no_json_parse",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_executor_loop",
    ]

    if fill_status == "inactive":
        send_status = "inactive"
        target_status = "missing"
        block_reason = "fill_not_ready"
        receipt_status = "not_created"
    elif fill_status == "not_attempted":
        send_status = "not_attempted"
        target_status = "blocked"
        block_reason = "fill_not_ready"
        receipt_status = "not_created"
    elif fill_status == "failed":
        send_status = "failed"
        target_status = "blocked"
        block_reason = "send_failed"
        receipt_status = "failed"
        receipt_kind = "failed_send_receipt"
    elif fill_status in {"blocked"}:
        send_status = "blocked"
        target_status = "blocked"
        block_reason = "fill_not_ready"
        receipt_status = "blocked"
        receipt_kind = "blocked_send_receipt"
    elif fill_status == "insufficient_truth":
        send_status = "insufficient_truth"
        target_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif (
        launch_status == "inactive"
        or page_status == "inactive"
        or dom_status == "inactive"
    ):
        send_status = "inactive"
        target_status = "missing"
        block_reason = "fill_not_ready"
        receipt_status = "not_created"
    elif (
        launch_status in {"blocked", "not_attempted", "failed"}
        or page_status in {"blocked", "not_attempted", "unavailable", "failed"}
        or dom_status in {"blocked", "not_attempted", "not_ready", "failed"}
    ):
        send_status = "blocked"
        target_status = "blocked"
        block_reason = "fill_not_ready"
        receipt_status = "blocked"
        receipt_kind = "blocked_send_receipt"
    elif (
        launch_status == "insufficient_truth"
        or page_status == "insufficient_truth"
        or dom_status == "insufficient_truth"
    ):
        send_status = "insufficient_truth"
        target_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif login_status == "detected" or page_status == "login_interruption":
        send_status = "blocked"
        target_status = "blocked"
        block_reason = "login_interruption"
        receipt_status = "blocked"
        receipt_kind = "blocked_send_receipt"
    elif command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
        send_status = "blocked"
        target_status = "blocked"
        block_reason = "unsupported_command_type"
        receipt_status = "blocked"
        receipt_kind = "blocked_send_receipt"
    elif send_target_status != "found":
        send_status = "blocked"
        target_status = (
            "insufficient_truth"
            if send_target_status == "insufficient_truth"
            else "missing"
        )
        block_reason = (
            "insufficient_truth"
            if send_target_status == "insufficient_truth"
            else "send_trigger_missing"
        )
        receipt_status = "blocked" if block_reason != "insufficient_truth" else "insufficient_truth"
        receipt_kind = "blocked_send_receipt" if receipt_status == "blocked" else "none"
    elif page is None:
        send_status = "failed"
        target_status = "available"
        block_reason = "send_failed"
        receipt_status = "failed"
        receipt_kind = "failed_send_receipt"
    else:
        send_attempted = True
        runtime_tokens.append("send_click_attempted")
        click_timeout_ms = _as_non_negative_int(
            dict(prior_browser_state or {}).get("project_browser_prompt_send_timeout_ms"),
            default=2000,
        )
        if click_timeout_ms <= 0 or click_timeout_ms > 10000:
            click_timeout_ms = 2000
        selector_candidates = _collect_project_browser_selector_candidates_for_target(
            target="send_trigger",
            prior_browser_state=prior_browser_state,
        )
        if not selector_candidates:
            send_status = "blocked"
            target_status = "missing"
            block_reason = "send_trigger_missing"
            receipt_status = "blocked"
            receipt_kind = "blocked_send_receipt"
        else:
            sent = False
            try:
                try:
                    page.set_default_timeout(click_timeout_ms)
                except Exception:
                    pass
                for selector in selector_candidates:
                    try:
                        locator = page.locator(selector).first
                        if locator.count() <= 0:
                            continue
                        locator.click(timeout=click_timeout_ms)
                        sent = True
                        break
                    except Exception:
                        continue
            except Exception:
                sent = False
            if sent:
                send_status = "sent"
                target_status = "available"
                block_reason = "none"
                receipt_status = "sent"
                receipt_kind = "prompt_send_receipt"
            else:
                send_status = "failed"
                target_status = "available"
                block_reason = "send_failed"
                receipt_status = "failed"
                receipt_kind = "failed_send_receipt"

    if send_status not in _PROJECT_BROWSER_PROMPT_SEND_STATUSES:
        send_status = "insufficient_truth"
    if target_status not in _PROJECT_BROWSER_PROMPT_SEND_TARGET_STATUSES:
        target_status = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_PROMPT_SEND_BLOCK_REASONS:
        block_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_PROMPT_SEND_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_PROMPT_SEND_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        token
        for token in runtime_tokens
        if token in _PROJECT_BROWSER_PROMPT_SEND_RUNTIME_POSTURES
    ]
    if not send_attempted and "send_click_attempted" in runtime_posture:
        runtime_posture = [
            token for token in runtime_posture if token != "send_click_attempted"
        ]

    return {
        "project_browser_prompt_send_status": send_status,
        "project_browser_prompt_send_target_status": target_status,
        "project_browser_prompt_send_block_reason": block_reason,
        "project_browser_prompt_send_runtime_posture": runtime_posture,
        "project_browser_prompt_send_receipt_status": receipt_status,
        "project_browser_prompt_send_receipt_kind": receipt_kind,
        "project_browser_prompt_send_runtime_send_click_attempted": bool(
            "send_click_attempted" in runtime_posture
        ),
        "project_browser_prompt_send_runtime_no_response_wait": True,
        "project_browser_prompt_send_runtime_no_response_read": True,
        "project_browser_prompt_send_runtime_no_json_parse": True,
        "project_browser_prompt_send_runtime_no_retry_execution": True,
        "project_browser_prompt_send_runtime_no_reload_execution": True,
        "project_browser_prompt_send_runtime_no_new_chat_execution": True,
        "project_browser_prompt_send_runtime_no_login_recovery": True,
        "project_browser_prompt_send_runtime_no_executor_loop": True,
    }


def _build_project_browser_response_wait_read_state(
    *,
    browser_command_type: str,
    browser_launch_status: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_prompt_send_status: str,
    browser_latest_assistant_response_target_status: str,
    browser_message_ready_target_status: str,
    browser_loading_state_target_status: str,
    prior_browser_state: Mapping[str, Any] | None,
    page: Any | None,
) -> dict[str, Any]:
    command_type = _normalize_text(browser_command_type, default="none")
    launch_status = _normalize_text(browser_launch_status, default="insufficient_truth")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    prompt_send_status = _normalize_text(
        browser_prompt_send_status,
        default="insufficient_truth",
    )
    latest_target_status = _normalize_text(
        browser_latest_assistant_response_target_status,
        default="insufficient_truth",
    )
    message_ready_target_status = _normalize_text(
        browser_message_ready_target_status,
        default="insufficient_truth",
    )
    _ = _normalize_text(browser_loading_state_target_status, default="insufficient_truth")

    wait_status = "insufficient_truth"
    read_status = "insufficient_truth"
    text_status = "insufficient_truth"
    block_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    response_text = ""
    response_text_length = 0
    response_text_truncated = False
    wait_attempted = False
    read_attempted = False
    runtime_tokens = [
        "no_json_parse",
        "no_decision_execution",
        "no_retry_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_executor_loop",
    ]

    if prompt_send_status == "inactive":
        wait_status = "inactive"
        read_status = "inactive"
        text_status = "unavailable"
        block_reason = "send_not_ready"
        receipt_status = "not_created"
    elif prompt_send_status == "not_attempted":
        wait_status = "not_attempted"
        read_status = "not_attempted"
        text_status = "unavailable"
        block_reason = "send_not_ready"
        receipt_status = "not_created"
    elif prompt_send_status in {"blocked"}:
        wait_status = "blocked"
        read_status = "blocked"
        text_status = "unavailable"
        block_reason = "send_not_ready"
        receipt_status = "blocked"
        receipt_kind = "blocked_response_receipt"
    elif prompt_send_status in {"failed"}:
        wait_status = "failed"
        read_status = "failed"
        text_status = "unavailable"
        block_reason = "page_unavailable"
        receipt_status = "failed"
        receipt_kind = "failed_response_receipt"
    elif prompt_send_status == "insufficient_truth":
        wait_status = "insufficient_truth"
        read_status = "insufficient_truth"
        text_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif (
        launch_status in {"inactive"}
        or page_status in {"inactive"}
    ):
        wait_status = "inactive"
        read_status = "inactive"
        text_status = "unavailable"
        block_reason = "send_not_ready"
        receipt_status = "not_created"
    elif (
        launch_status in {"blocked", "not_attempted", "failed"}
        or page_status in {"blocked", "not_attempted", "unavailable", "failed"}
    ):
        wait_status = "blocked"
        read_status = "blocked"
        text_status = "unavailable"
        block_reason = "page_unavailable"
        receipt_status = "blocked"
        receipt_kind = "blocked_response_receipt"
    elif launch_status == "insufficient_truth" or page_status == "insufficient_truth":
        wait_status = "insufficient_truth"
        read_status = "insufficient_truth"
        text_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif login_status == "detected" or page_status == "login_interruption":
        wait_status = "blocked"
        read_status = "blocked"
        text_status = "unavailable"
        block_reason = "login_interruption"
        receipt_status = "blocked"
        receipt_kind = "blocked_response_receipt"
    elif command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
        wait_status = "blocked"
        read_status = "blocked"
        text_status = "unavailable"
        block_reason = "unsupported_command_type"
        receipt_status = "blocked"
        receipt_kind = "blocked_response_receipt"
    elif (
        latest_target_status == "insufficient_truth"
        and message_ready_target_status == "insufficient_truth"
    ):
        wait_status = "insufficient_truth"
        read_status = "insufficient_truth"
        text_status = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif (
        latest_target_status == "missing"
        and message_ready_target_status == "missing"
    ):
        wait_status = "blocked"
        read_status = "blocked"
        text_status = "unavailable"
        block_reason = "assistant_response_missing"
        receipt_status = "blocked"
        receipt_kind = "blocked_response_receipt"
    elif page is None:
        wait_status = "failed"
        read_status = "failed"
        text_status = "unavailable"
        block_reason = "page_unavailable"
        receipt_status = "failed"
        receipt_kind = "failed_response_receipt"
    else:
        wait_attempted = True
        runtime_tokens.append("response_wait_attempted")
        read_attempted = True
        runtime_tokens.append("response_read_attempted")
        wait_timeout_ms = _as_non_negative_int(
            dict(prior_browser_state or {}).get("project_browser_response_wait_timeout_ms"),
            default=25000,
        )
        if wait_timeout_ms <= 0 or wait_timeout_ms > 120000:
            wait_timeout_ms = 25000
        text_max_chars = _as_non_negative_int(
            dict(prior_browser_state or {}).get("project_browser_response_text_max_chars"),
            default=4000,
        )
        if text_max_chars < 128 or text_max_chars > 12000:
            text_max_chars = 4000

        latest_candidates = _collect_project_browser_selector_candidates_for_target(
            target="latest_assistant_response",
            prior_browser_state=prior_browser_state,
        )
        message_ready_candidates = _collect_project_browser_selector_candidates_for_target(
            target="message_ready",
            prior_browser_state=prior_browser_state,
        )

        ready = False
        try:
            try:
                page.set_default_timeout(wait_timeout_ms)
            except Exception:
                pass
            for selector in message_ready_candidates:
                try:
                    locator = page.locator(selector).first
                    if locator.count() <= 0:
                        continue
                    locator.wait_for(state="visible", timeout=wait_timeout_ms)
                    ready = True
                    break
                except Exception:
                    continue
            if not ready:
                for selector in latest_candidates:
                    try:
                        locator = page.locator(selector).last
                        if locator.count() <= 0:
                            continue
                        locator.wait_for(state="visible", timeout=wait_timeout_ms)
                        ready = True
                        break
                    except Exception:
                        continue
        except Exception:
            ready = False

        if not ready:
            wait_status = "timeout"
            read_status = "not_attempted"
            text_status = "unavailable"
            block_reason = "response_timeout"
            receipt_status = "timeout"
            receipt_kind = "timeout_receipt"
        else:
            read_text = ""
            has_response_element = False
            try:
                for selector in latest_candidates:
                    try:
                        locator = page.locator(selector).last
                        if locator.count() <= 0:
                            continue
                        has_response_element = True
                        candidate_text = _normalize_text(
                            locator.inner_text(timeout=min(wait_timeout_ms, 3000)),
                            default="",
                        )
                        if candidate_text:
                            read_text = candidate_text
                            break
                    except Exception:
                        continue
            except Exception:
                has_response_element = False
                read_text = ""

            if not has_response_element:
                wait_status = "blocked"
                read_status = "blocked"
                text_status = "unavailable"
                block_reason = "assistant_response_missing"
                receipt_status = "blocked"
                receipt_kind = "blocked_response_receipt"
            elif not read_text:
                wait_status = "completed"
                read_status = "empty"
                text_status = "empty"
                block_reason = "response_empty"
                receipt_status = "response_read"
                receipt_kind = "response_wait_read_receipt"
            else:
                wait_status = "completed"
                read_status = "read"
                block_reason = "none"
                receipt_status = "response_read"
                receipt_kind = "response_wait_read_receipt"
                if len(read_text) > text_max_chars:
                    response_text = read_text[:text_max_chars]
                    response_text_length = len(read_text)
                    response_text_truncated = True
                    text_status = "too_large"
                else:
                    response_text = read_text
                    response_text_length = len(read_text)
                    response_text_truncated = False
                    text_status = "available"

    if wait_status not in _PROJECT_BROWSER_RESPONSE_WAIT_STATUSES:
        wait_status = "insufficient_truth"
    if read_status not in _PROJECT_BROWSER_RESPONSE_READ_STATUSES:
        read_status = "insufficient_truth"
    if text_status not in _PROJECT_BROWSER_RESPONSE_TEXT_STATUSES:
        text_status = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_RESPONSE_WAIT_BLOCK_REASONS:
        block_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_RESPONSE_READ_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_RESPONSE_READ_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        token
        for token in runtime_tokens
        if token in _PROJECT_BROWSER_RESPONSE_RUNTIME_POSTURES
    ]
    if not wait_attempted and "response_wait_attempted" in runtime_posture:
        runtime_posture = [
            token for token in runtime_posture if token != "response_wait_attempted"
        ]
    if not read_attempted and "response_read_attempted" in runtime_posture:
        runtime_posture = [
            token for token in runtime_posture if token != "response_read_attempted"
        ]

    return {
        "project_browser_response_wait_status": wait_status,
        "project_browser_response_read_status": read_status,
        "project_browser_response_text_status": text_status,
        "project_browser_response_wait_block_reason": block_reason,
        "project_browser_response_runtime_posture": runtime_posture,
        "project_browser_response_read_receipt_status": receipt_status,
        "project_browser_response_read_receipt_kind": receipt_kind,
        "project_browser_response_text": response_text,
        "project_browser_response_text_length": response_text_length,
        "project_browser_response_text_truncated": bool(response_text_truncated),
        "project_browser_response_runtime_response_wait_attempted": bool(
            "response_wait_attempted" in runtime_posture
        ),
        "project_browser_response_runtime_response_read_attempted": bool(
            "response_read_attempted" in runtime_posture
        ),
        "project_browser_response_runtime_no_json_parse": True,
        "project_browser_response_runtime_no_decision_execution": True,
        "project_browser_response_runtime_no_retry_execution": True,
        "project_browser_response_runtime_no_reload_execution": True,
        "project_browser_response_runtime_no_new_chat_execution": True,
        "project_browser_response_runtime_no_login_recovery": True,
        "project_browser_response_runtime_no_executor_loop": True,
    }


def _build_project_browser_response_parse_state(
    *,
    browser_command_type: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_response_wait_status: str,
    browser_response_read_status: str,
    browser_response_text_status: str,
    browser_response_text: str,
    browser_response_text_truncated: bool,
    browser_prompt_schema_required_json_ref: str,
) -> dict[str, Any]:
    command_type = _normalize_text(browser_command_type, default="none")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    wait_status = _normalize_text(browser_response_wait_status, default="insufficient_truth")
    read_status = _normalize_text(browser_response_read_status, default="insufficient_truth")
    text_status = _normalize_text(browser_response_text_status, default="insufficient_truth")
    response_text = _normalize_text(browser_response_text, default="")
    schema_ref = _normalize_text(browser_prompt_schema_required_json_ref, default="")

    parse_status = "insufficient_truth"
    schema_status = "insufficient_truth"
    decision_status = "insufficient_truth"
    execution_receipt_status = "insufficient_truth"
    execution_receipt_kind = "none"
    execution_result_status = "insufficient_truth"
    block_reason = "insufficient_truth"
    parse_attempted = False
    parsed_compact: dict[str, Any] = {}

    runtime_tokens = [
        "no_decision_execution",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_reload_execution",
        "no_new_chat_execution",
        "no_login_recovery",
        "no_executor_loop",
    ]

    if wait_status == "inactive" or read_status == "inactive":
        parse_status = "inactive"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "not_created"
        execution_result_status = "not_executed"
        block_reason = "response_not_read"
    elif wait_status == "not_attempted" or read_status == "not_attempted":
        parse_status = "not_attempted"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "not_created"
        execution_result_status = "not_executed"
        block_reason = "response_not_read"
    elif wait_status in {"blocked"} or read_status in {"blocked"}:
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_not_read"
    elif wait_status in {"failed"} or read_status in {"failed"}:
        parse_status = "failed"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "failed"
        execution_receipt_kind = "failed_parse_receipt"
        execution_result_status = "failed"
        block_reason = "response_not_read"
    elif wait_status in {"insufficient_truth"} or read_status in {"insufficient_truth"}:
        parse_status = "insufficient_truth"
        schema_status = "insufficient_truth"
        decision_status = "insufficient_truth"
        execution_receipt_status = "insufficient_truth"
        execution_result_status = "insufficient_truth"
        block_reason = "insufficient_truth"
    elif login_status == "detected" or page_status == "login_interruption":
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "login_interruption"
    elif command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "unsupported_command_type"
    elif text_status == "unavailable":
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_text_missing"
    elif text_status == "empty":
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_text_empty"
    elif text_status == "too_large" or bool(browser_response_text_truncated):
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_text_too_large"
    elif text_status == "insufficient_truth":
        parse_status = "insufficient_truth"
        schema_status = "insufficient_truth"
        decision_status = "insufficient_truth"
        execution_receipt_status = "insufficient_truth"
        execution_result_status = "insufficient_truth"
        block_reason = "insufficient_truth"
    elif read_status != "read":
        parse_status = "unavailable"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_not_read"
    elif not response_text:
        parse_status = "blocked"
        schema_status = "not_checked"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "response_text_empty"
    elif not schema_ref:
        parse_status = "blocked"
        schema_status = "missing"
        decision_status = "unavailable"
        execution_receipt_status = "blocked"
        execution_receipt_kind = "blocked_parse_receipt"
        execution_result_status = "blocked"
        block_reason = "schema_missing"
    else:
        parse_attempted = True
        runtime_tokens.append("json_parse_attempted")
        try:
            parsed_raw = json.loads(response_text)
        except Exception:
            parse_status = "invalid_response"
            schema_status = "not_checked"
            decision_status = "invalid"
            execution_receipt_status = "invalid_response"
            execution_receipt_kind = "invalid_response_receipt"
            execution_result_status = "invalid_response"
            block_reason = "json_parse_failed"
        else:
            if not isinstance(parsed_raw, Mapping):
                parse_status = "invalid_response"
                schema_status = "invalid"
                decision_status = "invalid"
                execution_receipt_status = "invalid_response"
                execution_receipt_kind = "invalid_response_receipt"
                execution_result_status = "invalid_response"
                block_reason = "schema_invalid"
            else:
                parsed = dict(parsed_raw)
                missing_fields = [
                    field
                    for field in _PROJECT_BROWSER_JSON_REQUIRED_FIELDS
                    if field not in parsed
                ]
                if missing_fields:
                    parse_status = "invalid_response"
                    schema_status = "missing"
                    decision_status = (
                        "missing" if "decision" in missing_fields else "invalid"
                    )
                    execution_receipt_status = "invalid_response"
                    execution_receipt_kind = "invalid_response_receipt"
                    execution_result_status = "invalid_response"
                    block_reason = (
                        "decision_missing" if "decision" in missing_fields else "schema_missing"
                    )
                else:
                    task_type = _normalize_text(parsed.get("task_type"), default="none")
                    decision = _normalize_text(parsed.get("decision"), default="")
                    risk_level = _normalize_text(parsed.get("risk_level"), default="")
                    success_score = _as_non_negative_int(parsed.get("success_score"), default=-1)
                    confidence_score = _as_non_negative_int(
                        parsed.get("confidence_score"),
                        default=-1,
                    )
                    schema_invalid = any(
                        (
                            task_type not in _PROJECT_BROWSER_TASK_TYPES
                            or task_type == "none",
                            decision not in _PROJECT_BROWSER_DECISIONS,
                            risk_level not in _PROJECT_BROWSER_RISK_LEVELS,
                            success_score < 0
                            or confidence_score < 0
                            or success_score > 100
                            or confidence_score > 100,
                            not _normalize_text(parsed.get("objective_id"), default=""),
                            not _normalize_text(parsed.get("step_id"), default=""),
                        )
                    )
                    if schema_invalid:
                        parse_status = "invalid_response"
                        schema_status = "invalid"
                        decision_status = (
                            "missing"
                            if not decision
                            else ("invalid" if decision not in _PROJECT_BROWSER_DECISIONS else "invalid")
                        )
                        execution_receipt_status = "invalid_response"
                        execution_receipt_kind = "invalid_response_receipt"
                        execution_result_status = "invalid_response"
                        block_reason = (
                            "decision_missing"
                            if not decision
                            else "schema_invalid"
                        )
                    else:
                        parse_status = "valid"
                        schema_status = "valid"
                        decision_status = "parsed"
                        execution_receipt_status = "parsed"
                        execution_receipt_kind = "browser_response_parse_receipt"
                        execution_result_status = "response_parsed"
                        block_reason = "none"
                        parsed_compact = {
                            "task_type": task_type,
                            "objective_id": _normalize_text(parsed.get("objective_id"), default=""),
                            "step_id": _normalize_text(parsed.get("step_id"), default=""),
                            "decision": decision,
                            "risk_level": risk_level,
                            "success_score": success_score,
                            "confidence_score": confidence_score,
                        }

    if parse_status not in _PROJECT_BROWSER_RESPONSE_JSON_PARSE_STATUSES:
        parse_status = "insufficient_truth"
    if schema_status not in _PROJECT_BROWSER_RESPONSE_JSON_SCHEMA_STATUSES:
        schema_status = "insufficient_truth"
    if decision_status not in _PROJECT_BROWSER_RESPONSE_JSON_DECISION_STATUSES:
        decision_status = "insufficient_truth"
    if execution_receipt_status not in _PROJECT_BROWSER_EXECUTION_RECEIPT_PARSE_STATUSES:
        execution_receipt_status = "insufficient_truth"
    if execution_receipt_kind not in _PROJECT_BROWSER_EXECUTION_RECEIPT_PARSE_KINDS:
        execution_receipt_kind = "none"
    if execution_result_status not in _PROJECT_BROWSER_EXECUTION_RESULT_STATUSES:
        execution_result_status = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_RESPONSE_PARSE_BLOCK_REASONS:
        block_reason = "insufficient_truth"

    runtime_posture = [
        token
        for token in runtime_tokens
        if token in _PROJECT_BROWSER_RESPONSE_PARSE_RUNTIME_POSTURES
    ]
    if not parse_attempted and "json_parse_attempted" in runtime_posture:
        runtime_posture = [
            token for token in runtime_posture if token != "json_parse_attempted"
        ]

    return {
        "project_browser_response_json_parse_status": parse_status,
        "project_browser_response_json_schema_status": schema_status,
        "project_browser_response_json_decision_status": decision_status,
        "project_browser_execution_receipt_status": execution_receipt_status,
        "project_browser_execution_receipt_kind": execution_receipt_kind,
        "project_browser_execution_result_status": execution_result_status,
        "project_browser_response_parse_block_reason": block_reason,
        "project_browser_response_parse_runtime_posture": runtime_posture,
        "project_browser_response_json_parse_compact": parsed_compact,
        "project_browser_response_parse_runtime_json_parse_attempted": bool(
            "json_parse_attempted" in runtime_posture
        ),
        "project_browser_response_parse_runtime_no_decision_execution": True,
        "project_browser_response_parse_runtime_no_queue_mutation": True,
        "project_browser_response_parse_runtime_no_retry_execution": True,
        "project_browser_response_parse_runtime_no_repair_execution": True,
        "project_browser_response_parse_runtime_no_restart_execution": True,
        "project_browser_response_parse_runtime_no_reload_execution": True,
        "project_browser_response_parse_runtime_no_new_chat_execution": True,
        "project_browser_response_parse_runtime_no_login_recovery": True,
        "project_browser_response_parse_runtime_no_executor_loop": True,
    }


def _build_project_browser_recovery_runtime_state(
    *,
    browser_command_type: str,
    browser_chatgpt_page_status: str,
    browser_login_interruption_status: str,
    browser_response_wait_status: str,
    browser_response_wait_block_reason: str,
    browser_response_json_parse_status: str,
    browser_execution_receipt_status: str,
    browser_response_parse_block_reason: str,
    browser_ui_recovery_decision_status: str,
    browser_recovery_candidate: str,
    browser_recovery_reason: str,
    browser_retry_count_posture: str,
    browser_handoff_dependency_posture: str,
    browser_handoff_compile_status: str,
    browser_handoff_payload_posture: str,
    prior_browser_state: Mapping[str, Any] | None,
    page: Any | None,
) -> dict[str, Any]:
    command_type = _normalize_text(browser_command_type, default="none")
    page_status = _normalize_text(browser_chatgpt_page_status, default="insufficient_truth")
    login_status = _normalize_text(
        browser_login_interruption_status,
        default="insufficient_truth",
    )
    response_wait_status = _normalize_text(
        browser_response_wait_status,
        default="insufficient_truth",
    )
    response_wait_block_reason = _normalize_text(
        browser_response_wait_block_reason,
        default="insufficient_truth",
    )
    parse_status = _normalize_text(
        browser_response_json_parse_status,
        default="insufficient_truth",
    )
    execution_receipt_status = _normalize_text(
        browser_execution_receipt_status,
        default="insufficient_truth",
    )
    parse_block_reason = _normalize_text(
        browser_response_parse_block_reason,
        default="insufficient_truth",
    )
    ui_recovery_decision_status = _normalize_text(
        browser_ui_recovery_decision_status,
        default="insufficient_truth",
    )
    recovery_candidate = _normalize_text(browser_recovery_candidate, default="none")
    recovery_reason = _normalize_text(
        browser_recovery_reason,
        default="insufficient_truth",
    )
    retry_count_posture = _normalize_text(
        browser_retry_count_posture,
        default="insufficient_truth",
    )
    handoff_dependency_posture = _normalize_text(
        browser_handoff_dependency_posture,
        default="insufficient_truth",
    )
    handoff_compile_status = _normalize_text(
        browser_handoff_compile_status,
        default="insufficient_truth",
    )
    handoff_payload_posture = _normalize_text(
        browser_handoff_payload_posture,
        default="insufficient_truth",
    )

    status = "insufficient_truth"
    action = "none"
    reason = "insufficient_truth"
    block_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"
    recovery_attempted = False
    runtime_tokens = [
        "no_prompt_refill",
        "no_resend",
        "no_response_wait",
        "no_response_read",
        "no_json_parse",
        "no_decision_execution",
        "no_queue_mutation",
        "no_retry_loop",
        "no_login_recovery",
        "no_executor_loop",
    ]

    if parse_status == "inactive" or execution_receipt_status == "not_created":
        status = "inactive"
        reason = "none"
        block_reason = "execution_receipt_missing"
        receipt_status = "not_created"
    elif parse_status == "failed" or execution_receipt_status == "failed":
        status = "failed"
        reason = "unsupported_outcome"
        block_reason = "parse_not_ready"
        receipt_status = "failed"
        receipt_kind = "failed_recovery_receipt"
    elif parse_status == "blocked" or execution_receipt_status == "blocked":
        status = "blocked"
        reason = "unsupported_outcome"
        block_reason = "parse_not_ready"
        receipt_status = "blocked"
        receipt_kind = "blocked_recovery_receipt"
    elif (
        parse_status == "insufficient_truth"
        or execution_receipt_status == "insufficient_truth"
        or ui_recovery_decision_status == "insufficient_truth"
        or retry_count_posture == "insufficient_truth"
    ):
        status = "insufficient_truth"
        reason = "insufficient_truth"
        block_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif (
        login_status == "detected"
        or page_status == "login_interruption"
        or recovery_reason == "login_interruption"
    ):
        status = "pause_required"
        action = "pause_for_login"
        reason = "login_interruption"
        block_reason = "login_interruption"
        receipt_status = "pause_required"
        receipt_kind = "pause_for_login_receipt"
    elif retry_count_posture == "retry_limit_reached":
        status = "blocked"
        action = "escalate"
        reason = "retry_limit_reached"
        block_reason = "retry_limit_reached"
        receipt_status = "blocked"
        receipt_kind = "blocked_recovery_receipt"
    elif parse_status == "valid" and execution_receipt_status == "parsed":
        status = "not_attempted"
        reason = "none"
        block_reason = "recovery_not_required"
        receipt_status = "not_created"
    else:
        if command_type not in _PROJECT_BROWSER_COMMAND_TYPES - {"none"}:
            status = "blocked"
            reason = "unsupported_outcome"
            block_reason = "recovery_not_allowed"
            receipt_status = "blocked"
            receipt_kind = "blocked_recovery_receipt"
        else:
            handoff_ready = bool(
                handoff_dependency_posture == "required_available"
                and handoff_compile_status == "ready"
                and handoff_payload_posture == "compact_ready"
            )
            handoff_missing = bool(
                handoff_dependency_posture == "required_missing"
                or handoff_compile_status in {"unavailable", "insufficient_truth"}
                or handoff_payload_posture
                in {"missing_required_sections", "unavailable", "insufficient_truth"}
            )
            wants_new_chat = bool(
                recovery_candidate == "new_chat_handoff"
                or recovery_reason == "rotation_due"
            )
            reload_outcome = _normalize_text(recovery_reason, default="")
            if reload_outcome not in {
                "response_timeout",
                "page_unavailable",
                "loading_timeout",
                "response_unavailable",
                "invalid_response",
            }:
                if response_wait_block_reason == "response_timeout":
                    reload_outcome = "response_timeout"
                elif response_wait_block_reason == "page_unavailable":
                    reload_outcome = "page_unavailable"
                elif parse_status == "invalid_response" or parse_block_reason in {
                    "json_parse_failed",
                    "schema_missing",
                    "schema_invalid",
                    "decision_missing",
                }:
                    reload_outcome = "invalid_response"
                elif parse_status in {"unavailable", "not_attempted"}:
                    reload_outcome = "response_unavailable"
            safe_reload_requested = bool(
                recovery_candidate == "page_reload"
                or (
                    reload_outcome in {"response_timeout", "page_unavailable", "loading_timeout"}
                    and recovery_reason == "loading_timeout"
                )
            )
            if wants_new_chat:
                if handoff_missing:
                    status = "blocked"
                    reason = "handoff_missing"
                    block_reason = "handoff_missing"
                    receipt_status = "blocked"
                    receipt_kind = "blocked_recovery_receipt"
                elif not handoff_ready:
                    status = "insufficient_truth"
                    reason = "insufficient_truth"
                    block_reason = "insufficient_truth"
                    receipt_status = "insufficient_truth"
                elif page is None:
                    status = "failed"
                    action = "new_chat"
                    reason = "rotation_due"
                    block_reason = "new_chat_failed"
                    receipt_status = "failed"
                    receipt_kind = "failed_recovery_receipt"
                else:
                    recovery_attempted = True
                    runtime_tokens.append("recovery_attempted")
                    timeout_ms = _as_non_negative_int(
                        dict(prior_browser_state or {}).get(
                            "project_browser_recovery_new_chat_timeout_ms"
                        ),
                        default=2000,
                    )
                    if timeout_ms <= 0 or timeout_ms > 10000:
                        timeout_ms = 2000
                    candidates = _collect_project_browser_selector_candidates_for_target(
                        target="new_chat_trigger",
                        prior_browser_state=prior_browser_state,
                    )
                    clicked = False
                    try:
                        try:
                            page.set_default_timeout(timeout_ms)
                        except Exception:
                            pass
                        for selector in candidates:
                            try:
                                locator = page.locator(selector).first
                                if locator.count() <= 0:
                                    continue
                                locator.click(timeout=timeout_ms)
                                clicked = True
                                break
                            except Exception:
                                continue
                    except Exception:
                        clicked = False
                    if clicked:
                        status = "recovered"
                        action = "new_chat"
                        reason = "rotation_due"
                        block_reason = "none"
                        receipt_status = "recovered"
                        receipt_kind = "new_chat_recovery_receipt"
                    else:
                        status = "failed"
                        action = "new_chat"
                        reason = "rotation_due"
                        block_reason = "new_chat_failed"
                        receipt_status = "failed"
                        receipt_kind = "failed_recovery_receipt"
            elif safe_reload_requested:
                if page is None:
                    status = "failed"
                    action = "page_reload"
                    reason = (
                        reload_outcome
                        if reload_outcome in _PROJECT_BROWSER_RECOVERY_REASONS
                        else "unsupported_outcome"
                    )
                    block_reason = "page_reload_failed"
                    receipt_status = "failed"
                    receipt_kind = "failed_recovery_receipt"
                else:
                    recovery_attempted = True
                    runtime_tokens.append("recovery_attempted")
                    timeout_ms = _as_non_negative_int(
                        dict(prior_browser_state or {}).get(
                            "project_browser_recovery_page_reload_timeout_ms"
                        ),
                        default=2500,
                    )
                    if timeout_ms <= 0 or timeout_ms > 12000:
                        timeout_ms = 2500
                    reloaded = False
                    try:
                        page.reload(
                            wait_until="domcontentloaded",
                            timeout=timeout_ms,
                        )
                        reloaded = True
                    except Exception:
                        reloaded = False
                    if reloaded:
                        status = "recovered"
                        action = "page_reload"
                        reason = (
                            reload_outcome
                            if reload_outcome in _PROJECT_BROWSER_RECOVERY_REASONS
                            else "unsupported_outcome"
                        )
                        block_reason = "none"
                        receipt_status = "recovered"
                        receipt_kind = "page_reload_recovery_receipt"
                    else:
                        status = "failed"
                        action = "page_reload"
                        reason = (
                            reload_outcome
                            if reload_outcome in _PROJECT_BROWSER_RECOVERY_REASONS
                            else "unsupported_outcome"
                        )
                        block_reason = "page_reload_failed"
                        receipt_status = "failed"
                        receipt_kind = "failed_recovery_receipt"
            elif handoff_missing and recovery_reason == "rotation_due":
                status = "blocked"
                reason = "handoff_missing"
                block_reason = "handoff_missing"
                receipt_status = "blocked"
                receipt_kind = "blocked_recovery_receipt"
            elif parse_status in {"invalid_response", "unavailable"}:
                status = "blocked"
                action = "escalate"
                reason = (
                    "invalid_response" if parse_status == "invalid_response" else "response_unavailable"
                )
                block_reason = "recovery_not_allowed"
                receipt_status = "blocked"
                receipt_kind = "blocked_recovery_receipt"
            else:
                status = "blocked"
                action = "escalate"
                reason = "unsupported_outcome"
                block_reason = "recovery_not_allowed"
                receipt_status = "blocked"
                receipt_kind = "blocked_recovery_receipt"

    if status not in _PROJECT_BROWSER_RECOVERY_STATUSES:
        status = "insufficient_truth"
    if action not in _PROJECT_BROWSER_RECOVERY_ACTIONS:
        action = "none"
    if reason not in _PROJECT_BROWSER_RECOVERY_REASONS:
        reason = "insufficient_truth"
    if block_reason not in _PROJECT_BROWSER_RECOVERY_BLOCK_REASONS:
        block_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_RECOVERY_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_RECOVERY_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        token
        for token in runtime_tokens
        if token in _PROJECT_BROWSER_RECOVERY_RUNTIME_POSTURES
    ]
    if not recovery_attempted and "recovery_attempted" in runtime_posture:
        runtime_posture = [
            token for token in runtime_posture if token != "recovery_attempted"
        ]

    return {
        "project_browser_recovery_status": status,
        "project_browser_recovery_action": action,
        "project_browser_recovery_reason": reason,
        "project_browser_recovery_block_reason": block_reason,
        "project_browser_recovery_runtime_posture": runtime_posture,
        "project_browser_recovery_receipt_status": receipt_status,
        "project_browser_recovery_receipt_kind": receipt_kind,
        "project_browser_recovery_runtime_recovery_attempted": bool(
            "recovery_attempted" in runtime_posture
        ),
        "project_browser_recovery_runtime_no_prompt_refill": True,
        "project_browser_recovery_runtime_no_resend": True,
        "project_browser_recovery_runtime_no_response_wait": True,
        "project_browser_recovery_runtime_no_response_read": True,
        "project_browser_recovery_runtime_no_json_parse": True,
        "project_browser_recovery_runtime_no_decision_execution": True,
        "project_browser_recovery_runtime_no_queue_mutation": True,
        "project_browser_recovery_runtime_no_retry_loop": True,
        "project_browser_recovery_runtime_no_login_recovery": True,
        "project_browser_recovery_runtime_no_executor_loop": True,
    }


def _build_project_browser_one_command_finalizer_state(
    *,
    browser_task_status: str,
    browser_command_queue_status: str,
    browser_command_type: str,
    browser_command_receipt_status: str,
    browser_launch_status: str,
    browser_prompt_send_status: str,
    browser_response_wait_status: str,
    browser_response_wait_block_reason: str,
    browser_response_json_parse_status: str,
    browser_execution_receipt_status: str,
    browser_execution_result_status: str,
    browser_recovery_status: str,
    browser_recovery_action: str,
    browser_recovery_receipt_status: str,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    queue_status = _normalize_text(browser_command_queue_status, default="insufficient_truth")
    command_type = _normalize_text(browser_command_type, default="none")
    command_receipt_status = _normalize_text(
        browser_command_receipt_status,
        default="insufficient_truth",
    )
    launch_status = _normalize_text(browser_launch_status, default="insufficient_truth")
    prompt_send_status = _normalize_text(browser_prompt_send_status, default="insufficient_truth")
    response_wait_status = _normalize_text(
        browser_response_wait_status,
        default="insufficient_truth",
    )
    response_wait_block_reason = _normalize_text(
        browser_response_wait_block_reason,
        default="insufficient_truth",
    )
    parse_status = _normalize_text(
        browser_response_json_parse_status,
        default="insufficient_truth",
    )
    execution_receipt_status = _normalize_text(
        browser_execution_receipt_status,
        default="insufficient_truth",
    )
    execution_result_status = _normalize_text(
        browser_execution_result_status,
        default="insufficient_truth",
    )
    recovery_status = _normalize_text(browser_recovery_status, default="insufficient_truth")
    recovery_action = _normalize_text(browser_recovery_action, default="none")
    recovery_receipt_status = _normalize_text(
        browser_recovery_receipt_status,
        default="insufficient_truth",
    )

    status = "insufficient_truth"
    result = "insufficient_truth"
    stop_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"

    if (
        queue_status == "inactive"
        or task_status == "inactive"
        or command_type == "none"
        or queue_status == "empty"
    ):
        status = "inactive"
        result = "none"
        stop_reason = "none"
        receipt_status = "not_created"
    elif queue_status in {"insufficient_truth", "unavailable"}:
        status = "insufficient_truth"
        result = "insufficient_truth"
        stop_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif queue_status == "blocked":
        status = "blocked"
        result = "blocked"
        stop_reason = "blocked_by_precondition"
        receipt_status = "blocked"
        receipt_kind = "one_command_blocked_receipt"
    elif recovery_status == "pause_required" or recovery_action == "pause_for_login":
        status = "pause_required"
        result = "pause_for_login"
        stop_reason = "pause_for_login"
        receipt_status = "pause_required"
        receipt_kind = "one_command_pause_for_login_receipt"
    elif recovery_status == "recovered" and recovery_receipt_status == "recovered":
        status = "completed_with_recovery"
        result = "recovered"
        stop_reason = "recovery_completed"
        receipt_status = "final_ready"
        receipt_kind = "one_command_recovery_receipt"
    elif parse_status == "valid" and execution_receipt_status == "parsed":
        status = "completed"
        result = "success"
        stop_reason = "command_completed"
        receipt_status = "final_ready"
        receipt_kind = "one_command_success_receipt"
    elif (
        parse_status == "invalid_response"
        or execution_receipt_status == "invalid_response"
        or execution_result_status == "invalid_response"
    ):
        status = "completed"
        result = "invalid_response"
        stop_reason = "invalid_response"
        receipt_status = "final_ready"
        receipt_kind = "one_command_invalid_response_receipt"
    elif (
        response_wait_status == "timeout"
        or response_wait_block_reason == "response_timeout"
    ):
        status = "completed"
        result = "timeout"
        stop_reason = "timeout"
        receipt_status = "final_ready"
        receipt_kind = "one_command_failed_receipt"
    elif recovery_status == "failed" or parse_status in {"failed"} or execution_receipt_status in {"failed"}:
        status = "failed"
        result = "failed"
        stop_reason = "runtime_failed"
        receipt_status = "failed"
        receipt_kind = "one_command_failed_receipt"
    elif (
        recovery_status == "blocked"
        or parse_status in {"blocked", "unavailable", "not_attempted", "inactive"}
        or execution_receipt_status in {"blocked", "unavailable", "not_created"}
        or prompt_send_status in {"blocked", "failed", "not_attempted"}
        or launch_status in {"blocked", "failed"}
        or command_receipt_status in {"blocked", "unavailable"}
    ):
        status = "blocked"
        result = "blocked"
        stop_reason = "blocked_by_precondition"
        receipt_status = "blocked"
        receipt_kind = "one_command_blocked_receipt"
    elif (
        recovery_status == "insufficient_truth"
        or parse_status == "insufficient_truth"
        or execution_receipt_status == "insufficient_truth"
        or prompt_send_status == "insufficient_truth"
        or launch_status == "insufficient_truth"
        or command_receipt_status == "insufficient_truth"
    ):
        status = "insufficient_truth"
        result = "insufficient_truth"
        stop_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    else:
        status = "insufficient_truth"
        result = "insufficient_truth"
        stop_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"

    if status not in _PROJECT_BROWSER_ONE_COMMAND_EXECUTOR_STATUSES:
        status = "insufficient_truth"
    if result not in _PROJECT_BROWSER_ONE_COMMAND_EXECUTOR_RESULTS:
        result = "insufficient_truth"
    if stop_reason not in _PROJECT_BROWSER_ONE_COMMAND_STOP_REASONS:
        stop_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_ONE_COMMAND_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_ONE_COMMAND_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        "no_additional_browser_action",
        "no_second_command",
        "no_queue_drain",
        "no_prompt_generation",
        "no_refill",
        "no_resend",
        "no_response_rewait",
        "no_json_reparse",
        "no_decision_execution",
        "no_retry_loop",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_background_loop",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_ONE_COMMAND_RUNTIME_POSTURES
    ]
    return {
        "project_browser_one_command_executor_status": status,
        "project_browser_one_command_executor_result": result,
        "project_browser_one_command_executor_stop_reason": stop_reason,
        "project_browser_one_command_executor_receipt_status": receipt_status,
        "project_browser_one_command_executor_receipt_kind": receipt_kind,
        "project_browser_one_command_executor_runtime_posture": runtime_posture,
        "project_browser_one_command_executor_runtime_no_additional_browser_action": True,
        "project_browser_one_command_executor_runtime_no_second_command": True,
        "project_browser_one_command_executor_runtime_no_queue_drain": True,
        "project_browser_one_command_executor_runtime_no_prompt_generation": True,
        "project_browser_one_command_executor_runtime_no_refill": True,
        "project_browser_one_command_executor_runtime_no_resend": True,
        "project_browser_one_command_executor_runtime_no_response_rewait": True,
        "project_browser_one_command_executor_runtime_no_json_reparse": True,
        "project_browser_one_command_executor_runtime_no_decision_execution": True,
        "project_browser_one_command_executor_runtime_no_retry_loop": True,
        "project_browser_one_command_executor_runtime_no_repair_execution": True,
        "project_browser_one_command_executor_runtime_no_restart_execution": True,
        "project_browser_one_command_executor_runtime_no_approval_execution": True,
        "project_browser_one_command_executor_runtime_no_background_loop": True,
    }


def _build_project_browser_autonomous_dev_assimilation_state(
    *,
    browser_task_status: str,
    one_command_executor_status: str,
    one_command_executor_result: str,
    one_command_executor_receipt_status: str,
    response_wait_block_reason: str,
    response_parse_block_reason: str,
    recovery_status: str,
    recovery_action: str,
    recovery_reason_runtime: str,
    retry_count_posture: str,
    login_interruption_status: str,
) -> dict[str, Any]:
    task_status = _normalize_text(browser_task_status, default="inactive")
    executor_status = _normalize_text(
        one_command_executor_status,
        default="insufficient_truth",
    )
    executor_result = _normalize_text(
        one_command_executor_result,
        default="insufficient_truth",
    )
    executor_receipt_status = _normalize_text(
        one_command_executor_receipt_status,
        default="insufficient_truth",
    )
    response_wait_block_reason = _normalize_text(
        response_wait_block_reason,
        default="insufficient_truth",
    )
    response_parse_block_reason = _normalize_text(
        response_parse_block_reason,
        default="insufficient_truth",
    )
    recovery_status = _normalize_text(recovery_status, default="insufficient_truth")
    recovery_action = _normalize_text(recovery_action, default="none")
    recovery_reason_runtime = _normalize_text(
        recovery_reason_runtime,
        default="insufficient_truth",
    )
    retry_count_posture = _normalize_text(
        retry_count_posture,
        default="insufficient_truth",
    )
    login_interruption_status = _normalize_text(
        login_interruption_status,
        default="insufficient_truth",
    )

    assimilation_status = "insufficient_truth"
    outcome = "insufficient_truth"
    next_action = "stop"
    stop_reason = "insufficient_truth"
    same_prompt_retry_policy = "insufficient_truth"
    same_prompt_retry_reason = "insufficient_truth"

    if task_status == "inactive" or executor_status == "inactive":
        assimilation_status = "inactive"
        outcome = "none"
        next_action = "none"
        stop_reason = "none"
        same_prompt_retry_policy = "not_applicable"
        same_prompt_retry_reason = "none"
    elif executor_receipt_status in {"not_created", "none", ""}:
        assimilation_status = "insufficient_truth"
        outcome = "insufficient_truth"
        next_action = "stop"
        stop_reason = "final_receipt_missing"
    elif executor_status == "pause_required" or executor_result == "pause_for_login":
        assimilation_status = "pause_required"
        outcome = "pause_for_login"
        next_action = "pause_for_login"
        stop_reason = "pause_for_login"
        same_prompt_retry_policy = "human_review_required"
        same_prompt_retry_reason = (
            "login_resumed"
            if login_interruption_status == "not_detected"
            else "insufficient_truth"
        )
    elif executor_status == "completed_with_recovery" or executor_result == "recovered":
        assimilation_status = "assimilated"
        outcome = "recovered"
        stop_reason = "recovery_completed"
        if recovery_action == "page_reload":
            next_action = "retry_same_prompt_candidate"
            same_prompt_retry_policy = (
                "allowed_candidate"
                if retry_count_posture == "retry_available"
                else (
                    "retry_budget_exhausted"
                    if retry_count_posture == "retry_limit_reached"
                    else "insufficient_truth"
                )
            )
            same_prompt_retry_reason = "page_reload_completed"
        elif recovery_action == "new_chat":
            next_action = "retry_same_prompt_candidate"
            same_prompt_retry_policy = (
                "allowed_candidate"
                if retry_count_posture == "retry_available"
                else (
                    "retry_budget_exhausted"
                    if retry_count_posture == "retry_limit_reached"
                    else "insufficient_truth"
                )
            )
            same_prompt_retry_reason = "new_chat_opened"
        elif recovery_action == "pause_for_login":
            assimilation_status = "pause_required"
            outcome = "pause_for_login"
            next_action = "pause_for_login"
            stop_reason = "pause_for_login"
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = "insufficient_truth"
        else:
            next_action = "human_review_required"
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = (
                "same_failure"
                if recovery_reason_runtime in {"invalid_response", "response_unavailable"}
                else "insufficient_truth"
            )
    elif executor_status == "completed" and executor_result == "success":
        assimilation_status = "assimilated"
        outcome = "success"
        next_action = "draft_md_update"
        stop_reason = "final_success"
        same_prompt_retry_policy = "not_applicable"
        same_prompt_retry_reason = "none"
    elif executor_status == "completed" and executor_result == "invalid_response":
        assimilation_status = "assimilated"
        outcome = "invalid_response"
        stop_reason = "invalid_response"
        if retry_count_posture == "retry_limit_reached":
            next_action = "draft_repair_prompt"
            same_prompt_retry_policy = "retry_budget_exhausted"
            same_prompt_retry_reason = "same_failure"
        elif retry_count_posture == "retry_available":
            if recovery_action in {"page_reload", "new_chat"}:
                next_action = "retry_same_prompt_candidate"
                same_prompt_retry_policy = "allowed_candidate"
                same_prompt_retry_reason = (
                    "page_reload_completed"
                    if recovery_action == "page_reload"
                    else "new_chat_opened"
                )
            elif response_parse_block_reason in {
                "json_parse_failed",
                "schema_missing",
                "schema_invalid",
                "decision_missing",
            }:
                next_action = "retry_same_prompt_candidate"
                same_prompt_retry_policy = "allowed_candidate"
                same_prompt_retry_reason = "invalid_response_retry_candidate"
            else:
                next_action = "draft_repair_prompt"
                same_prompt_retry_policy = "blocked_duplicate"
                same_prompt_retry_reason = "no_context_change"
        elif retry_count_posture == "insufficient_truth":
            next_action = "human_review_required"
            same_prompt_retry_policy = "insufficient_truth"
            same_prompt_retry_reason = "insufficient_truth"
        else:
            next_action = "draft_repair_prompt"
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = "same_failure"
    elif executor_status == "completed" and executor_result == "timeout":
        assimilation_status = "assimilated"
        outcome = "timeout"
        stop_reason = "timeout"
        if retry_count_posture == "retry_available":
            next_action = "retry_same_prompt_candidate"
            same_prompt_retry_policy = "allowed_candidate"
            same_prompt_retry_reason = (
                "response_unavailable"
                if response_wait_block_reason == "assistant_response_missing"
                else "transient_timeout"
            )
        elif retry_count_posture == "retry_limit_reached":
            next_action = "human_review_required"
            same_prompt_retry_policy = "retry_budget_exhausted"
            same_prompt_retry_reason = "same_failure"
        elif retry_count_posture == "insufficient_truth":
            next_action = "stop"
            same_prompt_retry_policy = "insufficient_truth"
            same_prompt_retry_reason = "insufficient_truth"
        else:
            next_action = "human_review_required"
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = "transient_timeout"
    elif executor_status == "blocked" or executor_result == "blocked":
        assimilation_status = "blocked"
        outcome = "blocked"
        next_action = "human_review_required"
        stop_reason = "blocked"
        if retry_count_posture == "retry_available" and recovery_reason_runtime in {
            "response_unavailable",
            "loading_timeout",
        }:
            same_prompt_retry_policy = "allowed_candidate"
            same_prompt_retry_reason = "response_unavailable"
            next_action = "retry_same_prompt_candidate"
        elif retry_count_posture == "retry_limit_reached":
            same_prompt_retry_policy = "retry_budget_exhausted"
            same_prompt_retry_reason = "same_failure"
        else:
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = "same_failure"
    elif executor_status == "failed" or executor_result == "failed":
        assimilation_status = "failed"
        outcome = "failed"
        next_action = "human_review_required"
        stop_reason = "failed"
        if retry_count_posture == "retry_available" and recovery_reason_runtime in {
            "response_unavailable",
            "loading_timeout",
        }:
            same_prompt_retry_policy = "allowed_candidate"
            same_prompt_retry_reason = "response_unavailable"
            next_action = "retry_same_prompt_candidate"
        elif retry_count_posture == "retry_limit_reached":
            same_prompt_retry_policy = "retry_budget_exhausted"
            same_prompt_retry_reason = "same_failure"
        else:
            same_prompt_retry_policy = "human_review_required"
            same_prompt_retry_reason = "same_failure"
    elif executor_status == "insufficient_truth" or executor_result == "insufficient_truth":
        assimilation_status = "insufficient_truth"
        outcome = "insufficient_truth"
        next_action = "stop"
        stop_reason = "insufficient_truth"
        same_prompt_retry_policy = "insufficient_truth"
        same_prompt_retry_reason = "insufficient_truth"
    else:
        assimilation_status = "insufficient_truth"
        outcome = "insufficient_truth"
        next_action = "stop"
        stop_reason = "unsupported_outcome"
        same_prompt_retry_policy = "insufficient_truth"
        same_prompt_retry_reason = "insufficient_truth"

    if assimilation_status not in _PROJECT_BROWSER_AUTONOMOUS_DEV_ASSIMILATION_STATUSES:
        assimilation_status = "insufficient_truth"
    if outcome not in _PROJECT_BROWSER_AUTONOMOUS_DEV_OUTCOMES:
        outcome = "insufficient_truth"
    if next_action not in _PROJECT_BROWSER_AUTONOMOUS_DEV_NEXT_ACTIONS:
        next_action = "stop"
    if stop_reason not in _PROJECT_BROWSER_AUTONOMOUS_DEV_STOP_REASONS:
        stop_reason = "insufficient_truth"
    if same_prompt_retry_policy not in _PROJECT_BROWSER_SAME_PROMPT_RETRY_POLICIES:
        same_prompt_retry_policy = "insufficient_truth"
    if same_prompt_retry_reason not in _PROJECT_BROWSER_SAME_PROMPT_RETRY_REASONS:
        same_prompt_retry_reason = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_next_prompt_generation",
        "no_md_write",
        "no_browser_action",
        "no_resend",
        "no_reload",
        "no_new_chat",
        "no_queue_mutation",
        "no_decision_execution",
        "no_executor_loop",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_DEV_RUNTIME_POSTURES
    ]

    return {
        "project_browser_autonomous_dev_assimilation_status": assimilation_status,
        "project_browser_autonomous_dev_outcome": outcome,
        "project_browser_autonomous_dev_next_action": next_action,
        "project_browser_autonomous_dev_stop_reason": stop_reason,
        "project_browser_same_prompt_retry_policy": same_prompt_retry_policy,
        "project_browser_same_prompt_retry_reason": same_prompt_retry_reason,
        "project_browser_autonomous_dev_runtime_posture": runtime_posture,
        "project_browser_autonomous_dev_runtime_metadata_only": True,
        "project_browser_autonomous_dev_runtime_no_next_prompt_generation": True,
        "project_browser_autonomous_dev_runtime_no_md_write": True,
        "project_browser_autonomous_dev_runtime_no_browser_action": True,
        "project_browser_autonomous_dev_runtime_no_resend": True,
        "project_browser_autonomous_dev_runtime_no_reload": True,
        "project_browser_autonomous_dev_runtime_no_new_chat": True,
        "project_browser_autonomous_dev_runtime_no_queue_mutation": True,
        "project_browser_autonomous_dev_runtime_no_decision_execution": True,
        "project_browser_autonomous_dev_runtime_no_executor_loop": True,
    }


def _build_project_browser_autonomous_draft_state(
    *,
    autonomous_dev_assimilation_status: str,
    autonomous_dev_outcome: str,
    autonomous_dev_next_action: str,
    autonomous_dev_stop_reason: str,
    same_prompt_retry_policy: str,
    same_prompt_retry_reason: str,
) -> dict[str, Any]:
    assimilation_status = _normalize_text(
        autonomous_dev_assimilation_status,
        default="insufficient_truth",
    )
    outcome = _normalize_text(autonomous_dev_outcome, default="insufficient_truth")
    next_action = _normalize_text(autonomous_dev_next_action, default="stop")
    stop_reason = _normalize_text(autonomous_dev_stop_reason, default="insufficient_truth")
    retry_policy = _normalize_text(same_prompt_retry_policy, default="insufficient_truth")
    retry_reason = _normalize_text(same_prompt_retry_reason, default="insufficient_truth")

    prompt_draft_status = "insufficient_truth"
    prompt_kind = "none"
    prompt_scope = "none"
    prompt_source = "insufficient_truth"
    prompt_block_reason = "insufficient_truth"

    md_draft_status = "insufficient_truth"
    md_update_kind = "none"
    md_command_draft_status = "insufficient_truth"
    md_block_reason = "insufficient_truth"
    md_command_draft = ""
    prompt_draft_compact: dict[str, Any] = {}
    md_draft_compact: dict[str, Any] = {}

    source_by_outcome = {
        "success": "pr109_success",
        "invalid_response": "pr109_invalid_response",
        "timeout": "pr109_timeout",
        "recovered": "pr109_recovered",
        "pause_for_login": "pr109_pause_for_login",
        "blocked": "pr109_blocked",
        "failed": "pr109_failed",
        "none": "none",
        "insufficient_truth": "insufficient_truth",
    }
    prompt_source = source_by_outcome.get(outcome, "insufficient_truth")
    prior_pr_summary_available = bool(
        assimilation_status in {"assimilated", "blocked", "failed", "pause_required"}
        and outcome in {"success", "invalid_response", "timeout", "recovered", "pause_for_login", "blocked", "failed"}
        and stop_reason not in {"final_receipt_missing", "insufficient_truth"}
    )

    def _build_md_update_payload(kind: str) -> dict[str, Any]:
        if kind == "history_only":
            return {
                "kind": "history_only",
                "target_path": "prompts/context/pr_history_index.md",
                "anchor_line": "- PR124 deterministic metadata-only low + standard risk execution adapter from PR123, mapping executor candidates to md/browser enqueue adapter candidates, classifying low/standard/high risk policy, emitting one adapter receipt, and preserving no-actual-execution posture.",
                "insertion_line": "- PR125 deterministic bounded one-file context .md apply executor from PR124 low-risk md_update_apply_candidate, with anchor-based duplicate-safe write receipt and strict no-browser/no-Codex/no-shell/no-loop runtime guards.",
                "anchor_required": True,
                "max_added_lines": 1,
            }
        if kind == "pr_history_and_constraints_append":
            return {
                "kind": "pr_history_and_constraints_append",
                "target_path": "prompts/context/current_architecture_constraints.md",
                "anchor_line": "- Preserve PR124 deterministic metadata-only low + standard risk execution adapter from PR123, mapping executor candidates to md/browser enqueue adapter candidates, classifying low/standard/high risk policy, emitting one adapter receipt, and preserving no-actual-execution posture.",
                "insertion_line": "- Preserve PR125 deterministic bounded one-file context .md apply executor from PR124 low-risk md_update_apply_candidate, with anchor-based duplicate-safe write receipt and strict no-browser/no-Codex/no-shell/no-loop runtime guards.",
                "anchor_required": True,
                "max_added_lines": 1,
            }
        return {}

    if assimilation_status == "inactive":
        prompt_draft_status = "not_required"
        prompt_kind = "none"
        prompt_scope = "none"
        prompt_source = "none"
        prompt_block_reason = "none"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    elif assimilation_status == "insufficient_truth":
        prompt_draft_status = "insufficient_truth"
        prompt_kind = "none"
        prompt_scope = "none"
        prompt_source = "insufficient_truth"
        prompt_block_reason = "assimilation_missing"
        md_draft_status = "insufficient_truth"
        md_update_kind = "none"
        md_command_draft_status = "insufficient_truth"
        md_block_reason = "assimilation_missing"
    elif assimilation_status == "pause_required" or next_action == "pause_for_login":
        prompt_draft_status = "human_review_required"
        prompt_kind = "human_review_prompt"
        prompt_scope = "human_review_only"
        prompt_block_reason = "pause_for_login"
        md_draft_status = "human_review_required"
        md_update_kind = "human_review_only"
        md_command_draft_status = "blocked"
        md_block_reason = "human_review_required"
    elif next_action == "draft_next_prompt":
        prompt_draft_status = "ready"
        prompt_kind = "next_pr_prompt"
        prompt_scope = "next_pr_only"
        prompt_block_reason = "none"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    elif next_action == "draft_repair_prompt":
        prompt_draft_status = "ready"
        prompt_kind = "repair_prompt"
        prompt_scope = "repair_only"
        prompt_block_reason = "none"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    elif next_action == "draft_md_update":
        prompt_draft_status = "not_required"
        prompt_kind = "none"
        prompt_scope = "md_update_only"
        prompt_block_reason = "none"
        if not prior_pr_summary_available:
            md_draft_status = "insufficient_truth"
            md_update_kind = "none"
            md_command_draft_status = "insufficient_truth"
            md_block_reason = "prior_pr_summary_missing"
        else:
            md_draft_status = "ready"
            md_update_kind = (
                "pr_history_and_constraints_append"
                if outcome in {"success", "recovered"}
                else "history_only"
            )
            md_command_draft_status = "ready"
            md_block_reason = "none"
            md_command_draft = (
                "codex-local-runner md-update --draft-only"
                f" --kind {md_update_kind}"
                " --target prompts/context/pr_history_index.md,prompts/context/current_architecture_constraints.md"
            )
    elif next_action == "retry_same_prompt_candidate":
        if retry_policy == "allowed_candidate":
            prompt_draft_status = "ready"
            prompt_kind = "retry_same_prompt"
            prompt_scope = "retry_same_prompt_only"
            prompt_block_reason = "none"
        elif retry_policy in {"blocked_duplicate", "retry_budget_exhausted", "cooldown_required"}:
            prompt_draft_status = "blocked"
            prompt_kind = "human_review_prompt"
            prompt_scope = "human_review_only"
            prompt_block_reason = "retry_policy_blocked"
        elif retry_policy == "human_review_required":
            prompt_draft_status = "human_review_required"
            prompt_kind = "human_review_prompt"
            prompt_scope = "human_review_only"
            prompt_block_reason = "human_review_required"
        else:
            prompt_draft_status = "insufficient_truth"
            prompt_kind = "none"
            prompt_scope = "none"
            prompt_block_reason = "insufficient_truth"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    elif next_action == "human_review_required":
        prompt_draft_status = "human_review_required"
        prompt_kind = "human_review_prompt"
        prompt_scope = "human_review_only"
        prompt_block_reason = "human_review_required"
        md_draft_status = "human_review_required"
        md_update_kind = "human_review_only"
        md_command_draft_status = "blocked"
        md_block_reason = "human_review_required"
    elif next_action == "stop":
        prompt_draft_status = "ready"
        prompt_kind = "stop_prompt"
        prompt_scope = "none"
        prompt_block_reason = "none"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    elif next_action == "none":
        prompt_draft_status = "not_required"
        prompt_kind = "none"
        prompt_scope = "none"
        prompt_block_reason = "none"
        md_draft_status = "not_required"
        md_update_kind = "none"
        md_command_draft_status = "not_required"
        md_block_reason = "none"
    else:
        prompt_draft_status = "blocked"
        prompt_kind = "none"
        prompt_scope = "none"
        prompt_block_reason = "next_action_not_supported"
        md_draft_status = "blocked"
        md_update_kind = "none"
        md_command_draft_status = "blocked"
        md_block_reason = "insufficient_truth"

    if prompt_draft_status == "ready":
        prompt_draft_compact = {
            "kind": prompt_kind,
            "scope": prompt_scope,
            "source": prompt_source,
            "retry_policy": retry_policy,
            "retry_reason": retry_reason,
        }
    if md_draft_status == "ready":
        md_payload = _build_md_update_payload(md_update_kind)
        md_draft_compact = {
            "kind": md_update_kind,
            "source": prompt_source,
            "stop_reason": stop_reason,
            "payload": md_payload,
        }

    if (
        prompt_draft_status
        not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_DRAFT_STATUSES
    ):
        prompt_draft_status = "insufficient_truth"
    if prompt_kind not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_KINDS:
        prompt_kind = "none"
    if prompt_scope not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_SCOPES:
        prompt_scope = "none"
    if prompt_source not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_SOURCES:
        prompt_source = "insufficient_truth"
    if (
        prompt_block_reason
        not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_BLOCK_REASONS
    ):
        prompt_block_reason = "insufficient_truth"

    if md_draft_status not in _PROJECT_BROWSER_AUTONOMOUS_MD_UPDATE_DRAFT_STATUSES:
        md_draft_status = "insufficient_truth"
    if md_update_kind not in _PROJECT_BROWSER_AUTONOMOUS_MD_UPDATE_KINDS:
        md_update_kind = "none"
    if (
        md_command_draft_status
        not in _PROJECT_BROWSER_AUTONOMOUS_MD_UPDATE_COMMAND_DRAFT_STATUSES
    ):
        md_command_draft_status = "insufficient_truth"
    if md_block_reason not in _PROJECT_BROWSER_AUTONOMOUS_MD_UPDATE_BLOCK_REASONS:
        md_block_reason = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_prompt_send",
        "no_browser_action",
        "no_md_write",
        "no_shell_execution",
        "no_queue_mutation",
        "no_continuation_execution",
        "no_retry_execution",
        "no_executor_loop",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_DRAFT_RUNTIME_POSTURES
    ]

    return {
        "project_browser_autonomous_next_prompt_draft_status": prompt_draft_status,
        "project_browser_autonomous_next_prompt_kind": prompt_kind,
        "project_browser_autonomous_next_prompt_scope": prompt_scope,
        "project_browser_autonomous_next_prompt_source": prompt_source,
        "project_browser_autonomous_next_prompt_block_reason": prompt_block_reason,
        "project_browser_autonomous_next_prompt_draft_compact": prompt_draft_compact,
        "project_browser_autonomous_md_update_draft_status": md_draft_status,
        "project_browser_autonomous_md_update_kind": md_update_kind,
        "project_browser_autonomous_md_update_command_draft_status": md_command_draft_status,
        "project_browser_autonomous_md_update_block_reason": md_block_reason,
        "project_browser_autonomous_md_update_draft_compact": md_draft_compact,
        "project_browser_autonomous_md_update_command_draft": md_command_draft,
        "project_browser_autonomous_draft_runtime_posture": runtime_posture,
        "project_browser_autonomous_draft_runtime_metadata_only": True,
        "project_browser_autonomous_draft_runtime_no_prompt_send": True,
        "project_browser_autonomous_draft_runtime_no_browser_action": True,
        "project_browser_autonomous_draft_runtime_no_md_write": True,
        "project_browser_autonomous_draft_runtime_no_shell_execution": True,
        "project_browser_autonomous_draft_runtime_no_queue_mutation": True,
        "project_browser_autonomous_draft_runtime_no_continuation_execution": True,
        "project_browser_autonomous_draft_runtime_no_retry_execution": True,
        "project_browser_autonomous_draft_runtime_no_executor_loop": True,
    }


def _build_project_browser_autonomous_continuation_gate_state(
    *,
    autonomous_dev_assimilation_status: str,
    autonomous_dev_outcome: str,
    autonomous_dev_next_action: str,
    same_prompt_retry_policy: str,
    same_prompt_retry_reason: str,
    next_prompt_draft_status: str,
    next_prompt_kind: str,
    next_prompt_scope: str,
    next_prompt_block_reason: str,
    md_update_draft_status: str,
    md_update_command_draft_status: str,
    md_update_block_reason: str,
) -> dict[str, Any]:
    assimilation_status = _normalize_text(
        autonomous_dev_assimilation_status,
        default="insufficient_truth",
    )
    outcome = _normalize_text(autonomous_dev_outcome, default="insufficient_truth")
    next_action = _normalize_text(autonomous_dev_next_action, default="stop")
    retry_policy = _normalize_text(same_prompt_retry_policy, default="insufficient_truth")
    retry_reason = _normalize_text(same_prompt_retry_reason, default="insufficient_truth")
    prompt_draft_status = _normalize_text(next_prompt_draft_status, default="insufficient_truth")
    prompt_kind = _normalize_text(next_prompt_kind, default="none")
    prompt_scope = _normalize_text(next_prompt_scope, default="none")
    prompt_block_reason = _normalize_text(
        next_prompt_block_reason,
        default="insufficient_truth",
    )
    md_draft_status = _normalize_text(md_update_draft_status, default="insufficient_truth")
    md_command_status = _normalize_text(
        md_update_command_draft_status,
        default="insufficient_truth",
    )
    md_block_reason = _normalize_text(
        md_update_block_reason,
        default="insufficient_truth",
    )

    gate_status = "insufficient_truth"
    gate_next_action = "stop"
    gate_block_reason = "insufficient_truth"
    duplicate_policy_status = "insufficient_truth"
    duplicate_reason = "insufficient_truth"
    retry_budget_posture = "insufficient_truth"

    if prompt_kind != "retry_same_prompt":
        retry_budget_posture = "not_applicable"
    elif retry_policy == "allowed_candidate":
        retry_budget_posture = "available"
    elif retry_policy == "retry_budget_exhausted":
        retry_budget_posture = "exhausted"
    elif retry_policy == "cooldown_required":
        retry_budget_posture = "cooldown_required"
    elif retry_policy == "insufficient_truth":
        retry_budget_posture = "insufficient_truth"
    else:
        retry_budget_posture = "not_applicable"

    if prompt_kind == "retry_same_prompt":
        if retry_policy == "allowed_candidate":
            if retry_reason == "transient_timeout":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_timeout"
            elif retry_reason == "response_unavailable":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_response_unavailable"
            elif retry_reason == "page_reload_completed":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_page_reload"
            elif retry_reason == "new_chat_opened":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_new_chat"
            elif retry_reason == "login_resumed":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_login_resume"
            elif retry_reason == "rate_limit":
                duplicate_policy_status = "retry_same_prompt_allowed"
                duplicate_reason = "allowed_after_timeout"
            elif retry_reason in {"same_failure", "no_context_change"}:
                duplicate_policy_status = "duplicate_blocked"
                duplicate_reason = (
                    "no_context_change"
                    if retry_reason == "no_context_change"
                    else "same_failure"
                )
            elif retry_reason == "invalid_response_retry_candidate":
                duplicate_policy_status = "loop_suspected"
                duplicate_reason = "loop_suspected"
            else:
                duplicate_policy_status = "insufficient_truth"
                duplicate_reason = "insufficient_truth"
        elif retry_policy == "blocked_duplicate":
            duplicate_policy_status = "duplicate_blocked"
            duplicate_reason = (
                "no_context_change"
                if retry_reason == "no_context_change"
                else "same_failure"
            )
        elif retry_policy == "retry_budget_exhausted":
            duplicate_policy_status = "duplicate_blocked"
            duplicate_reason = "retry_budget_exhausted"
        elif retry_policy == "cooldown_required":
            duplicate_policy_status = "cooldown_required"
            duplicate_reason = "cooldown_required"
        elif retry_policy == "human_review_required":
            duplicate_policy_status = "human_review_required"
            duplicate_reason = "insufficient_truth"
        elif retry_policy == "insufficient_truth":
            duplicate_policy_status = "insufficient_truth"
            duplicate_reason = "insufficient_truth"
        else:
            duplicate_policy_status = "insufficient_truth"
            duplicate_reason = "insufficient_truth"
    else:
        duplicate_policy_status = "clear"
        duplicate_reason = "none"

    if assimilation_status == "inactive":
        gate_status = "inactive"
        gate_next_action = "none"
        gate_block_reason = "none"
    elif assimilation_status == "insufficient_truth":
        gate_status = "insufficient_truth"
        gate_next_action = "stop"
        gate_block_reason = "insufficient_truth"
    elif assimilation_status == "pause_required" or next_action == "pause_for_login":
        gate_status = "pause_required"
        gate_next_action = "pause_for_login"
        gate_block_reason = "pause_for_login"
    elif (
        next_action == "human_review_required"
        or prompt_draft_status == "human_review_required"
        or md_draft_status == "human_review_required"
    ):
        gate_status = "human_review_required"
        gate_next_action = "human_review"
        gate_block_reason = "human_review_required"
    elif next_action == "draft_md_update":
        if md_draft_status == "ready" and md_command_status == "ready":
            gate_status = "allowed"
            gate_next_action = "use_md_update_draft"
            gate_block_reason = "none"
        elif md_draft_status == "insufficient_truth" or md_command_status == "insufficient_truth":
            gate_status = "insufficient_truth"
            gate_next_action = "stop"
            gate_block_reason = "insufficient_truth"
        else:
            gate_status = "blocked"
            gate_next_action = "stop"
            gate_block_reason = "md_update_missing"
    elif next_action in {"draft_next_prompt", "draft_repair_prompt", "stop"}:
        if prompt_draft_status == "ready" and prompt_kind in {
            "next_pr_prompt",
            "repair_prompt",
            "stop_prompt",
        }:
            gate_status = "allowed"
            gate_next_action = "use_next_prompt_draft"
            gate_block_reason = "none"
        elif prompt_draft_status == "insufficient_truth":
            gate_status = "insufficient_truth"
            gate_next_action = "stop"
            gate_block_reason = "insufficient_truth"
        else:
            gate_status = "blocked"
            gate_next_action = "stop"
            gate_block_reason = "draft_missing"
    elif next_action == "retry_same_prompt_candidate":
        if prompt_draft_status == "ready" and prompt_kind == "retry_same_prompt":
            if (
                duplicate_policy_status == "retry_same_prompt_allowed"
                and retry_budget_posture == "available"
            ):
                gate_status = "allowed"
                gate_next_action = "retry_same_prompt"
                gate_block_reason = "none"
            elif (
                duplicate_policy_status == "cooldown_required"
                or retry_budget_posture == "cooldown_required"
            ):
                gate_status = "blocked"
                gate_next_action = "stop"
                gate_block_reason = "cooldown_required"
            elif retry_budget_posture == "exhausted":
                gate_status = "blocked"
                gate_next_action = "stop"
                gate_block_reason = "retry_budget_exhausted"
            elif duplicate_policy_status == "loop_suspected":
                gate_status = "blocked"
                gate_next_action = "stop"
                gate_block_reason = "loop_suspected"
            elif duplicate_policy_status == "duplicate_blocked":
                gate_status = "blocked"
                gate_next_action = "stop"
                gate_block_reason = "duplicate_blocked"
            elif duplicate_policy_status == "human_review_required":
                gate_status = "human_review_required"
                gate_next_action = "human_review"
                gate_block_reason = "human_review_required"
            else:
                gate_status = "insufficient_truth"
                gate_next_action = "stop"
                gate_block_reason = "insufficient_truth"
        elif prompt_draft_status == "insufficient_truth":
            gate_status = "insufficient_truth"
            gate_next_action = "stop"
            gate_block_reason = "insufficient_truth"
        else:
            gate_status = "blocked"
            gate_next_action = "stop"
            gate_block_reason = "draft_missing"
    elif next_action == "none":
        gate_status = "inactive"
        gate_next_action = "none"
        gate_block_reason = "none"
    else:
        gate_status = "blocked"
        gate_next_action = "stop"
        gate_block_reason = (
            "retry_policy_blocked"
            if prompt_scope == "retry_same_prompt_only"
            else (
                "md_update_missing"
                if md_block_reason in {"prior_pr_summary_missing", "md_anchor_missing"}
                else "draft_missing"
            )
        )

    if gate_status not in _PROJECT_BROWSER_AUTONOMOUS_CONTINUATION_GATE_STATUSES:
        gate_status = "insufficient_truth"
    if gate_next_action not in _PROJECT_BROWSER_AUTONOMOUS_CONTINUATION_NEXT_ACTIONS:
        gate_next_action = "stop"
    if (
        gate_block_reason
        not in _PROJECT_BROWSER_AUTONOMOUS_CONTINUATION_BLOCK_REASONS
    ):
        gate_block_reason = "insufficient_truth"
    if duplicate_policy_status not in _PROJECT_BROWSER_AUTONOMOUS_DUPLICATE_POLICY_STATUSES:
        duplicate_policy_status = "insufficient_truth"
    if duplicate_reason not in _PROJECT_BROWSER_AUTONOMOUS_DUPLICATE_REASONS:
        duplicate_reason = "insufficient_truth"
    if retry_budget_posture not in _PROJECT_BROWSER_AUTONOMOUS_RETRY_BUDGET_POSTURES:
        retry_budget_posture = "insufficient_truth"

    runtime_posture = [
        "metadata_only",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_browser_action",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_controller_loop",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_GATE_RUNTIME_POSTURES
    ]

    return {
        "project_browser_autonomous_continuation_gate_status": gate_status,
        "project_browser_autonomous_continuation_next_action": gate_next_action,
        "project_browser_autonomous_continuation_block_reason": gate_block_reason,
        "project_browser_autonomous_duplicate_policy_status": duplicate_policy_status,
        "project_browser_autonomous_duplicate_reason": duplicate_reason,
        "project_browser_autonomous_retry_budget_posture": retry_budget_posture,
        "project_browser_autonomous_gate_runtime_posture": runtime_posture,
        "project_browser_autonomous_gate_runtime_metadata_only": True,
        "project_browser_autonomous_gate_runtime_no_prompt_send": True,
        "project_browser_autonomous_gate_runtime_no_md_write": True,
        "project_browser_autonomous_gate_runtime_no_shell_execution": True,
        "project_browser_autonomous_gate_runtime_no_browser_action": True,
        "project_browser_autonomous_gate_runtime_no_queue_mutation": True,
        "project_browser_autonomous_gate_runtime_no_retry_execution": True,
        "project_browser_autonomous_gate_runtime_no_continuation_execution": True,
        "project_browser_autonomous_gate_runtime_no_controller_loop": True,
    }


def _build_project_browser_autonomous_controller_state(
    *,
    autonomous_dev_assimilation_status: str,
    autonomous_dev_outcome: str,
    autonomous_dev_next_action: str,
    same_prompt_retry_policy: str,
    same_prompt_retry_reason: str,
    next_prompt_draft_status: str,
    next_prompt_kind: str,
    md_update_draft_status: str,
    md_update_command_draft_status: str,
    continuation_gate_status: str,
    continuation_next_action: str,
    continuation_block_reason: str,
    duplicate_policy_status: str,
    duplicate_reason: str,
    retry_budget_posture: str,
) -> dict[str, Any]:
    assimilation_status = _normalize_text(
        autonomous_dev_assimilation_status,
        default="insufficient_truth",
    )
    outcome = _normalize_text(autonomous_dev_outcome, default="insufficient_truth")
    dev_next_action = _normalize_text(autonomous_dev_next_action, default="stop")
    retry_policy = _normalize_text(same_prompt_retry_policy, default="insufficient_truth")
    retry_reason = _normalize_text(same_prompt_retry_reason, default="insufficient_truth")
    prompt_draft_status = _normalize_text(next_prompt_draft_status, default="insufficient_truth")
    prompt_kind = _normalize_text(next_prompt_kind, default="none")
    md_draft_status = _normalize_text(md_update_draft_status, default="insufficient_truth")
    md_command_status = _normalize_text(
        md_update_command_draft_status,
        default="insufficient_truth",
    )
    gate_status = _normalize_text(continuation_gate_status, default="insufficient_truth")
    gate_next_action = _normalize_text(continuation_next_action, default="stop")
    gate_block_reason = _normalize_text(
        continuation_block_reason,
        default="insufficient_truth",
    )
    dup_policy_status = _normalize_text(duplicate_policy_status, default="insufficient_truth")
    dup_reason = _normalize_text(duplicate_reason, default="insufficient_truth")
    retry_budget = _normalize_text(retry_budget_posture, default="insufficient_truth")

    controller_status = "insufficient_truth"
    controller_action = "none"
    action_source = "insufficient_truth"
    stop_reason = "insufficient_truth"
    receipt_status = "insufficient_truth"
    receipt_kind = "none"

    if gate_status == "inactive":
        controller_status = "inactive"
        controller_action = "none"
        action_source = "pr111_gate"
        stop_reason = "gate_inactive"
        receipt_status = "not_created"
    elif gate_status == "pause_required":
        controller_status = "pause_required"
        controller_action = "pause_for_login"
        action_source = "pr111_gate"
        stop_reason = "pause_for_login"
        receipt_status = "pause_required"
        receipt_kind = "pause_for_login_controller_receipt"
    elif gate_status == "human_review_required":
        controller_status = "human_review_required"
        controller_action = "human_review"
        action_source = "pr111_gate"
        stop_reason = "human_review_required"
        receipt_status = "human_review_required"
        receipt_kind = "human_review_controller_receipt"
    elif gate_status == "blocked":
        controller_status = "blocked"
        controller_action = "stop"
        action_source = "pr111_gate"
        if gate_block_reason == "duplicate_blocked":
            stop_reason = "duplicate_blocked"
        elif gate_block_reason == "retry_budget_exhausted":
            stop_reason = "retry_budget_exhausted"
        elif gate_block_reason == "cooldown_required":
            stop_reason = "cooldown_required"
        else:
            stop_reason = "gate_blocked"
        receipt_status = "blocked"
        receipt_kind = "blocked_controller_receipt"
    elif gate_status == "insufficient_truth":
        controller_status = "insufficient_truth"
        controller_action = "none"
        action_source = "pr111_gate"
        stop_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"
    elif gate_status == "allowed":
        candidates: list[str] = []
        cand_pause = bool(
            gate_next_action == "pause_for_login" or assimilation_status == "pause_required"
        )
        cand_human = bool(
            gate_next_action == "human_review" or dev_next_action == "human_review_required"
        )
        cand_md = bool(
            md_draft_status == "ready"
            and md_command_status == "ready"
            and (
                gate_next_action == "use_md_update_draft"
                or dev_next_action == "draft_md_update"
            )
        )
        cand_retry = bool(
            prompt_draft_status == "ready"
            and prompt_kind == "retry_same_prompt"
            and retry_policy == "allowed_candidate"
            and dup_policy_status == "retry_same_prompt_allowed"
            and retry_budget == "available"
            and retry_reason
            in {
                "transient_timeout",
                "response_unavailable",
                "page_reload_completed",
                "new_chat_opened",
                "login_resumed",
                "rate_limit",
                "invalid_response_retry_candidate",
            }
            and (
                gate_next_action == "retry_same_prompt"
                or dev_next_action == "retry_same_prompt_candidate"
            )
        )
        cand_next = bool(
            prompt_draft_status == "ready"
            and prompt_kind in {"next_pr_prompt", "repair_prompt", "stop_prompt"}
            and (
                gate_next_action == "use_next_prompt_draft"
                or dev_next_action in {"draft_next_prompt", "draft_repair_prompt"}
            )
        )
        cand_stop = bool(
            gate_next_action == "stop"
            or dev_next_action == "stop"
            or outcome == "insufficient_truth"
        )

        if cand_pause:
            candidates.append("pause_for_login")
        if cand_human:
            candidates.append("human_review")
        if cand_md:
            candidates.append("use_md_update_draft")
        if cand_retry:
            candidates.append("retry_same_prompt")
        if cand_next:
            candidates.append("use_next_prompt_draft")
        if cand_stop:
            candidates.append("stop")

        if "pause_for_login" in candidates:
            selected = "pause_for_login"
        elif "human_review" in candidates:
            selected = "human_review"
        elif "use_md_update_draft" in candidates:
            selected = "use_md_update_draft"
        elif "retry_same_prompt" in candidates:
            selected = "retry_same_prompt"
        elif "use_next_prompt_draft" in candidates:
            selected = "use_next_prompt_draft"
        elif "stop" in candidates:
            selected = "stop"
        else:
            selected = ""

        if selected:
            controller_status = "selected_one_action"
            controller_action = selected
            action_source = (
                "pr111_gate"
                if (
                    gate_next_action
                    in {
                        "pause_for_login",
                        "human_review",
                        "use_md_update_draft",
                        "retry_same_prompt",
                        "use_next_prompt_draft",
                        "stop",
                    }
                )
                else (
                    "pr110_draft"
                    if selected in {
                        "use_md_update_draft",
                        "use_next_prompt_draft",
                        "retry_same_prompt",
                    }
                    else "pr109_assimilation"
                )
            )
            stop_reason = "one_action_selected"
            receipt_status = "ready"
            receipt_kind = "one_pr_controller_receipt"
        else:
            controller_status = "ready"
            controller_action = "none"
            action_source = (
                "pr110_draft"
                if prompt_draft_status in {"ready", "blocked", "human_review_required"}
                or md_draft_status in {"ready", "blocked", "human_review_required"}
                else (
                    "pr109_assimilation"
                    if assimilation_status in {"assimilated", "blocked", "failed", "pause_required"}
                    else "pr111_gate"
                )
            )
            if dup_policy_status == "duplicate_blocked" or dup_reason in {"same_failure", "no_context_change"}:
                controller_status = "blocked"
                controller_action = "stop"
                stop_reason = "duplicate_blocked"
                receipt_status = "blocked"
                receipt_kind = "blocked_controller_receipt"
            elif retry_budget in {"exhausted"}:
                controller_status = "blocked"
                controller_action = "stop"
                stop_reason = "retry_budget_exhausted"
                receipt_status = "blocked"
                receipt_kind = "blocked_controller_receipt"
            elif retry_budget in {"cooldown_required"} or dup_policy_status == "cooldown_required":
                controller_status = "blocked"
                controller_action = "stop"
                stop_reason = "cooldown_required"
                receipt_status = "blocked"
                receipt_kind = "blocked_controller_receipt"
            elif gate_next_action in {"use_md_update_draft"} and (
                md_draft_status != "ready" or md_command_status != "ready"
            ):
                controller_status = "blocked"
                controller_action = "stop"
                stop_reason = "gate_blocked"
                receipt_status = "blocked"
                receipt_kind = "blocked_controller_receipt"
            elif gate_next_action in {"use_next_prompt_draft", "retry_same_prompt"} and (
                prompt_draft_status != "ready"
            ):
                controller_status = "blocked"
                controller_action = "stop"
                stop_reason = "gate_blocked"
                receipt_status = "blocked"
                receipt_kind = "blocked_controller_receipt"
            else:
                stop_reason = "insufficient_truth"
                receipt_status = "insufficient_truth"
    else:
        controller_status = "insufficient_truth"
        controller_action = "none"
        action_source = "insufficient_truth"
        stop_reason = "insufficient_truth"
        receipt_status = "insufficient_truth"

    if controller_status not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_STATUSES:
        controller_status = "insufficient_truth"
    if controller_action not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_ACTIONS:
        controller_action = "none"
    if action_source not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_ACTION_SOURCES:
        action_source = "insufficient_truth"
    if stop_reason not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_STOP_REASONS:
        stop_reason = "insufficient_truth"
    if receipt_status not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_RECEIPT_STATUSES:
        receipt_status = "insufficient_truth"
    if receipt_kind not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_RECEIPT_KINDS:
        receipt_kind = "none"

    runtime_posture = [
        "metadata_only",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_browser_action",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_multi_action",
        "no_controller_loop",
        "no_background_runtime",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_RUNTIME_POSTURES
    ]

    return {
        "project_browser_autonomous_controller_status": controller_status,
        "project_browser_autonomous_controller_action": controller_action,
        "project_browser_autonomous_controller_action_source": action_source,
        "project_browser_autonomous_controller_stop_reason": stop_reason,
        "project_browser_autonomous_controller_receipt_status": receipt_status,
        "project_browser_autonomous_controller_receipt_kind": receipt_kind,
        "project_browser_autonomous_controller_runtime_posture": runtime_posture,
        "project_browser_autonomous_controller_runtime_metadata_only": True,
        "project_browser_autonomous_controller_runtime_no_prompt_send": True,
        "project_browser_autonomous_controller_runtime_no_md_write": True,
        "project_browser_autonomous_controller_runtime_no_shell_execution": True,
        "project_browser_autonomous_controller_runtime_no_browser_action": True,
        "project_browser_autonomous_controller_runtime_no_queue_mutation": True,
        "project_browser_autonomous_controller_runtime_no_retry_execution": True,
        "project_browser_autonomous_controller_runtime_no_continuation_execution": True,
        "project_browser_autonomous_controller_runtime_no_multi_action": True,
        "project_browser_autonomous_controller_runtime_no_controller_loop": True,
        "project_browser_autonomous_controller_runtime_no_background_runtime": True,
    }


def _classify_project_browser_autonomous_duplicate_status(*, action_kind: str) -> str:
    normalized_kind = _normalize_text(action_kind, default="none")
    if normalized_kind in {"use_next_prompt_draft", "retry_same_prompt"}:
        return "duplicate_prompt"
    if normalized_kind == "use_md_update_draft":
        return "duplicate_md_update"
    if normalized_kind == "pause_for_login":
        return "duplicate_pause"
    if normalized_kind == "human_review":
        return "duplicate_human_review"
    return "duplicate_action"


def _build_project_browser_autonomous_run_ledger_state(
    *,
    autonomous_controller_status: str,
    autonomous_controller_action: str,
    autonomous_controller_action_source: str,
    autonomous_controller_stop_reason: str,
    autonomous_controller_receipt_status: str,
    autonomous_next_prompt_kind: str,
    autonomous_next_prompt_scope: str,
    autonomous_md_update_kind: str,
    same_prompt_retry_reason: str,
    prior_compact_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    controller_status = _normalize_text(
        autonomous_controller_status,
        default="insufficient_truth",
    )
    controller_action = _normalize_text(
        autonomous_controller_action,
        default="none",
    )
    controller_action_source = _normalize_text(
        autonomous_controller_action_source,
        default="insufficient_truth",
    )
    controller_stop_reason = _normalize_text(
        autonomous_controller_stop_reason,
        default="insufficient_truth",
    )
    controller_receipt_status = _normalize_text(
        autonomous_controller_receipt_status,
        default="insufficient_truth",
    )
    next_prompt_kind = _normalize_text(
        autonomous_next_prompt_kind,
        default="none",
    )
    next_prompt_scope = _normalize_text(
        autonomous_next_prompt_scope,
        default="none",
    )
    md_update_kind = _normalize_text(
        autonomous_md_update_kind,
        default="none",
    )
    retry_reason = _normalize_text(
        same_prompt_retry_reason,
        default="insufficient_truth",
    )
    prior = dict(prior_compact_state or {})

    action_kind = (
        controller_action
        if controller_action in _PROJECT_BROWSER_AUTONOMOUS_ACTION_KINDS
        else "none"
    )
    if controller_status in {"inactive", "insufficient_truth"}:
        action_kind = "none"
    if controller_status == "pause_required":
        action_kind = "pause_for_login"
    if controller_status == "human_review_required":
        action_kind = "human_review"

    inconsistent_state = (
        (controller_status == "inactive" and controller_receipt_status != "not_created")
        or (controller_status == "blocked" and controller_receipt_status != "blocked")
        or (
            controller_status == "human_review_required"
            and controller_receipt_status != "human_review_required"
        )
        or (controller_status == "pause_required" and controller_receipt_status != "pause_required")
        or (
            controller_status == "selected_one_action"
            and controller_receipt_status != "ready"
        )
    )

    identity_status = "unavailable"
    identity_compact: dict[str, Any] = {}
    fingerprint_status = "unavailable"
    fingerprint = ""
    duplicate_status = "clear"
    duplicate_matched = False

    if inconsistent_state:
        controller_status = "insufficient_truth"
        action_kind = "none"

    if controller_status == "selected_one_action":
        identity_compact = {
            "action_kind": action_kind,
            "action_source": controller_action_source,
            "controller_stop_reason": controller_stop_reason,
            "next_prompt_kind": "none",
            "next_prompt_scope": "none",
            "md_update_kind": "none",
            "same_prompt_retry_reason": "none",
        }
        identity_status = "available"
        if action_kind not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_KINDS or action_kind == "none":
            identity_status = "insufficient_truth"
        if (
            identity_status == "available"
            and controller_action_source not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_ACTION_SOURCES
        ):
            identity_status = "insufficient_truth"
        if (
            identity_status == "available"
            and controller_stop_reason not in _PROJECT_BROWSER_AUTONOMOUS_CONTROLLER_STOP_REASONS
        ):
            identity_status = "insufficient_truth"

        if identity_status == "available" and action_kind in {"use_next_prompt_draft", "retry_same_prompt"}:
            if (
                next_prompt_kind not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_KINDS
                or next_prompt_kind == "none"
                or next_prompt_scope not in _PROJECT_BROWSER_AUTONOMOUS_NEXT_PROMPT_SCOPES
                or next_prompt_scope == "none"
            ):
                identity_status = "insufficient_truth"
            else:
                identity_compact["next_prompt_kind"] = next_prompt_kind
                identity_compact["next_prompt_scope"] = next_prompt_scope

        if identity_status == "available" and action_kind == "use_md_update_draft":
            if (
                md_update_kind not in _PROJECT_BROWSER_AUTONOMOUS_MD_UPDATE_KINDS
                or md_update_kind == "none"
            ):
                identity_status = "insufficient_truth"
            else:
                identity_compact["md_update_kind"] = md_update_kind

        if identity_status == "available" and action_kind == "retry_same_prompt":
            if (
                retry_reason not in _PROJECT_BROWSER_SAME_PROMPT_RETRY_REASONS
                or retry_reason in {"none", "insufficient_truth"}
            ):
                identity_status = "insufficient_truth"
            else:
                identity_compact["same_prompt_retry_reason"] = retry_reason

        if identity_status == "available":
            fingerprint_input = json.dumps(
                identity_compact,
                sort_keys=True,
                separators=(",", ":"),
                ensure_ascii=True,
            )
            if fingerprint_input:
                fingerprint = hashlib.sha256(
                    fingerprint_input.encode("utf-8")
                ).hexdigest()
                fingerprint_status = "available" if fingerprint else "insufficient_truth"
            else:
                fingerprint_status = "insufficient_truth"
        else:
            fingerprint_status = "insufficient_truth"
            duplicate_status = "insufficient_truth"

        prior_fingerprint_status = _normalize_text(
            prior.get("project_browser_autonomous_action_fingerprint_status"),
            default="unavailable",
        )
        if (
            prior_fingerprint_status
            not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_FINGERPRINT_STATUSES
        ):
            prior_fingerprint_status = "unavailable"
        prior_fingerprint = _normalize_text(
            prior.get("project_browser_autonomous_action_fingerprint"),
            default="",
        )
        prior_comparable_available = bool(
            prior_fingerprint
            and prior_fingerprint_status in {"available", "duplicate"}
        )
        if fingerprint_status == "available":
            if prior_comparable_available and prior_fingerprint == fingerprint:
                duplicate_status = _classify_project_browser_autonomous_duplicate_status(
                    action_kind=action_kind
                )
                fingerprint_status = "duplicate"
                duplicate_matched = True
            else:
                duplicate_status = "clear"
        elif fingerprint_status == "unavailable":
            duplicate_status = "clear"
        else:
            duplicate_status = "insufficient_truth"

    ledger_status = "insufficient_truth"
    ledger_entry_status = "not_created"
    ledger_entry_kind = "none"
    action_receipt_status = "not_created"
    action_receipt_kind = "none"

    if controller_status == "inactive":
        ledger_status = "inactive"
        ledger_entry_status = "not_created"
        ledger_entry_kind = "none"
        action_receipt_status = "not_created"
        action_receipt_kind = "none"
    elif controller_status == "blocked":
        ledger_status = "blocked"
        ledger_entry_status = "blocked"
        ledger_entry_kind = "blocked_action_entry"
        action_receipt_status = "blocked"
        action_receipt_kind = "blocked_action_receipt"
    elif controller_status == "human_review_required":
        ledger_status = "human_review_required"
        ledger_entry_status = "created"
        ledger_entry_kind = "human_review_action_entry"
        action_receipt_status = "human_review_required"
        action_receipt_kind = "human_review_action_receipt"
    elif controller_status == "pause_required":
        ledger_status = "pause_required"
        ledger_entry_status = "created"
        ledger_entry_kind = "pause_action_entry"
        action_receipt_status = "pause_required"
        action_receipt_kind = "pause_action_receipt"
    elif controller_status == "insufficient_truth":
        ledger_status = "insufficient_truth"
        ledger_entry_status = "insufficient_truth"
        ledger_entry_kind = "none"
        identity_status = "insufficient_truth"
        action_kind = "none"
        fingerprint_status = "insufficient_truth"
        fingerprint = ""
        duplicate_status = "insufficient_truth"
        action_receipt_status = "insufficient_truth"
        action_receipt_kind = "none"
    elif controller_status == "selected_one_action":
        if (
            identity_status != "available"
            or fingerprint_status == "insufficient_truth"
            or duplicate_status == "insufficient_truth"
        ):
            ledger_status = "insufficient_truth"
            ledger_entry_status = "insufficient_truth"
            ledger_entry_kind = "none"
            action_receipt_status = "insufficient_truth"
            action_receipt_kind = "none"
        elif duplicate_matched:
            ledger_status = "duplicate_risk"
            ledger_entry_status = "duplicate_risk"
            ledger_entry_kind = "selected_action_entry"
            action_receipt_status = "duplicate_risk"
            action_receipt_kind = "duplicate_action_receipt"
        elif action_kind == "pause_for_login":
            ledger_status = "pause_required"
            ledger_entry_status = "created"
            ledger_entry_kind = "pause_action_entry"
            action_receipt_status = "pause_required"
            action_receipt_kind = "pause_action_receipt"
        elif action_kind == "human_review":
            ledger_status = "human_review_required"
            ledger_entry_status = "created"
            ledger_entry_kind = "human_review_action_entry"
            action_receipt_status = "human_review_required"
            action_receipt_kind = "human_review_action_receipt"
        else:
            ledger_status = "ready"
            ledger_entry_status = "created"
            ledger_entry_kind = "selected_action_entry"
            action_receipt_status = "ready"
            action_receipt_kind = "selected_action_receipt"
    elif controller_status == "ready":
        ledger_status = "ready"
        ledger_entry_status = "not_created"
        ledger_entry_kind = "none"
        action_receipt_status = "not_created"
        action_receipt_kind = "none"

    if ledger_status not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_STATUSES:
        ledger_status = "insufficient_truth"
    if (
        ledger_entry_status
        not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_ENTRY_STATUSES
    ):
        ledger_entry_status = "insufficient_truth"
    if ledger_entry_kind not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_ENTRY_KINDS:
        ledger_entry_kind = "none"
    if (
        identity_status
        not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_IDENTITY_STATUSES
    ):
        identity_status = "insufficient_truth"
    if action_kind not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_KINDS:
        action_kind = "none"
    if (
        fingerprint_status
        not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_FINGERPRINT_STATUSES
    ):
        fingerprint_status = "insufficient_truth"
    if (
        duplicate_status
        not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES
    ):
        duplicate_status = "insufficient_truth"
    if (
        action_receipt_status
        not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_RECEIPT_STATUSES
    ):
        action_receipt_status = "insufficient_truth"
    if (
        action_receipt_kind
        not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_RECEIPT_KINDS
    ):
        action_receipt_kind = "none"
    if fingerprint_status in {"unavailable", "insufficient_truth"}:
        fingerprint = ""
    if identity_status != "available":
        identity_compact = {}

    ledger_entry_compact: dict[str, Any] = {}
    if ledger_entry_status in {"created", "blocked", "duplicate_risk", "insufficient_truth"}:
        ledger_entry_compact = {
            "entry_status": ledger_entry_status,
            "entry_kind": ledger_entry_kind,
            "action_kind": action_kind,
            "fingerprint_status": fingerprint_status,
            "duplicate_status": duplicate_status,
        }

    action_receipt_compact: dict[str, Any] = {}
    if action_receipt_status != "not_created":
        action_receipt_compact = {
            "receipt_status": action_receipt_status,
            "receipt_kind": action_receipt_kind,
            "action_kind": action_kind,
            "candidate_only": True,
            "action_executed": False,
        }

    runtime_posture = [
        "metadata_only",
        "no_selected_action_execution",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_browser_action",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_multi_action",
        "no_controller_loop",
        "no_background_runtime",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_LEDGER_RUNTIME_POSTURES
    ]

    return {
        "project_browser_autonomous_run_ledger_status": ledger_status,
        "project_browser_autonomous_run_ledger_entry_status": ledger_entry_status,
        "project_browser_autonomous_run_ledger_entry_kind": ledger_entry_kind,
        "project_browser_autonomous_run_ledger_entry_compact": ledger_entry_compact,
        "project_browser_autonomous_action_identity_status": identity_status,
        "project_browser_autonomous_action_identity_compact": identity_compact,
        "project_browser_autonomous_action_kind": action_kind,
        "project_browser_autonomous_action_fingerprint_status": fingerprint_status,
        "project_browser_autonomous_action_fingerprint": fingerprint,
        "project_browser_autonomous_action_duplicate_status": duplicate_status,
        "project_browser_autonomous_action_receipt_status": action_receipt_status,
        "project_browser_autonomous_action_receipt_kind": action_receipt_kind,
        "project_browser_autonomous_action_receipt_compact": action_receipt_compact,
        "project_browser_autonomous_action_receipt_candidate_only": True,
        "project_browser_autonomous_action_receipt_action_executed": False,
        "project_browser_autonomous_ledger_runtime_posture": runtime_posture,
        "project_browser_autonomous_ledger_runtime_metadata_only": True,
        "project_browser_autonomous_ledger_runtime_no_selected_action_execution": True,
        "project_browser_autonomous_ledger_runtime_no_prompt_send": True,
        "project_browser_autonomous_ledger_runtime_no_md_write": True,
        "project_browser_autonomous_ledger_runtime_no_shell_execution": True,
        "project_browser_autonomous_ledger_runtime_no_browser_action": True,
        "project_browser_autonomous_ledger_runtime_no_queue_mutation": True,
        "project_browser_autonomous_ledger_runtime_no_retry_execution": True,
        "project_browser_autonomous_ledger_runtime_no_continuation_execution": True,
        "project_browser_autonomous_ledger_runtime_no_multi_action": True,
        "project_browser_autonomous_ledger_runtime_no_controller_loop": True,
        "project_browser_autonomous_ledger_runtime_no_background_runtime": True,
    }


def _build_project_browser_autonomous_safety_state(
    *,
    autonomous_run_ledger_status: str,
    autonomous_action_receipt_status: str,
    autonomous_action_duplicate_status: str,
    login_interruption_status: str,
    final_human_review_required: bool,
    project_human_escalation_required: bool,
    project_approval_reply_required_posture: str,
    approval_skip_gate_status: str,
    project_external_boundary_status: str,
    project_external_dependency_posture: str,
    project_external_manual_only_posture: str,
    long_running_stability_status: str,
    long_running_pause_required: bool,
    long_running_safe_stop_required: bool,
    prior_compact_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    ledger_status = _normalize_text(
        autonomous_run_ledger_status,
        default="insufficient_truth",
    )
    action_receipt_status = _normalize_text(
        autonomous_action_receipt_status,
        default="insufficient_truth",
    )
    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    login_status = _normalize_text(
        login_interruption_status,
        default="insufficient_truth",
    )
    approval_reply_posture = _normalize_text(
        project_approval_reply_required_posture,
        default="insufficient_truth",
    )
    approval_skip_status = _normalize_text(
        approval_skip_gate_status,
        default="insufficient_truth",
    )
    external_boundary_status = _normalize_text(
        project_external_boundary_status,
        default="insufficient_truth",
    )
    external_dependency_posture = _normalize_text(
        project_external_dependency_posture,
        default="insufficient_truth",
    )
    external_manual_only_posture = _normalize_text(
        project_external_manual_only_posture,
        default="insufficient_truth",
    )
    long_running_status = _normalize_text(
        long_running_stability_status,
        default="insufficient_truth",
    )
    prior = dict(prior_compact_state or {})

    runtime_posture = [
        "metadata_only",
        "no_selected_action_execution",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_browser_action",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_multi_step_execution",
        "no_background_runtime",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_RUNTIME_POSTURES
    ]

    def _insufficient_truth_state() -> dict[str, Any]:
        return {
            "project_browser_autonomous_safety_switch_status": "insufficient_truth",
            "project_browser_autonomous_manual_override_status": "insufficient_truth",
            "project_browser_autonomous_manual_override_reason": "insufficient_truth",
            "project_browser_autonomous_safe_stop_status": "insufficient_truth",
            "project_browser_autonomous_safe_stop_reason": "insufficient_truth",
            "project_browser_autonomous_execution_permission": "insufficient_truth",
            "project_browser_autonomous_safety_runtime_posture": runtime_posture,
            "project_browser_autonomous_safety_runtime_metadata_only": True,
            "project_browser_autonomous_safety_runtime_no_selected_action_execution": True,
            "project_browser_autonomous_safety_runtime_no_prompt_send": True,
            "project_browser_autonomous_safety_runtime_no_md_write": True,
            "project_browser_autonomous_safety_runtime_no_shell_execution": True,
            "project_browser_autonomous_safety_runtime_no_browser_action": True,
            "project_browser_autonomous_safety_runtime_no_queue_mutation": True,
            "project_browser_autonomous_safety_runtime_no_retry_execution": True,
            "project_browser_autonomous_safety_runtime_no_continuation_execution": True,
            "project_browser_autonomous_safety_runtime_no_multi_step_execution": True,
            "project_browser_autonomous_safety_runtime_no_background_runtime": True,
        }

    if ledger_status not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_STATUSES:
        return _insufficient_truth_state()
    if action_receipt_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_RECEIPT_STATUSES:
        return _insufficient_truth_state()
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state()
    if login_status not in _PROJECT_BROWSER_LOGIN_INTERRUPTION_STATUSES:
        return _insufficient_truth_state()
    if approval_reply_posture not in _PROJECT_APPROVAL_REPLY_REQUIRED_POSTURES:
        return _insufficient_truth_state()
    if approval_skip_status not in _APPROVAL_SKIP_GATE_STATUSES:
        return _insufficient_truth_state()
    if external_boundary_status not in _PROJECT_EXTERNAL_BOUNDARY_STATUSES:
        return _insufficient_truth_state()
    if external_dependency_posture not in _PROJECT_EXTERNAL_DEPENDENCY_POSTURES:
        return _insufficient_truth_state()
    if external_manual_only_posture not in _PROJECT_EXTERNAL_BOUNDARY_POSTURES:
        return _insufficient_truth_state()
    if long_running_status not in _LONG_RUNNING_STABILITY_STATUSES:
        return _insufficient_truth_state()

    prior_switch_raw = _normalize_text(
        prior.get("project_browser_autonomous_safety_switch_status"),
        default="",
    )
    prior_override_status_raw = _normalize_text(
        prior.get("project_browser_autonomous_manual_override_status"),
        default="",
    )
    prior_override_reason_raw = _normalize_text(
        prior.get("project_browser_autonomous_manual_override_reason"),
        default="",
    )
    prior_safe_stop_status_raw = _normalize_text(
        prior.get("project_browser_autonomous_safe_stop_status"),
        default="",
    )
    prior_safe_stop_reason_raw = _normalize_text(
        prior.get("project_browser_autonomous_safe_stop_reason"),
        default="",
    )

    if (
        prior_switch_raw
        and prior_switch_raw not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES
    ):
        return _insufficient_truth_state()
    if (
        prior_override_status_raw
        and prior_override_status_raw
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES
    ):
        return _insufficient_truth_state()
    if (
        prior_override_reason_raw
        and prior_override_reason_raw
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_REASONS
    ):
        return _insufficient_truth_state()
    if (
        prior_safe_stop_status_raw
        and prior_safe_stop_status_raw not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES
    ):
        return _insufficient_truth_state()
    if (
        prior_safe_stop_reason_raw
        and prior_safe_stop_reason_raw not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_REASONS
    ):
        return _insufficient_truth_state()

    expected_receipts_by_ledger = {
        "inactive": {"not_created"},
        "ready": {"ready", "not_created"},
        "blocked": {"blocked"},
        "duplicate_risk": {"duplicate_risk"},
        "human_review_required": {"human_review_required"},
        "pause_required": {"pause_required"},
    }
    if ledger_status in expected_receipts_by_ledger and (
        action_receipt_status not in expected_receipts_by_ledger[ledger_status]
    ):
        return _insufficient_truth_state()
    if ledger_status == "insufficient_truth" and action_receipt_status != "insufficient_truth":
        return _insufficient_truth_state()
    if action_receipt_status == "insufficient_truth" and ledger_status != "insufficient_truth":
        return _insufficient_truth_state()

    explicit_stop_all_requested = bool(
        prior_switch_raw == "stop_all"
        or prior_override_reason_raw == "user_requested_stop"
        or prior_safe_stop_status_raw == "stop_now"
        or prior_safe_stop_reason_raw == "stop_all_requested"
        or bool(prior.get("project_browser_autonomous_stop_all_requested", False))
        or bool(prior.get("project_browser_global_stop_requested", False))
        or bool(prior.get("global_stop", False))
        or bool(prior.get("global_stop_recommended", False))
    )
    explicit_pause_after_current_step = bool(
        prior_switch_raw == "pause_after_current_step"
        or prior_override_reason_raw == "user_requested_pause"
        or prior_safe_stop_status_raw == "pause_after_current_step"
        or bool(prior.get("project_browser_autonomous_pause_after_current_step", False))
    )
    kill_switch_disabled = bool(
        prior_switch_raw == "disabled"
        or bool(prior.get("project_browser_autonomous_kill_switch_disabled", False))
    )
    if explicit_stop_all_requested and explicit_pause_after_current_step:
        return _insufficient_truth_state()

    human_review_signal = bool(
        final_human_review_required or project_human_escalation_required
    )
    approval_required_signal = bool(
        approval_reply_posture == "reply_required"
        or approval_skip_status == "approval_required"
    )
    external_boundary_signal = bool(
        (
            external_boundary_status == "available"
            and external_dependency_posture in {"dependency_blocked", "manual_only"}
        )
        or external_manual_only_posture == "manual_only"
    )
    login_required_signal = login_status == "detected"
    unsafe_state_signal = bool(
        long_running_status in {"safe_stop", "escalated"}
        or (long_running_status == "paused" and long_running_pause_required)
        or (
            long_running_status not in {"monitoring", "resume_ready", "insufficient_truth"}
            and long_running_safe_stop_required
        )
    )

    safety_switch_status = "enabled"
    manual_override_status = "clear"
    manual_override_reason = "none"
    safe_stop_status = "not_required"
    safe_stop_reason = "none"
    execution_permission = "blocked"

    if ledger_status == "inactive":
        safety_switch_status = "inactive"
        manual_override_status = "inactive"
        execution_permission = "blocked"
    elif ledger_status == "insufficient_truth" or action_receipt_status == "insufficient_truth":
        safety_switch_status = "insufficient_truth"
        manual_override_status = "insufficient_truth"
        manual_override_reason = "insufficient_truth"
        safe_stop_status = "insufficient_truth"
        safe_stop_reason = "ledger_insufficient_truth"
        execution_permission = "insufficient_truth"
    elif (
        ledger_status == "duplicate_risk"
        or action_receipt_status == "duplicate_risk"
    ):
        safety_switch_status = "enabled"
        manual_override_status = "blocked"
        manual_override_reason = "duplicate_risk"
        safe_stop_status = "required"
        safe_stop_reason = "duplicate_risk"
        execution_permission = "blocked"
    elif ledger_status == "blocked" or action_receipt_status == "blocked":
        safety_switch_status = "enabled"
        manual_override_status = "blocked"
        manual_override_reason = "unsafe_state"
        safe_stop_status = "required"
        safe_stop_reason = "action_receipt_blocked"
        execution_permission = "blocked"
    elif (
        ledger_status == "human_review_required"
        or action_receipt_status == "human_review_required"
    ):
        safety_switch_status = "manual_review_required"
        manual_override_status = "required"
        manual_override_reason = "human_review_required"
        safe_stop_status = "human_review_required"
        safe_stop_reason = "human_review_required"
        execution_permission = "human_review_required"
    elif ledger_status == "pause_required" or action_receipt_status == "pause_required":
        safety_switch_status = "pause_required"
        manual_override_status = "required"
        manual_override_reason = (
            "human_review_required" if human_review_signal else "login_required"
        )
        safe_stop_status = "pause_after_current_step"
        safe_stop_reason = "pause_for_login"
        execution_permission = "pause_required"
    elif action_receipt_status == "ready":
        safety_switch_status = "enabled"
        execution_permission = "allowed_candidate"
    else:
        safety_switch_status = "enabled"
        execution_permission = "blocked"

    if explicit_stop_all_requested:
        if ledger_status != "inactive":
            safety_switch_status = "stop_all"
        manual_override_status = "requested"
        manual_override_reason = "user_requested_stop"
        safe_stop_status = "stop_now"
        safe_stop_reason = "stop_all_requested"
        execution_permission = "blocked"
    elif kill_switch_disabled:
        if ledger_status != "inactive":
            safety_switch_status = "disabled"
        if manual_override_status in {"clear", "inactive"}:
            manual_override_status = "blocked"
            manual_override_reason = "unsafe_state"
        safe_stop_status = "required"
        safe_stop_reason = "kill_switch_disabled"
        execution_permission = "blocked"

    if explicit_pause_after_current_step and not explicit_stop_all_requested:
        if ledger_status != "inactive":
            safety_switch_status = "pause_after_current_step"
        manual_override_status = "requested"
        manual_override_reason = "user_requested_pause"
        safe_stop_status = "pause_after_current_step"
        safe_stop_reason = "manual_override_requested"
        if execution_permission == "allowed_candidate":
            execution_permission = "pause_required"

    if execution_permission == "allowed_candidate":
        if external_boundary_signal or unsafe_state_signal:
            execution_permission = "blocked"
            manual_override_status = "blocked"
            manual_override_reason = (
                "external_boundary" if external_boundary_signal else "unsafe_state"
            )
            safe_stop_status = "required"
            safe_stop_reason = "unsafe_state"
        elif human_review_signal:
            execution_permission = "human_review_required"
            safety_switch_status = (
                "manual_review_required"
                if safety_switch_status == "enabled"
                else safety_switch_status
            )
            manual_override_status = "required"
            manual_override_reason = "human_review_required"
            safe_stop_status = "human_review_required"
            safe_stop_reason = "human_review_required"
        elif approval_required_signal:
            execution_permission = "human_review_required"
            safety_switch_status = (
                "manual_review_required"
                if safety_switch_status == "enabled"
                else safety_switch_status
            )
            manual_override_status = "required"
            manual_override_reason = "approval_required"
            safe_stop_status = "required"
            safe_stop_reason = "manual_override_requested"
        elif login_required_signal:
            execution_permission = "pause_required"
            safety_switch_status = (
                "pause_required"
                if safety_switch_status == "enabled"
                else safety_switch_status
            )
            manual_override_status = "required"
            manual_override_reason = "login_required"
            safe_stop_status = "pause_after_current_step"
            safe_stop_reason = "pause_for_login"

    if ledger_status == "inactive":
        safety_switch_status = "inactive"
        if manual_override_status == "clear":
            manual_override_status = "inactive"
        if execution_permission == "allowed_candidate":
            execution_permission = "blocked"

    if execution_permission == "allowed_candidate" and action_receipt_status != "ready":
        return _insufficient_truth_state()
    if safe_stop_status == "not_required":
        safe_stop_reason = "none"
    elif safe_stop_reason == "none":
        safe_stop_reason = (
            "manual_override_requested"
            if manual_override_reason not in {"none", "insufficient_truth"}
            else "unsafe_state"
        )
    if manual_override_status in {"clear", "inactive"}:
        manual_override_reason = "none"
    elif manual_override_reason == "none":
        return _insufficient_truth_state()

    if (
        safety_switch_status
        not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES
    ):
        return _insufficient_truth_state()
    if (
        manual_override_status
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES
    ):
        return _insufficient_truth_state()
    if (
        manual_override_reason
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_REASONS
    ):
        return _insufficient_truth_state()
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state()
    if safe_stop_reason not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_REASONS:
        return _insufficient_truth_state()
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()

    return {
        "project_browser_autonomous_safety_switch_status": safety_switch_status,
        "project_browser_autonomous_manual_override_status": manual_override_status,
        "project_browser_autonomous_manual_override_reason": manual_override_reason,
        "project_browser_autonomous_safe_stop_status": safe_stop_status,
        "project_browser_autonomous_safe_stop_reason": safe_stop_reason,
        "project_browser_autonomous_execution_permission": execution_permission,
        "project_browser_autonomous_safety_runtime_posture": runtime_posture,
        "project_browser_autonomous_safety_runtime_metadata_only": True,
        "project_browser_autonomous_safety_runtime_no_selected_action_execution": True,
        "project_browser_autonomous_safety_runtime_no_prompt_send": True,
        "project_browser_autonomous_safety_runtime_no_md_write": True,
        "project_browser_autonomous_safety_runtime_no_shell_execution": True,
        "project_browser_autonomous_safety_runtime_no_browser_action": True,
        "project_browser_autonomous_safety_runtime_no_queue_mutation": True,
        "project_browser_autonomous_safety_runtime_no_retry_execution": True,
        "project_browser_autonomous_safety_runtime_no_continuation_execution": True,
        "project_browser_autonomous_safety_runtime_no_multi_step_execution": True,
        "project_browser_autonomous_safety_runtime_no_background_runtime": True,
    }


def _build_project_browser_autonomous_execution_bridge_state(
    *,
    autonomous_run_ledger_status: str,
    autonomous_action_receipt_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_manual_override_reason: str,
    autonomous_safe_stop_status: str,
    autonomous_safe_stop_reason: str,
    autonomous_execution_permission: str,
) -> dict[str, Any]:
    ledger_status = _normalize_text(
        autonomous_run_ledger_status,
        default="insufficient_truth",
    )
    action_receipt_status = _normalize_text(
        autonomous_action_receipt_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    manual_override_reason = _normalize_text(
        autonomous_manual_override_reason,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    safe_stop_reason = _normalize_text(
        autonomous_safe_stop_reason,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_execution",
        "no_browser",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_multi_step_execution",
        "no_background_runtime",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_RUNTIME_POSTURES
    ]

    def _insufficient_truth_state(*, source_status: str) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES
            else "insufficient_truth"
        )
        return {
            "project_browser_autonomous_execution_bridge_status": "insufficient_truth",
            "project_browser_autonomous_execution_bridge_permission": "insufficient_truth",
            "project_browser_autonomous_execution_bridge_reason": "insufficient_truth",
            "project_browser_autonomous_execution_bridge_source_status": normalized_source_status,
            "project_browser_autonomous_execution_bridge_runtime_posture": runtime_posture,
            "project_browser_autonomous_execution_bridge_runtime_metadata_only": True,
            "project_browser_autonomous_execution_bridge_runtime_no_execution": True,
            "project_browser_autonomous_execution_bridge_runtime_no_browser": True,
            "project_browser_autonomous_execution_bridge_runtime_no_prompt_send": True,
            "project_browser_autonomous_execution_bridge_runtime_no_md_write": True,
            "project_browser_autonomous_execution_bridge_runtime_no_shell_execution": True,
            "project_browser_autonomous_execution_bridge_runtime_no_queue_mutation": True,
            "project_browser_autonomous_execution_bridge_runtime_no_retry_execution": True,
            "project_browser_autonomous_execution_bridge_runtime_no_continuation_execution": True,
            "project_browser_autonomous_execution_bridge_runtime_no_multi_step_execution": True,
            "project_browser_autonomous_execution_bridge_runtime_no_background_runtime": True,
        }

    if ledger_status not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if action_receipt_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_RECEIPT_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if (
        manual_override_status
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")
    if (
        manual_override_reason
        not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_REASONS
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safe_stop_reason not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_REASONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")

    if any(
        token == "insufficient_truth"
        for token in (
            ledger_status,
            action_receipt_status,
            safety_switch_status,
            manual_override_status,
            manual_override_reason,
            safe_stop_status,
            safe_stop_reason,
            execution_permission,
        )
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")

    inconsistent_source = False
    if ledger_status == "inactive" and safety_switch_status != "inactive":
        inconsistent_source = True
    if safety_switch_status == "inactive" and ledger_status != "inactive":
        inconsistent_source = True
    if (
        ledger_status == "inactive" or safety_switch_status == "inactive"
    ) and execution_permission != "blocked":
        inconsistent_source = True
    if execution_permission == "allowed_candidate" and action_receipt_status != "ready":
        inconsistent_source = True
    if execution_permission == "allowed_candidate" and (
        ledger_status in {"inactive", "insufficient_truth"}
        or safety_switch_status in {"inactive", "insufficient_truth"}
    ):
        inconsistent_source = True
    if (
        safety_switch_status == "insufficient_truth"
        and execution_permission != "insufficient_truth"
    ):
        inconsistent_source = True
    if (
        manual_override_status == "insufficient_truth"
        and execution_permission != "insufficient_truth"
    ):
        inconsistent_source = True
    if (
        safe_stop_status == "insufficient_truth"
        and execution_permission != "insufficient_truth"
    ):
        inconsistent_source = True
    if inconsistent_source:
        return _insufficient_truth_state(source_status="inconsistent")

    bridge_permission = execution_permission
    bridge_reason = {
        "allowed_candidate": "none",
        "blocked": "blocked_by_pr114",
        "pause_required": "pause_required",
        "human_review_required": "human_review_required",
        "insufficient_truth": "insufficient_truth",
    }.get(bridge_permission, "insufficient_truth")
    bridge_status = {
        "allowed_candidate": "ready",
        "blocked": "blocked",
        "pause_required": "blocked",
        "human_review_required": "blocked",
        "insufficient_truth": "insufficient_truth",
    }.get(bridge_permission, "insufficient_truth")
    if ledger_status == "inactive" or safety_switch_status == "inactive":
        bridge_status = "inactive"

    if (
        bridge_status
        not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")
    if (
        bridge_permission
        not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")
    if (
        bridge_reason
        not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_REASONS
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")

    return {
        "project_browser_autonomous_execution_bridge_status": bridge_status,
        "project_browser_autonomous_execution_bridge_permission": bridge_permission,
        "project_browser_autonomous_execution_bridge_reason": bridge_reason,
        "project_browser_autonomous_execution_bridge_source_status": "valid",
        "project_browser_autonomous_execution_bridge_runtime_posture": runtime_posture,
        "project_browser_autonomous_execution_bridge_runtime_metadata_only": True,
        "project_browser_autonomous_execution_bridge_runtime_no_execution": True,
        "project_browser_autonomous_execution_bridge_runtime_no_browser": True,
        "project_browser_autonomous_execution_bridge_runtime_no_prompt_send": True,
        "project_browser_autonomous_execution_bridge_runtime_no_md_write": True,
        "project_browser_autonomous_execution_bridge_runtime_no_shell_execution": True,
        "project_browser_autonomous_execution_bridge_runtime_no_queue_mutation": True,
        "project_browser_autonomous_execution_bridge_runtime_no_retry_execution": True,
        "project_browser_autonomous_execution_bridge_runtime_no_continuation_execution": True,
        "project_browser_autonomous_execution_bridge_runtime_no_multi_step_execution": True,
        "project_browser_autonomous_execution_bridge_runtime_no_background_runtime": True,
    }


def _build_project_browser_autonomous_multistep_budget_state(
    *,
    autonomous_action_kind: str,
    autonomous_run_ledger_status: str,
    autonomous_action_receipt_status: str,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
    prior_compact_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    action_kind = _normalize_text(autonomous_action_kind, default="none")
    ledger_status = _normalize_text(
        autonomous_run_ledger_status,
        default="insufficient_truth",
    )
    action_receipt_status = _normalize_text(
        autonomous_action_receipt_status,
        default="insufficient_truth",
    )
    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )
    prior = dict(prior_compact_state or {})

    controller_max_steps = 3
    controller_hard_limit = 5
    max_failures = 2
    same_prompt_retry_limit = 2
    codex_execution_limit = 1
    codex_repair_limit = 1

    runtime_posture = [
        "metadata_only",
        "no_step_execution",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_browser_action",
        "no_queue_mutation",
        "no_retry_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]
    runtime_posture = [
        token
        for token in runtime_posture
        if token in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_RUNTIME_POSTURES
        or token in {
            "metadata_only",
            "no_step_execution",
            "no_prompt_send",
            "no_md_write",
            "no_shell_execution",
            "no_browser_action",
            "no_queue_mutation",
            "no_retry_execution",
            "no_continuation_execution",
            "no_loop_execution",
            "no_background_runtime",
        }
    ]

    def _insufficient_truth_state(*, source_status: str) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in {"valid", "inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        return {
            "project_browser_autonomous_multistep_budget_status": "insufficient_truth",
            "project_browser_autonomous_multistep_permission": "insufficient_truth",
            "project_browser_autonomous_multistep_next_step_candidate": "none",
            "project_browser_autonomous_multistep_stop_reason": "insufficient_truth",
            "project_browser_autonomous_multistep_controller_max_steps": controller_max_steps,
            "project_browser_autonomous_multistep_controller_hard_limit": controller_hard_limit,
            "project_browser_autonomous_multistep_current_step_count": 0,
            "project_browser_autonomous_multistep_remaining_steps": controller_max_steps,
            "project_browser_autonomous_multistep_max_failures": max_failures,
            "project_browser_autonomous_multistep_current_failure_count": 0,
            "project_browser_autonomous_multistep_remaining_failures": max_failures,
            "project_browser_autonomous_multistep_same_prompt_retry_limit": same_prompt_retry_limit,
            "project_browser_autonomous_multistep_same_prompt_retry_count": 0,
            "project_browser_autonomous_multistep_same_prompt_retry_remaining": same_prompt_retry_limit,
            "project_browser_autonomous_multistep_codex_execution_limit": codex_execution_limit,
            "project_browser_autonomous_multistep_codex_repair_limit": codex_repair_limit,
            "project_browser_autonomous_multistep_budget_source_status": normalized_source_status,
            "project_browser_autonomous_multistep_runtime_posture": runtime_posture,
            "project_browser_autonomous_multistep_runtime_metadata_only": True,
            "project_browser_autonomous_multistep_runtime_no_step_execution": True,
            "project_browser_autonomous_multistep_runtime_no_prompt_send": True,
            "project_browser_autonomous_multistep_runtime_no_md_write": True,
            "project_browser_autonomous_multistep_runtime_no_shell_execution": True,
            "project_browser_autonomous_multistep_runtime_no_browser_action": True,
            "project_browser_autonomous_multistep_runtime_no_queue_mutation": True,
            "project_browser_autonomous_multistep_runtime_no_retry_execution": True,
            "project_browser_autonomous_multistep_runtime_no_continuation_execution": True,
            "project_browser_autonomous_multistep_runtime_no_loop_execution": True,
            "project_browser_autonomous_multistep_runtime_no_background_runtime": True,
        }

    if action_kind not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_KINDS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if ledger_status not in _PROJECT_BROWSER_AUTONOMOUS_RUN_LEDGER_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if action_receipt_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_RECEIPT_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")

    # Read structured prior counters only; default to zero when unavailable.
    raw_step_count = prior.get("project_browser_autonomous_multistep_current_step_count")
    raw_failure_count = prior.get("project_browser_autonomous_multistep_current_failure_count")
    raw_retry_count = prior.get("project_browser_autonomous_multistep_same_prompt_retry_count")
    raw_retry_count_fallback = prior.get("project_browser_retry_count_current")
    raw_retry_limit_override = prior.get("project_browser_autonomous_multistep_same_prompt_retry_limit")
    raw_remaining_steps = prior.get("project_browser_autonomous_multistep_remaining_steps")
    raw_remaining_failures = prior.get("project_browser_autonomous_multistep_remaining_failures")
    raw_retry_remaining = prior.get("project_browser_autonomous_multistep_same_prompt_retry_remaining")

    def _read_optional_non_negative_int(value: Any) -> tuple[int, bool]:
        if value is None or value == "":
            return 0, False
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if not text:
                return 0, False
            if text.isdigit():
                return int(text), False
            return 0, True
        return 0, True

    step_count, step_count_invalid = _read_optional_non_negative_int(raw_step_count)
    failure_count, failure_count_invalid = _read_optional_non_negative_int(raw_failure_count)
    retry_count, retry_count_invalid = _read_optional_non_negative_int(raw_retry_count)
    retry_count_fb, retry_count_fb_invalid = _read_optional_non_negative_int(raw_retry_count_fallback)
    retry_limit_override, retry_limit_override_invalid = _read_optional_non_negative_int(raw_retry_limit_override)

    if raw_retry_count in {None, ""} and raw_retry_count_fallback not in {None, ""}:
        retry_count = retry_count_fb
        retry_count_invalid = retry_count_fb_invalid

    if retry_limit_override and not retry_limit_override_invalid:
        same_prompt_retry_limit = retry_limit_override

    source_inconsistent = bool(
        step_count_invalid
        or failure_count_invalid
        or retry_count_invalid
        or retry_limit_override_invalid
    )
    if controller_max_steps > controller_hard_limit:
        source_inconsistent = True
    if step_count > controller_hard_limit:
        source_inconsistent = True

    remaining_steps = max(0, controller_max_steps - step_count)
    remaining_failures = max(0, max_failures - failure_count)
    same_prompt_retry_remaining = max(0, same_prompt_retry_limit - retry_count)

    expected_remaining_steps, expected_remaining_steps_invalid = _read_optional_non_negative_int(
        raw_remaining_steps
    )
    expected_remaining_failures, expected_remaining_failures_invalid = _read_optional_non_negative_int(
        raw_remaining_failures
    )
    expected_retry_remaining, expected_retry_remaining_invalid = _read_optional_non_negative_int(
        raw_retry_remaining
    )
    if expected_remaining_steps_invalid or expected_remaining_failures_invalid or expected_retry_remaining_invalid:
        source_inconsistent = True
    if raw_remaining_steps not in {None, ""} and expected_remaining_steps != remaining_steps:
        source_inconsistent = True
    if raw_remaining_failures not in {None, ""} and expected_remaining_failures != remaining_failures:
        source_inconsistent = True
    if raw_retry_remaining not in {None, ""} and expected_retry_remaining != same_prompt_retry_remaining:
        source_inconsistent = True

    if source_inconsistent:
        return _insufficient_truth_state(source_status="inconsistent")

    missing_pr113_pr114 = bool(
        ledger_status == "insufficient_truth"
        or action_receipt_status == "insufficient_truth"
        or duplicate_status == "insufficient_truth"
        or safety_switch_status == "insufficient_truth"
        or execution_permission == "insufficient_truth"
    )
    if missing_pr113_pr114:
        return _insufficient_truth_state(source_status="insufficient_truth")

    pr113_pr114_conflict = bool(
        (execution_permission == "allowed_candidate" and action_receipt_status != "ready")
        or (ledger_status == "inactive" and safety_switch_status != "inactive")
        or (
            ledger_status in {"blocked", "duplicate_risk", "pause_required", "human_review_required"}
            and execution_permission == "allowed_candidate"
        )
    )
    if pr113_pr114_conflict:
        return _insufficient_truth_state(source_status="inconsistent")

    if bridge_source_status == "insufficient_truth":
        return _insufficient_truth_state(source_status="insufficient_truth")
    if bridge_source_status == "inconsistent":
        return _insufficient_truth_state(source_status="inconsistent")

    next_step_candidate = {
        "use_md_update_draft": "apply_md_update",
        "use_next_prompt_draft": "send_next_prompt",
        "retry_same_prompt": "retry_same_prompt",
        "pause_for_login": "pause_for_login",
        "human_review": "human_review",
        "stop": "stop",
        "none": "none",
    }.get(action_kind, "none")

    multistep_permission = bridge_permission
    budget_status = "blocked"
    stop_reason = "bridge_not_ready"
    budget_source_status = "valid"

    if bridge_status == "inactive":
        budget_status = "inactive"
        stop_reason = "none"
    elif bridge_status == "insufficient_truth" or bridge_permission == "insufficient_truth":
        return _insufficient_truth_state(source_status="insufficient_truth")
    elif bridge_permission == "pause_required":
        budget_status = "pause_required"
        stop_reason = "pause_required"
    elif bridge_permission == "human_review_required":
        budget_status = "human_review_required"
        stop_reason = "human_review_required"
    elif bridge_status != "ready":
        budget_status = "blocked"
        multistep_permission = "blocked"
        stop_reason = "blocked_by_bridge"
    elif bridge_permission == "blocked":
        budget_status = "blocked"
        stop_reason = "blocked_by_bridge"
    elif bridge_permission == "allowed_candidate":
        budget_status = "ready"
        stop_reason = "none"
    else:
        return _insufficient_truth_state(source_status="insufficient_truth")

    duplicate_risk_present = bool(
        ledger_status == "duplicate_risk"
        or action_receipt_status == "duplicate_risk"
        or duplicate_status
        in {
            "duplicate_action",
            "duplicate_prompt",
            "duplicate_md_update",
            "duplicate_pause",
            "duplicate_human_review",
        }
    )
    action_receipt_ready = action_receipt_status == "ready"
    step_budget_exhausted = step_count >= controller_max_steps
    failure_budget_exhausted = failure_count >= max_failures
    retry_budget_exhausted = (
        next_step_candidate == "retry_same_prompt"
        and same_prompt_retry_remaining <= 0
    )

    if budget_status == "ready" and multistep_permission == "allowed_candidate":
        if duplicate_risk_present:
            budget_status = "blocked"
            multistep_permission = "blocked"
            stop_reason = "duplicate_risk"
        elif not action_receipt_ready:
            budget_status = "blocked"
            multistep_permission = "blocked"
            stop_reason = "action_receipt_not_ready"
        elif retry_budget_exhausted:
            budget_status = "blocked"
            multistep_permission = "blocked"
            stop_reason = "retry_budget_exhausted"
        elif failure_budget_exhausted:
            budget_status = "blocked"
            multistep_permission = "blocked"
            stop_reason = "failure_budget_exhausted"
        elif step_budget_exhausted:
            budget_status = "blocked"
            multistep_permission = "blocked"
            stop_reason = "step_budget_exhausted"

    if budget_status == "inactive":
        next_step_candidate = "none"
    if budget_status in {"pause_required", "human_review_required"} and next_step_candidate == "none":
        next_step_candidate = "pause_for_login" if budget_status == "pause_required" else "human_review"
    if budget_status == "blocked" and multistep_permission == "allowed_candidate":
        multistep_permission = "blocked"
    if budget_status == "ready" and multistep_permission != "allowed_candidate":
        return _insufficient_truth_state(source_status="inconsistent")

    if budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if stop_reason not in {
        "none",
        "bridge_not_ready",
        "blocked_by_bridge",
        "pause_required",
        "human_review_required",
        "duplicate_risk",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "action_receipt_not_ready",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")

    return {
        "project_browser_autonomous_multistep_budget_status": budget_status,
        "project_browser_autonomous_multistep_permission": multistep_permission,
        "project_browser_autonomous_multistep_next_step_candidate": next_step_candidate,
        "project_browser_autonomous_multistep_stop_reason": stop_reason,
        "project_browser_autonomous_multistep_controller_max_steps": controller_max_steps,
        "project_browser_autonomous_multistep_controller_hard_limit": controller_hard_limit,
        "project_browser_autonomous_multistep_current_step_count": step_count,
        "project_browser_autonomous_multistep_remaining_steps": remaining_steps,
        "project_browser_autonomous_multistep_max_failures": max_failures,
        "project_browser_autonomous_multistep_current_failure_count": failure_count,
        "project_browser_autonomous_multistep_remaining_failures": remaining_failures,
        "project_browser_autonomous_multistep_same_prompt_retry_limit": same_prompt_retry_limit,
        "project_browser_autonomous_multistep_same_prompt_retry_count": retry_count,
        "project_browser_autonomous_multistep_same_prompt_retry_remaining": same_prompt_retry_remaining,
        "project_browser_autonomous_multistep_codex_execution_limit": codex_execution_limit,
        "project_browser_autonomous_multistep_codex_repair_limit": codex_repair_limit,
        "project_browser_autonomous_multistep_budget_source_status": budget_source_status,
        "project_browser_autonomous_multistep_runtime_posture": runtime_posture,
        "project_browser_autonomous_multistep_runtime_metadata_only": True,
        "project_browser_autonomous_multistep_runtime_no_step_execution": True,
        "project_browser_autonomous_multistep_runtime_no_prompt_send": True,
        "project_browser_autonomous_multistep_runtime_no_md_write": True,
        "project_browser_autonomous_multistep_runtime_no_shell_execution": True,
        "project_browser_autonomous_multistep_runtime_no_browser_action": True,
        "project_browser_autonomous_multistep_runtime_no_queue_mutation": True,
        "project_browser_autonomous_multistep_runtime_no_retry_execution": True,
        "project_browser_autonomous_multistep_runtime_no_continuation_execution": True,
        "project_browser_autonomous_multistep_runtime_no_loop_execution": True,
        "project_browser_autonomous_multistep_runtime_no_background_runtime": True,
    }


def _build_project_browser_autonomous_step_wrapper_state(
    *,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_stop_reason: str,
    autonomous_multistep_budget_source_status: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
    prior_compact_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    multistep_stop_reason = _normalize_text(
        autonomous_multistep_stop_reason,
        default="insufficient_truth",
    )
    budget_source_status = _normalize_text(
        autonomous_multistep_budget_source_status,
        default="insufficient_truth",
    )
    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})
    prior = dict(prior_compact_state or {})

    runtime_posture = [
        "metadata_only",
        "no_multi_step_loop",
        "no_prompt_send",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_codex_execution",
        "no_shell_execution",
        "no_test_execution",
        "no_queue_drain",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        wrapper_status: str,
        step_action: str,
        score_status: str,
        safety_score: int,
        score_band: str,
        auto_approval_posture: str,
        execution_status: str,
        execution_result: str,
        receipt_status: str,
        receipt_kind: str,
        stop_reason: str,
        batch_posture: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_step_wrapper_status": wrapper_status,
            "project_browser_autonomous_step_action": step_action,
            "project_browser_autonomous_step_score_status": score_status,
            "project_browser_autonomous_step_safety_score": safety_score,
            "project_browser_autonomous_step_score_band": score_band,
            "project_browser_autonomous_step_auto_approval_posture": auto_approval_posture,
            "project_browser_autonomous_step_execution_status": execution_status,
            "project_browser_autonomous_step_execution_result": execution_result,
            "project_browser_autonomous_step_receipt_status": receipt_status,
            "project_browser_autonomous_step_receipt_kind": receipt_kind,
            "project_browser_autonomous_step_stop_reason": stop_reason,
            "project_browser_autonomous_step_batch_posture": batch_posture,
            "project_browser_autonomous_step_runtime_posture": runtime_posture,
            "project_browser_autonomous_step_runtime_metadata_only": True,
            "project_browser_autonomous_step_runtime_no_multi_step_loop": True,
            "project_browser_autonomous_step_runtime_no_prompt_send": True,
            "project_browser_autonomous_step_runtime_no_browser_action": True,
            "project_browser_autonomous_step_runtime_no_playwright": True,
            "project_browser_autonomous_step_runtime_no_dom_interaction": True,
            "project_browser_autonomous_step_runtime_no_codex_execution": True,
            "project_browser_autonomous_step_runtime_no_shell_execution": True,
            "project_browser_autonomous_step_runtime_no_test_execution": True,
            "project_browser_autonomous_step_runtime_no_queue_drain": True,
            "project_browser_autonomous_step_runtime_no_retry_execution": True,
            "project_browser_autonomous_step_runtime_no_repair_execution": True,
            "project_browser_autonomous_step_runtime_no_restart_execution": True,
            "project_browser_autonomous_step_runtime_no_approval_execution": True,
            "project_browser_autonomous_step_runtime_no_background_runtime": True,
        }

    def _insufficient_truth_state() -> dict[str, Any]:
        return _base_state(
            wrapper_status="insufficient_truth",
            step_action="none",
            score_status="insufficient_truth",
            safety_score=0,
            score_band="insufficient_truth",
            auto_approval_posture="insufficient_truth",
            execution_status="insufficient_truth",
            execution_result="insufficient_truth",
            receipt_status="insufficient_truth",
            receipt_kind="none",
            stop_reason="insufficient_truth",
            batch_posture="insufficient_truth",
        )

    if budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if multistep_stop_reason not in {
        "none",
        "bridge_not_ready",
        "blocked_by_bridge",
        "pause_required",
        "human_review_required",
        "duplicate_risk",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "action_receipt_not_ready",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if budget_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state()
    if bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state()
    if bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state()
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state()
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state()
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state()
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state()

    if budget_source_status == "inconsistent" or bridge_source_status == "inconsistent":
        return _insufficient_truth_state()
    if budget_source_status == "insufficient_truth" or bridge_source_status == "insufficient_truth":
        return _insufficient_truth_state()

    def _map_multistep_stop_reason(reason: str) -> str:
        if reason in {"bridge_not_ready", "blocked_by_bridge", "action_receipt_not_ready"}:
            return "bridge_or_budget_not_ready"
        if reason in {
            "duplicate_risk",
            "retry_budget_exhausted",
            "failure_budget_exhausted",
            "step_budget_exhausted",
            "insufficient_truth",
        }:
            return reason
        if reason == "pause_required":
            return "pause_for_login"
        if reason == "human_review_required":
            return "human_review_required"
        if reason == "none":
            return "none"
        return "insufficient_truth"

    if budget_status == "inactive":
        return _base_state(
            wrapper_status="inactive",
            step_action="none",
            score_status="unavailable",
            safety_score=0,
            score_band="insufficient_truth",
            auto_approval_posture="insufficient_truth",
            execution_status="not_attempted",
            execution_result="not_executed",
            receipt_status="not_created",
            receipt_kind="none",
            stop_reason="none",
            batch_posture="not_started",
        )
    if budget_status == "pause_required":
        return _base_state(
            wrapper_status="pause_required",
            step_action="pause_for_login",
            score_status="unavailable",
            safety_score=0,
            score_band="human_review_recommended",
            auto_approval_posture="pause_required",
            execution_status="pause_required",
            execution_result="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_step_receipt",
            stop_reason="pause_for_login",
            batch_posture="batch_pause_required",
        )
    if budget_status == "human_review_required":
        return _base_state(
            wrapper_status="human_review_required",
            step_action="human_review",
            score_status="unavailable",
            safety_score=0,
            score_band="human_review_recommended",
            auto_approval_posture="blocked_needs_human",
            execution_status="human_review_required",
            execution_result="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_step_receipt",
            stop_reason="human_review_required",
            batch_posture="batch_human_review_required",
        )
    if budget_status == "blocked":
        mapped_stop_reason = _map_multistep_stop_reason(multistep_stop_reason)
        if mapped_stop_reason == "insufficient_truth":
            return _insufficient_truth_state()
        return _base_state(
            wrapper_status="blocked",
            step_action=(
                next_step_candidate
                if next_step_candidate in {
                    "apply_md_update",
                    "send_next_prompt",
                    "retry_same_prompt",
                    "pause_for_login",
                    "human_review",
                    "stop",
                }
                else "none"
            ),
            score_status="unavailable",
            safety_score=0,
            score_band="blocked",
            auto_approval_posture=(
                "blocked_by_duplicate"
                if mapped_stop_reason == "duplicate_risk"
                else "blocked_by_budget"
            ),
            execution_status="blocked",
            execution_result="blocked",
            receipt_status="blocked",
            receipt_kind="blocked_step_receipt",
            stop_reason=mapped_stop_reason,
            batch_posture="batch_blocked",
        )
    if budget_status == "insufficient_truth":
        return _insufficient_truth_state()
    if budget_status != "ready" or multistep_permission != "allowed_candidate":
        return _insufficient_truth_state()

    remaining_steps = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps"),
        default=0,
    )
    remaining_failures = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures"),
        default=0,
    )
    same_prompt_retry_remaining = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_same_prompt_retry_remaining"),
        default=0,
    )

    score_keys = (
        "project_browser_autonomous_step_safety_score",
        "project_browser_autonomous_safety_score",
        "project_browser_autonomous_multistep_safety_score",
        "project_browser_autonomous_candidate_score",
        "project_browser_response_score",
        "project_browser_quality_score",
    )
    score_values: list[int] = []
    score_inconsistent = False
    for key in score_keys:
        if key not in prior:
            continue
        raw_value = prior.get(key)
        if raw_value in {None, ""}:
            continue
        if isinstance(raw_value, bool):
            score_inconsistent = True
            continue
        if isinstance(raw_value, int):
            parsed_value = raw_value
        elif isinstance(raw_value, str) and raw_value.strip().isdigit():
            parsed_value = int(raw_value.strip())
        else:
            score_inconsistent = True
            continue
        if parsed_value < 0 or parsed_value > 100:
            score_inconsistent = True
            continue
        score_values.append(parsed_value)

    if score_inconsistent:
        return _insufficient_truth_state()
    if not score_values:
        return _base_state(
            wrapper_status="insufficient_truth",
            step_action=next_step_candidate if next_step_candidate != "none" else "none",
            score_status="unavailable",
            safety_score=0,
            score_band="insufficient_truth",
            auto_approval_posture="insufficient_truth",
            execution_status="insufficient_truth",
            execution_result="insufficient_truth",
            receipt_status="insufficient_truth",
            receipt_kind="none",
            stop_reason="insufficient_truth",
            batch_posture="insufficient_truth",
        )
    score_value = score_values[0]
    if any(value != score_value for value in score_values[1:]):
        return _insufficient_truth_state()

    if score_value >= 95:
        score_band = "auto_safe_without_approval"
    elif score_value >= 90:
        score_band = "auto_candidate"
    elif score_value >= 75:
        score_band = "human_review_recommended"
    else:
        score_band = "blocked"

    duplicate_clear = duplicate_status in {"clear", "no_duplicate", "not_duplicate"}
    pr114_pr115_clear = bool(
        safety_switch_status in {"enabled", "inactive"}
        and manual_override_status in {"inactive", "clear"}
        and safe_stop_status in {"not_required", "pause_after_current_step"}
        and execution_permission == "allowed_candidate"
        and bridge_status == "ready"
        and bridge_permission == "allowed_candidate"
        and bridge_source_status == "valid"
    )
    retry_budget_clear = bool(
        next_step_candidate != "retry_same_prompt" or same_prompt_retry_remaining > 0
    )
    budget_clear = bool(remaining_steps > 0 and remaining_failures > 0 and retry_budget_clear)
    step_action = (
        next_step_candidate
        if next_step_candidate
        in {
            "apply_md_update",
            "send_next_prompt",
            "retry_same_prompt",
            "pause_for_login",
            "human_review",
            "stop",
        }
        else "none"
    )
    if step_action == "none":
        return _insufficient_truth_state()

    if not budget_clear:
        if remaining_steps <= 0:
            blocked_reason = "step_budget_exhausted"
        elif remaining_failures <= 0:
            blocked_reason = "failure_budget_exhausted"
        else:
            blocked_reason = "retry_budget_exhausted"
        return _base_state(
            wrapper_status="blocked",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band="blocked",
            auto_approval_posture="blocked_by_budget",
            execution_status="blocked",
            execution_result="blocked",
            receipt_status="blocked",
            receipt_kind="blocked_step_receipt",
            stop_reason=blocked_reason,
            batch_posture="batch_blocked",
        )

    if not duplicate_clear:
        return _base_state(
            wrapper_status="blocked",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band="blocked",
            auto_approval_posture="blocked_by_duplicate",
            execution_status="blocked",
            execution_result="blocked",
            receipt_status="blocked",
            receipt_kind="blocked_step_receipt",
            stop_reason="duplicate_risk",
            batch_posture="batch_blocked",
        )

    if not pr114_pr115_clear:
        return _base_state(
            wrapper_status="blocked",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band=score_band,
            auto_approval_posture="blocked_needs_human",
            execution_status="blocked",
            execution_result="blocked",
            receipt_status="blocked",
            receipt_kind="blocked_step_receipt",
            stop_reason="bridge_or_budget_not_ready",
            batch_posture="batch_blocked",
        )

    low_risk_action = step_action in {
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }
    hard_gates_clear = bool(
        budget_status == "ready"
        and multistep_permission == "allowed_candidate"
        and step_action != "none"
        and remaining_steps > 0
        and remaining_failures > 0
        and retry_budget_clear
        and duplicate_clear
        and pr114_pr115_clear
        and low_risk_action
        and score_band == "auto_safe_without_approval"
    )

    if score_band == "auto_safe_without_approval" and hard_gates_clear:
        return _base_state(
            wrapper_status="auto_safe",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band=score_band,
            auto_approval_posture="allowed_without_human",
            execution_status="receipt_ready",
            execution_result="candidate_recorded",
            receipt_status="ready",
            receipt_kind="auto_safe_step_receipt",
            stop_reason="one_step_recorded",
            batch_posture="batch_continue_candidate",
        )

    if score_band == "auto_candidate":
        return _base_state(
            wrapper_status="ready",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band=score_band,
            auto_approval_posture="blocked_needs_human",
            execution_status="human_review_required",
            execution_result="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_step_receipt",
            stop_reason="score_below_auto_safe",
            batch_posture="batch_human_review_required",
        )
    if score_band == "human_review_recommended":
        return _base_state(
            wrapper_status="human_review_required",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band=score_band,
            auto_approval_posture="blocked_needs_human",
            execution_status="human_review_required",
            execution_result="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_step_receipt",
            stop_reason="score_below_auto_safe",
            batch_posture="batch_human_review_required",
        )
    if score_band == "blocked":
        return _base_state(
            wrapper_status="blocked",
            step_action=step_action,
            score_status="scored",
            safety_score=score_value,
            score_band=score_band,
            auto_approval_posture="blocked_needs_human",
            execution_status="blocked",
            execution_result="blocked",
            receipt_status="blocked",
            receipt_kind="blocked_step_receipt",
            stop_reason="score_below_auto_safe",
            batch_posture="batch_blocked",
        )

    return _insufficient_truth_state()


def _build_project_browser_autonomous_batch_evaluation_state(
    *,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_stop_reason: str,
    autonomous_multistep_budget_source_status: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
    autonomous_step_wrapper_status: str,
    autonomous_step_action: str,
    autonomous_step_score_status: str,
    autonomous_step_score_band: str,
    autonomous_step_auto_approval_posture: str,
    autonomous_step_execution_result: str,
    autonomous_step_receipt_status: str,
    autonomous_step_stop_reason: str,
    autonomous_step_batch_posture: str,
) -> dict[str, Any]:
    budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    multistep_stop_reason = _normalize_text(
        autonomous_multistep_stop_reason,
        default="insufficient_truth",
    )
    budget_source_status = _normalize_text(
        autonomous_multistep_budget_source_status,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )

    step_wrapper_status = _normalize_text(
        autonomous_step_wrapper_status,
        default="insufficient_truth",
    )
    step_action = _normalize_text(autonomous_step_action, default="none")
    step_score_status = _normalize_text(
        autonomous_step_score_status,
        default="insufficient_truth",
    )
    step_score_band = _normalize_text(
        autonomous_step_score_band,
        default="insufficient_truth",
    )
    step_auto_approval_posture = _normalize_text(
        autonomous_step_auto_approval_posture,
        default="insufficient_truth",
    )
    step_execution_result = _normalize_text(
        autonomous_step_execution_result,
        default="insufficient_truth",
    )
    step_receipt_status = _normalize_text(
        autonomous_step_receipt_status,
        default="insufficient_truth",
    )
    step_stop_reason = _normalize_text(
        autonomous_step_stop_reason,
        default="insufficient_truth",
    )
    step_batch_posture = _normalize_text(
        autonomous_step_batch_posture,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        batch_evaluation_status: str,
        batch_continue_permission: str,
        batch_continue_reason: str,
        batch_next_action: str,
        batch_score_summary_status: str,
        batch_score_summary: str,
        observability_status: str,
        current_phase: str,
        last_action: str,
        last_result: str,
        last_stop_reason: str,
        remaining_budget_status: str,
        operator_summary_status: str,
        operator_summary_kind: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_batch_evaluation_status": batch_evaluation_status,
            "project_browser_autonomous_batch_continue_permission": batch_continue_permission,
            "project_browser_autonomous_batch_continue_reason": batch_continue_reason,
            "project_browser_autonomous_batch_next_action": batch_next_action,
            "project_browser_autonomous_batch_score_summary_status": batch_score_summary_status,
            "project_browser_autonomous_batch_score_summary": batch_score_summary,
            "project_browser_autonomous_observability_status": observability_status,
            "project_browser_autonomous_current_phase": current_phase,
            "project_browser_autonomous_last_action": last_action,
            "project_browser_autonomous_last_result": last_result,
            "project_browser_autonomous_last_stop_reason": last_stop_reason,
            "project_browser_autonomous_remaining_budget_status": remaining_budget_status,
            "project_browser_autonomous_operator_summary_status": operator_summary_status,
            "project_browser_autonomous_operator_summary_kind": operator_summary_kind,
            "project_browser_autonomous_observability_runtime_posture": runtime_posture,
            "project_browser_autonomous_observability_runtime_metadata_only": True,
            "project_browser_autonomous_observability_runtime_no_next_step_start": True,
            "project_browser_autonomous_observability_runtime_no_prompt_send": True,
            "project_browser_autonomous_observability_runtime_no_md_write": True,
            "project_browser_autonomous_observability_runtime_no_shell_execution": True,
            "project_browser_autonomous_observability_runtime_no_codex_execution": True,
            "project_browser_autonomous_observability_runtime_no_browser_action": True,
            "project_browser_autonomous_observability_runtime_no_playwright": True,
            "project_browser_autonomous_observability_runtime_no_dom_interaction": True,
            "project_browser_autonomous_observability_runtime_no_queue_mutation": True,
            "project_browser_autonomous_observability_runtime_no_retry_execution": True,
            "project_browser_autonomous_observability_runtime_no_repair_execution": True,
            "project_browser_autonomous_observability_runtime_no_restart_execution": True,
            "project_browser_autonomous_observability_runtime_no_approval_execution": True,
            "project_browser_autonomous_observability_runtime_no_continuation_execution": True,
            "project_browser_autonomous_observability_runtime_no_loop_execution": True,
            "project_browser_autonomous_observability_runtime_no_background_runtime": True,
        }

    def _insufficient_truth_state() -> dict[str, Any]:
        return _base_state(
            batch_evaluation_status="insufficient_truth",
            batch_continue_permission="insufficient_truth",
            batch_continue_reason="insufficient_truth",
            batch_next_action="none",
            batch_score_summary_status="insufficient_truth",
            batch_score_summary="insufficient_truth",
            observability_status="insufficient_truth",
            current_phase="insufficient_truth",
            last_action="none",
            last_result="insufficient_truth",
            last_stop_reason="insufficient_truth",
            remaining_budget_status="insufficient_truth",
            operator_summary_status="insufficient_truth",
            operator_summary_kind="insufficient_truth_summary",
        )

    if budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if multistep_stop_reason not in {
        "none",
        "bridge_not_ready",
        "blocked_by_bridge",
        "pause_required",
        "human_review_required",
        "duplicate_risk",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "action_receipt_not_ready",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if budget_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state()
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state()
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state()
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state()
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state()
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state()
    if bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state()
    if step_wrapper_status not in {
        "inactive",
        "ready",
        "auto_safe",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_action not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if step_score_status not in {"unavailable", "scored", "insufficient_truth"}:
        return _insufficient_truth_state()
    if step_score_band not in {
        "auto_safe_without_approval",
        "auto_candidate",
        "human_review_recommended",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_auto_approval_posture not in {
        "allowed_without_human",
        "blocked_needs_human",
        "pause_required",
        "blocked_by_budget",
        "blocked_by_duplicate",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_execution_result not in {
        "not_executed",
        "candidate_recorded",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_stop_reason not in {
        "none",
        "one_step_recorded",
        "score_below_auto_safe",
        "bridge_or_budget_not_ready",
        "duplicate_risk",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "pause_for_login",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_batch_posture not in {
        "not_started",
        "one_step_recorded",
        "batch_continue_candidate",
        "batch_blocked",
        "batch_pause_required",
        "batch_human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()

    if (
        budget_source_status in {"inconsistent", "insufficient_truth"}
        or bridge_source_status in {"inconsistent", "insufficient_truth"}
    ):
        return _insufficient_truth_state()

    remaining_steps = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps"),
        default=0,
    )
    remaining_failures = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures"),
        default=0,
    )
    retry_remaining = _as_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_same_prompt_retry_remaining"),
        default=0,
    )

    retry_exhausted = bool(step_action == "retry_same_prompt" and retry_remaining <= 0)
    duplicate_risk_present = duplicate_status not in {"clear", "no_duplicate", "not_duplicate"}
    budget_exhausted = remaining_steps <= 0
    failure_exhausted = remaining_failures <= 0

    def _map_stop_reason(value: str) -> str:
        if value in {"none", "one_step_recorded", "score_below_auto_safe", "duplicate_risk"}:
            return value
        if value in {"step_budget_exhausted", "bridge_or_budget_not_ready"}:
            return "budget_exhausted"
        if value == "failure_budget_exhausted":
            return "failure_budget_exhausted"
        if value == "retry_budget_exhausted":
            return "retry_budget_exhausted"
        if value == "pause_for_login":
            return "pause_for_login"
        if value == "human_review_required":
            return "human_review_required"
        return "insufficient_truth"

    mapped_last_stop_reason = _map_stop_reason(step_stop_reason)
    if mapped_last_stop_reason == "insufficient_truth":
        return _insufficient_truth_state()

    score_summary_status = (
        "available"
        if step_score_status == "scored"
        else ("unavailable" if step_score_status == "unavailable" else "insufficient_truth")
    )
    score_summary = (
        step_score_band
        if score_summary_status == "available"
        else ("insufficient_truth" if score_summary_status == "insufficient_truth" else "insufficient_truth")
    )
    if score_summary_status == "insufficient_truth":
        return _insufficient_truth_state()

    remaining_budget_status = "available"
    if budget_exhausted or failure_exhausted or retry_exhausted:
        remaining_budget_status = "exhausted"
    if step_wrapper_status == "inactive":
        remaining_budget_status = "unavailable"

    if step_wrapper_status == "inactive":
        current_phase = "inactive" if budget_status == "inactive" else "budget_compiled"
        return _base_state(
            batch_evaluation_status="inactive",
            batch_continue_permission="insufficient_truth",
            batch_continue_reason="none",
            batch_next_action="none",
            batch_score_summary_status="unavailable",
            batch_score_summary="insufficient_truth",
            observability_status="unavailable",
            current_phase=current_phase,
            last_action="none",
            last_result="none",
            last_stop_reason="none",
            remaining_budget_status="unavailable",
            operator_summary_status="unavailable",
            operator_summary_kind="none",
        )
    if step_wrapper_status == "insufficient_truth":
        return _insufficient_truth_state()
    if step_wrapper_status == "pause_required":
        return _base_state(
            batch_evaluation_status="pause_required",
            batch_continue_permission="pause_required",
            batch_continue_reason="pause_required",
            batch_next_action="pause_for_login",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="pause_required",
            last_action="pause_for_login",
            last_result="pause_required",
            last_stop_reason="pause_for_login",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="pause_summary",
        )
    if step_wrapper_status == "human_review_required":
        return _base_state(
            batch_evaluation_status="human_review_required",
            batch_continue_permission="human_review_required",
            batch_continue_reason="human_review_required",
            batch_next_action="human_review",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="human_review_required",
            last_action="human_review",
            last_result="human_review_required",
            last_stop_reason="human_review_required",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="human_review_summary",
        )
    if step_wrapper_status == "blocked":
        blocked_reason = "score_below_auto_safe"
        if mapped_last_stop_reason in {
            "duplicate_risk",
            "retry_budget_exhausted",
            "failure_budget_exhausted",
            "budget_exhausted",
        }:
            blocked_reason = mapped_last_stop_reason
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason=blocked_reason,
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason=mapped_last_stop_reason,
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )

    if step_wrapper_status not in {"ready", "auto_safe"}:
        return _insufficient_truth_state()

    upstream_clear = bool(
        budget_status == "ready"
        and multistep_permission == "allowed_candidate"
        and execution_permission == "allowed_candidate"
        and bridge_status == "ready"
        and bridge_permission == "allowed_candidate"
        and bridge_source_status == "valid"
        and safety_switch_status in {"enabled", "inactive"}
        and manual_override_status in {"inactive", "clear"}
        and safe_stop_status == "not_required"
    )

    if budget_exhausted:
        return _base_state(
            batch_evaluation_status="stopped",
            batch_continue_permission="blocked",
            batch_continue_reason="budget_exhausted",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="stopped",
            last_action=step_action,
            last_result=step_execution_result if step_execution_result != "insufficient_truth" else "none",
            last_stop_reason="budget_exhausted",
            remaining_budget_status="exhausted",
            operator_summary_status="compact_available",
            operator_summary_kind="stopped_summary",
        )
    if failure_exhausted:
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason="failure_budget_exhausted",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason="failure_budget_exhausted",
            remaining_budget_status="exhausted",
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )
    if retry_exhausted:
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason="retry_budget_exhausted",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason="retry_budget_exhausted",
            remaining_budget_status="exhausted",
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )
    if duplicate_risk_present:
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason="duplicate_risk",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason="duplicate_risk",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )
    if step_receipt_status != "ready":
        return _base_state(
            batch_evaluation_status="stopped",
            batch_continue_permission="blocked",
            batch_continue_reason="step_receipt_missing",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="stopped",
            last_action=step_action,
            last_result=step_execution_result if step_execution_result != "insufficient_truth" else "none",
            last_stop_reason="insufficient_truth",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="stopped_summary",
        )
    if not upstream_clear:
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason="insufficient_truth",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason="insufficient_truth",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )

    if step_score_band == "auto_safe_without_approval":
        if (
            step_auto_approval_posture == "allowed_without_human"
            and step_batch_posture == "batch_continue_candidate"
        ):
            return _base_state(
                batch_evaluation_status="continue_candidate",
                batch_continue_permission="allowed_candidate",
                batch_continue_reason="score_auto_safe",
                batch_next_action="continue_later",
                batch_score_summary_status=score_summary_status,
                batch_score_summary=score_summary,
                observability_status="available",
                current_phase="batch_continue_candidate",
                last_action=step_action,
                last_result="candidate_recorded",
                last_stop_reason="one_step_recorded",
                remaining_budget_status="available",
                operator_summary_status="compact_available",
                operator_summary_kind="batch_continue_summary",
            )
        return _base_state(
            batch_evaluation_status="stopped",
            batch_continue_permission="blocked",
            batch_continue_reason="score_below_auto_safe",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="stopped",
            last_action=step_action,
            last_result=step_execution_result if step_execution_result != "insufficient_truth" else "none",
            last_stop_reason="score_below_auto_safe",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="stopped_summary",
        )
    if step_score_band == "auto_candidate":
        return _base_state(
            batch_evaluation_status="human_review_required",
            batch_continue_permission="human_review_required",
            batch_continue_reason="score_below_auto_safe",
            batch_next_action="human_review",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="human_review_required",
            last_action=step_action,
            last_result="human_review_required",
            last_stop_reason="score_below_auto_safe",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="human_review_summary",
        )
    if step_score_band == "human_review_recommended":
        return _base_state(
            batch_evaluation_status="human_review_required",
            batch_continue_permission="human_review_required",
            batch_continue_reason="human_review_required",
            batch_next_action="human_review",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="available",
            current_phase="human_review_required",
            last_action=step_action,
            last_result="human_review_required",
            last_stop_reason="human_review_required",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="human_review_summary",
        )
    if step_score_band == "blocked":
        return _base_state(
            batch_evaluation_status="blocked",
            batch_continue_permission="blocked",
            batch_continue_reason="score_below_auto_safe",
            batch_next_action="stop",
            batch_score_summary_status=score_summary_status,
            batch_score_summary=score_summary,
            observability_status="blocked",
            current_phase="blocked",
            last_action=step_action,
            last_result="blocked",
            last_stop_reason="score_below_auto_safe",
            remaining_budget_status=remaining_budget_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
        )

    return _insufficient_truth_state()


def _build_project_browser_autonomous_rolling_gate_state(
    *,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_budget_source_status: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
    autonomous_step_wrapper_status: str,
    autonomous_step_action: str,
    autonomous_step_score_band: str,
    autonomous_step_auto_approval_posture: str,
    autonomous_step_receipt_status: str,
    autonomous_step_stop_reason: str,
    autonomous_batch_evaluation_status: str,
    autonomous_batch_continue_permission: str,
    autonomous_batch_continue_reason: str,
    autonomous_batch_next_action: str,
    current_browser_ui_failure_status: str,
    current_browser_response_status: str,
    current_browser_response_assimilation_status: str,
    prior_compact_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    budget_source_status = _normalize_text(
        autonomous_multistep_budget_source_status,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )

    step_wrapper_status = _normalize_text(
        autonomous_step_wrapper_status,
        default="insufficient_truth",
    )
    step_action = _normalize_text(autonomous_step_action, default="none")
    step_score_band = _normalize_text(
        autonomous_step_score_band,
        default="insufficient_truth",
    )
    step_auto_approval_posture = _normalize_text(
        autonomous_step_auto_approval_posture,
        default="insufficient_truth",
    )
    step_receipt_status = _normalize_text(
        autonomous_step_receipt_status,
        default="insufficient_truth",
    )
    step_stop_reason = _normalize_text(
        autonomous_step_stop_reason,
        default="insufficient_truth",
    )

    batch_evaluation_status = _normalize_text(
        autonomous_batch_evaluation_status,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )
    batch_continue_reason = _normalize_text(
        autonomous_batch_continue_reason,
        default="insufficient_truth",
    )
    batch_next_action = _normalize_text(autonomous_batch_next_action, default="none")

    ui_failure_status = _normalize_text(
        current_browser_ui_failure_status,
        default="insufficient_truth",
    )
    response_status = _normalize_text(
        current_browser_response_status,
        default="insufficient_truth",
    )
    response_assimilation_status = _normalize_text(
        current_browser_response_assimilation_status,
        default="insufficient_truth",
    )
    prior = dict(prior_compact_state or {})

    runtime_posture = [
        "metadata_only",
        "no_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        rolling_gate_status: str,
        rolling_continue_permission: str,
        rolling_continue_reason: str,
        cooldown_status: str,
        cooldown_reason: str,
        retry_hardening_status: str,
        same_prompt_retry_remaining: int,
        same_failure_count: int,
        loop_risk_status: str,
        loop_risk_reason: str,
        rolling_next_action: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_rolling_gate_status": rolling_gate_status,
            "project_browser_autonomous_rolling_continue_permission": rolling_continue_permission,
            "project_browser_autonomous_rolling_continue_reason": rolling_continue_reason,
            "project_browser_autonomous_cooldown_status": cooldown_status,
            "project_browser_autonomous_cooldown_reason": cooldown_reason,
            "project_browser_autonomous_retry_hardening_status": retry_hardening_status,
            "project_browser_autonomous_same_prompt_retry_remaining": same_prompt_retry_remaining,
            "project_browser_autonomous_same_failure_count": same_failure_count,
            "project_browser_autonomous_loop_risk_status": loop_risk_status,
            "project_browser_autonomous_loop_risk_reason": loop_risk_reason,
            "project_browser_autonomous_rolling_next_action": rolling_next_action,
            "project_browser_autonomous_rolling_runtime_posture": runtime_posture,
            "project_browser_autonomous_rolling_runtime_metadata_only": True,
            "project_browser_autonomous_rolling_runtime_no_next_step_start": True,
            "project_browser_autonomous_rolling_runtime_no_prompt_send": True,
            "project_browser_autonomous_rolling_runtime_no_md_write": True,
            "project_browser_autonomous_rolling_runtime_no_shell_execution": True,
            "project_browser_autonomous_rolling_runtime_no_codex_execution": True,
            "project_browser_autonomous_rolling_runtime_no_browser_action": True,
            "project_browser_autonomous_rolling_runtime_no_playwright": True,
            "project_browser_autonomous_rolling_runtime_no_dom_interaction": True,
            "project_browser_autonomous_rolling_runtime_no_queue_mutation": True,
            "project_browser_autonomous_rolling_runtime_no_retry_execution": True,
            "project_browser_autonomous_rolling_runtime_no_repair_execution": True,
            "project_browser_autonomous_rolling_runtime_no_restart_execution": True,
            "project_browser_autonomous_rolling_runtime_no_approval_execution": True,
            "project_browser_autonomous_rolling_runtime_no_continuation_execution": True,
            "project_browser_autonomous_rolling_runtime_no_loop_execution": True,
            "project_browser_autonomous_rolling_runtime_no_background_runtime": True,
        }

    def _insufficient_truth_state() -> dict[str, Any]:
        return _base_state(
            rolling_gate_status="insufficient_truth",
            rolling_continue_permission="insufficient_truth",
            rolling_continue_reason="insufficient_truth",
            cooldown_status="insufficient_truth",
            cooldown_reason="insufficient_truth",
            retry_hardening_status="insufficient_truth",
            same_prompt_retry_remaining=0,
            same_failure_count=0,
            loop_risk_status="insufficient_truth",
            loop_risk_reason="insufficient_truth",
            rolling_next_action="none",
        )

    if budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if budget_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state()
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state()
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state()
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state()
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state()
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state()
    if bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state()
    if step_wrapper_status not in {
        "inactive",
        "ready",
        "auto_safe",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_action not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if step_score_band not in {
        "auto_safe_without_approval",
        "auto_candidate",
        "human_review_recommended",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_auto_approval_posture not in {
        "allowed_without_human",
        "blocked_needs_human",
        "pause_required",
        "blocked_by_budget",
        "blocked_by_duplicate",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_stop_reason not in {
        "none",
        "one_step_recorded",
        "score_below_auto_safe",
        "bridge_or_budget_not_ready",
        "duplicate_risk",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "pause_for_login",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_evaluation_status not in {
        "inactive",
        "continue_candidate",
        "stopped",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_continue_reason not in {
        "none",
        "score_auto_safe",
        "score_below_auto_safe",
        "budget_remaining",
        "budget_exhausted",
        "failure_budget_exhausted",
        "retry_budget_exhausted",
        "duplicate_risk",
        "pause_required",
        "human_review_required",
        "step_receipt_missing",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_next_action not in {
        "none",
        "continue_later",
        "stop",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state()

    if (
        budget_source_status in {"inconsistent", "insufficient_truth"}
        or bridge_source_status in {"inconsistent", "insufficient_truth"}
    ):
        return _insufficient_truth_state()

    required_counter_keys = (
        "project_browser_autonomous_multistep_remaining_steps",
        "project_browser_autonomous_multistep_remaining_failures",
        "project_browser_autonomous_multistep_same_prompt_retry_remaining",
    )
    if any(key not in multistep_state for key in required_counter_keys):
        return _insufficient_truth_state()

    def _read_optional_non_negative_int(value: Any) -> tuple[int, bool]:
        if value is None or value == "":
            return 0, False
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if not text:
                return 0, False
            if text.isdigit():
                return int(text), False
            return 0, True
        return 0, True

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    same_prompt_retry_remaining, same_prompt_retry_remaining_invalid = (
        _read_required_non_negative_int(
            multistep_state.get(
                "project_browser_autonomous_multistep_same_prompt_retry_remaining"
            )
        )
    )
    if (
        remaining_steps_invalid
        or remaining_failures_invalid
        or same_prompt_retry_remaining_invalid
    ):
        return _insufficient_truth_state()

    prior_same_failure_count, prior_same_failure_invalid = _read_optional_non_negative_int(
        prior.get("project_browser_autonomous_same_failure_count")
    )
    if prior_same_failure_invalid:
        return _insufficient_truth_state()
    prior_last_stop_reason = _normalize_text(
        prior.get("project_browser_autonomous_last_stop_reason"),
        default="none",
    )
    same_failure_signature = step_stop_reason if step_stop_reason != "none" else batch_continue_reason
    same_failure_count = 0
    if same_failure_signature in {
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "duplicate_risk",
        "bridge_or_budget_not_ready",
        "score_below_auto_safe",
    }:
        if prior_last_stop_reason == same_failure_signature:
            same_failure_count = max(2, prior_same_failure_count + 1)
        else:
            same_failure_count = 1
    else:
        same_failure_count = 0

    prior_ui_failure_status = _normalize_text(
        prior.get("project_browser_ui_failure_status"),
        default="",
    )
    prior_response_status = _normalize_text(
        prior.get("project_browser_response_status"),
        default="",
    )
    prior_response_assimilation_status = _normalize_text(
        prior.get("project_browser_response_assimilation_status"),
        default="",
    )

    repeated_timeout = bool(
        ui_failure_status == "loading_timeout"
        and prior_ui_failure_status == "loading_timeout"
    )
    repeated_response_unavailable = bool(
        (
            ui_failure_status == "response_unavailable"
            and prior_ui_failure_status == "response_unavailable"
        )
        or (
            response_status == "unavailable"
            and prior_response_status == "unavailable"
        )
    )
    repeated_invalid_response = bool(
        (
            response_status == "invalid_response"
            and prior_response_status == "invalid_response"
        )
        or (
            response_assimilation_status == "invalid_response"
            and prior_response_assimilation_status == "invalid_response"
        )
    )

    retry_exhausted = bool(
        next_step_candidate == "retry_same_prompt" and same_prompt_retry_remaining <= 0
    )
    failure_exhausted = remaining_failures <= 0
    step_exhausted = remaining_steps <= 0
    duplicate_prompt_or_action = duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
    }

    loop_risk_status = "clear"
    loop_risk_reason = "none"
    if duplicate_status == "duplicate_action":
        loop_risk_status = "blocked"
        loop_risk_reason = "duplicate_action"
    elif duplicate_status == "duplicate_prompt":
        loop_risk_status = "blocked"
        loop_risk_reason = "duplicate_prompt"
    elif retry_exhausted:
        loop_risk_status = "blocked"
        loop_risk_reason = "exhausted_retry_budget"
    elif same_failure_count >= 2:
        loop_risk_status = "blocked"
        loop_risk_reason = "same_failure_no_context_change"
    elif step_action == "retry_same_prompt" and same_failure_count >= 1:
        loop_risk_status = "suspected"
        loop_risk_reason = "repeated_retry_without_progress"

    cooldown_status = "not_required"
    cooldown_reason = "none"
    if retry_exhausted:
        cooldown_status = "blocked"
        cooldown_reason = "retry_budget_exhausted"
    elif repeated_timeout:
        cooldown_status = "required"
        cooldown_reason = "repeated_timeout"
    elif repeated_response_unavailable:
        cooldown_status = "required"
        cooldown_reason = "repeated_response_unavailable"
    elif repeated_invalid_response:
        cooldown_status = "required"
        cooldown_reason = "repeated_invalid_response"
    elif same_failure_count >= 2:
        cooldown_status = "required"
        cooldown_reason = "same_failure_repeated"
    elif loop_risk_status in {"suspected", "blocked"}:
        cooldown_status = "required"
        cooldown_reason = "loop_suspected"

    retry_hardening_status = "not_required"
    if step_action == "retry_same_prompt" or next_step_candidate == "retry_same_prompt":
        retry_hardening_status = "available" if same_prompt_retry_remaining > 0 else "exhausted"
    if loop_risk_status == "blocked" and retry_hardening_status != "exhausted":
        retry_hardening_status = "blocked"

    def _map_batch_reason_to_rolling(reason: str) -> str:
        if reason == "none":
            return "none"
        if reason == "score_auto_safe":
            return "score_auto_safe"
        if reason == "budget_exhausted":
            return "step_budget_exhausted"
        if reason == "failure_budget_exhausted":
            return "failure_budget_exhausted"
        if reason == "retry_budget_exhausted":
            return "retry_budget_exhausted"
        if reason == "duplicate_risk":
            return "duplicate_risk"
        if reason == "pause_required":
            return "pause_required"
        if reason == "human_review_required":
            return "human_review_required"
        if reason == "score_below_auto_safe":
            return "human_review_required"
        if reason in {"step_receipt_missing", "insufficient_truth"}:
            return "insufficient_truth"
        if reason == "budget_remaining":
            return "pr118_continue_allowed"
        return "insufficient_truth"

    mapped_batch_reason = _map_batch_reason_to_rolling(batch_continue_reason)
    if mapped_batch_reason == "insufficient_truth" and batch_continue_reason not in {
        "score_below_auto_safe",
        "step_receipt_missing",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()

    if batch_evaluation_status == "inactive":
        return _base_state(
            rolling_gate_status="inactive",
            rolling_continue_permission="insufficient_truth",
            rolling_continue_reason="none",
            cooldown_status="not_required",
            cooldown_reason="none",
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="none",
        )
    if batch_evaluation_status == "pause_required":
        return _base_state(
            rolling_gate_status="pause_required",
            rolling_continue_permission="pause_required",
            rolling_continue_reason="pause_required",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="pause_for_login",
        )
    if batch_evaluation_status == "human_review_required":
        return _base_state(
            rolling_gate_status="human_review_required",
            rolling_continue_permission="human_review_required",
            rolling_continue_reason="human_review_required",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="human_review",
        )
    if batch_evaluation_status == "insufficient_truth":
        return _insufficient_truth_state()
    if batch_evaluation_status == "blocked":
        reason = mapped_batch_reason
        if reason == "none":
            reason = "insufficient_truth"
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason=reason,
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )

    if batch_continue_permission != "allowed_candidate":
        if batch_continue_permission == "pause_required":
            return _base_state(
                rolling_gate_status="pause_required",
                rolling_continue_permission="pause_required",
                rolling_continue_reason="pause_required",
                cooldown_status=cooldown_status,
                cooldown_reason=cooldown_reason,
                retry_hardening_status=retry_hardening_status,
                same_prompt_retry_remaining=same_prompt_retry_remaining,
                same_failure_count=same_failure_count,
                loop_risk_status=loop_risk_status,
                loop_risk_reason=loop_risk_reason,
                rolling_next_action="pause_for_login",
            )
        if batch_continue_permission == "human_review_required":
            return _base_state(
                rolling_gate_status="human_review_required",
                rolling_continue_permission="human_review_required",
                rolling_continue_reason="human_review_required",
                cooldown_status=cooldown_status,
                cooldown_reason=cooldown_reason,
                retry_hardening_status=retry_hardening_status,
                same_prompt_retry_remaining=same_prompt_retry_remaining,
                same_failure_count=same_failure_count,
                loop_risk_status=loop_risk_status,
                loop_risk_reason=loop_risk_reason,
                rolling_next_action="human_review",
            )
        if batch_continue_permission in {"blocked", "insufficient_truth"}:
            return _base_state(
                rolling_gate_status=(
                    "blocked"
                    if batch_continue_permission == "blocked"
                    else "insufficient_truth"
                ),
                rolling_continue_permission=batch_continue_permission,
                rolling_continue_reason=(
                    mapped_batch_reason
                    if batch_continue_permission == "blocked"
                    else "insufficient_truth"
                ),
                cooldown_status=cooldown_status,
                cooldown_reason=cooldown_reason,
                retry_hardening_status=retry_hardening_status,
                same_prompt_retry_remaining=same_prompt_retry_remaining,
                same_failure_count=same_failure_count,
                loop_risk_status=loop_risk_status,
                loop_risk_reason=loop_risk_reason,
                rolling_next_action="stop",
            )
        return _insufficient_truth_state()

    if step_exhausted:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="step_budget_exhausted",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status="exhausted",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )
    if failure_exhausted:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="failure_budget_exhausted",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status="exhausted",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )
    if retry_exhausted:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="retry_budget_exhausted",
            cooldown_status="blocked",
            cooldown_reason="retry_budget_exhausted",
            retry_hardening_status="exhausted",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status="blocked",
            loop_risk_reason="exhausted_retry_budget",
            rolling_next_action="stop",
        )
    if duplicate_prompt_or_action:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="duplicate_risk",
            cooldown_status="required",
            cooldown_reason="loop_suspected",
            retry_hardening_status="blocked",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status="blocked",
            loop_risk_reason=(
                "duplicate_action"
                if duplicate_status == "duplicate_action"
                else "duplicate_prompt"
            ),
            rolling_next_action="stop",
        )
    if same_failure_count >= 2:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="same_failure_repeated",
            cooldown_status="required",
            cooldown_reason="same_failure_repeated",
            retry_hardening_status="blocked",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status="blocked",
            loop_risk_reason="same_failure_no_context_change",
            rolling_next_action="cooldown",
        )
    if cooldown_status == "required":
        return _base_state(
            rolling_gate_status="cooldown_required",
            rolling_continue_permission="cooldown_required",
            rolling_continue_reason="cooldown_required",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="cooldown",
        )
    if cooldown_status == "blocked":
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason=(
                "retry_budget_exhausted"
                if cooldown_reason == "retry_budget_exhausted"
                else "cooldown_required"
            ),
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )
    if retry_hardening_status in {"exhausted", "blocked"}:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="retry_budget_exhausted",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )
    if loop_risk_status != "clear":
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="loop_suspected",
            cooldown_status=cooldown_status,
            cooldown_reason="loop_suspected",
            retry_hardening_status="blocked",
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )

    hard_gates_clear = bool(
        batch_evaluation_status == "continue_candidate"
        and batch_continue_permission == "allowed_candidate"
        and step_score_band == "auto_safe_without_approval"
        and step_auto_approval_posture == "allowed_without_human"
        and step_receipt_status == "ready"
        and remaining_steps > 0
        and remaining_failures > 0
        and cooldown_status == "not_required"
        and retry_hardening_status not in {"exhausted", "blocked"}
        and loop_risk_status == "clear"
        and safety_switch_status in {"enabled", "inactive"}
        and manual_override_status in {"inactive", "clear"}
        and safe_stop_status == "not_required"
        and execution_permission == "allowed_candidate"
        and bridge_status == "ready"
        and bridge_permission == "allowed_candidate"
        and bridge_source_status == "valid"
        and budget_status == "ready"
        and multistep_permission == "allowed_candidate"
    )
    if next_step_candidate == "retry_same_prompt" and same_prompt_retry_remaining <= 0:
        hard_gates_clear = False

    if hard_gates_clear:
        return _base_state(
            rolling_gate_status="allowed_candidate",
            rolling_continue_permission="allowed_candidate",
            rolling_continue_reason="pr118_continue_allowed",
            cooldown_status="not_required",
            cooldown_reason="none",
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status="clear",
            loop_risk_reason="none",
            rolling_next_action="continue_short_batch_later",
        )
    if step_score_band == "auto_safe_without_approval":
        if (
            safe_stop_status == "pause_after_current_step"
            or manual_override_status == "requested"
        ):
            return _base_state(
                rolling_gate_status="pause_required",
                rolling_continue_permission="pause_required",
                rolling_continue_reason="pause_required",
                cooldown_status=cooldown_status,
                cooldown_reason=cooldown_reason,
                retry_hardening_status=retry_hardening_status,
                same_prompt_retry_remaining=same_prompt_retry_remaining,
                same_failure_count=same_failure_count,
                loop_risk_status=loop_risk_status,
                loop_risk_reason=loop_risk_reason,
                rolling_next_action="pause_for_login",
            )
        if (
            safe_stop_status == "human_review_required"
            or manual_override_status in {"required", "blocked"}
        ):
            return _base_state(
                rolling_gate_status="human_review_required",
                rolling_continue_permission="human_review_required",
                rolling_continue_reason="human_review_required",
                cooldown_status=cooldown_status,
                cooldown_reason=cooldown_reason,
                retry_hardening_status=retry_hardening_status,
                same_prompt_retry_remaining=same_prompt_retry_remaining,
                same_failure_count=same_failure_count,
                loop_risk_status=loop_risk_status,
                loop_risk_reason=loop_risk_reason,
                rolling_next_action="human_review",
            )
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="insufficient_truth",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="stop",
        )

    if step_score_band == "auto_candidate":
        return _base_state(
            rolling_gate_status="human_review_required",
            rolling_continue_permission="human_review_required",
            rolling_continue_reason="human_review_required",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="human_review",
        )
    if step_score_band in {"human_review_recommended", "blocked"}:
        return _base_state(
            rolling_gate_status="blocked",
            rolling_continue_permission="blocked",
            rolling_continue_reason="human_review_required",
            cooldown_status=cooldown_status,
            cooldown_reason=cooldown_reason,
            retry_hardening_status=retry_hardening_status,
            same_prompt_retry_remaining=same_prompt_retry_remaining,
            same_failure_count=same_failure_count,
            loop_risk_status=loop_risk_status,
            loop_risk_reason=loop_risk_reason,
            rolling_next_action="human_review",
        )

    return _insufficient_truth_state()


def _build_project_browser_autonomous_operation_contract_state(
    *,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_budget_source_status: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
    autonomous_step_wrapper_status: str,
    autonomous_step_score_band: str,
    autonomous_step_auto_approval_posture: str,
    autonomous_step_receipt_status: str,
    autonomous_batch_evaluation_status: str,
    autonomous_batch_continue_permission: str,
    autonomous_rolling_gate_status: str,
    autonomous_rolling_continue_permission: str,
    autonomous_rolling_continue_reason: str,
    autonomous_cooldown_status: str,
    autonomous_retry_hardening_status: str,
    autonomous_loop_risk_status: str,
    autonomous_loop_risk_reason: str,
    autonomous_rolling_next_action: str,
    autonomous_rolling_state: Mapping[str, Any] | None,
) -> dict[str, Any]:
    budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    budget_source_status = _normalize_text(
        autonomous_multistep_budget_source_status,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )

    step_wrapper_status = _normalize_text(
        autonomous_step_wrapper_status,
        default="insufficient_truth",
    )
    step_score_band = _normalize_text(
        autonomous_step_score_band,
        default="insufficient_truth",
    )
    step_auto_approval_posture = _normalize_text(
        autonomous_step_auto_approval_posture,
        default="insufficient_truth",
    )
    step_receipt_status = _normalize_text(
        autonomous_step_receipt_status,
        default="insufficient_truth",
    )

    batch_evaluation_status = _normalize_text(
        autonomous_batch_evaluation_status,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )

    rolling_gate_status = _normalize_text(
        autonomous_rolling_gate_status,
        default="insufficient_truth",
    )
    rolling_continue_permission = _normalize_text(
        autonomous_rolling_continue_permission,
        default="insufficient_truth",
    )
    rolling_continue_reason = _normalize_text(
        autonomous_rolling_continue_reason,
        default="insufficient_truth",
    )
    cooldown_status = _normalize_text(
        autonomous_cooldown_status,
        default="insufficient_truth",
    )
    retry_hardening_status = _normalize_text(
        autonomous_retry_hardening_status,
        default="insufficient_truth",
    )
    loop_risk_status = _normalize_text(
        autonomous_loop_risk_status,
        default="insufficient_truth",
    )
    loop_risk_reason = _normalize_text(
        autonomous_loop_risk_reason,
        default="insufficient_truth",
    )
    rolling_next_action = _normalize_text(
        autonomous_rolling_next_action,
        default="none",
    )
    rolling_state = dict(autonomous_rolling_state or {})

    runtime_posture = [
        "metadata_only",
        "no_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        contract_status: str,
        operation_mode: str,
        operation_permission: str,
        next_safe_action: str,
        stop_reason: str,
        batch_policy_status: str,
        batch_size_policy: str,
        no_approval_policy: str,
        score_policy: str,
        budget_policy: str,
        cooldown_policy: str,
        loop_policy: str,
        operator_summary_status: str,
        operator_summary_kind: str,
        receipt_status: str,
        receipt_kind: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_operation_contract_status": contract_status,
            "project_browser_autonomous_operation_mode": operation_mode,
            "project_browser_autonomous_operation_permission": operation_permission,
            "project_browser_autonomous_operation_next_safe_action": next_safe_action,
            "project_browser_autonomous_operation_stop_reason": stop_reason,
            "project_browser_autonomous_operation_batch_policy_status": batch_policy_status,
            "project_browser_autonomous_operation_batch_size_policy": batch_size_policy,
            "project_browser_autonomous_operation_no_approval_policy": no_approval_policy,
            "project_browser_autonomous_operation_score_policy": score_policy,
            "project_browser_autonomous_operation_budget_policy": budget_policy,
            "project_browser_autonomous_operation_cooldown_policy": cooldown_policy,
            "project_browser_autonomous_operation_loop_policy": loop_policy,
            "project_browser_autonomous_operation_operator_summary_status": operator_summary_status,
            "project_browser_autonomous_operation_operator_summary_kind": operator_summary_kind,
            "project_browser_autonomous_operation_contract_receipt_status": receipt_status,
            "project_browser_autonomous_operation_contract_receipt_kind": receipt_kind,
            "project_browser_autonomous_operation_runtime_posture": runtime_posture,
            "project_browser_autonomous_operation_runtime_metadata_only": True,
            "project_browser_autonomous_operation_runtime_no_next_step_start": True,
            "project_browser_autonomous_operation_runtime_no_prompt_send": True,
            "project_browser_autonomous_operation_runtime_no_md_write": True,
            "project_browser_autonomous_operation_runtime_no_shell_execution": True,
            "project_browser_autonomous_operation_runtime_no_codex_execution": True,
            "project_browser_autonomous_operation_runtime_no_browser_action": True,
            "project_browser_autonomous_operation_runtime_no_playwright": True,
            "project_browser_autonomous_operation_runtime_no_dom_interaction": True,
            "project_browser_autonomous_operation_runtime_no_queue_mutation": True,
            "project_browser_autonomous_operation_runtime_no_retry_execution": True,
            "project_browser_autonomous_operation_runtime_no_repair_execution": True,
            "project_browser_autonomous_operation_runtime_no_restart_execution": True,
            "project_browser_autonomous_operation_runtime_no_approval_execution": True,
            "project_browser_autonomous_operation_runtime_no_continuation_execution": True,
            "project_browser_autonomous_operation_runtime_no_loop_execution": True,
            "project_browser_autonomous_operation_runtime_no_background_runtime": True,
        }

    def _insufficient_truth_state() -> dict[str, Any]:
        return _base_state(
            contract_status="insufficient_truth",
            operation_mode="insufficient_truth",
            operation_permission="insufficient_truth",
            next_safe_action="none",
            stop_reason="insufficient_truth",
            batch_policy_status="insufficient_truth",
            batch_size_policy="insufficient_truth",
            no_approval_policy="insufficient_truth",
            score_policy="insufficient_truth",
            budget_policy="insufficient_truth",
            cooldown_policy="insufficient_truth",
            loop_policy="insufficient_truth",
            operator_summary_status="insufficient_truth",
            operator_summary_kind="insufficient_truth_summary",
            receipt_status="insufficient_truth",
            receipt_kind="insufficient_truth_contract_receipt",
        )

    if budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state()
    if budget_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state()
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state()
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state()
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state()
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state()
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state()
    if bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state()
    if bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state()
    if step_wrapper_status not in {
        "inactive",
        "ready",
        "auto_safe",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_score_band not in {
        "auto_safe_without_approval",
        "auto_candidate",
        "human_review_recommended",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_auto_approval_posture not in {
        "allowed_without_human",
        "blocked_needs_human",
        "pause_required",
        "blocked_by_budget",
        "blocked_by_duplicate",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if step_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_evaluation_status not in {
        "inactive",
        "continue_candidate",
        "stopped",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if rolling_gate_status not in {
        "inactive",
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if rolling_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if rolling_continue_reason not in {
        "none",
        "pr118_continue_allowed",
        "score_auto_safe",
        "cooldown_required",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "duplicate_risk",
        "loop_suspected",
        "same_failure_repeated",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if cooldown_status not in {"not_required", "required", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state()
    if retry_hardening_status not in {
        "not_required",
        "available",
        "exhausted",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if loop_risk_status not in {"clear", "suspected", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state()
    if loop_risk_reason not in {
        "none",
        "duplicate_action",
        "duplicate_prompt",
        "same_failure_no_context_change",
        "repeated_retry_without_progress",
        "exhausted_retry_budget",
        "insufficient_truth",
    }:
        return _insufficient_truth_state()
    if rolling_next_action not in {
        "none",
        "continue_short_batch_later",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state()

    if (
        budget_source_status in {"inconsistent", "insufficient_truth"}
        or bridge_source_status in {"inconsistent", "insufficient_truth"}
    ):
        return _insufficient_truth_state()

    required_counter_keys = (
        "project_browser_autonomous_multistep_remaining_steps",
        "project_browser_autonomous_multistep_remaining_failures",
        "project_browser_autonomous_multistep_same_prompt_retry_remaining",
        "project_browser_autonomous_multistep_controller_max_steps",
        "project_browser_autonomous_multistep_controller_hard_limit",
    )
    if any(key not in multistep_state for key in required_counter_keys):
        return _insufficient_truth_state()

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    same_prompt_retry_remaining, same_prompt_retry_remaining_invalid = (
        _read_required_non_negative_int(
            multistep_state.get(
                "project_browser_autonomous_multistep_same_prompt_retry_remaining"
            )
        )
    )
    controller_max_steps, controller_max_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_controller_max_steps")
    )
    controller_hard_limit, controller_hard_limit_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_controller_hard_limit")
    )
    if (
        remaining_steps_invalid
        or remaining_failures_invalid
        or same_prompt_retry_remaining_invalid
        or controller_max_steps_invalid
        or controller_hard_limit_invalid
    ):
        return _insufficient_truth_state()
    if controller_max_steps > controller_hard_limit:
        return _insufficient_truth_state()

    rolling_same_prompt_retry_remaining, rolling_same_prompt_retry_remaining_invalid = (
        _read_required_non_negative_int(
            rolling_state.get("project_browser_autonomous_same_prompt_retry_remaining")
        )
    )
    if rolling_same_prompt_retry_remaining_invalid:
        return _insufficient_truth_state()
    if (
        rolling_state
        and rolling_same_prompt_retry_remaining != same_prompt_retry_remaining
    ):
        return _insufficient_truth_state()

    retry_path = next_step_candidate == "retry_same_prompt"
    retry_budget_exhausted = bool(retry_path and same_prompt_retry_remaining <= 0)
    failure_budget_exhausted = remaining_failures <= 0
    step_budget_exhausted = remaining_steps <= 0
    duplicate_risk_present = duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
        "duplicate_md_update",
        "duplicate_pause",
        "duplicate_human_review",
        "duplicate_risk",
    }

    batch_size_policy = (
        "hard_limit_5_metadata_only"
        if controller_hard_limit == 5
        else ("normal_3_steps" if controller_max_steps == 3 else "none")
    )

    if rolling_gate_status == "inactive":
        return _base_state(
            contract_status="inactive",
            operation_mode="none",
            operation_permission="insufficient_truth",
            next_safe_action="none",
            stop_reason="none",
            batch_policy_status="unavailable",
            batch_size_policy="none",
            no_approval_policy="unavailable",
            score_policy="unavailable",
            budget_policy="unavailable",
            cooldown_policy="not_required",
            loop_policy="clear",
            operator_summary_status="unavailable",
            operator_summary_kind="none",
            receipt_status="not_created",
            receipt_kind="none",
        )
    if rolling_gate_status == "pause_required":
        return _base_state(
            contract_status="pause_required",
            operation_mode="pause_for_login",
            operation_permission="pause_required",
            next_safe_action="pause_for_login",
            stop_reason="pause_required",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy=(
                "budget_exhausted"
                if step_budget_exhausted or failure_budget_exhausted or retry_budget_exhausted
                else "budget_remaining"
            ),
            cooldown_policy=(
                "required" if cooldown_status == "required" else cooldown_status
            ),
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="pause_summary",
            receipt_status="pause_required",
            receipt_kind="pause_contract_receipt",
        )
    if rolling_gate_status == "human_review_required":
        return _base_state(
            contract_status="human_review_required",
            operation_mode="human_review",
            operation_permission="human_review_required",
            next_safe_action="human_review",
            stop_reason="human_review_required",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy="score_below_required",
            budget_policy=(
                "budget_exhausted"
                if step_budget_exhausted or failure_budget_exhausted or retry_budget_exhausted
                else "budget_remaining"
            ),
            cooldown_policy=(
                "required" if cooldown_status == "required" else cooldown_status
            ),
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="human_review_summary",
            receipt_status="human_review_required",
            receipt_kind="human_review_contract_receipt",
        )
    if rolling_gate_status == "insufficient_truth":
        return _insufficient_truth_state()
    if rolling_gate_status == "cooldown_required":
        return _base_state(
            contract_status="cooldown_required",
            operation_mode="cooldown",
            operation_permission="cooldown_required",
            next_safe_action="cooldown",
            stop_reason="cooldown_required",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy=(
                "budget_exhausted"
                if step_budget_exhausted or failure_budget_exhausted or retry_budget_exhausted
                else "budget_remaining"
            ),
            cooldown_policy="required",
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="cooldown_summary",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_contract_receipt",
        )
    if rolling_gate_status == "blocked":
        if rolling_continue_reason in {"retry_budget_exhausted", "failure_budget_exhausted"}:
            stop_reason = rolling_continue_reason
        elif rolling_continue_reason == "step_budget_exhausted":
            stop_reason = "budget_exhausted"
        elif rolling_continue_reason == "duplicate_risk":
            stop_reason = "duplicate_risk"
        elif rolling_continue_reason in {"loop_suspected", "same_failure_repeated"}:
            stop_reason = "loop_suspected"
        elif rolling_continue_reason == "cooldown_required":
            stop_reason = "cooldown_required"
        elif rolling_continue_reason in {"pause_required", "human_review_required"}:
            stop_reason = rolling_continue_reason
        elif rolling_continue_reason == "insufficient_truth":
            stop_reason = "insufficient_truth"
        else:
            stop_reason = "rolling_gate_not_allowed"
        return _base_state(
            contract_status="blocked",
            operation_mode=(
                "stopped"
                if stop_reason in {"budget_exhausted", "score_below_auto_safe"}
                else "blocked"
            ),
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason=stop_reason,
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else (
                    "score_below_required"
                    if step_score_band in {"auto_candidate", "human_review_recommended", "blocked"}
                    else "insufficient_truth"
                )
            ),
            budget_policy=(
                "budget_exhausted"
                if step_budget_exhausted or failure_budget_exhausted or retry_budget_exhausted
                else "budget_remaining"
            ),
            cooldown_policy=(
                "required"
                if cooldown_status == "required"
                else ("blocked" if cooldown_status == "blocked" else "not_required")
            ),
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )

    if rolling_continue_permission != "allowed_candidate":
        return _base_state(
            contract_status=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "blocked"
            ),
            operation_mode=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "blocked"
            ),
            operation_permission=rolling_continue_permission,
            next_safe_action=(
                "pause_for_login"
                if rolling_continue_permission == "pause_required"
                else (
                    "human_review"
                    if rolling_continue_permission == "human_review_required"
                    else ("cooldown" if rolling_continue_permission == "cooldown_required" else "stop")
                )
            ),
            stop_reason=(
                "pause_required"
                if rolling_continue_permission == "pause_required"
                else (
                    "human_review_required"
                    if rolling_continue_permission == "human_review_required"
                    else (
                        "cooldown_required"
                        if rolling_continue_permission == "cooldown_required"
                        else "rolling_gate_not_allowed"
                    )
                )
            ),
            batch_policy_status=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "blocked"
            ),
            batch_size_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else batch_size_policy
            ),
            no_approval_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "blocked"
            ),
            score_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "score_below_required"
            ),
            budget_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "budget_remaining"
            ),
            cooldown_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else (
                    "required"
                    if rolling_continue_permission == "cooldown_required"
                    else cooldown_status
                )
            ),
            loop_policy=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else loop_risk_status
            ),
            operator_summary_status=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else "compact_available"
            ),
            operator_summary_kind=(
                "insufficient_truth_summary"
                if rolling_continue_permission == "insufficient_truth"
                else (
                    "pause_summary"
                    if rolling_continue_permission == "pause_required"
                    else (
                        "human_review_summary"
                        if rolling_continue_permission == "human_review_required"
                        else (
                            "cooldown_summary"
                            if rolling_continue_permission == "cooldown_required"
                            else "blocked_summary"
                        )
                    )
                )
            ),
            receipt_status=(
                "insufficient_truth"
                if rolling_continue_permission == "insufficient_truth"
                else (
                    "pause_required"
                    if rolling_continue_permission == "pause_required"
                    else (
                        "human_review_required"
                        if rolling_continue_permission == "human_review_required"
                        else (
                            "cooldown_required"
                            if rolling_continue_permission == "cooldown_required"
                            else "blocked"
                        )
                    )
                )
            ),
            receipt_kind=(
                "insufficient_truth_contract_receipt"
                if rolling_continue_permission == "insufficient_truth"
                else (
                    "pause_contract_receipt"
                    if rolling_continue_permission == "pause_required"
                    else (
                        "human_review_contract_receipt"
                        if rolling_continue_permission == "human_review_required"
                        else (
                            "cooldown_contract_receipt"
                            if rolling_continue_permission == "cooldown_required"
                            else "blocked_contract_receipt"
                        )
                    )
                )
            ),
        )

    upstream_clear = bool(
        batch_continue_permission == "allowed_candidate"
        and batch_evaluation_status == "continue_candidate"
        and step_score_band == "auto_safe_without_approval"
        and step_auto_approval_posture == "allowed_without_human"
        and step_receipt_status == "ready"
        and remaining_steps > 0
        and remaining_failures > 0
        and cooldown_status == "not_required"
        and loop_risk_status == "clear"
        and retry_hardening_status not in {"exhausted", "blocked"}
        and safety_switch_status in {"enabled", "inactive"}
        and manual_override_status in {"inactive", "clear"}
        and safe_stop_status == "not_required"
        and execution_permission == "allowed_candidate"
        and bridge_status == "ready"
        and bridge_permission == "allowed_candidate"
        and bridge_source_status == "valid"
        and budget_status == "ready"
        and multistep_permission == "allowed_candidate"
    )
    if retry_path and same_prompt_retry_remaining <= 0:
        upstream_clear = False

    if step_budget_exhausted:
        return _base_state(
            contract_status="blocked",
            operation_mode="stopped",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="budget_exhausted",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_exhausted",
            cooldown_policy=cooldown_status,
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="stopped_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )
    if failure_budget_exhausted:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="failure_budget_exhausted",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_exhausted",
            cooldown_policy=cooldown_status,
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )
    if retry_budget_exhausted:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="retry_budget_exhausted",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_exhausted",
            cooldown_policy="blocked",
            loop_policy="blocked",
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )
    if duplicate_risk_present:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="duplicate_risk",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_remaining",
            cooldown_policy="required",
            loop_policy="blocked",
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )
    if cooldown_status == "required":
        return _base_state(
            contract_status="cooldown_required",
            operation_mode="cooldown",
            operation_permission="cooldown_required",
            next_safe_action="cooldown",
            stop_reason="cooldown_required",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_remaining",
            cooldown_policy="required",
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="cooldown_summary",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_contract_receipt",
        )
    if loop_risk_status in {"suspected", "blocked"}:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="loop_suspected",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy=(
                "score_95_required"
                if step_score_band == "auto_safe_without_approval"
                else "score_below_required"
            ),
            budget_policy="budget_remaining",
            cooldown_policy=(
                "required" if cooldown_status == "required" else cooldown_status
            ),
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )

    if step_score_band == "auto_candidate":
        return _base_state(
            contract_status="human_review_required",
            operation_mode="human_review",
            operation_permission="human_review_required",
            next_safe_action="human_review",
            stop_reason="score_below_auto_safe",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy="score_below_required",
            budget_policy="budget_remaining",
            cooldown_policy=cooldown_status,
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="human_review_summary",
            receipt_status="human_review_required",
            receipt_kind="human_review_contract_receipt",
        )
    if step_score_band in {"human_review_recommended", "blocked"}:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="human_review",
            stop_reason=(
                "score_below_auto_safe"
                if step_score_band == "blocked"
                else "human_review_required"
            ),
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy="score_below_required",
            budget_policy="budget_remaining",
            cooldown_policy=cooldown_status,
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )
    if step_score_band != "auto_safe_without_approval":
        return _insufficient_truth_state()

    if not upstream_clear:
        return _base_state(
            contract_status="blocked",
            operation_mode="blocked",
            operation_permission="blocked",
            next_safe_action="stop",
            stop_reason="rolling_gate_not_allowed",
            batch_policy_status="blocked",
            batch_size_policy=batch_size_policy,
            no_approval_policy="blocked",
            score_policy="score_95_required",
            budget_policy="budget_remaining",
            cooldown_policy=cooldown_status,
            loop_policy=loop_risk_status,
            operator_summary_status="compact_available",
            operator_summary_kind="blocked_summary",
            receipt_status="blocked",
            receipt_kind="blocked_contract_receipt",
        )

    return _base_state(
        contract_status="ready",
        operation_mode="bounded_short_batch",
        operation_permission="allowed_candidate",
        next_safe_action="continue_short_batch_later",
        stop_reason="none",
        batch_policy_status="available",
        batch_size_policy="normal_3_steps",
        no_approval_policy="allowed_candidate",
        score_policy="score_95_required",
        budget_policy="budget_remaining",
        cooldown_policy="not_required",
        loop_policy="clear",
        operator_summary_status="compact_available",
        operator_summary_kind="continue_candidate_summary",
        receipt_status="ready",
        receipt_kind="bounded_rolling_contract_receipt",
    )


def _build_project_browser_autonomous_invocation_state(
    *,
    autonomous_operation_contract_status: str,
    autonomous_operation_mode: str,
    autonomous_operation_permission: str,
    autonomous_operation_next_safe_action: str,
    autonomous_operation_stop_reason: str,
    autonomous_operation_contract_state: Mapping[str, Any] | None,
    autonomous_rolling_gate_status: str,
    autonomous_rolling_continue_permission: str,
    autonomous_rolling_continue_reason: str,
    autonomous_cooldown_status: str,
    autonomous_retry_hardening_status: str,
    autonomous_loop_risk_status: str,
    autonomous_rolling_state: Mapping[str, Any] | None,
    autonomous_batch_evaluation_status: str,
    autonomous_batch_continue_permission: str,
    autonomous_step_score_band: str,
    autonomous_step_receipt_status: str,
    autonomous_step_state: Mapping[str, Any] | None,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_budget_source_status: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
    autonomous_execution_bridge_source_status: str,
) -> dict[str, Any]:
    operation_status = _normalize_text(
        autonomous_operation_contract_status,
        default="insufficient_truth",
    )
    operation_mode = _normalize_text(
        autonomous_operation_mode,
        default="insufficient_truth",
    )
    operation_permission = _normalize_text(
        autonomous_operation_permission,
        default="insufficient_truth",
    )
    operation_next_safe_action = _normalize_text(
        autonomous_operation_next_safe_action,
        default="none",
    )
    operation_stop_reason = _normalize_text(
        autonomous_operation_stop_reason,
        default="insufficient_truth",
    )
    operation_state = dict(autonomous_operation_contract_state or {})

    rolling_gate_status = _normalize_text(
        autonomous_rolling_gate_status,
        default="insufficient_truth",
    )
    rolling_continue_permission = _normalize_text(
        autonomous_rolling_continue_permission,
        default="insufficient_truth",
    )
    rolling_continue_reason = _normalize_text(
        autonomous_rolling_continue_reason,
        default="insufficient_truth",
    )
    cooldown_status = _normalize_text(
        autonomous_cooldown_status,
        default="insufficient_truth",
    )
    retry_hardening_status = _normalize_text(
        autonomous_retry_hardening_status,
        default="insufficient_truth",
    )
    loop_risk_status = _normalize_text(
        autonomous_loop_risk_status,
        default="insufficient_truth",
    )
    rolling_state = dict(autonomous_rolling_state or {})

    batch_evaluation_status = _normalize_text(
        autonomous_batch_evaluation_status,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )

    step_score_band = _normalize_text(
        autonomous_step_score_band,
        default="insufficient_truth",
    )
    step_receipt_status = _normalize_text(
        autonomous_step_receipt_status,
        default="insufficient_truth",
    )
    step_state = dict(autonomous_step_state or {})

    multistep_budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    multistep_next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    multistep_budget_source_status = _normalize_text(
        autonomous_multistep_budget_source_status,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    execution_bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    execution_bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )
    execution_bridge_source_status = _normalize_text(
        autonomous_execution_bridge_source_status,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_actual_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        invocation_status: str,
        invocation_kind: str,
        invocation_permission: str,
        invocation_action: str,
        source_status: str,
        block_reason: str,
        receipt_status: str,
        receipt_kind: str,
        counter_posture: str,
        remaining_steps_after: int,
        remaining_failures_after: int,
        same_prompt_retry_remaining_after: int,
        threshold_used: str,
        task_size_status: str,
        simple_task_status: str,
        extra_hard_gate_status: str,
        extra_hard_gate_reason: str,
        simple_task_gate_status: str,
        simple_task_gate_reason: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_invocation_status": invocation_status,
            "project_browser_autonomous_invocation_kind": invocation_kind,
            "project_browser_autonomous_invocation_permission": invocation_permission,
            "project_browser_autonomous_invocation_action": invocation_action,
            "project_browser_autonomous_invocation_source_status": source_status,
            "project_browser_autonomous_invocation_block_reason": block_reason,
            "project_browser_autonomous_invocation_receipt_status": receipt_status,
            "project_browser_autonomous_invocation_receipt_kind": receipt_kind,
            "project_browser_autonomous_invocation_counter_posture": counter_posture,
            "project_browser_autonomous_invocation_remaining_steps_after": remaining_steps_after,
            "project_browser_autonomous_invocation_remaining_failures_after": remaining_failures_after,
            "project_browser_autonomous_invocation_same_prompt_retry_remaining_after": (
                same_prompt_retry_remaining_after
            ),
            "project_browser_autonomous_invocation_no_approval_threshold": 92,
            "project_browser_autonomous_invocation_simple_task_threshold": 90,
            "project_browser_autonomous_invocation_threshold_used": threshold_used,
            "project_browser_autonomous_invocation_task_size_status": task_size_status,
            "project_browser_autonomous_invocation_simple_task_status": simple_task_status,
            "project_browser_autonomous_invocation_extra_hard_gate_status": (
                extra_hard_gate_status
            ),
            "project_browser_autonomous_invocation_extra_hard_gate_reason": (
                extra_hard_gate_reason
            ),
            "project_browser_autonomous_invocation_simple_task_gate_status": (
                simple_task_gate_status
            ),
            "project_browser_autonomous_invocation_simple_task_gate_reason": (
                simple_task_gate_reason
            ),
            "project_browser_autonomous_invocation_runtime_posture": runtime_posture,
        }

    def _insufficient_truth_state(*, source_status: str) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in {"valid", "inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        return _base_state(
            invocation_status="insufficient_truth",
            invocation_kind="insufficient_truth_invocation",
            invocation_permission="insufficient_truth",
            invocation_action="none",
            source_status=normalized_source_status,
            block_reason="insufficient_truth",
            receipt_status="insufficient_truth",
            receipt_kind="insufficient_truth_invocation_receipt",
            counter_posture="insufficient_truth",
            remaining_steps_after=0,
            remaining_failures_after=0,
            same_prompt_retry_remaining_after=0,
            threshold_used="insufficient_truth",
            task_size_status="insufficient_truth",
            simple_task_status="insufficient_truth",
            extra_hard_gate_status="insufficient_truth",
            extra_hard_gate_reason="insufficient_truth",
            simple_task_gate_status="insufficient_truth",
            simple_task_gate_reason="insufficient_truth",
        )

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    def _read_required_bool(value: Any) -> tuple[bool, bool]:
        if isinstance(value, bool):
            return value, False
        return True, True

    if operation_status not in {
        "inactive",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_mode not in {
        "none",
        "bounded_short_batch",
        "stopped",
        "cooldown",
        "pause_for_login",
        "human_review",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_next_safe_action not in {
        "none",
        "continue_short_batch_later",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_stop_reason not in {
        "none",
        "rolling_gate_not_allowed",
        "score_below_auto_safe",
        "budget_exhausted",
        "failure_budget_exhausted",
        "retry_budget_exhausted",
        "cooldown_required",
        "duplicate_risk",
        "loop_suspected",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if rolling_gate_status not in {
        "inactive",
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if rolling_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if rolling_continue_reason not in {
        "none",
        "pr118_continue_allowed",
        "score_auto_safe",
        "cooldown_required",
        "retry_budget_exhausted",
        "failure_budget_exhausted",
        "step_budget_exhausted",
        "duplicate_risk",
        "loop_suspected",
        "same_failure_repeated",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if cooldown_status not in {"not_required", "required", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if retry_hardening_status not in {
        "not_required",
        "available",
        "exhausted",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if loop_risk_status not in {"clear", "suspected", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if batch_evaluation_status not in {
        "inactive",
        "continue_candidate",
        "stopped",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if step_score_band not in {
        "auto_safe_without_approval",
        "auto_candidate",
        "human_review_recommended",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if step_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_budget_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_bridge_source_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_SOURCE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    same_prompt_retry_remaining, same_prompt_retry_remaining_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_same_prompt_retry_remaining")
    )
    controller_max_steps, controller_max_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_controller_max_steps")
    )
    controller_hard_limit, controller_hard_limit_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_controller_hard_limit")
    )
    rolling_same_prompt_retry_remaining, rolling_same_prompt_retry_remaining_invalid = (
        _read_required_non_negative_int(
            rolling_state.get("project_browser_autonomous_same_prompt_retry_remaining")
        )
    )
    same_failure_count, same_failure_count_invalid = _read_required_non_negative_int(
        rolling_state.get("project_browser_autonomous_same_failure_count")
    )
    safety_score, safety_score_invalid = _read_required_non_negative_int(
        step_state.get("project_browser_autonomous_step_safety_score")
    )
    if safety_score > 100:
        safety_score_invalid = True

    operation_runtime_metadata_only, operation_runtime_metadata_only_invalid = _read_required_bool(
        operation_state.get("project_browser_autonomous_operation_runtime_metadata_only")
    )
    operation_runtime_no_next_step_start, operation_runtime_no_next_step_start_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_next_step_start")
        )
    )
    operation_runtime_no_prompt_send, operation_runtime_no_prompt_send_invalid = _read_required_bool(
        operation_state.get("project_browser_autonomous_operation_runtime_no_prompt_send")
    )
    operation_runtime_no_md_write, operation_runtime_no_md_write_invalid = _read_required_bool(
        operation_state.get("project_browser_autonomous_operation_runtime_no_md_write")
    )
    operation_runtime_no_shell_execution, operation_runtime_no_shell_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_shell_execution")
        )
    )
    operation_runtime_no_codex_execution, operation_runtime_no_codex_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_codex_execution")
        )
    )
    operation_runtime_no_browser_action, operation_runtime_no_browser_action_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_browser_action")
        )
    )
    operation_runtime_no_playwright, operation_runtime_no_playwright_invalid = _read_required_bool(
        operation_state.get("project_browser_autonomous_operation_runtime_no_playwright")
    )
    operation_runtime_no_dom_interaction, operation_runtime_no_dom_interaction_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_dom_interaction")
        )
    )
    operation_runtime_no_queue_mutation, operation_runtime_no_queue_mutation_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_queue_mutation")
        )
    )
    operation_runtime_no_retry_execution, operation_runtime_no_retry_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_retry_execution")
        )
    )
    operation_runtime_no_repair_execution, operation_runtime_no_repair_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_repair_execution")
        )
    )
    operation_runtime_no_restart_execution, operation_runtime_no_restart_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_restart_execution")
        )
    )
    operation_runtime_no_approval_execution, operation_runtime_no_approval_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_approval_execution")
        )
    )
    operation_runtime_no_continuation_execution, operation_runtime_no_continuation_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_continuation_execution")
        )
    )
    operation_runtime_no_loop_execution, operation_runtime_no_loop_execution_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_loop_execution")
        )
    )
    operation_runtime_no_background_runtime, operation_runtime_no_background_runtime_invalid = (
        _read_required_bool(
            operation_state.get("project_browser_autonomous_operation_runtime_no_background_runtime")
        )
    )

    if (
        remaining_steps_invalid
        or remaining_failures_invalid
        or same_prompt_retry_remaining_invalid
        or controller_max_steps_invalid
        or controller_hard_limit_invalid
        or rolling_same_prompt_retry_remaining_invalid
        or same_failure_count_invalid
        or safety_score_invalid
        or operation_runtime_metadata_only_invalid
        or operation_runtime_no_next_step_start_invalid
        or operation_runtime_no_prompt_send_invalid
        or operation_runtime_no_md_write_invalid
        or operation_runtime_no_shell_execution_invalid
        or operation_runtime_no_codex_execution_invalid
        or operation_runtime_no_browser_action_invalid
        or operation_runtime_no_playwright_invalid
        or operation_runtime_no_dom_interaction_invalid
        or operation_runtime_no_queue_mutation_invalid
        or operation_runtime_no_retry_execution_invalid
        or operation_runtime_no_repair_execution_invalid
        or operation_runtime_no_restart_execution_invalid
        or operation_runtime_no_approval_execution_invalid
        or operation_runtime_no_continuation_execution_invalid
        or operation_runtime_no_loop_execution_invalid
        or operation_runtime_no_background_runtime_invalid
    ):
        return _insufficient_truth_state(source_status="insufficient_truth")

    source_inconsistent = False
    if controller_max_steps > controller_hard_limit:
        source_inconsistent = True
    if rolling_same_prompt_retry_remaining != same_prompt_retry_remaining:
        source_inconsistent = True
    if operation_status == "inactive":
        if operation_mode != "none" or operation_next_safe_action != "none":
            source_inconsistent = True
    if operation_status == "ready":
        if operation_mode != "bounded_short_batch":
            source_inconsistent = True
        if operation_permission != "allowed_candidate":
            source_inconsistent = True
        if operation_next_safe_action != "continue_short_batch_later":
            source_inconsistent = True
        if operation_stop_reason != "none":
            source_inconsistent = True
        if rolling_gate_status != "allowed_candidate":
            source_inconsistent = True
        if rolling_continue_permission != "allowed_candidate":
            source_inconsistent = True
        if batch_continue_permission != "allowed_candidate":
            source_inconsistent = True
        if step_receipt_status != "ready":
            source_inconsistent = True
        if step_score_band not in {"auto_safe_without_approval", "auto_candidate"}:
            source_inconsistent = True
        if remaining_steps <= 0 or remaining_failures <= 0:
            source_inconsistent = True
        if cooldown_status != "not_required":
            source_inconsistent = True
        if loop_risk_status != "clear":
            source_inconsistent = True
        if retry_hardening_status in {"exhausted", "blocked"}:
            source_inconsistent = True
        if same_failure_count != 0:
            source_inconsistent = True
        if multistep_budget_status != "ready" or multistep_permission != "allowed_candidate":
            source_inconsistent = True
        if multistep_budget_source_status != "valid":
            source_inconsistent = True
        if execution_bridge_source_status != "valid":
            source_inconsistent = True
    if operation_status == "blocked" and operation_permission != "blocked":
        source_inconsistent = True
    if operation_status == "cooldown_required":
        if operation_permission != "cooldown_required" or operation_next_safe_action != "cooldown":
            source_inconsistent = True
    if operation_status == "pause_required":
        if operation_permission != "pause_required" or operation_next_safe_action != "pause_for_login":
            source_inconsistent = True
    if operation_status == "human_review_required":
        if operation_permission != "human_review_required" or operation_next_safe_action != "human_review":
            source_inconsistent = True

    if source_inconsistent:
        return _insufficient_truth_state(source_status="inconsistent")

    metadata_runtime_clear = bool(
        operation_runtime_metadata_only
        and operation_runtime_no_next_step_start
        and operation_runtime_no_prompt_send
        and operation_runtime_no_md_write
        and operation_runtime_no_shell_execution
        and operation_runtime_no_codex_execution
        and operation_runtime_no_browser_action
        and operation_runtime_no_playwright
        and operation_runtime_no_dom_interaction
        and operation_runtime_no_queue_mutation
        and operation_runtime_no_retry_execution
        and operation_runtime_no_repair_execution
        and operation_runtime_no_restart_execution
        and operation_runtime_no_approval_execution
        and operation_runtime_no_continuation_execution
        and operation_runtime_no_loop_execution
        and operation_runtime_no_background_runtime
    )

    retry_path = multistep_next_step_candidate == "retry_same_prompt"
    raw_remaining_steps_after = remaining_steps - 1
    raw_remaining_failures_after = remaining_failures
    raw_same_prompt_retry_remaining_after = (
        same_prompt_retry_remaining - 1 if retry_path else same_prompt_retry_remaining
    )
    remaining_steps_after = max(0, raw_remaining_steps_after)
    remaining_failures_after = max(0, raw_remaining_failures_after)
    same_prompt_retry_remaining_after = max(0, raw_same_prompt_retry_remaining_after)

    task_size_status = "standard"
    if operation_status == "inactive":
        task_size_status = "unknown"
    elif metadata_runtime_clear:
        task_size_status = "simple_low_risk"
    else:
        task_size_status = "high_risk"

    def _map_operation_stop_reason_to_block_reason(
        value: str,
        fallback_reason: str,
    ) -> str:
        mapping = {
            "none": "contract_not_ready",
            "rolling_gate_not_allowed": "permission_not_allowed",
            "score_below_auto_safe": "score_below_no_approval_threshold",
            "budget_exhausted": "budget_exhausted",
            "failure_budget_exhausted": "failure_budget_exhausted",
            "retry_budget_exhausted": "retry_budget_exhausted",
            "cooldown_required": "cooldown_required",
            "duplicate_risk": "duplicate_risk",
            "loop_suspected": "loop_suspected",
            "pause_required": "pause_required",
            "human_review_required": "human_review_required",
            "insufficient_truth": "insufficient_truth",
        }
        if value in mapping:
            return mapping[value]
        if fallback_reason == "same_failure_repeated":
            return "same_failure_repeated"
        return "contract_not_ready"

    def _map_block_reason_to_extra_reason(block_reason: str) -> str:
        if block_reason in {
            "duplicate_risk",
            "cooldown_required",
            "loop_suspected",
            "same_failure_repeated",
            "retry_budget_exhausted",
            "budget_exhausted",
            "failure_budget_exhausted",
        }:
            return block_reason
        if block_reason == "pause_required":
            return "upstream_pause_required"
        if block_reason == "human_review_required":
            return "upstream_human_review_required"
        if block_reason == "insufficient_truth":
            return "insufficient_truth"
        return "upstream_blocked"

    if operation_status == "insufficient_truth":
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_status == "inactive":
        return _base_state(
            invocation_status="inactive",
            invocation_kind="none",
            invocation_permission="blocked",
            invocation_action="none",
            source_status="valid",
            block_reason="contract_not_ready",
            receipt_status="not_created",
            receipt_kind="none",
            counter_posture="not_applicable",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status="false",
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="upstream_blocked",
            simple_task_gate_status="blocked",
            simple_task_gate_reason="not_simple",
        )
    if operation_status == "blocked":
        block_reason = _map_operation_stop_reason_to_block_reason(
            operation_stop_reason,
            rolling_continue_reason,
        )
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason=block_reason,
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status="false",
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason=_map_block_reason_to_extra_reason(block_reason),
            simple_task_gate_status="blocked",
            simple_task_gate_reason="not_simple",
        )
    if operation_status == "cooldown_required":
        return _base_state(
            invocation_status="cooldown_required",
            invocation_kind="cooldown_invocation",
            invocation_permission="cooldown_required",
            invocation_action="cooldown",
            source_status="valid",
            block_reason="cooldown_required",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status="false",
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="cooldown_required",
            simple_task_gate_status="blocked",
            simple_task_gate_reason="high_risk_action",
        )
    if operation_status == "pause_required":
        return _base_state(
            invocation_status="pause_required",
            invocation_kind="pause_invocation",
            invocation_permission="pause_required",
            invocation_action="pause_for_login",
            source_status="valid",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status="false",
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="upstream_pause_required",
            simple_task_gate_status="blocked",
            simple_task_gate_reason="auth_or_secret_boundary",
        )
    if operation_status == "human_review_required":
        return _base_state(
            invocation_status="human_review_required",
            invocation_kind="human_review_invocation",
            invocation_permission="human_review_required",
            invocation_action="human_review",
            source_status="valid",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status="false",
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="upstream_human_review_required",
            simple_task_gate_status="blocked",
            simple_task_gate_reason="high_risk_action",
        )

    if operation_status != "ready":
        return _insufficient_truth_state(source_status="inconsistent")

    duplicate_risk_present = duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
        "duplicate_md_update",
        "duplicate_pause",
        "duplicate_human_review",
    }
    upstream_insufficient_truth = bool(
        multistep_budget_source_status in {"insufficient_truth", "inconsistent"}
        or execution_bridge_source_status in {"insufficient_truth", "inconsistent"}
        or safety_switch_status == "insufficient_truth"
        or manual_override_status == "insufficient_truth"
        or safe_stop_status == "insufficient_truth"
        or execution_permission == "insufficient_truth"
        or execution_bridge_status == "insufficient_truth"
        or execution_bridge_permission == "insufficient_truth"
        or rolling_gate_status == "insufficient_truth"
        or rolling_continue_permission == "insufficient_truth"
        or batch_continue_permission == "insufficient_truth"
        or step_receipt_status == "insufficient_truth"
        or step_score_band == "insufficient_truth"
        or cooldown_status == "insufficient_truth"
        or retry_hardening_status == "insufficient_truth"
        or loop_risk_status == "insufficient_truth"
    )
    upstream_pause_required = bool(
        safety_switch_status in {"pause_after_current_step", "pause_required"}
        or manual_override_status == "requested"
        or safe_stop_status == "pause_after_current_step"
        or execution_permission == "pause_required"
        or execution_bridge_permission == "pause_required"
        or rolling_continue_permission == "pause_required"
        or operation_permission == "pause_required"
    )
    upstream_human_review_required = bool(
        safety_switch_status in {"manual_review_required"}
        or manual_override_status in {"required", "blocked"}
        or safe_stop_status == "human_review_required"
        or execution_permission == "human_review_required"
        or execution_bridge_permission == "human_review_required"
        or rolling_continue_permission == "human_review_required"
        or operation_permission == "human_review_required"
    )
    upstream_blocked = bool(
        safety_switch_status in {"disabled", "stop_all"}
        or execution_permission == "blocked"
        or execution_bridge_status == "blocked"
        or execution_bridge_permission == "blocked"
        or multistep_budget_status != "ready"
        or multistep_permission != "allowed_candidate"
        or rolling_gate_status != "allowed_candidate"
        or rolling_continue_permission != "allowed_candidate"
        or batch_evaluation_status != "continue_candidate"
        or batch_continue_permission != "allowed_candidate"
        or step_receipt_status != "ready"
    )

    extra_hard_gate_reason = "none"
    if upstream_insufficient_truth:
        extra_hard_gate_reason = "upstream_insufficient_truth"
    elif upstream_pause_required:
        extra_hard_gate_reason = "upstream_pause_required"
    elif upstream_human_review_required:
        extra_hard_gate_reason = "upstream_human_review_required"
    elif raw_remaining_steps_after < 0:
        extra_hard_gate_reason = "budget_exhausted"
    elif raw_remaining_failures_after < 0:
        extra_hard_gate_reason = "failure_budget_exhausted"
    elif raw_same_prompt_retry_remaining_after < 0:
        extra_hard_gate_reason = "retry_budget_exhausted"
    elif cooldown_status != "not_required" or rolling_continue_permission == "cooldown_required":
        extra_hard_gate_reason = "cooldown_required"
    elif duplicate_risk_present:
        extra_hard_gate_reason = "duplicate_risk"
    elif same_failure_count > 0 or rolling_continue_reason == "same_failure_repeated":
        extra_hard_gate_reason = "same_failure_repeated"
    elif loop_risk_status != "clear" or rolling_continue_reason == "loop_suspected":
        extra_hard_gate_reason = "loop_suspected"
    elif (
        retry_hardening_status in {"exhausted", "blocked"}
        or (retry_path and same_prompt_retry_remaining <= 0)
    ):
        extra_hard_gate_reason = "retry_budget_exhausted"
    elif upstream_blocked:
        extra_hard_gate_reason = "upstream_blocked"
    extra_hard_gate_status = "clear" if extra_hard_gate_reason == "none" else "blocked"

    simple_task_gate_reason = "none"
    if upstream_insufficient_truth:
        simple_task_gate_reason = "insufficient_truth"
    elif task_size_status != "simple_low_risk":
        simple_task_gate_reason = "not_simple"
    elif not operation_runtime_metadata_only or not operation_runtime_no_next_step_start:
        simple_task_gate_reason = "high_risk_action"
    elif (
        not operation_runtime_no_prompt_send
        or not operation_runtime_no_browser_action
        or not operation_runtime_no_playwright
        or not operation_runtime_no_dom_interaction
        or not operation_runtime_no_codex_execution
    ):
        simple_task_gate_reason = "browser_or_codex_execution"
    elif not operation_runtime_no_md_write or not operation_runtime_no_shell_execution:
        simple_task_gate_reason = "execution_side_effect"
    elif (
        not operation_runtime_no_queue_mutation
        or not operation_runtime_no_retry_execution
        or not operation_runtime_no_repair_execution
        or not operation_runtime_no_restart_execution
        or not operation_runtime_no_approval_execution
        or not operation_runtime_no_continuation_execution
    ):
        simple_task_gate_reason = "state_mutation"
    elif not operation_runtime_no_loop_execution or not operation_runtime_no_background_runtime:
        simple_task_gate_reason = "high_risk_action"
    elif operation_status != "ready":
        simple_task_gate_reason = "not_simple"
    elif operation_permission != "allowed_candidate":
        simple_task_gate_reason = "not_simple"
    elif operation_next_safe_action != "continue_short_batch_later":
        simple_task_gate_reason = "not_simple"
    elif rolling_continue_permission != "allowed_candidate":
        simple_task_gate_reason = "high_risk_action"
    elif batch_continue_permission != "allowed_candidate":
        simple_task_gate_reason = "high_risk_action"
    elif step_receipt_status != "ready":
        simple_task_gate_reason = "not_simple"
    elif raw_remaining_steps_after < 0 or raw_remaining_failures_after < 0:
        simple_task_gate_reason = "high_risk_action"
    elif raw_same_prompt_retry_remaining_after < 0:
        simple_task_gate_reason = "high_risk_action"
    elif duplicate_risk_present:
        simple_task_gate_reason = "high_risk_action"
    elif cooldown_status != "not_required":
        simple_task_gate_reason = "high_risk_action"
    elif loop_risk_status != "clear":
        simple_task_gate_reason = "high_risk_action"
    elif same_failure_count != 0:
        simple_task_gate_reason = "high_risk_action"
    elif upstream_pause_required or upstream_human_review_required or upstream_blocked:
        simple_task_gate_reason = "not_simple"

    simple_task_gate_status = "clear" if simple_task_gate_reason == "none" else "blocked"
    simple_task_status = (
        "true"
        if simple_task_gate_status == "clear" and task_size_status == "simple_low_risk"
        else "false"
    )

    threshold_used_for_block = "none"
    if safety_score >= 92:
        threshold_used_for_block = "standard_92"
    elif safety_score >= 90:
        threshold_used_for_block = "simple_task_90"

    if raw_remaining_steps_after < 0:
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason="budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used=threshold_used_for_block,
            task_size_status=task_size_status,
            simple_task_status=simple_task_status,
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="budget_exhausted",
            simple_task_gate_status=simple_task_gate_status,
            simple_task_gate_reason=simple_task_gate_reason,
        )
    if raw_remaining_failures_after < 0:
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason="failure_budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used=threshold_used_for_block,
            task_size_status=task_size_status,
            simple_task_status=simple_task_status,
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="failure_budget_exhausted",
            simple_task_gate_status=simple_task_gate_status,
            simple_task_gate_reason=simple_task_gate_reason,
        )
    if raw_same_prompt_retry_remaining_after < 0:
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason="retry_budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used=threshold_used_for_block,
            task_size_status=task_size_status,
            simple_task_status=simple_task_status,
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason="retry_budget_exhausted",
            simple_task_gate_status=simple_task_gate_status,
            simple_task_gate_reason=simple_task_gate_reason,
        )

    if safety_score < 90:
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason="score_below_no_approval_threshold",
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="none",
            task_size_status=task_size_status,
            simple_task_status=simple_task_status,
            extra_hard_gate_status=extra_hard_gate_status,
            extra_hard_gate_reason=extra_hard_gate_reason,
            simple_task_gate_status=simple_task_gate_status,
            simple_task_gate_reason=simple_task_gate_reason,
        )

    if safety_score >= 92:
        if extra_hard_gate_status == "clear":
            return _base_state(
                invocation_status="prepared",
                invocation_kind="bounded_short_batch_invocation",
                invocation_permission="allowed_candidate",
                invocation_action="continue_short_batch_later",
                source_status="valid",
                block_reason="none",
                receipt_status="ready",
                receipt_kind="one_continuation_invocation_receipt",
                counter_posture="would_increment_one_step",
                remaining_steps_after=remaining_steps_after,
                remaining_failures_after=remaining_failures_after,
                same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
                threshold_used="standard_92",
                task_size_status=task_size_status,
                simple_task_status=simple_task_status,
                extra_hard_gate_status="clear",
                extra_hard_gate_reason="none",
                simple_task_gate_status=simple_task_gate_status,
                simple_task_gate_reason=simple_task_gate_reason,
            )
        return _base_state(
            invocation_status="blocked",
            invocation_kind="blocked_invocation",
            invocation_permission="blocked",
            invocation_action="stop",
            source_status="valid",
            block_reason="extra_hard_gate_blocked",
            receipt_status="blocked",
            receipt_kind="blocked_invocation_receipt",
            counter_posture="blocked",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="standard_92",
            task_size_status=task_size_status,
            simple_task_status=simple_task_status,
            extra_hard_gate_status="blocked",
            extra_hard_gate_reason=extra_hard_gate_reason,
            simple_task_gate_status=simple_task_gate_status,
            simple_task_gate_reason=simple_task_gate_reason,
        )

    if simple_task_gate_status == "clear" and simple_task_status == "true":
        return _base_state(
            invocation_status="prepared",
            invocation_kind="bounded_short_batch_invocation",
            invocation_permission="allowed_candidate",
            invocation_action="continue_short_batch_later",
            source_status="valid",
            block_reason="none",
            receipt_status="ready",
            receipt_kind="one_continuation_invocation_receipt",
            counter_posture="would_increment_one_step",
            remaining_steps_after=remaining_steps_after,
            remaining_failures_after=remaining_failures_after,
            same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
            threshold_used="simple_task_90",
            task_size_status=task_size_status,
            simple_task_status="true",
            extra_hard_gate_status=extra_hard_gate_status,
            extra_hard_gate_reason=extra_hard_gate_reason,
            simple_task_gate_status="clear",
            simple_task_gate_reason="none",
        )

    return _base_state(
        invocation_status="blocked",
        invocation_kind="blocked_invocation",
        invocation_permission="blocked",
        invocation_action="stop",
        source_status="valid",
        block_reason="simple_task_gate_blocked",
        receipt_status="blocked",
        receipt_kind="blocked_invocation_receipt",
        counter_posture="blocked",
        remaining_steps_after=remaining_steps_after,
        remaining_failures_after=remaining_failures_after,
        same_prompt_retry_remaining_after=same_prompt_retry_remaining_after,
        threshold_used="simple_task_90",
        task_size_status=task_size_status,
        simple_task_status=simple_task_status,
        extra_hard_gate_status=extra_hard_gate_status,
        extra_hard_gate_reason=extra_hard_gate_reason,
        simple_task_gate_status="blocked",
        simple_task_gate_reason=simple_task_gate_reason,
    )


def _build_project_browser_autonomous_dispatch_state(
    *,
    autonomous_invocation_status: str,
    autonomous_invocation_permission: str,
    autonomous_invocation_action: str,
    autonomous_invocation_source_status: str,
    autonomous_invocation_block_reason: str,
    autonomous_invocation_receipt_status: str,
    autonomous_invocation_threshold_used: str,
    autonomous_invocation_task_size_status: str,
    autonomous_invocation_simple_task_status: str,
    autonomous_invocation_simple_task_gate_status: str,
    autonomous_operation_contract_status: str,
    autonomous_operation_permission: str,
    autonomous_rolling_continue_permission: str,
    autonomous_cooldown_status: str,
    autonomous_loop_risk_status: str,
    autonomous_batch_continue_permission: str,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_next_step_candidate: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
) -> dict[str, Any]:
    invocation_status = _normalize_text(
        autonomous_invocation_status,
        default="insufficient_truth",
    )
    invocation_permission = _normalize_text(
        autonomous_invocation_permission,
        default="insufficient_truth",
    )
    invocation_action = _normalize_text(
        autonomous_invocation_action,
        default="none",
    )
    invocation_source_status = _normalize_text(
        autonomous_invocation_source_status,
        default="insufficient_truth",
    )
    invocation_block_reason = _normalize_text(
        autonomous_invocation_block_reason,
        default="insufficient_truth",
    )
    invocation_receipt_status = _normalize_text(
        autonomous_invocation_receipt_status,
        default="insufficient_truth",
    )
    invocation_threshold_used = _normalize_text(
        autonomous_invocation_threshold_used,
        default="insufficient_truth",
    )
    invocation_task_size_status = _normalize_text(
        autonomous_invocation_task_size_status,
        default="insufficient_truth",
    )
    invocation_simple_task_status = _normalize_text(
        autonomous_invocation_simple_task_status,
        default="insufficient_truth",
    )
    invocation_simple_task_gate_status = _normalize_text(
        autonomous_invocation_simple_task_gate_status,
        default="insufficient_truth",
    )

    operation_contract_status = _normalize_text(
        autonomous_operation_contract_status,
        default="insufficient_truth",
    )
    operation_permission = _normalize_text(
        autonomous_operation_permission,
        default="insufficient_truth",
    )
    rolling_continue_permission = _normalize_text(
        autonomous_rolling_continue_permission,
        default="insufficient_truth",
    )
    cooldown_status = _normalize_text(
        autonomous_cooldown_status,
        default="insufficient_truth",
    )
    loop_risk_status = _normalize_text(
        autonomous_loop_risk_status,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )

    multistep_budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    multistep_next_step_candidate = _normalize_text(
        autonomous_multistep_next_step_candidate,
        default="none",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    execution_bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    execution_bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_actual_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        dispatch_status: str,
        dispatch_kind: str,
        dispatch_permission: str,
        dispatch_action: str,
        source_status: str,
        risk_status: str,
        task_size_status: str,
        block_reason: str,
        receipt_status: str,
        receipt_kind: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_dispatch_status": dispatch_status,
            "project_browser_autonomous_dispatch_kind": dispatch_kind,
            "project_browser_autonomous_dispatch_permission": dispatch_permission,
            "project_browser_autonomous_dispatch_action": dispatch_action,
            "project_browser_autonomous_dispatch_source_status": source_status,
            "project_browser_autonomous_dispatch_risk_status": risk_status,
            "project_browser_autonomous_dispatch_task_size_status": task_size_status,
            "project_browser_autonomous_dispatch_block_reason": block_reason,
            "project_browser_autonomous_dispatch_receipt_status": receipt_status,
            "project_browser_autonomous_dispatch_receipt_kind": receipt_kind,
            "project_browser_autonomous_dispatch_runtime_posture": runtime_posture,
        }

    def _insufficient_truth_state(
        *,
        source_status: str,
        block_reason: str = "insufficient_truth",
    ) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in {"valid", "inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        normalized_block_reason = (
            block_reason
            if block_reason in {"source_inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        return _base_state(
            dispatch_status="insufficient_truth",
            dispatch_kind="insufficient_truth_dispatch",
            dispatch_permission="insufficient_truth",
            dispatch_action="none",
            source_status=normalized_source_status,
            risk_status="insufficient_truth",
            task_size_status="insufficient_truth",
            block_reason=normalized_block_reason,
            receipt_status="insufficient_truth",
            receipt_kind="insufficient_truth_dispatch_receipt",
        )

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    def _map_invocation_block_reason(value: str) -> str:
        mapping = {
            "none": "none",
            "contract_not_ready": "invocation_not_ready",
            "permission_not_allowed": "permission_not_allowed",
            "score_below_no_approval_threshold": "permission_not_allowed",
            "extra_hard_gate_blocked": "permission_not_allowed",
            "simple_task_gate_blocked": "high_risk_action",
            "budget_exhausted": "budget_exhausted",
            "failure_budget_exhausted": "failure_budget_exhausted",
            "retry_budget_exhausted": "retry_budget_exhausted",
            "cooldown_required": "cooldown_required",
            "duplicate_risk": "duplicate_risk",
            "loop_suspected": "loop_suspected",
            "same_failure_repeated": "loop_suspected",
            "pause_required": "pause_required",
            "human_review_required": "human_review_required",
            "insufficient_truth": "insufficient_truth",
        }
        return mapping.get(value, "insufficient_truth")

    def _map_invocation_action(value: str) -> str:
        mapping = {
            "none": "none",
            "continue_short_batch_later": "none",
            "stop": "stop",
            "cooldown": "cooldown",
            "pause_for_login": "pause_for_login",
            "human_review": "human_review",
        }
        return mapping.get(value, "none")

    def _map_continue_candidate_to_dispatch_action(value: str) -> str:
        mapping = {
            "apply_md_update": "prepare_md_update_handoff",
            "send_next_prompt": "prepare_next_prompt_handoff",
            "retry_same_prompt": "prepare_retry_same_prompt_handoff",
            "stop": "stop",
            "pause_for_login": "pause_for_login",
            "human_review": "human_review",
            "none": "none",
        }
        return mapping.get(value, "none")

    if invocation_status not in {
        "inactive",
        "prepared",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_action not in {
        "none",
        "continue_short_batch_later",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_block_reason not in {
        "none",
        "contract_not_ready",
        "permission_not_allowed",
        "score_below_no_approval_threshold",
        "extra_hard_gate_blocked",
        "simple_task_gate_blocked",
        "budget_exhausted",
        "failure_budget_exhausted",
        "retry_budget_exhausted",
        "cooldown_required",
        "duplicate_risk",
        "loop_suspected",
        "same_failure_repeated",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_threshold_used not in {
        "none",
        "standard_92",
        "simple_task_90",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_task_size_status not in {
        "unknown",
        "simple_low_risk",
        "standard",
        "high_risk",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_simple_task_status not in {"true", "false", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_simple_task_gate_status not in {"clear", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_contract_status not in {
        "inactive",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if operation_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if rolling_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if cooldown_status not in {"not_required", "required", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if loop_risk_status not in {"clear", "suspected", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if multistep_next_step_candidate not in {
        "none",
        "apply_md_update",
        "send_next_prompt",
        "retry_same_prompt",
        "pause_for_login",
        "human_review",
        "stop",
    }:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state(source_status="insufficient_truth")
    if execution_bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(source_status="insufficient_truth")

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    same_prompt_retry_remaining, same_prompt_retry_remaining_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_same_prompt_retry_remaining")
    )
    if remaining_steps_invalid or remaining_failures_invalid or same_prompt_retry_remaining_invalid:
        return _insufficient_truth_state(source_status="insufficient_truth")

    if invocation_source_status == "insufficient_truth":
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_source_status == "inconsistent":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    if invocation_status == "insufficient_truth":
        return _insufficient_truth_state(source_status="insufficient_truth")
    if invocation_status == "inactive":
        return _base_state(
            dispatch_status="inactive",
            dispatch_kind="none",
            dispatch_permission="blocked",
            dispatch_action="none",
            source_status="valid",
            risk_status="blocked",
            task_size_status="insufficient_truth",
            block_reason="invocation_not_ready",
            receipt_status="not_created",
            receipt_kind="none",
        )
    if invocation_status == "blocked":
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action=_map_invocation_action(invocation_action),
            source_status="valid",
            risk_status="blocked",
            task_size_status=(
                invocation_task_size_status
                if invocation_task_size_status in {"simple_low_risk", "standard", "high_risk"}
                else "standard"
            ),
            block_reason=_map_invocation_block_reason(invocation_block_reason),
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )
    if invocation_status == "cooldown_required":
        return _base_state(
            dispatch_status="cooldown_required",
            dispatch_kind="cooldown_dispatch",
            dispatch_permission="cooldown_required",
            dispatch_action="cooldown",
            source_status="valid",
            risk_status="high",
            task_size_status="high_risk",
            block_reason="cooldown_required",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_dispatch_receipt",
        )
    if invocation_status == "pause_required":
        return _base_state(
            dispatch_status="pause_required",
            dispatch_kind="pause_dispatch",
            dispatch_permission="pause_required",
            dispatch_action="pause_for_login",
            source_status="valid",
            risk_status="high",
            task_size_status="high_risk",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_dispatch_receipt",
        )
    if invocation_status == "human_review_required":
        return _base_state(
            dispatch_status="human_review_required",
            dispatch_kind="human_review_dispatch",
            dispatch_permission="human_review_required",
            dispatch_action="human_review",
            source_status="valid",
            risk_status="high",
            task_size_status="high_risk",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_dispatch_receipt",
        )

    if invocation_status != "prepared":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    source_conflict = False
    if invocation_permission != "allowed_candidate":
        source_conflict = True
    if invocation_receipt_status != "ready":
        source_conflict = True
    if invocation_action != "continue_short_batch_later":
        source_conflict = True
    if operation_contract_status != "ready":
        source_conflict = True
    if operation_permission != "allowed_candidate":
        source_conflict = True
    if rolling_continue_permission != "allowed_candidate":
        source_conflict = True
    if batch_continue_permission != "allowed_candidate":
        source_conflict = True
    if multistep_budget_status != "ready" or multistep_permission != "allowed_candidate":
        source_conflict = True
    if remaining_steps <= 0 or remaining_failures <= 0:
        source_conflict = True
    if cooldown_status != "not_required":
        source_conflict = True
    if loop_risk_status != "clear":
        source_conflict = True
    if safety_switch_status in {
        "disabled",
        "stop_all",
        "pause_after_current_step",
        "manual_review_required",
        "pause_required",
        "insufficient_truth",
    }:
        source_conflict = True
    if manual_override_status in {"requested", "required", "blocked", "insufficient_truth"}:
        source_conflict = True
    if safe_stop_status != "not_required":
        source_conflict = True
    if execution_permission != "allowed_candidate":
        source_conflict = True
    if execution_bridge_status != "ready":
        source_conflict = True
    if execution_bridge_permission != "allowed_candidate":
        source_conflict = True
    if any(
        token == "insufficient_truth"
        for token in (
            invocation_threshold_used,
            invocation_task_size_status,
            invocation_simple_task_status,
            invocation_simple_task_gate_status,
            duplicate_status,
            rolling_continue_permission,
            batch_continue_permission,
        )
    ):
        source_conflict = True
    if source_conflict:
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    dispatch_action = _map_continue_candidate_to_dispatch_action(multistep_next_step_candidate)
    if dispatch_action == "none":
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action="none",
            source_status="valid",
            risk_status="blocked",
            task_size_status="standard",
            block_reason="invocation_not_ready",
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )

    if duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
        "duplicate_md_update",
        "duplicate_pause",
        "duplicate_human_review",
    }:
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action=dispatch_action,
            source_status="valid",
            risk_status="blocked",
            task_size_status="high_risk",
            block_reason="duplicate_risk",
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )

    if dispatch_action == "prepare_retry_same_prompt_handoff" and same_prompt_retry_remaining <= 0:
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action=dispatch_action,
            source_status="valid",
            risk_status="blocked",
            task_size_status="high_risk",
            block_reason="retry_budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )

    if dispatch_action in {"stop", "cooldown", "pause_for_login", "human_review"}:
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action=dispatch_action,
            source_status="valid",
            risk_status="high",
            task_size_status="high_risk",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )

    task_size_status = "standard"
    risk_status = "standard"
    if (
        invocation_threshold_used == "simple_task_90"
        and invocation_simple_task_status == "true"
        and invocation_simple_task_gate_status == "clear"
    ):
        task_size_status = "simple_low_risk"
        risk_status = "low"
    elif invocation_task_size_status == "high_risk":
        task_size_status = "high_risk"
        risk_status = "high"
    elif invocation_task_size_status in {"simple_low_risk", "standard"}:
        task_size_status = invocation_task_size_status
        risk_status = "low" if task_size_status == "simple_low_risk" else "standard"

    if task_size_status == "high_risk" or risk_status == "high":
        return _base_state(
            dispatch_status="blocked",
            dispatch_kind="blocked_dispatch",
            dispatch_permission="blocked",
            dispatch_action=dispatch_action,
            source_status="valid",
            risk_status="high",
            task_size_status="high_risk",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_dispatch_receipt",
        )

    return _base_state(
        dispatch_status="prepared",
        dispatch_kind="one_dispatch_candidate",
        dispatch_permission="allowed_candidate",
        dispatch_action=dispatch_action,
        source_status="valid",
        risk_status=risk_status,
        task_size_status=task_size_status,
        block_reason="none",
        receipt_status="ready",
        receipt_kind="one_dispatch_candidate_receipt",
    )


def _build_project_browser_autonomous_executor_readiness_state(
    *,
    autonomous_dispatch_status: str,
    autonomous_dispatch_permission: str,
    autonomous_dispatch_action: str,
    autonomous_dispatch_source_status: str,
    autonomous_dispatch_risk_status: str,
    autonomous_dispatch_task_size_status: str,
    autonomous_dispatch_block_reason: str,
    autonomous_dispatch_receipt_status: str,
    autonomous_invocation_status: str,
    autonomous_invocation_threshold_used: str,
    autonomous_operation_contract_status: str,
    autonomous_rolling_continue_permission: str,
    autonomous_batch_continue_permission: str,
    autonomous_cooldown_status: str,
    autonomous_loop_risk_status: str,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
) -> dict[str, Any]:
    dispatch_status = _normalize_text(
        autonomous_dispatch_status,
        default="insufficient_truth",
    )
    dispatch_permission = _normalize_text(
        autonomous_dispatch_permission,
        default="insufficient_truth",
    )
    dispatch_action = _normalize_text(
        autonomous_dispatch_action,
        default="none",
    )
    dispatch_source_status = _normalize_text(
        autonomous_dispatch_source_status,
        default="insufficient_truth",
    )
    dispatch_risk_status = _normalize_text(
        autonomous_dispatch_risk_status,
        default="insufficient_truth",
    )
    dispatch_task_size_status = _normalize_text(
        autonomous_dispatch_task_size_status,
        default="insufficient_truth",
    )
    dispatch_block_reason = _normalize_text(
        autonomous_dispatch_block_reason,
        default="insufficient_truth",
    )
    dispatch_receipt_status = _normalize_text(
        autonomous_dispatch_receipt_status,
        default="insufficient_truth",
    )

    invocation_status = _normalize_text(
        autonomous_invocation_status,
        default="insufficient_truth",
    )
    invocation_threshold_used = _normalize_text(
        autonomous_invocation_threshold_used,
        default="insufficient_truth",
    )

    operation_contract_status = _normalize_text(
        autonomous_operation_contract_status,
        default="insufficient_truth",
    )
    rolling_continue_permission = _normalize_text(
        autonomous_rolling_continue_permission,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )
    cooldown_status = _normalize_text(
        autonomous_cooldown_status,
        default="insufficient_truth",
    )
    loop_risk_status = _normalize_text(
        autonomous_loop_risk_status,
        default="insufficient_truth",
    )
    multistep_budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    execution_bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    execution_bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_actual_execution",
        "no_next_step_start",
        "no_prompt_send",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        readiness_status: str,
        candidate_kind: str,
        permission: str,
        action: str,
        source_status: str,
        risk_status: str,
        side_effect_status: str,
        low_risk_path_status: str,
        standard_path_status: str,
        block_reason: str,
        receipt_status: str,
        receipt_kind: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_executor_readiness_status": readiness_status,
            "project_browser_autonomous_executor_candidate_kind": candidate_kind,
            "project_browser_autonomous_executor_permission": permission,
            "project_browser_autonomous_executor_action": action,
            "project_browser_autonomous_executor_source_status": source_status,
            "project_browser_autonomous_executor_risk_status": risk_status,
            "project_browser_autonomous_executor_side_effect_status": side_effect_status,
            "project_browser_autonomous_executor_low_risk_path_status": low_risk_path_status,
            "project_browser_autonomous_executor_standard_path_status": standard_path_status,
            "project_browser_autonomous_executor_block_reason": block_reason,
            "project_browser_autonomous_executor_receipt_status": receipt_status,
            "project_browser_autonomous_executor_receipt_kind": receipt_kind,
            "project_browser_autonomous_executor_runtime_posture": runtime_posture,
        }

    def _insufficient_truth_state(*, source_status: str, block_reason: str) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in {"valid", "inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        normalized_block_reason = (
            block_reason
            if block_reason in {"source_inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        return _base_state(
            readiness_status="insufficient_truth",
            candidate_kind="insufficient_truth_executor_candidate",
            permission="insufficient_truth",
            action="none",
            source_status=normalized_source_status,
            risk_status="insufficient_truth",
            side_effect_status="insufficient_truth",
            low_risk_path_status="insufficient_truth",
            standard_path_status="insufficient_truth",
            block_reason=normalized_block_reason,
            receipt_status="insufficient_truth",
            receipt_kind="insufficient_truth_executor_receipt",
        )

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    def _map_dispatch_action(value: str) -> tuple[str, str]:
        mapping = {
            "none": ("none", "none"),
            "prepare_next_prompt_handoff": (
                "next_prompt_handoff",
                "next_prompt_handoff_executor_candidate",
            ),
            "prepare_retry_same_prompt_handoff": (
                "retry_same_prompt_handoff",
                "retry_same_prompt_handoff_executor_candidate",
            ),
            "prepare_md_update_handoff": (
                "md_update_handoff",
                "md_update_handoff_executor_candidate",
            ),
            "stop": ("stop", "stop_executor_candidate"),
            "cooldown": ("cooldown", "cooldown_executor_candidate"),
            "pause_for_login": ("pause_for_login", "pause_executor_candidate"),
            "human_review": ("human_review", "human_review_executor_candidate"),
        }
        return mapping.get(value, ("none", "none"))

    def _map_dispatch_block_reason(value: str) -> str:
        mapping = {
            "none": "dispatch_not_ready",
            "invocation_not_ready": "dispatch_not_ready",
            "permission_not_allowed": "permission_not_allowed",
            "source_inconsistent": "source_inconsistent",
            "high_risk_action": "high_risk_action",
            "execution_side_effect": "side_effect_not_allowed",
            "duplicate_risk": "duplicate_risk",
            "cooldown_required": "cooldown_required",
            "loop_suspected": "loop_suspected",
            "retry_budget_exhausted": "retry_budget_exhausted",
            "budget_exhausted": "budget_exhausted",
            "failure_budget_exhausted": "failure_budget_exhausted",
            "pause_required": "pause_required",
            "human_review_required": "human_review_required",
            "insufficient_truth": "insufficient_truth",
        }
        return mapping.get(value, "insufficient_truth")

    if dispatch_status not in {
        "inactive",
        "prepared",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_action not in {
        "none",
        "prepare_next_prompt_handoff",
        "prepare_retry_same_prompt_handoff",
        "prepare_md_update_handoff",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_risk_status not in {"low", "standard", "high", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_task_size_status not in {
        "simple_low_risk",
        "standard",
        "high_risk",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_block_reason not in {
        "none",
        "invocation_not_ready",
        "permission_not_allowed",
        "source_inconsistent",
        "high_risk_action",
        "execution_side_effect",
        "duplicate_risk",
        "cooldown_required",
        "loop_suspected",
        "retry_budget_exhausted",
        "budget_exhausted",
        "failure_budget_exhausted",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if invocation_status not in {
        "inactive",
        "prepared",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if invocation_threshold_used not in {
        "none",
        "standard_92",
        "simple_task_90",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if operation_contract_status not in {
        "inactive",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if rolling_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if cooldown_status not in {"not_required", "required", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if loop_risk_status not in {"clear", "suspected", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if multistep_budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    if remaining_steps_invalid or remaining_failures_invalid:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    mapped_executor_action, mapped_candidate_kind = _map_dispatch_action(dispatch_action)
    if mapped_executor_action == "none" and dispatch_action != "none":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    if dispatch_source_status == "insufficient_truth":
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if dispatch_source_status == "inconsistent":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )
    if dispatch_status == "insufficient_truth":
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    if dispatch_status == "inactive":
        return _base_state(
            readiness_status="inactive",
            candidate_kind="none",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_status="none",
            low_risk_path_status="unavailable",
            standard_path_status="unavailable",
            block_reason="dispatch_not_ready",
            receipt_status="not_created",
            receipt_kind="none",
        )
    if dispatch_status == "blocked":
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action=mapped_executor_action,
            source_status="valid",
            risk_status="blocked",
            side_effect_status="blocked",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason=_map_dispatch_block_reason(dispatch_block_reason),
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )
    if dispatch_status == "cooldown_required":
        return _base_state(
            readiness_status="cooldown_required",
            candidate_kind="cooldown_executor_candidate",
            permission="cooldown_required",
            action="cooldown",
            source_status="valid",
            risk_status="high",
            side_effect_status="none",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="cooldown_required",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_executor_receipt",
        )
    if dispatch_status == "pause_required":
        return _base_state(
            readiness_status="pause_required",
            candidate_kind="pause_executor_candidate",
            permission="pause_required",
            action="pause_for_login",
            source_status="valid",
            risk_status="high",
            side_effect_status="none",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_executor_receipt",
        )
    if dispatch_status == "human_review_required":
        return _base_state(
            readiness_status="human_review_required",
            candidate_kind="human_review_executor_candidate",
            permission="human_review_required",
            action="human_review",
            source_status="valid",
            risk_status="high",
            side_effect_status="none",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_executor_receipt",
        )

    if dispatch_status != "prepared":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    source_conflict = False
    if dispatch_permission != "allowed_candidate":
        source_conflict = True
    if dispatch_receipt_status != "ready":
        source_conflict = True
    if dispatch_source_status != "valid":
        source_conflict = True
    if dispatch_action not in {
        "prepare_next_prompt_handoff",
        "prepare_retry_same_prompt_handoff",
        "prepare_md_update_handoff",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        source_conflict = True
    if invocation_status != "prepared":
        source_conflict = True
    if operation_contract_status != "ready":
        source_conflict = True
    if rolling_continue_permission != "allowed_candidate":
        source_conflict = True
    if batch_continue_permission != "allowed_candidate":
        source_conflict = True
    if multistep_budget_status != "ready" or multistep_permission != "allowed_candidate":
        source_conflict = True
    if remaining_steps <= 0:
        source_conflict = True
    if remaining_failures <= 0:
        source_conflict = True
    if cooldown_status != "not_required":
        source_conflict = True
    if loop_risk_status != "clear":
        source_conflict = True
    if safety_switch_status in {
        "disabled",
        "stop_all",
        "pause_after_current_step",
        "manual_review_required",
        "pause_required",
        "insufficient_truth",
    }:
        source_conflict = True
    if manual_override_status in {"requested", "required", "blocked", "insufficient_truth"}:
        source_conflict = True
    if safe_stop_status != "not_required":
        source_conflict = True
    if execution_permission != "allowed_candidate":
        source_conflict = True
    if execution_bridge_status != "ready":
        source_conflict = True
    if execution_bridge_permission != "allowed_candidate":
        source_conflict = True
    if duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
        "duplicate_md_update",
        "duplicate_pause",
        "duplicate_human_review",
    }:
        source_conflict = True
    if any(
        token == "insufficient_truth"
        for token in (
            dispatch_risk_status,
            dispatch_task_size_status,
            invocation_threshold_used,
        )
    ):
        source_conflict = True
    if source_conflict:
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    side_effect_status = "none"
    if mapped_executor_action in {
        "next_prompt_handoff",
        "retry_same_prompt_handoff",
        "md_update_handoff",
    }:
        side_effect_status = "handoff_only"
    if side_effect_status == "none" and mapped_executor_action in {
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        side_effect_status = "none"
    if mapped_executor_action == "none":
        side_effect_status = "blocked"

    if side_effect_status in {
        "would_send_prompt",
        "would_write_md",
        "would_call_codex",
        "would_touch_browser",
        "would_execute_shell",
        "would_mutate_state",
    }:
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action=mapped_executor_action,
            source_status="valid",
            risk_status="blocked",
            side_effect_status=side_effect_status,
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="side_effect_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )
    if mapped_executor_action == "none":
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_status="blocked",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="dispatch_not_ready",
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )
    if mapped_executor_action in {"stop", "cooldown", "pause_for_login", "human_review"}:
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action=mapped_executor_action,
            source_status="valid",
            risk_status="high",
            side_effect_status="blocked",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )

    low_risk_path_status = "unavailable"
    standard_path_status = "unavailable"
    risk_status = "standard"

    if dispatch_task_size_status == "high_risk" or dispatch_risk_status in {"high", "blocked"}:
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action=mapped_executor_action,
            source_status="valid",
            risk_status="blocked",
            side_effect_status="blocked",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )
    if dispatch_task_size_status == "simple_low_risk" and dispatch_risk_status == "low":
        if invocation_threshold_used in {"simple_task_90", "standard_92"}:
            low_risk_path_status = "available"
            standard_path_status = "unavailable"
            risk_status = "low"
        else:
            low_risk_path_status = "blocked"
            standard_path_status = "blocked"
    elif dispatch_task_size_status == "standard" and dispatch_risk_status == "standard":
        if invocation_threshold_used == "standard_92":
            low_risk_path_status = "unavailable"
            standard_path_status = "available"
            risk_status = "standard"
        else:
            low_risk_path_status = "blocked"
            standard_path_status = "blocked"
    else:
        low_risk_path_status = "blocked"
        standard_path_status = "blocked"

    if low_risk_path_status == "blocked" and standard_path_status == "blocked":
        return _base_state(
            readiness_status="blocked",
            candidate_kind="blocked_executor_candidate",
            permission="blocked",
            action=mapped_executor_action,
            source_status="valid",
            risk_status="blocked",
            side_effect_status="blocked",
            low_risk_path_status="blocked",
            standard_path_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_executor_receipt",
        )

    return _base_state(
        readiness_status="ready",
        candidate_kind=mapped_candidate_kind,
        permission="allowed_candidate",
        action=mapped_executor_action,
        source_status="valid",
        risk_status=risk_status,
        side_effect_status=side_effect_status,
        low_risk_path_status=low_risk_path_status,
        standard_path_status=standard_path_status,
        block_reason="none",
        receipt_status="ready",
        receipt_kind="one_executor_candidate_receipt",
    )


def _build_project_browser_autonomous_execution_adapter_state(
    *,
    autonomous_executor_readiness_status: str,
    autonomous_executor_candidate_kind: str,
    autonomous_executor_permission: str,
    autonomous_executor_action: str,
    autonomous_executor_source_status: str,
    autonomous_executor_risk_status: str,
    autonomous_executor_low_risk_path_status: str,
    autonomous_executor_standard_path_status: str,
    autonomous_executor_block_reason: str,
    autonomous_executor_receipt_status: str,
    autonomous_dispatch_status: str,
    autonomous_invocation_status: str,
    autonomous_invocation_threshold_used: str,
    autonomous_operation_contract_status: str,
    autonomous_rolling_continue_permission: str,
    autonomous_batch_continue_permission: str,
    autonomous_cooldown_status: str,
    autonomous_loop_risk_status: str,
    autonomous_multistep_budget_status: str,
    autonomous_multistep_permission: str,
    autonomous_multistep_state: Mapping[str, Any] | None,
    autonomous_action_duplicate_status: str,
    autonomous_safety_switch_status: str,
    autonomous_manual_override_status: str,
    autonomous_safe_stop_status: str,
    autonomous_execution_permission: str,
    autonomous_execution_bridge_status: str,
    autonomous_execution_bridge_permission: str,
) -> dict[str, Any]:
    executor_readiness_status = _normalize_text(
        autonomous_executor_readiness_status,
        default="insufficient_truth",
    )
    executor_candidate_kind = _normalize_text(
        autonomous_executor_candidate_kind,
        default="insufficient_truth_executor_candidate",
    )
    executor_permission = _normalize_text(
        autonomous_executor_permission,
        default="insufficient_truth",
    )
    executor_action = _normalize_text(
        autonomous_executor_action,
        default="none",
    )
    executor_source_status = _normalize_text(
        autonomous_executor_source_status,
        default="insufficient_truth",
    )
    executor_risk_status = _normalize_text(
        autonomous_executor_risk_status,
        default="insufficient_truth",
    )
    executor_low_risk_path_status = _normalize_text(
        autonomous_executor_low_risk_path_status,
        default="insufficient_truth",
    )
    executor_standard_path_status = _normalize_text(
        autonomous_executor_standard_path_status,
        default="insufficient_truth",
    )
    executor_block_reason = _normalize_text(
        autonomous_executor_block_reason,
        default="insufficient_truth",
    )
    executor_receipt_status = _normalize_text(
        autonomous_executor_receipt_status,
        default="insufficient_truth",
    )

    dispatch_status = _normalize_text(
        autonomous_dispatch_status,
        default="insufficient_truth",
    )
    invocation_status = _normalize_text(
        autonomous_invocation_status,
        default="insufficient_truth",
    )
    invocation_threshold_used = _normalize_text(
        autonomous_invocation_threshold_used,
        default="insufficient_truth",
    )
    operation_contract_status = _normalize_text(
        autonomous_operation_contract_status,
        default="insufficient_truth",
    )
    rolling_continue_permission = _normalize_text(
        autonomous_rolling_continue_permission,
        default="insufficient_truth",
    )
    batch_continue_permission = _normalize_text(
        autonomous_batch_continue_permission,
        default="insufficient_truth",
    )
    cooldown_status = _normalize_text(
        autonomous_cooldown_status,
        default="insufficient_truth",
    )
    loop_risk_status = _normalize_text(
        autonomous_loop_risk_status,
        default="insufficient_truth",
    )
    multistep_budget_status = _normalize_text(
        autonomous_multistep_budget_status,
        default="insufficient_truth",
    )
    multistep_permission = _normalize_text(
        autonomous_multistep_permission,
        default="insufficient_truth",
    )
    multistep_state = dict(autonomous_multistep_state or {})

    duplicate_status = _normalize_text(
        autonomous_action_duplicate_status,
        default="insufficient_truth",
    )
    safety_switch_status = _normalize_text(
        autonomous_safety_switch_status,
        default="insufficient_truth",
    )
    manual_override_status = _normalize_text(
        autonomous_manual_override_status,
        default="insufficient_truth",
    )
    safe_stop_status = _normalize_text(
        autonomous_safe_stop_status,
        default="insufficient_truth",
    )
    execution_permission = _normalize_text(
        autonomous_execution_permission,
        default="insufficient_truth",
    )
    execution_bridge_status = _normalize_text(
        autonomous_execution_bridge_status,
        default="insufficient_truth",
    )
    execution_bridge_permission = _normalize_text(
        autonomous_execution_bridge_permission,
        default="insufficient_truth",
    )

    runtime_posture = [
        "metadata_only",
        "no_actual_execution",
        "no_actual_next_step_start",
        "no_prompt_send",
        "no_browser_enqueue",
        "no_md_write",
        "no_shell_execution",
        "no_codex_execution",
        "no_browser_action",
        "no_playwright",
        "no_dom_interaction",
        "no_queue_mutation",
        "no_retry_execution",
        "no_repair_execution",
        "no_restart_execution",
        "no_approval_execution",
        "no_continuation_execution",
        "no_counter_mutation",
        "no_loop_execution",
        "no_background_runtime",
    ]

    def _base_state(
        *,
        status: str,
        kind: str,
        permission: str,
        action: str,
        source_status: str,
        risk_status: str,
        side_effect_class: str,
        low_risk_policy_status: str,
        standard_policy_status: str,
        high_risk_policy_status: str,
        block_reason: str,
        receipt_status: str,
        receipt_kind: str,
    ) -> dict[str, Any]:
        return {
            "project_browser_autonomous_execution_adapter_status": status,
            "project_browser_autonomous_execution_adapter_kind": kind,
            "project_browser_autonomous_execution_adapter_permission": permission,
            "project_browser_autonomous_execution_adapter_action": action,
            "project_browser_autonomous_execution_adapter_source_status": source_status,
            "project_browser_autonomous_execution_adapter_risk_status": risk_status,
            "project_browser_autonomous_execution_adapter_side_effect_class": (
                side_effect_class
            ),
            "project_browser_autonomous_execution_adapter_low_risk_policy_status": (
                low_risk_policy_status
            ),
            "project_browser_autonomous_execution_adapter_standard_policy_status": (
                standard_policy_status
            ),
            "project_browser_autonomous_execution_adapter_high_risk_policy_status": (
                high_risk_policy_status
            ),
            "project_browser_autonomous_execution_adapter_block_reason": block_reason,
            "project_browser_autonomous_execution_adapter_receipt_status": receipt_status,
            "project_browser_autonomous_execution_adapter_receipt_kind": receipt_kind,
            "project_browser_autonomous_execution_adapter_runtime_posture": runtime_posture,
        }

    def _insufficient_truth_state(*, source_status: str, block_reason: str) -> dict[str, Any]:
        normalized_source_status = (
            source_status
            if source_status in {"valid", "inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        normalized_block_reason = (
            block_reason
            if block_reason in {"source_inconsistent", "insufficient_truth"}
            else "insufficient_truth"
        )
        return _base_state(
            status="insufficient_truth",
            kind="insufficient_truth_adapter",
            permission="insufficient_truth",
            action="none",
            source_status=normalized_source_status,
            risk_status="insufficient_truth",
            side_effect_class="insufficient_truth",
            low_risk_policy_status="insufficient_truth",
            standard_policy_status="insufficient_truth",
            high_risk_policy_status="insufficient_truth",
            block_reason=normalized_block_reason,
            receipt_status="insufficient_truth",
            receipt_kind="insufficient_truth_adapter_receipt",
        )

    def _read_required_non_negative_int(value: Any) -> tuple[int, bool]:
        if isinstance(value, bool):
            return 0, True
        if isinstance(value, int):
            return (value if value >= 0 else 0), value < 0
        if isinstance(value, str):
            text = value.strip()
            if text.isdigit():
                return int(text), False
        return 0, True

    def _map_executor_candidate(
        value: str,
    ) -> tuple[str, str, str]:
        mapping = {
            "none": ("none", "none", "none"),
            "next_prompt_handoff_executor_candidate": (
                "next_prompt_handoff",
                "browser_prompt_enqueue_candidate",
                "standard_execution_adapter",
            ),
            "retry_same_prompt_handoff_executor_candidate": (
                "retry_same_prompt_handoff",
                "browser_retry_enqueue_candidate",
                "standard_execution_adapter",
            ),
            "md_update_handoff_executor_candidate": (
                "md_update_handoff",
                "md_update_apply_candidate",
                "low_risk_execution_adapter",
            ),
            "stop_executor_candidate": ("stop", "stop", "stopped_adapter"),
            "cooldown_executor_candidate": (
                "cooldown",
                "cooldown",
                "cooldown_adapter",
            ),
            "pause_executor_candidate": (
                "pause_for_login",
                "pause_for_login",
                "pause_adapter",
            ),
            "human_review_executor_candidate": (
                "human_review",
                "human_review",
                "human_review_adapter",
            ),
            "blocked_executor_candidate": ("none", "none", "blocked_adapter"),
            "insufficient_truth_executor_candidate": (
                "none",
                "none",
                "insufficient_truth_adapter",
            ),
        }
        return mapping.get(value, ("none", "none", "none"))

    def _map_executor_action(value: str) -> tuple[str, str]:
        mapping = {
            "none": ("none", "none"),
            "next_prompt_handoff": (
                "browser_prompt_enqueue_candidate",
                "standard_execution_adapter",
            ),
            "retry_same_prompt_handoff": (
                "browser_retry_enqueue_candidate",
                "standard_execution_adapter",
            ),
            "md_update_handoff": (
                "md_update_apply_candidate",
                "low_risk_execution_adapter",
            ),
            "stop": ("stop", "stopped_adapter"),
            "cooldown": ("cooldown", "cooldown_adapter"),
            "pause_for_login": ("pause_for_login", "pause_adapter"),
            "human_review": ("human_review", "human_review_adapter"),
        }
        return mapping.get(value, ("none", "none"))

    def _map_side_effect_class(value: str) -> str:
        if value == "md_update_apply_candidate":
            return "md_write_future"
        if value in {"browser_prompt_enqueue_candidate", "browser_retry_enqueue_candidate"}:
            return "browser_enqueue_future"
        if value == "codex_invocation_candidate":
            return "codex_run_future"
        if value in {"stop", "cooldown", "pause_for_login", "human_review"}:
            return "metadata_only"
        if value == "none":
            return "none"
        return "blocked"

    def _map_executor_block_reason(value: str) -> str:
        mapping = {
            "none": "executor_not_ready",
            "dispatch_not_ready": "executor_not_ready",
            "permission_not_allowed": "permission_not_allowed",
            "source_inconsistent": "source_inconsistent",
            "high_risk_action": "high_risk_action",
            "side_effect_not_allowed": "side_effect_not_allowed",
            "duplicate_risk": "duplicate_risk",
            "cooldown_required": "cooldown_required",
            "loop_suspected": "loop_suspected",
            "retry_budget_exhausted": "retry_budget_exhausted",
            "budget_exhausted": "budget_exhausted",
            "failure_budget_exhausted": "failure_budget_exhausted",
            "pause_required": "pause_required",
            "human_review_required": "human_review_required",
            "insufficient_truth": "insufficient_truth",
        }
        return mapping.get(value, "insufficient_truth")

    if executor_readiness_status not in {
        "inactive",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_candidate_kind not in {
        "none",
        "next_prompt_handoff_executor_candidate",
        "retry_same_prompt_handoff_executor_candidate",
        "md_update_handoff_executor_candidate",
        "stop_executor_candidate",
        "cooldown_executor_candidate",
        "pause_executor_candidate",
        "human_review_executor_candidate",
        "blocked_executor_candidate",
        "insufficient_truth_executor_candidate",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_action not in {
        "none",
        "next_prompt_handoff",
        "retry_same_prompt_handoff",
        "md_update_handoff",
        "stop",
        "cooldown",
        "pause_for_login",
        "human_review",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_source_status not in {"valid", "inconsistent", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_risk_status not in {"low", "standard", "high", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_low_risk_path_status not in {
        "unavailable",
        "available",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_standard_path_status not in {
        "unavailable",
        "available",
        "blocked",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_block_reason not in {
        "none",
        "dispatch_not_ready",
        "permission_not_allowed",
        "source_inconsistent",
        "high_risk_action",
        "side_effect_not_allowed",
        "duplicate_risk",
        "cooldown_required",
        "loop_suspected",
        "retry_budget_exhausted",
        "budget_exhausted",
        "failure_budget_exhausted",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_receipt_status not in {
        "not_created",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    if dispatch_status not in {
        "inactive",
        "prepared",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if invocation_status not in {
        "inactive",
        "prepared",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if invocation_threshold_used not in {
        "none",
        "standard_92",
        "simple_task_90",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if operation_contract_status not in {
        "inactive",
        "ready",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if rolling_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "cooldown_required",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if batch_continue_permission not in {
        "allowed_candidate",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if cooldown_status not in {"not_required", "required", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if loop_risk_status not in {"clear", "suspected", "blocked", "insufficient_truth"}:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if multistep_budget_status not in {
        "inactive",
        "ready",
        "blocked",
        "pause_required",
        "human_review_required",
        "insufficient_truth",
    }:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if multistep_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if duplicate_status not in _PROJECT_BROWSER_AUTONOMOUS_ACTION_DUPLICATE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if safety_switch_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFETY_SWITCH_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if manual_override_status not in _PROJECT_BROWSER_AUTONOMOUS_MANUAL_OVERRIDE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if safe_stop_status not in _PROJECT_BROWSER_AUTONOMOUS_SAFE_STOP_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_bridge_status not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_BRIDGE_STATUSES:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if execution_bridge_permission not in _PROJECT_BROWSER_AUTONOMOUS_EXECUTION_PERMISSIONS:
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    remaining_steps, remaining_steps_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_steps")
    )
    remaining_failures, remaining_failures_invalid = _read_required_non_negative_int(
        multistep_state.get("project_browser_autonomous_multistep_remaining_failures")
    )
    same_prompt_retry_remaining, same_prompt_retry_remaining_invalid = (
        _read_required_non_negative_int(
            multistep_state.get("project_browser_autonomous_multistep_same_prompt_retry_remaining")
        )
    )
    if (
        remaining_steps_invalid
        or remaining_failures_invalid
        or same_prompt_retry_remaining_invalid
    ):
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )

    expected_executor_action, mapped_action, mapped_kind = _map_executor_candidate(
        executor_candidate_kind
    )
    mapped_action_from_action, mapped_kind_from_action = _map_executor_action(executor_action)

    if executor_source_status == "insufficient_truth" or executor_readiness_status == "insufficient_truth":
        return _insufficient_truth_state(
            source_status="insufficient_truth",
            block_reason="insufficient_truth",
        )
    if executor_source_status == "inconsistent":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    if executor_readiness_status == "inactive":
        return _base_state(
            status="inactive",
            kind="none",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="none",
            low_risk_policy_status="unavailable",
            standard_policy_status="unavailable",
            high_risk_policy_status="unavailable",
            block_reason="executor_not_ready",
            receipt_status="not_created",
            receipt_kind="none",
        )
    if executor_readiness_status == "blocked":
        blocked_action = mapped_action_from_action if mapped_action_from_action != "none" else "none"
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action=blocked_action,
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason=_map_executor_block_reason(executor_block_reason),
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if executor_readiness_status == "cooldown_required":
        return _base_state(
            status="cooldown_required",
            kind="cooldown_adapter",
            permission="cooldown_required",
            action="cooldown",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="cooldown_required",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_adapter_receipt",
        )
    if executor_readiness_status == "pause_required":
        return _base_state(
            status="pause_required",
            kind="pause_adapter",
            permission="pause_required",
            action="pause_for_login",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_adapter_receipt",
        )
    if executor_readiness_status == "human_review_required":
        return _base_state(
            status="human_review_required",
            kind="human_review_adapter",
            permission="human_review_required",
            action="human_review",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="human_review_required",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_adapter_receipt",
        )
    if executor_readiness_status != "ready":
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    source_conflict = False
    if executor_permission != "allowed_candidate":
        source_conflict = True
    if executor_receipt_status != "ready":
        source_conflict = True
    if expected_executor_action == "none" and executor_candidate_kind != "none":
        source_conflict = True
    if expected_executor_action != "none" and expected_executor_action != executor_action:
        source_conflict = True
    if mapped_action == "none" and mapped_action_from_action != "none":
        mapped_action = mapped_action_from_action
        mapped_kind = mapped_kind_from_action
    if mapped_action == "none" and executor_action != "none":
        source_conflict = True
    if any(
        token == "insufficient_truth"
        for token in (
            dispatch_status,
            invocation_status,
            invocation_threshold_used,
            operation_contract_status,
            rolling_continue_permission,
            batch_continue_permission,
            cooldown_status,
            loop_risk_status,
            multistep_budget_status,
            multistep_permission,
            duplicate_status,
            safety_switch_status,
            manual_override_status,
            safe_stop_status,
            execution_permission,
            execution_bridge_status,
            execution_bridge_permission,
            executor_risk_status,
            executor_low_risk_path_status,
            executor_standard_path_status,
        )
    ):
        source_conflict = True
    if source_conflict:
        return _insufficient_truth_state(
            source_status="inconsistent",
            block_reason="source_inconsistent",
        )

    if dispatch_status != "prepared" or invocation_status != "prepared":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="executor_not_ready",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if operation_contract_status != "ready":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if rolling_continue_permission != "allowed_candidate":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if batch_continue_permission != "allowed_candidate":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if multistep_budget_status != "ready" or multistep_permission != "allowed_candidate":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if remaining_steps <= 0:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if remaining_failures <= 0:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="failure_budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if cooldown_status != "not_required":
        return _base_state(
            status="cooldown_required",
            kind="cooldown_adapter",
            permission="cooldown_required",
            action="cooldown",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="cooldown_required",
            receipt_status="cooldown_required",
            receipt_kind="cooldown_adapter_receipt",
        )
    if loop_risk_status != "clear":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="loop_suspected",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if safety_switch_status in {"pause_after_current_step", "pause_required"}:
        return _base_state(
            status="pause_required",
            kind="pause_adapter",
            permission="pause_required",
            action="pause_for_login",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_adapter_receipt",
        )
    if safety_switch_status in {"manual_review_required"}:
        return _base_state(
            status="human_review_required",
            kind="human_review_adapter",
            permission="human_review_required",
            action="human_review",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="human_review_required",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_adapter_receipt",
        )
    if safety_switch_status in {"disabled", "stop_all"}:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if manual_override_status in {"requested"}:
        return _base_state(
            status="pause_required",
            kind="pause_adapter",
            permission="pause_required",
            action="pause_for_login",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="pause_required",
            receipt_status="pause_required",
            receipt_kind="pause_adapter_receipt",
        )
    if manual_override_status in {"required"}:
        return _base_state(
            status="human_review_required",
            kind="human_review_adapter",
            permission="human_review_required",
            action="human_review",
            source_status="valid",
            risk_status="high",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="human_review_required",
            block_reason="human_review_required",
            receipt_status="human_review_required",
            receipt_kind="human_review_adapter_receipt",
        )
    if manual_override_status in {"blocked"}:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if safe_stop_status != "not_required":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if execution_permission != "allowed_candidate":
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if (
        execution_bridge_status != "ready"
        or execution_bridge_permission != "allowed_candidate"
    ):
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="permission_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if duplicate_status in {
        "duplicate_action",
        "duplicate_prompt",
        "duplicate_md_update",
        "duplicate_pause",
        "duplicate_human_review",
    }:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="duplicate_risk",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )

    if executor_risk_status in {"high", "blocked"}:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )

    side_effect_class = _map_side_effect_class(mapped_action)
    if side_effect_class in {"blocked", "insufficient_truth"}:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="side_effect_not_allowed",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if mapped_action == "browser_retry_enqueue_candidate" and same_prompt_retry_remaining <= 0:
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="none",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="blocked",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="retry_budget_exhausted",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )
    if mapped_action in {"stop", "cooldown", "pause_for_login", "human_review"}:
        if mapped_action == "cooldown":
            return _base_state(
                status="cooldown_required",
                kind="cooldown_adapter",
                permission="cooldown_required",
                action="cooldown",
                source_status="valid",
                risk_status="high",
                side_effect_class="metadata_only",
                low_risk_policy_status="blocked",
                standard_policy_status="blocked",
                high_risk_policy_status="blocked",
                block_reason="cooldown_required",
                receipt_status="cooldown_required",
                receipt_kind="cooldown_adapter_receipt",
            )
        if mapped_action == "pause_for_login":
            return _base_state(
                status="pause_required",
                kind="pause_adapter",
                permission="pause_required",
                action="pause_for_login",
                source_status="valid",
                risk_status="high",
                side_effect_class="metadata_only",
                low_risk_policy_status="blocked",
                standard_policy_status="blocked",
                high_risk_policy_status="blocked",
                block_reason="pause_required",
                receipt_status="pause_required",
                receipt_kind="pause_adapter_receipt",
            )
        if mapped_action == "human_review":
            return _base_state(
                status="human_review_required",
                kind="human_review_adapter",
                permission="human_review_required",
                action="human_review",
                source_status="valid",
                risk_status="high",
                side_effect_class="metadata_only",
                low_risk_policy_status="blocked",
                standard_policy_status="blocked",
                high_risk_policy_status="human_review_required",
                block_reason="human_review_required",
                receipt_status="human_review_required",
                receipt_kind="human_review_adapter_receipt",
            )
        return _base_state(
            status="blocked",
            kind="blocked_adapter",
            permission="blocked",
            action="stop",
            source_status="valid",
            risk_status="blocked",
            side_effect_class="metadata_only",
            low_risk_policy_status="blocked",
            standard_policy_status="blocked",
            high_risk_policy_status="blocked",
            block_reason="high_risk_action",
            receipt_status="blocked",
            receipt_kind="blocked_adapter_receipt",
        )

    if executor_risk_status == "low":
        if executor_low_risk_path_status != "available":
            return _base_state(
                status="blocked",
                kind="blocked_adapter",
                permission="blocked",
                action="none",
                source_status="valid",
                risk_status="blocked",
                side_effect_class="blocked",
                low_risk_policy_status="blocked",
                standard_policy_status="blocked",
                high_risk_policy_status="unavailable",
                block_reason="permission_not_allowed",
                receipt_status="blocked",
                receipt_kind="blocked_adapter_receipt",
            )
        if invocation_threshold_used not in {"simple_task_90", "standard_92"}:
            return _base_state(
                status="blocked",
                kind="blocked_adapter",
                permission="blocked",
                action="none",
                source_status="valid",
                risk_status="blocked",
                side_effect_class="blocked",
                low_risk_policy_status="blocked",
                standard_policy_status="blocked",
                high_risk_policy_status="unavailable",
                block_reason="permission_not_allowed",
                receipt_status="blocked",
                receipt_kind="blocked_adapter_receipt",
            )
        return _base_state(
            status="executable_candidate",
            kind="low_risk_execution_adapter",
            permission="allowed_candidate",
            action=mapped_action,
            source_status="valid",
            risk_status="low",
            side_effect_class=side_effect_class,
            low_risk_policy_status="available",
            standard_policy_status="unavailable",
            high_risk_policy_status="unavailable",
            block_reason="none",
            receipt_status="ready",
            receipt_kind="executable_candidate_receipt",
        )

    if executor_risk_status == "standard":
        if executor_standard_path_status != "available":
            return _base_state(
                status="blocked",
                kind="blocked_adapter",
                permission="blocked",
                action="none",
                source_status="valid",
                risk_status="blocked",
                side_effect_class="blocked",
                low_risk_policy_status="unavailable",
                standard_policy_status="blocked",
                high_risk_policy_status="unavailable",
                block_reason="permission_not_allowed",
                receipt_status="blocked",
                receipt_kind="blocked_adapter_receipt",
            )
        if invocation_threshold_used != "standard_92":
            return _base_state(
                status="blocked",
                kind="blocked_adapter",
                permission="blocked",
                action="none",
                source_status="valid",
                risk_status="blocked",
                side_effect_class="blocked",
                low_risk_policy_status="unavailable",
                standard_policy_status="blocked",
                high_risk_policy_status="unavailable",
                block_reason="permission_not_allowed",
                receipt_status="blocked",
                receipt_kind="blocked_adapter_receipt",
            )
        return _base_state(
            status="execution_ready_candidate",
            kind="standard_execution_adapter",
            permission="allowed_candidate",
            action=mapped_action,
            source_status="valid",
            risk_status="standard",
            side_effect_class=side_effect_class,
            low_risk_policy_status="unavailable",
            standard_policy_status="available",
            high_risk_policy_status="unavailable",
            block_reason="none",
            receipt_status="ready",
            receipt_kind="execution_ready_candidate_receipt",
        )

    return _insufficient_truth_state(
        source_status="inconsistent",
        block_reason="source_inconsistent",
    )


